function jsonOk(reply: FastifyReply, payload: Record<string, unknown>, status = 200): FastifyReply {
  return reply.status(status).send({ ok: true, ...payload });
}

function jsonError(reply: FastifyReply, error: string, status = 400, details?: unknown): FastifyReply {
  return reply.status(status).send({ ok: false, error, ...(details !== undefined ? { details } : {}) });
}

function readAuthToken(request: FastifyRequest): string {
  const authorization = request.headers.authorization;
  if (authorization?.startsWith('Bearer ')) {
    return authorization.slice('Bearer '.length);
  }

  const tokenHeader = request.headers['x-api-token'];
  if (Array.isArray(tokenHeader)) {
    return tokenHeader[0] ?? '';
  }
  if (typeof tokenHeader === 'string' && tokenHeader.length > 0) {
    return tokenHeader;
  }

  // EventSource cannot set custom headers, so allow query-token auth only on stream routes.
  const pathname = normalizeRequestPath(request.url);
  if (!pathMatchesPrefix(pathname, '/api/events/stream') && !pathMatchesPrefix(pathname, '/api/office/stream')) {
    return '';
  }

  try {
    const parsed = new URL(request.url, 'http://localhost');
    const queryToken = parsed.searchParams.get('token') ?? parsed.searchParams.get('api_token');
    return queryToken?.trim() ?? '';
  } catch {
    return '';
  }
}

function hasValidApiToken(request: FastifyRequest, expectedToken: string): boolean {
  const token = readAuthToken(request);
  return token.length > 0 && token === expectedToken;
}

type AccessRole = 'viewer' | 'operator' | 'admin';

const ACCESS_ROLE_RANK: Record<AccessRole, number> = {
  viewer: 1,
  operator: 2,
  admin: 3
};

function normalizeAccessRole(input: unknown): AccessRole | null {
  if (typeof input !== 'string') {
    return null;
  }
  const normalized = input.trim().toLowerCase();
  if (normalized === 'viewer' || normalized === 'operator' || normalized === 'admin') {
    return normalized;
  }
  return null;
}

function readHeaderString(headers: Record<string, unknown>, key: string): string | null {
  const value = headers[key];
  if (Array.isArray(value)) {
    for (const entry of value) {
      if (typeof entry === 'string' && entry.trim().length > 0) {
        return entry.trim();
      }
    }
    return null;
  }
  return typeof value === 'string' && value.trim().length > 0 ? value.trim() : null;
}

function resolveAuthenticatedBaseRole(request: FastifyRequest, expectedToken: string): AccessRole {
  if (!hasValidApiToken(request, expectedToken)) {
    return 'viewer';
  }
  return 'admin';
}

function resolveRequestRole(request: FastifyRequest, expectedToken: string): AccessRole {
  const baseRole = resolveAuthenticatedBaseRole(request, expectedToken);
  const headerRole = normalizeAccessRole(request.headers['x-ops-role']);
  if (!headerRole) {
    return baseRole;
  }
  return ACCESS_ROLE_RANK[headerRole] <= ACCESS_ROLE_RANK[baseRole] ? headerRole : baseRole;
}

function resolveRequestAuditActor(request: FastifyRequest, expectedToken: string): string {
  if (!hasValidApiToken(request, expectedToken)) {
    return 'anonymous';
  }
  return `api:${resolveRequestRole(request, expectedToken)}`;
}

function buildFrontierActorProof(secret: string, input: { principalId: string; actorType: string; companyId: string | null }): string {
  return createHmac('sha256', secret)
    .update([input.principalId.trim(), input.actorType.trim().toLowerCase(), input.companyId?.trim() ?? ''].join('\n'))
    .digest('hex');
}

function isVerifiedFrontierActorProof(
  providedProof: string | null,
  expectedProof: string
): boolean {
  if (!providedProof) {
    return false;
  }
  const left = Buffer.from(providedProof, 'utf8');
  const right = Buffer.from(expectedProof, 'utf8');
  return left.length === right.length && timingSafeEqual(left, right);
}

function resolveTrustedFrontierActorContext(
  request: FastifyRequest,
  fallbackCompanyId: string,
  apiToken: string
): ReturnType<typeof resolveFrontierActorContext> {
  const defaultActor = resolveFrontierActorContext({}, fallbackCompanyId);
  const requestedActor = resolveFrontierActorContext(
    request.headers as unknown as Record<string, unknown>,
    fallbackCompanyId
  );
  const overrideRequested =
    readHeaderString(request.headers as Record<string, unknown>, 'x-ops-principal-id') !== null ||
    readHeaderString(request.headers as Record<string, unknown>, 'x-ops-actor-type') !== null ||
    readHeaderString(request.headers as Record<string, unknown>, 'x-ops-company-id') !== null;
  if (!overrideRequested) {
    return defaultActor;
  }
  const providedProof = readHeaderString(request.headers as Record<string, unknown>, 'x-ops-frontier-proof');
  const expectedProof = buildFrontierActorProof(apiToken, requestedActor);
  return isVerifiedFrontierActorProof(providedProof, expectedProof) ? requestedActor : defaultActor;
}

function requiredRoleForApiRoute(pathname: string, method: string): AccessRole {
  const upperMethod = method.toUpperCase();
  if (upperMethod === 'GET' || upperMethod === 'HEAD') {
    return 'viewer';
  }

  // Reserve admin-only policy mutation surfaces.
  if (pathMatchesPrefix(pathname, '/api/rbac/policy')) {
    return 'admin';
  }
  return 'operator';
}

function hasRequiredRole(actual: AccessRole, required: AccessRole): boolean {
  return ACCESS_ROLE_RANK[actual] >= ACCESS_ROLE_RANK[required];
}

function tokenFingerprint(token: string): string {
  return createHash('sha256').update(token).digest('hex').slice(0, 12);
}

function normalizeToolName(command: string): string {
  return command.trim().split(/\s+/)[0] ?? '';
}

function isPathLikeCommand(command: string): boolean {
  return command.includes('/') || command.includes('\\');
}

function normalizeCatalogToolName(command: string): string {
  const binary = normalizeToolName(command);
  if (!binary) {
    return '';
  }
  if (isPathLikeCommand(binary) && !path.isAbsolute(binary)) {
    const basename = path.basename(binary).trim();
    return basename || binary;
  }
  return binary;
}

function isSameExecutableFamily(leftArgv: string[], rightArgv: string[]): boolean {
  const left = normalizeCatalogToolName(leftArgv[0] ?? '');
  const right = normalizeCatalogToolName(rightArgv[0] ?? '');
  return left.length > 0 && right.length > 0 && left === right;
}

const EXECUTABLE_ALIAS_CACHE_MAX_ENTRIES = 512;
const executableAliasCache = new Map<string, string | null>();

const rememberExecutableAliasResolution = (cacheKey: string, resolvedPath: string | null): string | null => {
  if (executableAliasCache.size >= EXECUTABLE_ALIAS_CACHE_MAX_ENTRIES) {
    executableAliasCache.clear();
  }
  executableAliasCache.set(cacheKey, resolvedPath);
  return resolvedPath;
};

const buildExecutableAliasCacheKey = (binary: string): string =>
  `${process.platform}\u0000${resolveRuntimeToolBinDir()}\u0000${process.env.PATH ?? ''}\u0000${binary}`;

function isPathWithinDirectory(targetPath: string, directoryPath: string): boolean {
  const normalizedTargetPath = path.resolve(targetPath);
  const normalizedDirectoryPath = path.resolve(directoryPath);
  return (
    normalizedTargetPath === normalizedDirectoryPath ||
    normalizedTargetPath.startsWith(`${normalizedDirectoryPath}${path.sep}`)
  );
}

function resolveExecutableAlias(command: string, cwd?: string): string | null {
  const binary = normalizeToolName(command);
  if (!binary) {
    return null;
  }
  if (isPathLikeCommand(binary)) {
    const resolvedPath = path.isAbsolute(binary) ? path.resolve(binary) : path.resolve(cwd ?? process.cwd(), binary);
    try {
      fsSync.accessSync(resolvedPath, fsSync.constants.X_OK);
      return resolvedPath;
    } catch {
      return null;
    }
  }
  const cacheKey = buildExecutableAliasCacheKey(binary);
  if (executableAliasCache.has(cacheKey)) {
    return executableAliasCache.get(cacheKey) ?? null;
  }
  const lookup = process.platform === 'win32' ? 'where' : 'which';
  const candidates = binary === 'python' ? ['python', 'python3'] : [binary];
  for (const candidate of candidates) {
    const bootstrapCandidate = path.resolve(resolveRuntimeToolBinDir(), candidate);
    try {
      fsSync.accessSync(bootstrapCandidate, fsSync.constants.X_OK);
      return rememberExecutableAliasResolution(cacheKey, bootstrapCandidate);
    } catch {
      // Fall through to host PATH lookup.
    }
    const result = spawnSync(lookup, [candidate], {
      stdio: ['ignore', 'pipe', 'ignore'],
      encoding: 'utf8'
    });
    if (result.status === 0) {
      const resolvedPath = String(result.stdout ?? '')
        .split(/\r?\n/u)
        .map((entry) => entry.trim())
        .find((entry) => entry.length > 0);
      return rememberExecutableAliasResolution(cacheKey, resolvedPath ?? candidate);
    }
  }
  return rememberExecutableAliasResolution(cacheKey, null);
}

function resolveExecutableAliasOutsideDirectory(command: string, excludedDir: string, cwd?: string): string | null {
  const binary = normalizeToolName(command);
  if (!binary) {
    return null;
  }
  if (isPathLikeCommand(binary)) {
    const resolvedPath = path.isAbsolute(binary) ? path.resolve(binary) : path.resolve(cwd ?? process.cwd(), binary);
    try {
      fsSync.accessSync(resolvedPath, fsSync.constants.X_OK);
      return isPathWithinDirectory(resolvedPath, excludedDir) ? null : resolvedPath;
    } catch {
      return null;
    }
  }

  const candidates = binary === 'python' ? ['python', 'python3'] : [binary];
  const pathEntries = (process.env.PATH ?? '')
    .split(path.delimiter)
    .map((entry) => entry.trim())
    .filter((entry) => entry.length > 0);

  for (const candidate of candidates) {
    for (const entry of pathEntries) {
      if (isPathWithinDirectory(entry, excludedDir)) {
        continue;
      }
      const resolvedPath = path.resolve(entry, candidate);
      try {
        fsSync.accessSync(resolvedPath, fsSync.constants.X_OK);
        return resolvedPath;
      } catch {
        continue;
      }
    }
  }
  return null;
}

function commandExists(command: string, cwd?: string): boolean {
  return resolveExecutableAlias(command, cwd) !== null;
}

function resolveRuntimeToolBinDir(): string {
  const configured = process.env.OPS_RUNTIME_TOOL_BIN_DIR?.trim();
  if (configured) {
    return path.resolve(configured);
  }
  return path.resolve('/var/lib/ops/tooling/bin');
}

function parseModelCatalog(envValue: string | undefined): string[] {
  if (!envValue) {
    return ['default'];
  }

  const parsed = envValue
    .split(',')
    .map((item) => item.trim())
    .filter(Boolean);

  return parsed.length > 0 ? parsed : ['default'];
}

function parsePagination(query: Record<string, unknown>): { limit: number; offset: number } {
  const limit = Math.max(1, Math.min(200, Number(query.limit ?? 25)));
  const offset = Math.max(0, Number(query.offset ?? 0));
  return {
    limit: Number.isFinite(limit) ? limit : 25,
    offset: Number.isFinite(offset) ? offset : 0
  };
}

function isoHoursAgo(hours: number): string {
  return new Date(Date.now() - Math.max(1, hours) * 60 * 60 * 1000).toISOString();
}

function isoDaysAgo(days: number): string {
  return new Date(Date.now() - Math.max(1, days) * 24 * 60 * 60 * 1000).toISOString();
}

function isoDayUtcAgo(days: number): string {
  return isoDaysAgo(days).slice(0, 10);
}

function parseStringList(raw: string, fallback: string[] = []): string[] {
  const parsed = parseJsonSafe<unknown>(raw, fallback);
  if (!Array.isArray(parsed)) {
    return fallback;
  }
  return parsed.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0);
}

function parseOptionalBodyStringArray(raw: unknown): string[] | undefined {
  if (!Array.isArray(raw)) {
    return undefined;
  }
  const parsed = raw.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0);
  return parsed;
}

function latestPresenceByAgent(rows: OfficePresenceRecord[]): OfficePresenceRecord[] {
  const latest = new Map<string, OfficePresenceRecord>();
  for (const row of rows) {
    if (!latest.has(row.agentId)) {
      latest.set(row.agentId, row);
    }
  }
  return Array.from(latest.values());
}

const RUNTIME_CONFIG_OVERLAY_RESOURCE = 'sqlite:runtime_config_overlay';
const DEFAULT_CONTROL_PLANE_CONFIG_PATH = path.resolve('config/control-plane.yaml');

function shouldApplyRuntimeConfigOverlay(runtimeConfigPath?: string | null): boolean {
  const resolvedRuntimeConfigPath =
    typeof runtimeConfigPath === 'string' && runtimeConfigPath.trim().length > 0
      ? path.resolve(runtimeConfigPath)
      : DEFAULT_CONTROL_PLANE_CONFIG_PATH;
  return resolvedRuntimeConfigPath === DEFAULT_CONTROL_PLANE_CONFIG_PATH;
}

function resolveRuntimeConfigOverlay(
  baseConfig: ControlPlaneConfig,
  database: ControlPlaneDatabase,
  options?: {
    runtimeConfigPath?: string | null;
  }
): {
  config: ControlPlaneConfig;
  overlayApplied: boolean;
  issues: Array<{ path: string; message: string }>;
} {
  if (!shouldApplyRuntimeConfigOverlay(options?.runtimeConfigPath)) {
    return {
      config: baseConfig,
      overlayApplied: false,
      issues: []
    };
  }
  const overlay = database.getRuntimeConfigOverlay();
  if (!overlay) {
    return {
      config: baseConfig,
      overlayApplied: false,
      issues: []
    };
  }

  const parsedRaw = parseJsonSafe<unknown>(overlay.configJson, null);
  const parsed = controlPlaneConfigSchema.safeParse(parsedRaw);
  if (!parsed.success) {
    return {
      config: baseConfig,
      overlayApplied: false,
      issues: parsed.error.issues.map((issue) => ({
        path: issue.path.join('.'),
        message: issue.message
      }))
    };
  }

  const overlayConfig = structuredClone(parsed.data);
  const envDefined = (name: string): boolean => process.env[name] !== undefined;

  // Env vars should remain the strongest source of truth for critical secrets and startup controls.
  if (envDefined('OPS_API_TOKEN')) {
    overlayConfig.server.apiToken = baseConfig.server.apiToken;
  }

  if (envDefined('OPS_TELEGRAM_ENABLED')) {
    overlayConfig.channel.telegram.enabled = baseConfig.channel.telegram.enabled;
  }
  if (envDefined('OPS_TELEGRAM_BOT_TOKEN')) {
    overlayConfig.channel.telegram.botToken = baseConfig.channel.telegram.botToken;
  }
  if (envDefined('OPS_TELEGRAM_USE_WEBHOOK')) {
    overlayConfig.channel.telegram.useWebhook = baseConfig.channel.telegram.useWebhook;
  }
  if (envDefined('OPS_TELEGRAM_DEBUG_RAW_OUTPUT')) {
    overlayConfig.channel.telegram.debugRawOutput = baseConfig.channel.telegram.debugRawOutput;
  }
  if (envDefined('OPS_TELEGRAM_DM_SCOPE')) {
    overlayConfig.channel.telegram.dmScope = baseConfig.channel.telegram.dmScope;
  }
  if (envDefined('OPS_TELEGRAM_REQUIRE_MENTION')) {
    overlayConfig.channel.telegram.requireMentionInGroups = baseConfig.channel.telegram.requireMentionInGroups;
  }
  if (envDefined('OPS_TELEGRAM_ALLOWLIST')) {
    overlayConfig.channel.telegram.allowlist = baseConfig.channel.telegram.allowlist;
  }

  if (envDefined('OPS_VAULT_ENABLED')) {
    overlayConfig.vault.enabled = baseConfig.vault.enabled;
  }
  if (envDefined('OPS_VAULT_REQUIRE_UNLOCK_ON_STARTUP')) {
    overlayConfig.vault.requireUnlockOnStartup = baseConfig.vault.requireUnlockOnStartup;
  }
  if (envDefined('OPS_VAULT_AUTO_UNLOCK_FROM_ENV')) {
    overlayConfig.vault.autoUnlockFromEnv = baseConfig.vault.autoUnlockFromEnv;
  }
  if (envDefined('OPS_VAULT_ENV_KEY')) {
    overlayConfig.vault.envKey = baseConfig.vault.envKey;
  }
  if (envDefined('OPS_VAULT_ALLOW_PASSPHRASE_UNLOCK')) {
    overlayConfig.vault.allowPassphraseUnlock = baseConfig.vault.allowPassphraseUnlock;
  }
  if (envDefined('OPS_VAULT_PASSPHRASE_SALT')) {
    overlayConfig.vault.passphraseSalt = baseConfig.vault.passphraseSalt;
  }
  if (envDefined('OPS_VAULT_PASSPHRASE_ITERATIONS')) {
    overlayConfig.vault.passphraseIterations = baseConfig.vault.passphraseIterations;
  }

  return {
    config: overlayConfig,
    overlayApplied: true,
    issues: []
  };
}

interface ParsedPlanTask {
  taskId: string;
  category: string | null;
  description: string;
  summary: string | null;
  surface: string | null;
  files: string[];
  passes: boolean;
  dependsOnTaskIds: string[];
  steps: string[];
  criteria: string[];
  priority: number;
}

function defaultPriorityForPlanCategory(category: string | null): number {
  const normalized = category?.trim().toLowerCase() ?? '';
  if (normalized === 'setup') {
    return 50;
  }
  if (normalized === 'feature' || normalized === 'api') {
    return 78;
  }
  if (normalized === 'data') {
    return 72;
  }
  if (normalized === 'testing') {
    return 68;
  }
  if (normalized === 'ui') {
    return 64;
  }
  return 60;
}

function coercePlanTaskRecords(payload: unknown): Array<Record<string, unknown>> | null {
  if (Array.isArray(payload)) {
    const records = payload.filter((entry) => isRecord(entry));
    return records.length > 0 ? records : null;
  }
  if (isRecord(payload) && Array.isArray(payload.tasks)) {
    const records = payload.tasks.filter((entry) => isRecord(entry));
    return records.length > 0 ? records : null;
  }
  return null;
}

function normalizePlanTaskCriteria(value: unknown): string[] {
  if (Array.isArray(value)) {
    return value.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0);
  }
  if (!isRecord(value)) {
    return [];
  }
  const example =
    typeof value.example === 'string' && value.example.trim().length > 0 ? `Example: ${value.example.trim()}` : null;
  const negative =
    typeof value.negative === 'string' && value.negative.trim().length > 0
      ? `Negative: ${value.negative.trim()}`
      : null;
  return [example, negative].filter((entry): entry is string => Boolean(entry));
}

function normalizePlanTaskStringList(value: unknown): string[] {
  if (!Array.isArray(value)) {
    return [];
  }
  return value.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0);
}

const PLAN_TASK_TEXT_STOPWORDS = new Set([
  'a',
  'an',
  'and',
  'app',
  'application',
  'auth',
  'build',
  'create',
  'fix',
  'for',
  'from',
  'in',
  'inside',
  'into',
  'make',
  'nav',
  'navigation',
  'new',
  'of',
  'on',
  'page',
  'pages',
  'public',
  'route',
  'routes',
  'screen',
  'shell',
  'simple',
  'support',
  'the',
  'to',
  'update',
  'wire',
  'with'
]);

const DISCOVERY_ONLY_PLAN_VERBS = [
  'analyze',
  'assess',
  'audit',
  'check',
  'confirm',
  'discover',
  'identify',
  'inspect',
  'inventory',
  'map',
  'read',
  'review',
  'survey',
  'understand',
  'verify'
] as const;

const DELIVERY_PLAN_VERBS = [
  'add',
  'build',
  'configure',
  'create',
  'implement',
  'integrate',
  'link',
  'migrate',
  'publish',
  'refactor',
  'remove',
  'replace',
  'ship',
  'update',
  'wire',
  'write'
] as const;

function tokenizePlanTaskText(value: string): string[] {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9/._-]+/g, ' ')
    .split(/\s+/)
    .map((token) => token.trim().replace(/^[./_-]+|[./_-]+$/g, ''))
    .filter((token) => token.length >= 3 && !PLAN_TASK_TEXT_STOPWORDS.has(token) && !/^t-\d+$/i.test(token));
}

function normalizedPlanTaskSignature(task: Pick<ParsedPlanTask, 'description' | 'steps' | 'criteria'>): string {
  return Array.from(new Set(tokenizePlanTaskText([task.description, ...task.steps, ...task.criteria].join(' '))))
    .sort()
    .join(' ');
}

function planTaskWorkstreamFamily(category: string | null): 'setup' | 'validation' | 'product' | 'service' | 'other' {
  const normalized = category?.trim().toLowerCase() ?? '';
  if (normalized === 'setup') {
    return 'setup';
  }
  if (normalized === 'testing') {
    return 'validation';
  }
  if (normalized === 'feature' || normalized === 'ui') {
    return 'product';
  }
  if (normalized === 'api' || normalized === 'data') {
    return 'service';
  }
  return 'other';
}

function isSimpleSingleFeaturePrompt(prompt: string): boolean {
  const normalized = prompt.trim().toLowerCase();
  if (normalized.length === 0 || normalized.length > 220) {
    return false;
  }
  if (/\b(audit|benchmark|compare|deploy|infra|investigate|migrate|migration|roadmap)\b/.test(normalized)) {
    return false;
  }
  const actionHits = normalized.match(/\b(add|build|create|fix|implement|make|publish|ship|update)\b/g) ?? [];
  if (actionHits.length === 0) {
    return false;
  }
  const connectorHits = normalized.match(/\b(and|plus|then)\b/g) ?? [];
  return connectorHits.length <= 2;
}

function extractPromptFeatureTokens(prompt: string): string[] {
  return Array.from(
    new Set(
      tokenizePlanTaskText(prompt).filter((token) => {
        if (token === 'clone' || token === 'repo' || token === 'repository' || token === 'workspace') {
          return false;
        }
        if (token.includes('.') || token.includes('/')) {
          return !token.endsWith('.ai') && !token.endsWith('.com');
        }
        return true;
      })
    )
  );
}

function isDiscoveryOnlyPlanTask(task: ParsedPlanTask): boolean {
  const text = [task.description, ...task.steps].join(' ').trim().toLowerCase();
  if (text.length === 0) {
    return false;
  }
  const hasDiscoveryVerb = DISCOVERY_ONLY_PLAN_VERBS.some((verb) => new RegExp(`\\b${verb}\\b`, 'i').test(text));
  if (!hasDiscoveryVerb) {
    return false;
  }
  const hasDeliveryVerb = DELIVERY_PLAN_VERBS.some((verb) => new RegExp(`\\b${verb}\\b`, 'i').test(text));
  return !hasDeliveryVerb;
}

function validateProjectIntakePlanTasks(tasks: ParsedPlanTask[], prompt: string): string | null {
  const duplicateTaskIds: string[] = [];
  const seenTaskIds = new Set<string>();
  for (const task of tasks) {
    if (seenTaskIds.has(task.taskId)) {
      duplicateTaskIds.push(task.taskId);
      continue;
    }
    seenTaskIds.add(task.taskId);
  }
  if (duplicateTaskIds.length > 0) {
    return `Duplicate PLAN task ids detected: ${Array.from(new Set(duplicateTaskIds)).join(', ')}.`;
  }

  const descriptionOwnerBySignature = new Map<string, string>();
  for (const task of tasks) {
    const signature = normalizedPlanTaskSignature(task);
    if (!signature) {
      continue;
    }
    const existingOwner = descriptionOwnerBySignature.get(signature);
    if (existingOwner && existingOwner !== task.taskId) {
      return `Duplicate PLAN task scope detected between ${existingOwner} and ${task.taskId}.`;
    }
    descriptionOwnerBySignature.set(signature, task.taskId);
  }

  if (!isSimpleSingleFeaturePrompt(prompt)) {
    return null;
  }

  const featureTokens = extractPromptFeatureTokens(prompt);
  if (featureTokens.length === 0) {
    return null;
  }

  const implementationTasks = tasks
    .map((task) => ({
      task,
      family: planTaskWorkstreamFamily(task.category),
      tokens: new Set(tokenizePlanTaskText([task.description, ...task.steps, ...task.criteria].join(' ')))
    }))
    .filter((entry) => entry.family === 'product' || entry.family === 'service');

  if (implementationTasks.length > 2) {
    return `Simple single-feature intake is oversplit across ${implementationTasks.length} implementation tasks. Collapse related implementation work into one cohesive task plus setup/validation.`;
  }

  const discoveryOnlySetupTasks = tasks.filter((task) => {
    const family = planTaskWorkstreamFamily(task.category);
    return (family === 'setup' || family === 'other') && isDiscoveryOnlyPlanTask(task);
  });
  if (discoveryOnlySetupTasks.length > 0 && implementationTasks.length > 0) {
    return `Simple single-feature intake split discovery-only work into ${discoveryOnlySetupTasks
      .map((task) => task.taskId)
      .join(', ')}. Fold route/nav/test surface confirmation into the implementation or validation task instead of creating a standalone discovery task.`;
  }

  for (let index = 0; index < implementationTasks.length; index += 1) {
    const current = implementationTasks[index];
    if (!current) {
      continue;
    }
    for (let candidateIndex = index + 1; candidateIndex < implementationTasks.length; candidateIndex += 1) {
      const candidate = implementationTasks[candidateIndex];
      if (!candidate) {
        continue;
      }
      if (candidate.family !== current.family) {
        continue;
      }
      const overlappingFeatureTokens = featureTokens.filter(
        (token) => current.tokens.has(token) && candidate.tokens.has(token)
      );
      if (overlappingFeatureTokens.length > 0) {
        return `Simple single-feature intake duplicates ${current.task.taskId} and ${candidate.task.taskId} around ${overlappingFeatureTokens.slice(0, 3).join(', ')}. Merge them into one cohesive implementation task.`;
      }
    }
  }

  return null;
}

function parsePlanTasksFromDocument(raw: string): ParsedPlanTask[] {
  const parsePayload = (value: string): Array<Record<string, unknown>> | null => {
    const parsed = parseJsonSafe<unknown>(value, null);
    return coercePlanTaskRecords(parsed);
  };

  let taskRecords = parsePayload(raw);
  if (!taskRecords) {
    const fencedBlocks = Array.from(raw.matchAll(/```json\s*([\s\S]*?)```/gi));
    for (const block of fencedBlocks) {
      const candidate = block[1];
      if (!candidate) {
        continue;
      }
      taskRecords = parsePayload(candidate);
      if (taskRecords) {
        break;
      }
    }
  }

  if (!taskRecords) {
    throw new Error('No JSON task list found in PLAN document.');
  }

  const parsedTasks: ParsedPlanTask[] = [];
  for (const record of taskRecords) {
    const taskId = String(record.id ?? '').trim();
    const description = String(record.description ?? record.title ?? record.summary ?? '').trim();
    if (!taskId || !description) {
      continue;
    }

    const category = typeof record.category === 'string' && record.category.trim().length > 0 ? record.category.trim() : null;
    const summary = typeof record.summary === 'string' && record.summary.trim().length > 0 ? record.summary.trim() : null;
    const surface = typeof record.surface === 'string' && record.surface.trim().length > 0 ? record.surface.trim() : null;
    const files = normalizePlanTaskStringList(record.files).slice(0, 24);
    const dependsOnRaw = Array.isArray(record.depends_on)
      ? record.depends_on
      : Array.isArray(record.dependsOn)
        ? record.dependsOn
        : [];
    const dependsOnTaskIds = dependsOnRaw
      .map((entry) => String(entry).trim())
      .filter((entry) => entry.length > 0 && entry !== taskId);
    const stepCandidates = [
      ...normalizePlanTaskStringList(record.steps),
      ...normalizePlanTaskStringList(record.implementation)
    ];
    const steps = Array.from(new Set(stepCandidates));
    const criteria = Array.from(
      new Set([
        ...normalizePlanTaskCriteria(record.criteria),
        ...normalizePlanTaskStringList(record.acceptanceCriteria),
        ...normalizePlanTaskStringList(record.qualityGates).map((entry) =>
          /^quality gate:/i.test(entry) ? entry : `Quality gate: ${entry}`
        ),
        ...normalizePlanTaskStringList(record.negativeCases).map((entry) =>
          /^negative:/i.test(entry) ? entry : `Negative: ${entry}`
        )
      ])
    );

    const priorityRaw = Number(record.priority);
    const priority = Number.isFinite(priorityRaw)
      ? Math.max(1, Math.min(100, Math.floor(priorityRaw)))
      : defaultPriorityForPlanCategory(category);

    parsedTasks.push({
      taskId,
      category,
      description,
      summary,
      surface,
      files,
      passes: record.passes === true,
      dependsOnTaskIds: Array.from(new Set(dependsOnTaskIds)),
      steps,
      criteria,
      priority
    });
  }

  if (parsedTasks.length === 0) {
    throw new Error('PLAN JSON contains no valid tasks with id + description.');
  }

  return parsedTasks;
}

function buildProjectIntakeArtifactRetryPrompt(input: {
  basePrompt: string;
  planPath: string;
  prdPath: string;
  validationReason: string | null;
}): string {
  const lines = [
    input.basePrompt.trim(),
    '',
    'PROJECT_INTAKE_RETRY:',
    'The previous attempt claimed completion, but the required intake artifacts were not updated in place to a syncable state.',
    `Required PRD path: ${input.prdPath}`,
    `Required PLAN path: ${input.planPath}`,
    ...(input.validationReason ? [`Validation failure: ${input.validationReason}`] : []),
    'Write-first protocol:',
    '1. Update the PRD and PLAN at the exact paths above before doing any broad repo audit.',
    '2. Do not inspect repo-local `.agents/*` unless the required target files themselves live in `.agents`.',
    '3. Keep discovery narrow: README, top-level manifests/lockfiles, and only the route/nav files needed for the request.',
    '4. Do not run installs, builds, or tests in this planning run.',
    '5. Limit the PLAN to 3-5 tasks for simple single-feature requests; use 4-6 tasks only when the request truly spans multiple independent surfaces.',
    '6. Merge overlapping implementation work. Do not split one page/route/nav surface into multiple sequential implementation tasks.',
    '7. Derive paths, scope, and task count from the linked repo context and existing PRD/PLAN artifacts. Do not hardcode repo-specific assumptions.',
    'You must directly edit those files in this run.',
    'Do not return a bash script, patch snippet, or instructions for someone else to execute.',
    'Required before final answer:',
    '1. Write the PRD markdown directly to the PRD path above.',
    '2. Write the PLAN directly to the PLAN path above.',
    '3. The PLAN must contain a parseable task list as raw JSON or a fenced ```json``` block.',
    '4. Each task must include at least: id, description, depends_on, steps, criteria, passes.',
    '5. Keep dependencies acyclic and reference only earlier task ids.',
    '6. Confirm the files were written by referencing the exact paths you updated.',
    '7. If you cannot write the files directly, return a blocker instead of claiming completion.'
  ];
  return lines.join('\n');
}

async function materializeProjectIntakeFallbackArtifacts(input: {
  prompt: string;
  projectId: string | null;
  repoRoot: string | null;
  planPath: string;
  prdPath: string;
  fallbackReason: string;
}): Promise<{
  reason: string;
  metadata: ReturnType<typeof buildDeterministicProjectIntakeArtifacts>['metadata'];
}> {
  const fallback = buildDeterministicProjectIntakeArtifacts({
    prompt: input.prompt,
    projectId: input.projectId,
    repoRoot: input.repoRoot,
    fallbackReason: input.fallbackReason
  });
  await fs.mkdir(path.dirname(input.planPath), { recursive: true });
  await fs.mkdir(path.dirname(input.prdPath), { recursive: true });
  await fs.writeFile(input.planPath, fallback.plan, 'utf8');
  await fs.writeFile(input.prdPath, fallback.prd, 'utf8');
  return {
    reason: input.fallbackReason,
    metadata: fallback.metadata
  };
}

interface GithubOwnerRepo {
  owner: string;
  repo: string;
}

function sanitizeGithubReferenceToken(value: string): string {
  return value
    .trim()
    .replace(/^[`"'([{<\s]+/, '')
    .replace(/[`"')\]}>.,;:!?]+$/g, '');
}

function normalizeGithubOwnerRepo(owner: string, repo: string): GithubOwnerRepo {
  const normalizedOwner = sanitizeGithubReferenceToken(owner).replace(/^@/, '').toLowerCase();
  const normalizedRepo = sanitizeGithubReferenceToken(repo).replace(/\.git$/i, '').replace(/\/+$/, '').toLowerCase();
  return {
    owner: normalizedOwner,
    repo: normalizedRepo
  };
}

function parseGithubOwnerRepoReference(raw: unknown): GithubOwnerRepo | null {
  if (typeof raw !== 'string') {
    return null;
  }
  const input = raw.trim();
  if (!input) {
    return null;
  }

  const httpsMatch = input.match(/^https?:\/\/(?:www\.)?github\.com\/([^/\s]+)\/([^/\s?#]+)(?:[/?#].*)?$/i);
  if (httpsMatch?.[1] && httpsMatch?.[2]) {
    const normalized = normalizeGithubOwnerRepo(httpsMatch[1], httpsMatch[2]);
    return normalized.owner && normalized.repo ? normalized : null;
  }

  const sshMatch = input.match(/^git@github\.com:([^/\s]+)\/([^/\s]+)$/i);
  if (sshMatch?.[1] && sshMatch?.[2]) {
    const normalized = normalizeGithubOwnerRepo(sshMatch[1], sshMatch[2]);
    return normalized.owner && normalized.repo ? normalized : null;
  }

  const shortMatch = input.match(/^([^/\s]+)\/([^/\s]+)$/);
  if (shortMatch?.[1] && shortMatch?.[2]) {
    const normalized = normalizeGithubOwnerRepo(shortMatch[1], shortMatch[2]);
    return normalized.owner && normalized.repo ? normalized : null;
  }

  return null;
}

function findGithubOwnerRepoInText(raw: string): GithubOwnerRepo | null {
  const direct = parseGithubOwnerRepoReference(raw);
  if (direct) {
    return direct;
  }

  const httpsMatch = raw.match(/https?:\/\/(?:www\.)?github\.com\/([^/\s]+)\/([^/\s?#]+)/i);
  if (httpsMatch?.[1] && httpsMatch?.[2]) {
    return normalizeGithubOwnerRepo(httpsMatch[1], httpsMatch[2]);
  }

  const sshMatch = raw.match(/git@github\.com:([^/\s]+)\/([^/\s]+)(?:\.git)?/i);
  if (sshMatch?.[1] && sshMatch?.[2]) {
    return normalizeGithubOwnerRepo(sshMatch[1], sshMatch[2]);
  }

  const prefixedShortMatch = raw.match(/\b(?:repo|repository|github)\s*[:=]\s*([A-Za-z0-9_.-]+)\/([A-Za-z0-9_.-]+)\b/i);
  if (prefixedShortMatch?.[1] && prefixedShortMatch?.[2]) {
    return normalizeGithubOwnerRepo(prefixedShortMatch[1], prefixedShortMatch[2]);
  }

  return null;
}

type GithubIssueSyncMode = 'one_way' | 'two_way';
type GithubIssueConflictResolution = 'backlog_wins' | 'github_wins' | 'manual';

interface GithubIssueSyncPolicy {
  mode: GithubIssueSyncMode;
  conflictResolution: GithubIssueConflictResolution;
  stateLabelMap: Record<BacklogState, string[]>;
  priorityLabelRules: Array<{ minPriority: number; label: string }>;
  assigneeByAgentId: Record<string, string>;
}

const DEFAULT_GITHUB_ISSUE_SYNC_POLICY: GithubIssueSyncPolicy = {
  mode: 'two_way',
  conflictResolution: 'backlog_wins',
  stateLabelMap: {
    idea: ['backlog:idea'],
    triage: ['backlog:triage'],
    planned: ['backlog:planned'],
    in_progress: ['backlog:in-progress'],
    review: ['backlog:review'],
    blocked: ['backlog:blocked'],
    done: ['backlog:done'],
    archived: ['backlog:archived']
  },
  priorityLabelRules: [
    { minPriority: 90, label: 'priority:P0' },
    { minPriority: 80, label: 'priority:P1' },
    { minPriority: 70, label: 'priority:P2' }
  ],
  assigneeByAgentId: {}
};

function canonicalizeOpenRouterAlias(value: string): string {
  const trimmed = value.trim();
  const lowered = trimmed.toLowerCase();
  let remainder: string | null = null;

  if (lowered.startsWith('openrouter/')) {
    remainder = trimmed.slice('openrouter/'.length).trim();
  } else if (lowered.startsWith('openrouter:')) {
    remainder = trimmed.slice('openrouter:'.length).trim();
  } else if (lowered.startsWith('openrouter|')) {
    remainder = trimmed.slice('openrouter|'.length).trim();
  } else if (lowered.startsWith('or:')) {
    remainder = trimmed.slice('or:'.length).trim();
  }

  if (!remainder) {
    return trimmed;
  }

  // Polybot-compatible shorthand: `openrouter/free` => `openrouter/openrouter/free`
  if (!remainder.includes('/')) {
    return `openrouter/openrouter/${remainder}`;
  }
  return `openrouter/${remainder}`;
}

function normalizeModelInput(value: unknown): string | null {
  if (typeof value !== 'string') {
    return null;
  }
  const trimmed = value.trim();
  if (!trimmed) {
    return null;
  }
  const lowered = trimmed.toLowerCase();
  if (lowered === 'default' || lowered === 'none' || lowered === 'null') {
    return null;
  }
  return canonicalizeOpenRouterAlias(trimmed);
}

function isGoogleProviderModel(model: string | null): boolean {
  const normalized = normalizeModelInput(model);
  return normalized?.toLowerCase().startsWith('gemini') ?? false;
}

type ReasoningEffort = 'low' | 'medium' | 'high' | 'xhigh';

function normalizeReasoningInput(value: unknown): ReasoningEffort | null {
  if (typeof value !== 'string') {
    return null;
  }
  return normalizeReasoningEffort(value);
}

function splitModelAndReasoning(value: unknown): { model: string | null; reasoningEffort: ReasoningEffort | null } {
  if (typeof value !== 'string') {
    return {
      model: normalizeModelInput(value),
      reasoningEffort: null
    };
  }
  const parsed = parseModelAndReasoning(value);
  return {
    model: normalizeModelInput(parsed.model),
    reasoningEffort: normalizeReasoningInput(parsed.reasoningEffort)
  };
}

function isIsoDay(value: string): boolean {
  return /^\d{4}-\d{2}-\d{2}$/.test(value);
}

function isIsoMonth(value: string): boolean {
  return /^\d{4}-\d{2}$/.test(value);
}

function dayAtOffset(date: Date, tzOffsetMinutes: number): string {
  const shifted = new Date(date.getTime() - tzOffsetMinutes * 60_000);
  const year = shifted.getUTCFullYear();
  const month = String(shifted.getUTCMonth() + 1).padStart(2, '0');
  const day = String(shifted.getUTCDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function localDayRangeToUtc(dayLocal: string, tzOffsetMinutes: number): { startTs: string; endTs: string } | null {
  if (!isIsoDay(dayLocal)) {
    return null;
  }
  const [yearRaw, monthRaw, dayRaw] = dayLocal.split('-');
  const year = Number(yearRaw);
  const month = Number(monthRaw);
  const day = Number(dayRaw);
  if (!Number.isInteger(year) || !Number.isInteger(month) || !Number.isInteger(day)) {
    return null;
  }
  const startMs = Date.UTC(year, month - 1, day, 0, 0, 0, 0) + tzOffsetMinutes * 60_000;
  const endMs = startMs + 24 * 60 * 60 * 1000;
  return {
    startTs: new Date(startMs).toISOString(),
    endTs: new Date(endMs).toISOString()
  };
}

function localMonthRangeToUtc(monthLocal: string, tzOffsetMinutes: number): { startTs: string; endTs: string } | null {
  if (!isIsoMonth(monthLocal)) {
    return null;
  }
  const [yearRaw, monthRaw] = monthLocal.split('-');
  const year = Number(yearRaw);
  const month = Number(monthRaw);
  if (!Number.isInteger(year) || !Number.isInteger(month)) {
    return null;
  }
  const startMs = Date.UTC(year, month - 1, 1, 0, 0, 0, 0) + tzOffsetMinutes * 60_000;
  const endMs = Date.UTC(year, month, 1, 0, 0, 0, 0) + tzOffsetMinutes * 60_000;
  return {
    startTs: new Date(startMs).toISOString(),
    endTs: new Date(endMs).toISOString()
  };
}

function validateNonNegativeBudgetMapField(input: unknown): boolean {
  if (!isRecord(input)) {
    return false;
  }
  return Object.values(input).every((value) => {
    const numeric = Number(value);
    return Number.isFinite(numeric) && numeric >= 0;
  });
}

function validateFallbackByRuntimeField(input: unknown): boolean {
  if (!isRecord(input)) {
    return false;
  }
  const runtimeKeys: RuntimeKind[] = ['codex', 'claude', 'gemini', 'process'];
  for (const runtimeKey of runtimeKeys) {
    const rawTargets = input[runtimeKey];
    if (rawTargets === undefined) {
      continue;
    }
    if (!Array.isArray(rawTargets)) {
      return false;
    }
    for (const rawTarget of rawTargets) {
      if (!isRecord(rawTarget)) {
        return false;
      }
      const targetRuntime = typeof rawTarget.runtime === 'string' ? rawTarget.runtime.trim() : '';
      if (!runtimeKeys.includes(targetRuntime as RuntimeKind)) {
        return false;
      }
      const targetModel = rawTarget.model;
      if (targetModel !== undefined && targetModel !== null && typeof targetModel !== 'string') {
        return false;
      }
    }
  }
  return true;
}

function validatePrimaryModelByRuntimeField(input: unknown): boolean {
  if (!isRecord(input)) {
    return false;
  }
  const runtimeKeys: RuntimeKind[] = ['codex', 'claude', 'gemini', 'process'];
  for (const runtimeKey of runtimeKeys) {
    const rawModel = input[runtimeKey];
    if (rawModel === undefined || rawModel === null) {
      continue;
    }
    if (typeof rawModel !== 'string') {
      return false;
    }
  }
  return true;
}

function validateRuntimeBooleanByRuntimeField(input: unknown): boolean {
  if (!isRecord(input)) {
    return false;
  }
  const runtimeKeys: RuntimeKind[] = ['codex', 'claude', 'gemini', 'process'];
  for (const runtimeKey of runtimeKeys) {
    const rawValue = input[runtimeKey];
    if (rawValue === undefined || rawValue === null) {
      continue;
    }
    if (typeof rawValue !== 'boolean') {
      return false;
    }
  }
  return true;
}

function validateLlmLimitsPayload(candidate: Record<string, unknown>): string | null {
  const budgetMapFields = [
    'providerCallBudgetDaily',
    'providerCallsPerMinute',
    'providerCostBudgetUsdDaily',
    'providerCostBudgetUsdMonthly',
    'modelCallBudgetDaily'
  ] as const;

  for (const field of budgetMapFields) {
    if (candidate[field] !== undefined && !validateNonNegativeBudgetMapField(candidate[field])) {
      return `Invalid ${field}: expected key/value map of non-negative numbers`;
    }
  }

  if (candidate.fallbackByRuntime !== undefined && !validateFallbackByRuntimeField(candidate.fallbackByRuntime)) {
    return 'Invalid fallbackByRuntime: expected runtime-keyed arrays of { runtime, model? } entries';
  }

  if (
    candidate.primaryModelByRuntime !== undefined &&
    !validatePrimaryModelByRuntimeField(candidate.primaryModelByRuntime)
  ) {
    return 'Invalid primaryModelByRuntime: expected runtime-keyed values of string|null';
  }
  if (
    candidate.orchestratorPrimaryModelByRuntime !== undefined &&
    !validatePrimaryModelByRuntimeField(candidate.orchestratorPrimaryModelByRuntime)
  ) {
    return 'Invalid orchestratorPrimaryModelByRuntime: expected runtime-keyed values of string|null';
  }
  if (
    candidate.orchestratorFallbackByRuntime !== undefined &&
    !validateFallbackByRuntimeField(candidate.orchestratorFallbackByRuntime)
  ) {
    return 'Invalid orchestratorFallbackByRuntime: expected runtime-keyed arrays of { runtime, model? } entries';
  }
  if (
    candidate.localHarnessByRuntime !== undefined &&
    !validateRuntimeBooleanByRuntimeField(candidate.localHarnessByRuntime)
  ) {
    return 'Invalid localHarnessByRuntime: expected runtime-keyed values of boolean';
  }
  if (
    candidate.strictPrimaryByRuntime !== undefined &&
    !validateRuntimeBooleanByRuntimeField(candidate.strictPrimaryByRuntime)
  ) {
    return 'Invalid strictPrimaryByRuntime: expected runtime-keyed values of boolean';
  }
  if (
    candidate.orchestratorLocalHarnessByRuntime !== undefined &&
    !validateRuntimeBooleanByRuntimeField(candidate.orchestratorLocalHarnessByRuntime)
  ) {
    return 'Invalid orchestratorLocalHarnessByRuntime: expected runtime-keyed values of boolean';
  }
  if (
    candidate.orchestratorStrictPrimaryByRuntime !== undefined &&
    !validateRuntimeBooleanByRuntimeField(candidate.orchestratorStrictPrimaryByRuntime)
  ) {
    return 'Invalid orchestratorStrictPrimaryByRuntime: expected runtime-keyed values of boolean';
  }

  return null;
}

function parseNonNegativeBudgetMap(input: unknown): Record<string, number> {
  if (!isRecord(input)) {
    return {};
  }
  const output: Record<string, number> = {};
  for (const [key, rawValue] of Object.entries(input)) {
    const value = Number(rawValue);
    if (!Number.isFinite(value) || value < 0) {
      continue;
    }
    output[key] = value;
  }
  return output;
}

function parseProviderBudgetMap(input: unknown): Partial<Record<LlmProviderKey, number>> {
  const parsed = parseNonNegativeBudgetMap(input);
  const output: Partial<Record<LlmProviderKey, number>> = {};
  for (const [rawKey, value] of Object.entries(parsed)) {
    const key = rawKey.trim().toLowerCase();
    if (key === 'openrouter' || key === 'google') {
      output[key] = value;
    }
  }
  return output;
}

function parseModelBudgetMap(input: unknown): Record<string, number> {
  const parsed = parseNonNegativeBudgetMap(input);
  const output: Record<string, number> = {};
  for (const [rawKey, value] of Object.entries(parsed)) {
    const delimiterIndex = rawKey.indexOf(':');
    if (delimiterIndex < 0) {
      output[rawKey] = value;
      continue;
    }
    const providerKey = rawKey.slice(0, delimiterIndex).trim().toLowerCase();
    const modelKey = rawKey.slice(delimiterIndex + 1).trim().toLowerCase();
    if (!modelKey) {
      continue;
    }
    const normalizedProvider = providerKey === 'google' ? 'google' : 'openrouter';
    output[`${normalizedProvider}:${modelKey}`] = value;
  }
  return output;
}

function parseRuntimeBooleanMap(input: unknown): Partial<Record<RuntimeKind, boolean>> {
  if (!isRecord(input)) {
    return {};
  }
  const output: Partial<Record<RuntimeKind, boolean>> = {};
  for (const runtime of ['codex', 'claude', 'gemini', 'process'] as RuntimeKind[]) {
    if (typeof input[runtime] === 'boolean') {
      output[runtime] = input[runtime];
    }
  }
  return output;
}

function normalizeFallbackByRuntime(input: unknown): Record<RuntimeKind, LlmFallbackTarget[]> {
  const fallback = isRecord(input) ? input : {};
  const parseTargets = (raw: unknown): LlmFallbackTarget[] => {
    if (!Array.isArray(raw)) {
      return [];
    }
    return raw
      .map((entry) => (isRecord(entry) ? entry : null))
      .filter((entry): entry is Record<string, unknown> => entry !== null)
      .map((entry) => {
        const runtime = typeof entry.runtime === 'string' ? entry.runtime.trim() : '';
        const model = normalizeModelInput(entry.model);
        if (!['codex', 'claude', 'gemini', 'process'].includes(runtime)) {
          return null;
        }
        return {
          runtime: runtime as RuntimeKind,
          model
        };
      })
      .filter((entry): entry is LlmFallbackTarget => entry !== null);
  };

  return {
    codex: parseTargets(fallback.codex),
    claude: parseTargets(fallback.claude),
    gemini: parseTargets(fallback.gemini),
    process: parseTargets(fallback.process)
  };
}

function normalizePrimaryModelByRuntime(input: unknown): Partial<Record<RuntimeKind, string | null>> {
  const raw = isRecord(input) ? input : {};
  const output: Partial<Record<RuntimeKind, string | null>> = {};
  for (const runtime of ['codex', 'claude', 'gemini', 'process'] as const) {
    if (raw[runtime] === undefined) {
      continue;
    }
    output[runtime] = normalizeModelInput(raw[runtime]);
  }
  return output;
}

function normalizeLlmLimits(input: unknown): LlmLimitsConfig {
  const candidate = isRecord(input) ? input : {};
  const normalizeFallbackWithDefaults = (
    value: unknown,
    defaults: Record<RuntimeKind, LlmFallbackTarget[]>
  ): Record<RuntimeKind, LlmFallbackTarget[]> => {
    const normalized = normalizeFallbackByRuntime(value);
    const source = isRecord(value) ? value : {};
    const resolveRuntimeFallback = (runtime: RuntimeKind): LlmFallbackTarget[] => {
      if (Object.prototype.hasOwnProperty.call(source, runtime)) {
        return normalized[runtime];
      }
      return defaults[runtime];
    };
    return {
      codex: resolveRuntimeFallback('codex'),
      claude: resolveRuntimeFallback('claude'),
      gemini: resolveRuntimeFallback('gemini'),
      process: resolveRuntimeFallback('process')
    };
  };

  return {
    providerCallBudgetDaily: parseProviderBudgetMap(candidate.providerCallBudgetDaily),
    providerCallsPerMinute: parseProviderBudgetMap(candidate.providerCallsPerMinute),
    providerCostBudgetUsdDaily: parseProviderBudgetMap(candidate.providerCostBudgetUsdDaily),
    providerCostBudgetUsdMonthly: parseProviderBudgetMap(candidate.providerCostBudgetUsdMonthly),
    modelCallBudgetDaily: parseModelBudgetMap(candidate.modelCallBudgetDaily),
    primaryModelByRuntime: {
      ...DEFAULT_LLM_LIMITS.primaryModelByRuntime,
      ...normalizePrimaryModelByRuntime(candidate.primaryModelByRuntime)
    },
    fallbackByRuntime: normalizeFallbackWithDefaults(candidate.fallbackByRuntime, DEFAULT_LLM_LIMITS.fallbackByRuntime),
    strictPrimaryByRuntime: {
      ...DEFAULT_LLM_LIMITS.strictPrimaryByRuntime,
      ...parseRuntimeBooleanMap(candidate.strictPrimaryByRuntime)
    },
    localHarnessByRuntime: {
      ...DEFAULT_LLM_LIMITS.localHarnessByRuntime,
      ...parseRuntimeBooleanMap(candidate.localHarnessByRuntime)
    },
    orchestratorPrimaryModelByRuntime: {
      ...DEFAULT_LLM_LIMITS.orchestratorPrimaryModelByRuntime,
      ...normalizePrimaryModelByRuntime(candidate.orchestratorPrimaryModelByRuntime)
    },
    orchestratorFallbackByRuntime: normalizeFallbackWithDefaults(
      candidate.orchestratorFallbackByRuntime,
      DEFAULT_LLM_LIMITS.orchestratorFallbackByRuntime
    ),
    orchestratorStrictPrimaryByRuntime: {
      ...DEFAULT_LLM_LIMITS.orchestratorStrictPrimaryByRuntime,
      ...parseRuntimeBooleanMap(candidate.orchestratorStrictPrimaryByRuntime)
    },
    orchestratorLocalHarnessByRuntime: {
      ...DEFAULT_LLM_LIMITS.orchestratorLocalHarnessByRuntime,
      ...parseRuntimeBooleanMap(candidate.orchestratorLocalHarnessByRuntime)
    }
  };
}

function mergeLlmLimits(base: LlmLimitsConfig, override: LlmLimitsConfig): LlmLimitsConfig {
  return {
    providerCallBudgetDaily: {
      ...base.providerCallBudgetDaily,
      ...override.providerCallBudgetDaily
    },
    providerCallsPerMinute: {
      ...base.providerCallsPerMinute,
      ...override.providerCallsPerMinute
    },
    providerCostBudgetUsdDaily: {
      ...base.providerCostBudgetUsdDaily,
      ...override.providerCostBudgetUsdDaily
    },
    providerCostBudgetUsdMonthly: {
      ...base.providerCostBudgetUsdMonthly,
      ...override.providerCostBudgetUsdMonthly
    },
    modelCallBudgetDaily: {
      ...base.modelCallBudgetDaily,
      ...override.modelCallBudgetDaily
    },
    primaryModelByRuntime: {
      ...base.primaryModelByRuntime,
      ...override.primaryModelByRuntime
    },
    fallbackByRuntime: {
      codex: override.fallbackByRuntime.codex,
      claude: override.fallbackByRuntime.claude,
      gemini: override.fallbackByRuntime.gemini,
      process: override.fallbackByRuntime.process
    },
    strictPrimaryByRuntime: {
      ...base.strictPrimaryByRuntime,
      ...override.strictPrimaryByRuntime
    },
    localHarnessByRuntime: {
      ...base.localHarnessByRuntime,
      ...override.localHarnessByRuntime
    },
    orchestratorPrimaryModelByRuntime: {
      ...base.orchestratorPrimaryModelByRuntime,
      ...override.orchestratorPrimaryModelByRuntime
    },
    orchestratorFallbackByRuntime: {
      codex: override.orchestratorFallbackByRuntime.codex,
      claude: override.orchestratorFallbackByRuntime.claude,
      gemini: override.orchestratorFallbackByRuntime.gemini,
      process: override.orchestratorFallbackByRuntime.process
    },
    orchestratorStrictPrimaryByRuntime: {
      ...base.orchestratorStrictPrimaryByRuntime,
      ...override.orchestratorStrictPrimaryByRuntime
    },
    orchestratorLocalHarnessByRuntime: {
      ...base.orchestratorLocalHarnessByRuntime,
      ...override.orchestratorLocalHarnessByRuntime
    }
  };
}

function extractOpenRouterModelAlias(model: string | null): string | null {
  const normalized = normalizeModelInput(model);
  if (!normalized) {
    return null;
  }
  const lowered = normalized.toLowerCase();
  if (lowered.startsWith('openrouter/')) {
    const value = normalized.slice('openrouter/'.length).trim();
    if (!value) {
      return null;
    }
    // Keep openrouter namespace when shorthand was canonicalized.
    return value.includes('/') ? value : `openrouter/${value}`;
  }
  if (lowered.includes('openrouter')) {
    return normalized;
  }
  return null;
}

function extractStructuredAgentMessage(output: string): string | null {
  const messages: string[] = [];
  const seenMessages = new Set<string>();
  for (const line of output.split(/\r?\n/g)) {
    const trimmed = line.trim();
    if (!trimmed.startsWith('{') || !trimmed.endsWith('}')) {
      continue;
    }
    const parsed = parseJsonSafe<Record<string, unknown>>(trimmed, {});
    if (!isRecord(parsed)) {
      continue;
    }

    const item = parsed.item;
    if (!isRecord(item)) {
      continue;
    }
    const itemType = String(item.type ?? '').trim().toLowerCase();
    if (itemType !== 'agent_message' && itemType !== 'output_text' && itemType !== 'message') {
      continue;
    }
    const text = item.text;
    if (typeof text === 'string' && text.trim().length > 0) {
      const normalized = text.trim();
      const key = normalized.toLowerCase();
      if (seenMessages.has(key)) {
        continue;
      }
      seenMessages.add(key);
      messages.push(normalized);
    }
  }

  if (messages.length === 0) {
    return null;
  }
  return messages.join('\n').trim();
}

type OperatorInterventionBlockerCode =
  | 'git_ssh_passphrase_prompt'
  | 'git_https_credentials_prompt'
  | 'git_ssh_host_verification'
  | 'git_ssh_publickey_denied'
  | 'git_authentication_failed';

interface OperatorInterventionBlocker {
  code: OperatorInterventionBlockerCode;
  summary: string;
  waitingPrompt: string;
  remediation: string;
}

const OPERATOR_INTERVENTION_BLOCKERS: Array<{
  code: OperatorInterventionBlockerCode;
  pattern: RegExp;
  summary: string;
  waitingPrompt: string;
  remediation: string;
}> = [
  {
    code: 'git_ssh_passphrase_prompt',
    pattern: /\b(enter passphrase for key|passphrase for key)\b/i,
    summary: 'Git/SSH command is waiting for an SSH key passphrase.',
    waitingPrompt: 'Unlock SSH key access, then resume the run.',
    remediation: 'Load or unlock your SSH key in this environment (for example via ssh-agent).'
  },
  {
    code: 'git_https_credentials_prompt',
    pattern: /\b(username for 'https:\/\/github\.com|password for 'https:\/\/github\.com|could not read username for 'https:\/\/github\.com)\b/i,
    summary: 'Git HTTPS credentials are missing or blocked.',
    waitingPrompt: 'Provide valid GitHub credentials, then resume the run.',
    remediation: 'Authenticate GitHub access (PAT/credential helper) or switch remote auth mode.'
  },
  {
    code: 'git_ssh_host_verification',
    pattern: /\b(are you sure you want to continue connecting \(yes\/no(?:\/\[fingerprint\])?\)\?|host key verification failed)\b/i,
    summary: 'SSH host verification is blocking command execution.',
    waitingPrompt: 'Verify the SSH host key and resume the run.',
    remediation: 'Trust/verify the host key for github.com in known_hosts before resuming.'
  },
  {
    code: 'git_ssh_publickey_denied',
    pattern: /(permission denied \(publickey\)|publickey denied)/i,
    summary: 'SSH authentication failed (public key rejected).',
    waitingPrompt: 'Fix SSH key permissions or key registration, then resume the run.',
    remediation: 'Use a registered SSH key for GitHub or switch to HTTPS + token auth.'
  },
  {
    code: 'git_authentication_failed',
    pattern: /\b(authentication failed|repository not found)\b/i,
    summary: 'Git authentication failed for the target repository.',
    waitingPrompt: 'Fix repository access rights, then resume the run.',
    remediation: 'Confirm repo URL and access scope, then re-authenticate GitHub access.'
  }
];

export function detectOperatorInterventionBlocker(text: string | null | undefined): OperatorInterventionBlocker | null {
  const normalized = String(text ?? '').trim();
  if (!normalized) {
    return null;
  }
  for (const signature of OPERATOR_INTERVENTION_BLOCKERS) {
    if (!signature.pattern.test(normalized)) {
      continue;
    }
    return {
      code: signature.code,
      summary: signature.summary,
      waitingPrompt: signature.waitingPrompt,
      remediation: signature.remediation
    };
  }
  return null;
}

function buildOperatorInterventionPauseMessage(input: {
  runId: string;
  blocker: OperatorInterventionBlocker;
  detectedPattern?: string | null;
}): string {
  const detectedPattern = typeof input.detectedPattern === 'string' ? input.detectedPattern.trim() : '';
  const lines = [
    `Run ${input.runId} paused for operator action.`,
    `Reason: ${input.blocker.summary}`,
    detectedPattern.length > 0 ? `Detected signal: ${summarizeCommandOutputSnippet(detectedPattern, 180)}` : null,
    `Action: ${input.blocker.remediation}`,
    'After fixing access, resume from Run Controls or send /resume in Telegram.'
  ].filter((entry): entry is string => Boolean(entry));
  return lines.join('\n');
}

function isShellBootstrapNoiseLine(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed) {
    return false;
  }
  return (
    /^if command -v\b.*;\s*then\b.*;\s*fi$/i.test(trimmed) ||
    /^if command -v\b.*;\s*elif\b.*;\s*fi$/i.test(trimmed) ||
    /^elif \[ -f\b.*&&\s*grep -q\b.*;\s*then\b/i.test(trimmed) ||
    /^else echo ['"]error:/i.test(trimmed) ||
    /^find \.\s+-maxdepth\s+\d+\s+-name\b.*-type\s+f;\s*exit\s+\d+;\s*fi$/i.test(trimmed)
  );
}

function isStandaloneMarkdownFence(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed) {
    return false;
  }
  return /^```(?:[a-z0-9_-]+)?$/i.test(trimmed);
}

function isStructuredNoiseLine(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed) {
    return true;
  }
  return (
    trimmed.startsWith('{') ||
    trimmed.startsWith('}') ||
    trimmed.startsWith('[') ||
    trimmed.startsWith(']') ||
    /^".*"$/.test(trimmed) ||
    /^"[^"]+"\s*:/.test(trimmed) ||
    trimmed.endsWith(',') ||
    /^[,:\s]+$/.test(trimmed) ||
    /^<\/?[a-z][a-z0-9_-]*(?:\s+[^>]*)?>\s*$/i.test(trimmed)
  );
}

function isRuntimeNoiseLine(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed) {
    return true;
  }
  return (
    isStandaloneMarkdownFence(trimmed) ||
    trimmed.toLowerCase().startsWith('reading prompt from stdin') ||
    /^loaded cached credentials\.?$/i.test(trimmed) ||
    /^skill .* is overriding the built-in skill\.?$/i.test(trimmed) ||
    /^skill conflict detected: .*$/i.test(trimmed) ||
    /^error executing tool\b/i.test(trimmed) ||
    /^path not in workspace\b/i.test(trimmed) ||
    /^skipping subagent tool\b/i.test(trimmed) ||
    /^\[localagentexecutor\]\s+/i.test(trimmed) ||
    /^blocked call: unauthorized tool call\b/i.test(trimmed) ||
    /^unauthorized tool call\b/i.test(trimmed) ||
    /^i will read the .* skill documentation\b/i.test(trimmed) ||
    /^i will use the [`'"]?[^`'"\n]+[`'"]? agent\b/i.test(trimmed) ||
    /^enter passphrase for key\b/i.test(trimmed) ||
    /^username for 'https:\/\/github\.com'\s*:?\s*$/i.test(trimmed) ||
    /^password for 'https:\/\/github\.com'\s*:?\s*$/i.test(trimmed) ||
    /^the authenticity of host ['"].* can't be established\.?$/i.test(trimmed) ||
    /^are you sure you want to continue connecting \(yes\/no(?:\/\[fingerprint\])?\)\?\s*$/i.test(trimmed) ||
    isShellBootstrapNoiseLine(trimmed)
  );
}

const INLINE_RUNTIME_NOISE_MARKERS: RegExp[] = [
  /Loaded cached credentials\.?/i,
  /Skill .* is overriding the built-in skill\.?/i,
  /Skill conflict detected:/i,
  /Error executing tool\b/i,
  /Path not in workspace\b/i,
  /Skipping subagent tool\b/i,
  /\[LocalAgentExecutor\]\s+/i,
  /Blocked call: Unauthorized tool call\b/i,
  /I will read the .* skill documentation\b/i,
  /I will use the [`'"]?[^`'"\n]+[`'"]? agent\b/i
];

const RUNTIME_FAILURE_NOISE_PATTERNS: RegExp[] = [
  /^error executing tool\b/i,
  /^path not in workspace\b/i,
  /^\[localagentexecutor\].*blocked call\b/i,
  /^blocked call: unauthorized tool call\b/i,
  /^unauthorized tool call\b/i
];

const TRANSCRIPT_SPEAKER_PATTERN = /^([A-Za-z0-9._-]{2,32}):(\S.*)$/;

function containsRuntimeNoiseMarker(text: string): boolean {
  const normalized = stripAnsiEscapeSequences(text).trim();
  if (!normalized) {
    return false;
  }
  return INLINE_RUNTIME_NOISE_MARKERS.some((pattern) => pattern.test(normalized));
}

function isRuntimeFailureNoiseLine(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed) {
    return false;
  }
  return RUNTIME_FAILURE_NOISE_PATTERNS.some((pattern) => pattern.test(trimmed));
}

function isAssistantLikeSpeakerLabel(label: string): boolean {
  const normalized = label
    .toLowerCase()
    .replace(/4/g, 'a')
    .replace(/0/g, 'o')
    .replace(/1/g, 'i')
    .replace(/3/g, 'e')
    .replace(/\$/g, 's');
  return /assistant|bot|agent|codex|gpt|claude|gemini/i.test(normalized);
}

function insertInlineRuntimeBoundary(text: string, pattern: RegExp): string {
  const flags = pattern.flags.includes('g') ? pattern.flags : `${pattern.flags}g`;
  return text.replace(new RegExp(`([^\\n])(${pattern.source})`, flags), '$1\n$2');
}

function extractRuntimeSummaryLines(summary: string): string[] {
  let normalized = stripAnsiEscapeSequences(summary).replace(/\r\n?/g, '\n');
  normalized = normalized.replace(/([.!?])(?=(?:[A-Z<]|\[))/g, '$1\n');
  for (const pattern of INLINE_RUNTIME_NOISE_MARKERS) {
    normalized = insertInlineRuntimeBoundary(normalized, pattern);
  }

  const rawLines = normalized
    .split(/\n+/g)
    .map((line) => line.trim())
    .filter((line) => line.length > 0);
  const preferAssistantTurns = rawLines.some((line) => {
    const match = line.match(TRANSCRIPT_SPEAKER_PATTERN);
    const label = match?.[1] ?? '';
    return label.length > 0 ? isAssistantLikeSpeakerLabel(label) : false;
  });

  return rawLines
    .flatMap((line) => {
      const match = line.match(TRANSCRIPT_SPEAKER_PATTERN);
      if (!match) {
        return [line];
      }
      const label = match[1] ?? '';
      const content = match[2]?.trim() ?? '';
      if (!content) {
        return [];
      }
      if (preferAssistantTurns && !isAssistantLikeSpeakerLabel(label)) {
        return [];
      }
      return [content];
    })
    .filter((line) => line.length > 0);
}

function tryParseJsonStringScalar(input: string): string | null {
  const trimmed = input.trim();
  if (!trimmed.startsWith('"') || !trimmed.endsWith('"')) {
    return null;
  }
  const parsed = parseJsonSafe<unknown>(trimmed, null);
  if (typeof parsed !== 'string') {
    return null;
  }
  return parsed.trim();
}

export function sanitizeRuntimeSummary(summary: string): string {
  const summaryTrimmed = summary.trim();
  if (!summaryTrimmed) {
    return summaryTrimmed;
  }

  if (isStandaloneMarkdownFence(summaryTrimmed)) {
    return 'Run completed.';
  }

  const scalar = tryParseJsonStringScalar(summaryTrimmed);
  if (scalar !== null) {
    if (!scalar || isRuntimeNoiseLine(scalar)) {
      return 'Run completed.';
    }
    return scalar;
  }

  const structured = extractStructuredAgentMessage(summaryTrimmed);
  if (structured) {
    return structured;
  }

  const lines = extractRuntimeSummaryLines(summaryTrimmed);
  if (lines.length === 0) {
    return summaryTrimmed;
  }

  const hasStructuredNoise = lines.some((line) => line.startsWith('{"type":')) || lines.some((line) => line.startsWith('{'));
  const plainCandidates = lines.filter(
    (line) =>
      !line.startsWith('202') &&
      !isStructuredNoiseLine(line) &&
      !isRuntimeNoiseLine(line)
  );
  if (plainCandidates.length > 0) {
    if (!hasStructuredNoise) {
      const droppedNoiseCount = lines.length - plainCandidates.length;
      if (droppedNoiseCount === 0) {
        return summaryTrimmed;
      }
    }
    return plainCandidates[0]!;
  }

  const hasOnlyNoise = lines.every((line) => line.startsWith('202') || isStructuredNoiseLine(line) || isRuntimeNoiseLine(line));
  if (hasOnlyNoise) {
    if (lines.some((line) => isRuntimeFailureNoiseLine(line))) {
      return 'Run failed before a verified tool result was produced.';
    }
    return 'Run completed.';
  }

  return summaryTrimmed;
}

function isExecutionEnvironmentDisclosureParagraph(paragraph: string): boolean {
  const lines = paragraph
    .split('\n')
    .map((line) => line.trim())
    .filter((line) => line.length > 0);
  if (lines.length === 0) {
    return false;
  }
  return lines.every((line) => /^[*-]\s+\*\*(?:Runtime|Model|Provider):/.test(line));
}

function isRuntimeIdentityDisclosureParagraph(paragraph: string): boolean {
  const normalized = paragraph.trim().toLowerCase();
  if (!normalized) {
    return false;
  }
  if (
    /^(?:\*\*|#{1,6}\s*\**)\s*(?:active\b[ a-z]*|environment check|system info|current execution environment)\b/i.test(
      paragraph
    )
  ) {
    return true;
  }
  if (isExecutionEnvironmentDisclosureParagraph(paragraph)) {
    return true;
  }
  const mentionsRuntimeIdentity = /\b(runtime|model|provider)\b/.test(normalized);
  if (!mentionsRuntimeIdentity) {
    return false;
  }
  if (/\bruntime\b/.test(normalized) && /\bmodel\b/.test(normalized) && /\bprovider\b/.test(normalized)) {
    return true;
  }
  if (
    /^(?:for (?:your )?reference|for this (?:run|session|response|answer)|for the current (?:run|session|response|answer))\b/.test(
      normalized
    )
  ) {
    return true;
  }
  return (
    /^for (?:your )?reference,/.test(normalized) ||
    /^for this session,/.test(normalized) ||
    /^for this run,/.test(normalized) ||
    /^for this response,/.test(normalized) ||
    /^for this answer,/.test(normalized) ||
    /^to provide context on my own operating environment\b/.test(normalized) ||
    /^to answer your technical metadata question\b/.test(normalized) ||
    /^regarding the environment for this conversation\b/.test(normalized) ||
    /^to confirm the environment for this response\b/.test(normalized) ||
    /^i(?:'m| am)\s+currently\b/.test(normalized) ||
    /^i(?:'m| am)\s+active on\b/.test(normalized) ||
    /^i(?:'m| am)\s+operating on\b/.test(normalized) ||
    /^i(?:'m| am)\s+running on\b/.test(normalized) ||
    /\bcurrently operating as\b/.test(normalized) ||
    /\bcurrently operating using\b/.test(normalized) ||
    /\bactive on the\b/.test(normalized) ||
    /\boperating on the\b/.test(normalized) ||
    /\brunning on the\b/.test(normalized) ||
    /\bprocessing this request using\b/.test(normalized) ||
    /\bprovided by\b/.test(normalized)
  );
}

function stripRuntimeIdentityDisclosureFromReply(
  summary: string,
  options?: {
    allowEnvironmentDisclosure?: boolean;
  }
): string {
  const trimmed = summary.trim();
  if (!trimmed || options?.allowEnvironmentDisclosure === true) {
    return stripDanglingOpeningMarkdownFence(trimmed).trim();
  }

  const paragraphs = trimmed
    .split(/\n\s*\n/g)
    .map((paragraph) => paragraph.trim())
    .filter((paragraph) => paragraph.length > 0)
    .filter((paragraph) => !isRuntimeIdentityDisclosureParagraph(paragraph));

  return stripDanglingOpeningMarkdownFence(paragraphs.join('\n\n').trim()).trim();
}

function stripUnusedReasoningEffortDisclosure(
  summary: string,
  options?: {
    allowReasoningEffortDisclosure?: boolean;
  }
): string {
  const trimmed = summary.trim();
  if (!trimmed || options?.allowReasoningEffortDisclosure === true) {
    return stripDanglingOpeningMarkdownFence(trimmed).trim();
  }

  return stripDanglingOpeningMarkdownFence(
    trimmed
      .replace(/\s*The reasoning effort for (?:this run|this session|this response) is \*\*[^*]+\*\*\.?/gi, '')
      .replace(/\s*Reasoning effort(?: for (?:this run|this session|this response))?:\s*\*\*[^*]+\*\*\.?/gi, '')
      .replace(/\n\s*[-*]\s+\*\*Reasoning Effort\*\*:\s*[^\n]+/gi, '')
      .trim()
  ).trim();
}

function stripEnvironmentIdentityTelemetryDetail(summary: string): string {
  const trimmed = summary.trim();
  if (!trimmed) {
    return stripDanglingOpeningMarkdownFence(trimmed).trim();
  }

  const paragraphs = trimmed
    .split(/\n\s*\n/g)
    .map((paragraph) => paragraph.trim())
    .filter((paragraph) => paragraph.length > 0)
    .filter(
      (paragraph) =>
        !/^According to my active execution context:?/i.test(paragraph) &&
        !/^Active execution context:?/i.test(paragraph) &&
        !/\*\*Selected Runtime\*\*:/i.test(paragraph) &&
        !/\*\*Selected Model\*\*:/i.test(paragraph) &&
        !/\*\*Selected Provider\*\*:/i.test(paragraph)
    );

  return stripDanglingOpeningMarkdownFence(paragraphs.join('\n\n').trim()).trim();
}

function sanitizeCommonKnowledgeConversationalReply(
  summary: string,
  options?: {
    genericFilenameConceptPrompt?: boolean;
    allowEnvironmentDisclosure?: boolean;
  }
): string {
  const trimmed = summary.trim();
  if (!trimmed) {
    return trimmed;
  }

  let cleaned = trimmed
    .replace(/```(?:json)?\s*[\s\S]*?ops\.execution-contract\.v1[\s\S]*?```/gi, '')
    .replace(/\{\s*"schema"\s*:\s*"ops\.execution-contract\.v1"[\s\S]*$/i, '')
    .replace(/\n?\s*<execution_contract>[\s\S]*$/i, '')
    .replace(/^The current execution context indicates[^\n]*(?:\n\s*\n)?/i, '')
    .replace(/^The currently active runtime[^\n]*(?:\n\s*\n)?/i, '')
    .replace(/\bSince this is a direct request, I will provide guidance rather than delegating a sub-run\.\s*/gi, '')
    .replace(/\bSince this is [^.]*?(?:learning request|informational request|common-knowledge request|not a code delivery task)[^.]*\.\s*/gi, '')
    .replace(/\bI will use the available process runtime[^\n]*\.?\s*/gi, '')
    .replace(/\n?\s*The active model for this session(?:\s+remains|\s+is)?[^\n]*?\bruntime\.\s*/gi, '\n\n')
    .replace(/\n\s*(?:\*\*|#{1,6}\s*\**)\s*Active Environment Info\b[\s\S]*$/i, '')
    .replace(/\n\s*For (?:your )?reference,\s*I(?:\s+am|['’]m)\s+currently operating using[^\n]*$/gim, '')
    .replace(/\n\s*For this session,\s*I(?:\s+am|['’]m)\s+operating on[^\n]*$/gim, '')
    .replace(/\n\s*For this session,\s*I(?:\s+am|['’]m)\s+running on[^\n]*$/gim, '')
    .replace(/\n\s*For (?:your )?reference,\s*this (?:response|answer) was generated using[\s\S]*$/i, '')
    .replace(/\n\s*This (?:response|answer) was generated using[\s\S]*$/i, '')
    .replace(/\n\s*\*\*\*\s*\n+\s*\*\*System Info:\*\*[\s\S]*$/i, '')
    .replace(/\n\s*(?:\*\*|#{1,6}\s*\**)\s*Active Execution Environment\b[\s\S]*$/i, '')
    .replace(/\n\s*(?:\*\*|#{1,6}\s*\**)\s*Active Environment Note\b[\s\S]*$/i, '')
    .replace(/\n\s*(?:\*\*|#{1,6}\s*\**)\s*Current Execution Environment\b[\s\S]*$/i, '')
    .trim();

  const paragraphs = cleaned
    .split(/\n\s*\n/g)
    .map((paragraph) => paragraph.trim())
    .filter((paragraph) => paragraph.length > 0)
    .filter(
      (paragraph) =>
        !/^The current execution context indicates\b/i.test(paragraph) &&
        !/^The currently active runtime\b/i.test(paragraph) &&
        !/^The active model for this session(?:\s+remains|\s+is)?\b/i.test(paragraph) &&
        !/^Since this is\b/i.test(paragraph) &&
        !/^I will use the available process runtime\b/i.test(paragraph) &&
        !/^Do you have access to a terminal or a development environment\b/i.test(paragraph) &&
        !/^(?:\*\*|#{1,6}\s*\**)\s*Active Environment Info\b/i.test(paragraph) &&
        !/^(?:\*\*|#{1,6}\s*\**)\s*Active Environment Note\b/i.test(paragraph) &&
        !/^(?:\*\*|#{1,6}\s*\**)\s*Active Execution Environment\b/i.test(paragraph) &&
        !/^(?:\*\*|#{1,6}\s*\**)\s*System Info\b/i.test(paragraph) &&
        !/^(?:\*\*|#{1,6}\s*\**)\s*Current Execution Environment\b/i.test(paragraph) &&
        !(options?.allowEnvironmentDisclosure !== true && isRuntimeIdentityDisclosureParagraph(paragraph)) &&
        !/^\*{3,}$/.test(paragraph) &&
        !/\bdelegate a [a-z0-9 _-]*agent\b/i.test(paragraph) &&
        !/^For (?:your )?reference,\s*I(?:\s+am|['’]m)\s+currently operating using\b/i.test(paragraph) &&
        !/^For this session,\s*I(?:\s+am|['’]m)\s+operating on\b/i.test(paragraph) &&
        !/^For this session,\s*I(?:\s+am|['’]m)\s+running on\b/i.test(paragraph) &&
        !/^For (?:your )?reference,\s*this (?:response|answer) was generated using\b/i.test(paragraph) &&
        !/^This (?:response|answer) was generated using\b/i.test(paragraph) &&
        !(options?.genericFilenameConceptPrompt === true && /it can serve a few other roles:\s*$/i.test(paragraph)) &&
        !(options?.genericFilenameConceptPrompt === true && /^In the specific environment\b/i.test(paragraph)) &&
        !(options?.genericFilenameConceptPrompt === true && /^For this specific run,\s*the active configuration is\b/i.test(paragraph)) &&
        !(options?.genericFilenameConceptPrompt === true && isExecutionEnvironmentDisclosureParagraph(paragraph)) &&
        !(options?.genericFilenameConceptPrompt === true && /\bElyzeLabs\b/i.test(paragraph)) &&
        !(options?.genericFilenameConceptPrompt === true && /\bExecution Context\b/i.test(paragraph)) &&
        !(options?.genericFilenameConceptPrompt === true && /\bwe are currently operating in\b/i.test(paragraph)) &&
        !/<execution_contract>/i.test(paragraph) &&
        !/\bops\.execution-contract\.v1\b/i.test(paragraph) &&
        !/\bdispatch_subrun\b/i.test(paragraph) &&
        !/\bexecute_command\b/i.test(paragraph) &&
        !/\bdelegating a sub-run\b/i.test(paragraph)
    );

  cleaned = paragraphs.join('\n\n').trim();
  return stripDanglingOpeningMarkdownFence(cleaned).trim();
}

function extractGenericFilenameConcept(taskPrompt: string): string | null {
  const trimmed = taskPrompt.trim();
  const match = trimmed.match(
    /^(?:what(?:'s| is)|explain|define|tell me about)\s+[`'"]?([a-z0-9_-]+\.[a-z0-9._-]+)[`'"]?(?:\s+file)?\s*\??$/i
  );
  const filename = match?.[1]?.trim() ?? '';
  return filename.length > 0 ? filename : null;
}

function buildGenericFilenameConceptFallback(filename: string): string {
  const lowerFilename = filename.trim().toLowerCase();
  if (lowerFilename === 'context.js') {
    return [
      'In JavaScript projects, `context.js` is usually a project-defined file name rather than a built-in platform file.',
      '',
      'Most commonly, it is used for one of these roles:',
      '1. React Context: defining a Context object/provider for shared state such as auth, theme, or settings.',
      '2. App or request context: centralizing shared configuration, user/session data, or per-request helpers in backend code.',
      '3. Shared wiring: exporting common services or setup that multiple modules need.',
      '',
      'The exact meaning depends on the codebase, so the reliable way to know is to open that specific file in the project you are looking at.'
    ].join('\n');
  }
  return [
    `\`${filename}\` is usually a project-defined filename, not a built-in JavaScript file.`,
    '',
    'In practice, files with names like this often hold shared configuration, state, framework setup, or helper logic that multiple parts of the app reuse.',
    '',
    'Its exact purpose depends on the codebase, so the reliable answer comes from opening that specific file in the project you are looking at.'
  ].join('\n');
}

const BACKLOG_PROGRESS_PREFIX_PATTERNS: RegExp[] = [
  /^i(?:['’]m| am)\s+(?:going to|now|currently|next)\b/i,
  /^quick update\b/i,
  /^plan to\b/i,
  /^i\s+(?:found|confirmed|pulled|detected|checked|read|inspected|patched|updated|verified|am|will|have)\b/i,
  /^\d+\.\s+/,
  /^(?:dependency dag validation passed|typecheck passed|lint is in progress|lint failed|build completed)\b/i,
  /^tooling confirms\b/i
];

function isBacklogProgressNarrationLine(line: string): boolean {
  const trimmed = line.trim();
  if (!trimmed) {
    return false;
  }
  return BACKLOG_PROGRESS_PREFIX_PATTERNS.some((pattern) => pattern.test(trimmed));
}

function compactSummaryLine(value: string, maxLength = 320): string {
  const normalized = value.replace(/\s+/g, ' ').trim();
  if (normalized.length <= maxLength) {
    return normalized;
  }
  return `${normalized.slice(0, Math.max(0, maxLength - 3))}...`;
}

const CONTACT_SURFACE_TASK_PATTERN = /\b(contact|support|help(?:\s+page|\s+center|\s+desk)?)\b/i;

const DEFERRED_EXECUTION_COMPLETION_PATTERNS: RegExp[] = [
  /\b(?:i|we)\s+need to\b/i,
  /\b(?:i|we)\s+(?:will|['’]ll)\s+(?:execute|inspect|run|check|verify|gather)\b/i,
  /\b(?:i|we)\s+(?:will|['’]ll)\b/i,
  /\bonce executed\b/i,
  /\bthe shell will output\b/i,
  /\buse a comprehensive shell script\b/i,
  /\bassum(?:e|ing)\s+[a-z0-9/+ -]+\s+conventions\b/i,
  /\bdetected\s+[a-z0-9/+ -]+\s+conventions\b/i,
  /```json/i,
  /```(?:bash|sh|zsh)/i,
  /#!\/bin\/(?:bash|sh|zsh)/i,
  /"name"\s*:\s*"(?:node|bash|sh|zsh|codex|claude|gemini)"/i,
  /"arguments"\s*:/i,
  /\bexecSync\s*\(/i
];

function matchesContactSurfaceTaskText(value: string): boolean {
  return CONTACT_SURFACE_TASK_PATTERN.test(value);
}

function looksLikeDeferredExecutionCompletion(summary: string): boolean {
  const normalized = summary.trim();
  if (!normalized) {
    return false;
  }
  const futureSignal =
    /\b(?:i|we)\s+need to\b/i.test(normalized) ||
    /\b(?:i|we)\s+(?:will|['’]ll)\s+(?:execute|inspect|run|check|verify|gather)\b/i.test(normalized) ||
    /\bonce executed\b/i.test(normalized);
  const commandPlanSignal =
    /```json/i.test(normalized) ||
    /```(?:bash|sh|zsh)/i.test(normalized) ||
    /"name"\s*:\s*"(?:node|bash|sh|zsh|codex|claude|gemini)"/i.test(normalized) ||
    /"arguments"\s*:/i.test(normalized) ||
    /\bexecSync\s*\(/i.test(normalized);
  if (futureSignal && commandPlanSignal) {
    return true;
  }
  let score = 0;
  for (const pattern of DEFERRED_EXECUTION_COMPLETION_PATTERNS) {
    if (pattern.test(normalized)) {
      score += pattern.source.includes('```') || pattern.source.includes('#!') ? 2 : 1;
    }
  }
  return score >= 3;
}

export function sanitizeBacklogReceiptSummary(summary: string): string {
  const summaryTrimmed = summary.trim();
  if (!summaryTrimmed) {
    return '';
  }

  const structured = extractStructuredAgentMessage(summaryTrimmed);
  const rawNormalized = (structured ?? summaryTrimmed).trim();
  if (looksLikeDeferredExecutionCompletion(rawNormalized)) {
    return '';
  }
  const normalized = sanitizeRuntimeSummary(rawNormalized).trim();
  if (!normalized) {
    return '';
  }
  if (looksLikeDeferredExecutionCompletion(normalized)) {
    return '';
  }

  const lines = normalized
    .split(/\r?\n/g)
    .map((line) => line.trim())
    .filter((line) => line.length > 0);
  if (lines.length === 0) {
    return compactSummaryLine(normalized);
  }

  const nonNoiseLines = lines.filter((line) => !isStructuredNoiseLine(line) && !isRuntimeNoiseLine(line));
  const candidateLines = nonNoiseLines.length > 0 ? nonNoiseLines : lines;
  const nonProgressLines = candidateLines.filter((line) => !isBacklogProgressNarrationLine(line));
  const selected = nonProgressLines[0] ?? candidateLines[0] ?? normalized;
  return compactSummaryLine(selected);
}

function stripDanglingOpeningMarkdownFence(text: string): string {
  if (!text) {
    return text;
  }
  const lines = text.split(/\r?\n/g);
  if (lines.length === 0) {
    return text;
  }
  const firstLine = (lines[0] ?? '').trim();
  if (!firstLine.startsWith('```')) {
    return text;
  }
  const fenceCount = lines.reduce((count, line) => (line.trim().startsWith('```') ? count + 1 : count), 0);
  if (fenceCount % 2 === 0) {
    return text;
  }
  return lines
    .slice(1)
    .join('\n')
    .trim();
}

const MARKDOWN_ESCAPED_IDENTIFIER_PATTERN = /(^|[^A-Za-z0-9\\/:-])([A-Za-z0-9]+(?:\\_[A-Za-z0-9]+)+)(?=$|[^A-Za-z0-9\\/:-])/g;

export function normalizeMarkdownEscapedIdentifiers(text: string): string {
  if (!text.includes('\\_')) {
    return text;
  }
  return text.replace(MARKDOWN_ESCAPED_IDENTIFIER_PATTERN, (_match, prefix: string, identifier: string) => {
    return `${prefix}${identifier.replace(/\\_/g, '_')}`;
  });
}

const ANSI_ESCAPE_SEQUENCE_REGEX = new RegExp(String.raw`\u001b(?:[@-Z\\-_]|\[[0-?]*[ -/]*[@-~])`, 'g');
const ERROR_LIKE_OUTPUT_LINE_REGEX =
  /(?:^|\b)(?:Error|Exception|Traceback|Caused by|ModuleNotFoundError|ConfigurationError|RuntimeError|ValueError|TypeError|SyntaxError|NameError|ImportError)\b/i;

function stripAnsiEscapeSequences(text: string): string {
  if (!text) {
    return '';
  }
  return text.replace(ANSI_ESCAPE_SEQUENCE_REGEX, '');
}

function summarizeCommandOutputSnippet(text: string, maxLength = 180): string | null {
  const lines = stripAnsiEscapeSequences(text)
    .split(/\r?\n/g)
    .map((line) => line.trim())
    .filter((line) => line.length > 0);
  if (lines.length === 0) {
    return null;
  }
  const preferredLine =
    lines.find(
      (line) =>
        !/^skill\s+.+\(.+\)$/i.test(line) &&
        !/^requested task:/i.test(line) &&
        !/^#{1,6}\s+/.test(line)
    ) ??
    lines[0] ??
    null;
  if (!preferredLine) {
    return null;
  }
  if (preferredLine.length <= maxLength) {
    return preferredLine;
  }
  return `${preferredLine.slice(0, Math.max(1, maxLength - 3))}...`;
}

function formatCommandOutputEvidenceSnippet(
  text: string,
  options: {
    maxLength?: number;
    maxLines?: number;
    preferTail?: boolean;
  } = {}
): string | null {
  const maxLength =
    typeof options.maxLength === 'number' && Number.isFinite(options.maxLength)
      ? Math.max(60, Math.floor(options.maxLength))
      : 420;
  const maxLines =
    typeof options.maxLines === 'number' && Number.isFinite(options.maxLines)
      ? Math.max(1, Math.floor(options.maxLines))
      : 6;
  const preferTail = options.preferTail === true;
  const normalized = stripAnsiEscapeSequences(text)
    .replace(/\r\n?/g, '\n')
    .replaceAll('\0', '')
    .trim();
  if (!normalized) {
    return null;
  }

  const lines = normalized.split('\n');
  const selectedLines: string[] = [];
  let truncated = false;
  let pendingBlank = false;

  if (preferTail) {
    const nonEmptyIndices = lines
      .map((line, index) => (line.trim().length > 0 ? index : -1))
      .filter((index) => index >= 0);
    if (nonEmptyIndices.length === 0) {
      return null;
    }
    const errorAnchorIndex = [...nonEmptyIndices]
      .reverse()
      .find((index) => ERROR_LIKE_OUTPUT_LINE_REGEX.test(lines[index] ?? ''));
    const tailIndices = nonEmptyIndices.slice(-maxLines);
    const selectedIndices =
      errorAnchorIndex !== undefined && !tailIndices.includes(errorAnchorIndex)
        ? [...new Set<number>([errorAnchorIndex, ...tailIndices.slice(-(maxLines - 1))])].sort((left, right) => left - right)
        : tailIndices;
    const selectedIndexSet = new Set<number>(selectedIndices);
    let firstSelectedIndex = selectedIndices[0] ?? 0;
    let lastSelectedIndex = selectedIndices[selectedIndices.length - 1] ?? lines.length - 1;
    while (firstSelectedIndex > 0 && lines[firstSelectedIndex - 1]?.trim().length === 0) {
      firstSelectedIndex -= 1;
    }
    while (lastSelectedIndex + 1 < lines.length && lines[lastSelectedIndex + 1]?.trim().length === 0) {
      lastSelectedIndex += 1;
    }
    for (let index = firstSelectedIndex; index <= lastSelectedIndex; index += 1) {
      const line = lines[index]?.trimEnd() ?? '';
      if (line.trim().length === 0) {
        if (selectedLines.length > 0 && selectedLines[selectedLines.length - 1] !== '') {
          selectedLines.push('');
        }
        continue;
      }
      if (selectedIndexSet.has(index)) {
        selectedLines.push(line);
      }
    }
    truncated =
      nonEmptyIndices.length > selectedIndices.length ||
      firstSelectedIndex > 0 ||
      lastSelectedIndex < lines.length - 1;
  } else {
    for (const [index, rawLine] of lines.entries()) {
      const line = rawLine.trimEnd();
      if (line.trim().length === 0) {
        if (selectedLines.length > 0) {
          pendingBlank = true;
        }
        continue;
      }
      if (pendingBlank && selectedLines.length > 0 && selectedLines[selectedLines.length - 1] !== '') {
        selectedLines.push('');
      }
      pendingBlank = false;
      selectedLines.push(line);
      if (selectedLines.filter((entry) => entry !== '').length >= maxLines) {
        truncated = lines.slice(index + 1).some((entry) => entry.trim().length > 0);
        break;
      }
    }
  }

  const visibleLines = selectedLines.length > 0 ? selectedLines : [normalized];
  let snippet = visibleLines.join('\n').trim();
  if (snippet.length > maxLength) {
    snippet = preferTail
      ? `...${snippet.slice(-Math.max(1, maxLength - 3)).trimStart()}`
      : `${snippet.slice(0, Math.max(1, maxLength - 3)).trimEnd()}...`;
    truncated = true;
  } else if (!truncated) {
    const fullyNormalized = lines
      .map((line) => line.trimEnd())
      .join('\n')
      .trim();
    truncated = fullyNormalized.length > snippet.length;
  }
  if (truncated) {
    if (preferTail && !snippet.startsWith('...')) {
      snippet = `...\n${snippet}`;
    } else if (!preferTail && !snippet.endsWith('...')) {
      snippet = `${snippet}\n...`;
    }
  }
  return snippet;
}

function buildVerifiedDirectExecutionFailureSummaries(
  dispatches: Array<{
    action: string;
    status?: string;
    title: string;
    details?: Record<string, unknown>;
  }>
): string[] {
  return dispatches
    .filter((dispatch) => dispatch.action === 'execute_command')
    .flatMap((dispatch, index) => {
      const details = isRecord(dispatch.details) ? dispatch.details : {};
      const execution = isRecord(details.execution) ? details.execution : {};
      const executionPlan = isRecord(details.executionPlan) ? details.executionPlan : {};
      const exitCode = Number(execution.exitCode ?? NaN);
      if (!Number.isFinite(exitCode) || exitCode === 0) {
        return [];
      }
      const argv = Array.isArray(executionPlan.argv)
        ? executionPlan.argv.map((entry) => String(entry)).join(' ')
        : dispatch.title || `command ${index + 1}`;
      const stderr = typeof execution.stderr === 'string' ? execution.stderr.trim() : '';
      const stdout = typeof execution.stdout === 'string' ? execution.stdout.trim() : '';
      const failureSnippet =
        formatCommandOutputEvidenceSnippet(stderr, {
          maxLength: 480,
          maxLines: 4,
          preferTail: true
        }) ??
        formatCommandOutputEvidenceSnippet(stdout, {
          maxLength: 360,
          maxLines: 3,
          preferTail: true
        }) ??
        `exit ${exitCode}`;
      return [`${argv}: ${failureSnippet}`];
    });
}

type DirectExecutionEvidenceDispatch = {
  action: string;
  status?: string;
  title: string;
  details?: Record<string, unknown>;
};

type DirectExecutionAttemptEvidence = {
  argv: string[];
  stdout: string;
  stderr: string;
  exitCode: number | null;
};

type DirectExecutionRepairStage =
  | {
      kind: 'usage_failure';
      latest: DirectExecutionAttemptEvidence;
      latestDispatch: DirectExecutionEvidenceDispatch;
      failingArgv: string[];
      helpProbeArgv: string[] | null;
      failureSummary: string;
    }
  | {
      kind: 'help_probe_completed';
      latest: DirectExecutionAttemptEvidence;
      latestDispatch: DirectExecutionEvidenceDispatch;
      failingArgv: string[];
      helpProbeArgv: string[] | null;
      failureSummary: string;
    };

const REPAIRABLE_CLI_FAILURE_PATTERNS = [
  /\bno such option\b/i,
  /\bunknown option\b/i,
  /\bunknown argument\b/i,
  /\bmissing (?:required )?(?:argument|option)\b/i,
  /\bgot unexpected extra argument\b/i,
  /\binvalid choice\b/i,
  /\btry ['"`].+--help['"`] for help\b/i,
  /^usage:/im
] as const;

const extractDirectExecutionAttemptEvidence = (
  dispatch: DirectExecutionEvidenceDispatch
): DirectExecutionAttemptEvidence | null => {
  if (dispatch.action !== 'execute_command') {
    return null;
  }
  const details = isRecord(dispatch.details) ? dispatch.details : {};
  const execution = isRecord(details.execution) ? details.execution : {};
  const executionPlan = isRecord(details.executionPlan) ? details.executionPlan : {};
  const argv = Array.isArray(executionPlan.argv) ? executionPlan.argv.map((entry) => String(entry)) : [];
  if (argv.length === 0) {
    return null;
  }
  return {
    argv,
    stdout: typeof execution.stdout === 'string' ? execution.stdout.trim() : '',
    stderr: typeof execution.stderr === 'string' ? execution.stderr.trim() : '',
    exitCode: Number.isFinite(Number(execution.exitCode ?? NaN)) ? Number(execution.exitCode) : null
  };
};

const isHelpProbeArgv = (argv: string[]): boolean => {
  if (argv.length === 0) {
    return false;
  }
  return argv.includes('--help') || argv.includes('-h') || argv[1] === 'help';
};

const buildSuggestedHelpProbeArgv = (argv: string[]): string[] | null => {
  if (argv.length === 0 || isHelpProbeArgv(argv)) {
    return null;
  }
  const [binary, subcommand] = argv;
  if (!binary) {
    return null;
  }
  if (typeof subcommand === 'string' && subcommand.length > 0 && !subcommand.startsWith('-')) {
    return [binary, subcommand, '--help'];
  }
  return [binary, '--help'];
};

const argvMatches = (left: string[], right: string[]): boolean =>
  left.length === right.length && left.every((entry, index) => entry === right[index]);

const findLatestCompletedHelpProbeAttempt = (
  dispatches: DirectExecutionEvidenceDispatch[],
  helpProbeArgv: string[] | null
): { dispatch: DirectExecutionEvidenceDispatch; attempt: DirectExecutionAttemptEvidence } | null => {
  if (!helpProbeArgv || helpProbeArgv.length === 0) {
    return null;
  }
  for (const dispatch of [...dispatches].reverse()) {
    if (dispatch.action !== 'execute_command' || dispatch.status !== 'completed') {
      continue;
    }
    const attempt = extractDirectExecutionAttemptEvidence(dispatch);
    if (!attempt) {
      continue;
    }
    if (argvMatches(attempt.argv, helpProbeArgv)) {
      return {
        dispatch,
        attempt
      };
    }
  }
  return null;
};

const extractUsageLineFromOutput = (output: string): string | null => {
  const match = output.match(/^usage:\s+(.+)$/im);
  return match?.[1]?.trim() ?? null;
};

const isUsagePlaceholderToken = (token: string): boolean =>
  /^[A-Z][A-Z0-9_-]*$/.test(token) || /^<[^>]+>$/.test(token);

const extractSinglePositionalUsagePlaceholder = (usageLine: string, failingArgv: string[]): string | null => {
  const usageTokens = usageLine.split(/\s+/).filter((token) => token.length > 0);
  const prefixTokens = failingArgv.slice(0, Math.min(2, failingArgv.length));
  let startIndex = 0;
  while (startIndex < usageTokens.length && startIndex < prefixTokens.length && usageTokens[startIndex] === prefixTokens[startIndex]) {
    startIndex += 1;
  }
  const placeholders = usageTokens
    .slice(startIndex)
    .filter((token) => !token.startsWith('[') && isUsagePlaceholderToken(token));
  return placeholders.length === 1 ? (placeholders[0] ?? null) : null;
};

const extractUnsupportedOptionFromFailureText = (text: string): string | null => {
  const match = text.match(/\bNo such option:\s+([-\w][^\s,)]*)/i);
  return match?.[1]?.trim() ?? null;
};

const extractSupportedOptionsFromHelpOutput = (output: string): Set<string> => {
  const supported = new Set<string>();
  for (const match of output.matchAll(/(^|\s)(--[a-zA-Z0-9][a-zA-Z0-9-]*)/gm)) {
    const option = match[2]?.trim();
    if (option) {
      supported.add(option);
    }
  }
  return supported;
};

const inferDeterministicCorrectedArgvFromHelpOutput = (input: {
  failingArgv: string[];
  helpOutput: string;
  failureSummary?: string | null;
}): string[] | null => {
  const usageLine = extractUsageLineFromOutput(input.helpOutput);
  const singlePositionalPlaceholder =
    usageLine !== null ? extractSinglePositionalUsagePlaceholder(usageLine, input.failingArgv) : null;
  const supportedOptions = extractSupportedOptionsFromHelpOutput(input.helpOutput);
  let corrected = [...input.failingArgv];
  const unsupportedOption =
    extractUnsupportedOptionFromFailureText(input.failureSummary ?? '') ??
    corrected.find((entry) => entry.startsWith('--') && !supportedOptions.has(entry)) ??
    null;

  if (unsupportedOption) {
    const optionIndex = corrected.findIndex((entry) => entry === unsupportedOption);
    if (optionIndex >= 0) {
      const nextToken = corrected[optionIndex + 1] ?? null;
      const hasAttachedValue = unsupportedOption.includes('=');
      const shouldDropNextValue =
        !hasAttachedValue &&
        typeof nextToken === 'string' &&
        nextToken.length > 0 &&
        !nextToken.startsWith('-');
      corrected = corrected.filter((_, index) => {
        if (index === optionIndex) {
          return false;
        }
        if (shouldDropNextValue && index === optionIndex + 1) {
          return false;
        }
        return true;
      });
    }
  }

  if (singlePositionalPlaceholder) {
    const [binary, maybeSubcommand, ...rest] = corrected;
    if (!binary) {
      return null;
    }
    const head =
      typeof maybeSubcommand === 'string' && maybeSubcommand.length > 0 && !maybeSubcommand.startsWith('-')
        ? [binary, maybeSubcommand]
        : [binary];
    const tail = head.length === 2 ? rest : corrected.slice(1);
    if (tail.length > 1 && tail.every((entry) => !entry.startsWith('-'))) {
      corrected = [...head, tail.join(' ')];
    }
  }

  return argvMatches(corrected, input.failingArgv) ? null : corrected;
};

const inferDeterministicCorrectedArgvFromHelp = (
  stage: Extract<DirectExecutionRepairStage, { kind: 'help_probe_completed' }>
): string[] | null =>
  inferDeterministicCorrectedArgvFromHelpOutput({
    failingArgv: stage.failingArgv,
    helpOutput: [stage.latest.stderr, stage.latest.stdout].filter((entry) => entry.length > 0).join('\n'),
    failureSummary: stage.failureSummary
  });

const shouldRunDeterministicHelpPreflight = (input: {
  argv: string[];
  metadata: Record<string, unknown>;
}): boolean => {
  if (input.argv.length < 2 || isHelpProbeArgv(input.argv)) {
    return false;
  }
  const [binary, subcommand] = input.argv;
  if (!binary || !subcommand || subcommand.startsWith('-')) {
    return false;
  }
  const hasLongFlag = input.argv.slice(2).some((entry) => entry.startsWith('--'));
  const positionalTailCount = input.argv.slice(2).filter((entry) => !entry.startsWith('-')).length;
  if (!hasLongFlag && positionalTailCount < 2) {
    return false;
  }
  return (
    input.metadata.native === true &&
    (input.metadata.recoveredFromSkillCall === true || input.metadata.priorNativeSkillCall === true)
  );
};

const summarizeRepairableFailure = (attempt: DirectExecutionAttemptEvidence, fallbackTitle: string): string => {
  const argvLabel = attempt.argv.length > 0 ? attempt.argv.join(' ') : fallbackTitle;
  const failureSnippet =
    formatCommandOutputEvidenceSnippet(attempt.stderr, {
      maxLength: 480,
      maxLines: 4,
      preferTail: true
    }) ??
    formatCommandOutputEvidenceSnippet(attempt.stdout, {
      maxLength: 360,
      maxLines: 3,
      preferTail: true
    }) ??
    `exit ${attempt.exitCode ?? 'unknown'}`;
  return `${argvLabel}: ${failureSnippet}`;
};

const isRepairableCliUsageFailure = (attempt: DirectExecutionAttemptEvidence): boolean => {
  const combinedOutput = [attempt.stderr, attempt.stdout].filter((entry) => entry.length > 0).join('\n');
  if (!combinedOutput) {
    return false;
  }
  return REPAIRABLE_CLI_FAILURE_PATTERNS.some((pattern) => pattern.test(combinedOutput));
};

const detectDirectExecutionRepairStage = (
  dispatches: DirectExecutionEvidenceDispatch[]
): DirectExecutionRepairStage | null => {
  const directDispatches = dispatches.filter((dispatch) => dispatch.action === 'execute_command');
  if (directDispatches.length === 0) {
    return null;
  }
  const latestDispatch = directDispatches[directDispatches.length - 1] ?? null;
  if (!latestDispatch) {
    return null;
  }
  const latestAttempt = extractDirectExecutionAttemptEvidence(latestDispatch);
  if (!latestAttempt) {
    return null;
  }
  if (latestDispatch.status === 'failed' && isRepairableCliUsageFailure(latestAttempt)) {
    return {
      kind: 'usage_failure',
      latest: latestAttempt,
      latestDispatch,
      failingArgv: latestAttempt.argv,
      helpProbeArgv: buildSuggestedHelpProbeArgv(latestAttempt.argv),
      failureSummary: summarizeRepairableFailure(latestAttempt, latestDispatch.title)
    };
  }
  if (!isHelpProbeArgv(latestAttempt.argv) || latestDispatch.status !== 'completed') {
    return null;
  }
  const previousFailed = [...directDispatches]
    .reverse()
    .slice(1)
    .find((dispatch) => {
      const attempt = extractDirectExecutionAttemptEvidence(dispatch);
      return dispatch.status === 'failed' && attempt !== null && isRepairableCliUsageFailure(attempt);
    });
  if (!previousFailed) {
    return null;
  }
  const previousAttempt = extractDirectExecutionAttemptEvidence(previousFailed);
  if (!previousAttempt) {
    return null;
  }
  return {
    kind: 'help_probe_completed',
    latest: latestAttempt,
    latestDispatch,
    failingArgv: previousAttempt.argv,
    helpProbeArgv: buildSuggestedHelpProbeArgv(previousAttempt.argv),
    failureSummary: summarizeRepairableFailure(previousAttempt, previousFailed.title)
  };
};

function ensureVerifiedFailureSummaryVisible(
  answer: string,
  dispatches: Array<{
    action: string;
    status?: string;
    title: string;
    details?: Record<string, unknown>;
  }>
): string {
  const summaries = buildVerifiedDirectExecutionFailureSummaries(dispatches);
  if (summaries.length === 0) {
    return answer;
  }
  const latestDirectDispatch = [...dispatches]
    .reverse()
    .find((dispatch) => dispatch.action === 'execute_command');
  const latestAttempt = latestDirectDispatch ? extractDirectExecutionAttemptEvidence(latestDirectDispatch) : null;
  if (
    latestDirectDispatch?.status === 'completed' &&
    latestAttempt?.exitCode === 0 &&
    !isHelpProbeArgv(latestAttempt.argv)
  ) {
    return answer;
  }
  const normalizedAnswer = stripAnsiEscapeSequences(answer).toLowerCase();
  const missingSummaries = summaries.filter(
    (summary) => !normalizedAnswer.includes(stripAnsiEscapeSequences(summary).toLowerCase())
  );
  if (missingSummaries.length === 0) {
    return answer;
  }
  return `${answer.trim()}\n\nVerified failure:\n${missingSummaries.join('\n')}`;
}

function isGenericNativeToolSessionSummary(text: string): boolean {
  const normalized = stripAnsiEscapeSequences(text).trim();
  if (!normalized) {
    return false;
  }
  return /^native tool session requested(?:[:.]|$)/i.test(normalized) || /^resumed native tool session\b/i.test(normalized);
}

function isProviderNoTextOutputSummary(text: string): boolean {
  const normalized = stripAnsiEscapeSequences(text).trim();
  if (!normalized) {
    return false;
  }
  return /completed with no text output\.$/i.test(normalized);
}

const INTERNAL_TOOL_DEBUGGING_PATTERNS = [
  /\b(?:the|this)\s+[`'"]?[a-z0-9_-]+[`'"]?\s+(?:skill|tool)\b/i,
  /\brequires?\s+(?:a|an)\s+url\b/i,
  /\bdoes not support (?:a )?direct search query\b/i,
  /\b(?:previous|prior)\s+attempts?\s+failed\b/i,
  /\bsince i cannot (?:perform|run|execute)\b/i,
  /\bgiven the context and the error\b/i,
  /\b(?:tool|skill)\s+(?:constraint|constraints|selection|selection rationale|capability mismatch|debugging)\b/i,
  /\b(?:execution|search)\s+error blocks\b/i,
  /\bnative tool session requested\b/i,
  /\bmissing capability\b/i
];

function looksLikeInternalToolDebuggingAnswer(text: string): boolean {
  const normalized = stripAnsiEscapeSequences(text).trim();
  if (!normalized) {
    return false;
  }
  const matchCount = INTERNAL_TOOL_DEBUGGING_PATTERNS.reduce(
    (count, pattern) => (pattern.test(normalized) ? count + 1 : count),
    0
  );
  return matchCount >= 2;
}

interface RecentVerifiedToolContext {
  schema: 'ops.verified-tool-context.v1';
  sourceRunId: string;
  skillNames: string[];
  executables: string[];
  latestSuccessfulArgv: string[] | null;
  latestSuccessfulCommand: string | null;
  resultPreview: string | null;
}

interface RecentVerifiedToolFollowupContext extends RecentVerifiedToolContext {
  prompt: string;
}

interface DirectExecutionAttemptEnvelope {
  dispatch: ExecutionContractDispatchResult;
  attempt: DirectExecutionAttemptEvidence;
}

interface RunTimelineEntryShape {
  type: string;
  details: string;
  payloadJson: string;
}

const RECENT_VERIFIED_TOOL_CONTEXT_MAX_AGE_MS = 30 * 60 * 1000;
const FOLLOWUP_REFERENTIAL_PROMPT_PREFIX =
  /^(?:what|why|how|who|where|when|which|so|and|then|tell me more|what about|can you explain)\b/i;
const LIGHTWEIGHT_COMMAND_PROMPT_PREFIX =
  /^(?:run|execute|launch|start|stop|restart|status|health|check|tail|list|show|open|inspect|use)\b/i;
const FRESH_TARGET_URL_PATTERN = /\b(?:https?:\/\/|www\.)\S+/i;
const TELEGRAM_SANITIZED_PROGRESS_TEXT = 'Working...';

const shouldSuppressTelegramLiveChunk = (chunk: string): boolean => {
  const normalized = stripAnsiEscapeSequences(chunk).trim();
  if (!normalized) {
    return false;
  }
  return (
    containsRuntimeNoiseMarker(normalized) ||
    /^\[native_tool_session:[^\]]+\]/i.test(normalized) ||
    /^\[skill\]\s+/i.test(normalized) ||
    isGenericNativeToolSessionSummary(normalized)
  );
};

const listDirectExecutionAttemptEnvelopes = (
  dispatches: ExecutionContractDispatchResult[]
): DirectExecutionAttemptEnvelope[] =>
  dispatches
    .filter((dispatch) => dispatch.action === 'execute_command')
    .flatMap((dispatch) => {
      const attempt = extractDirectExecutionAttemptEvidence(dispatch);
      return attempt ? [{ dispatch, attempt }] : [];
    });

const selectLatestNonHelpDirectExecutionAttempt = (
  dispatches: ExecutionContractDispatchResult[]
): DirectExecutionAttemptEnvelope | null =>
  [...listDirectExecutionAttemptEnvelopes(dispatches)]
    .reverse()
    .find((entry) => !isHelpProbeArgv(entry.attempt.argv)) ?? null;

const selectLatestSuccessfulNonHelpDirectExecutionAttempt = (
  dispatches: ExecutionContractDispatchResult[]
): DirectExecutionAttemptEnvelope | null =>
  [...listDirectExecutionAttemptEnvelopes(dispatches)]
    .reverse()
    .find(
      (entry) =>
        entry.dispatch.status === 'completed' &&
        entry.attempt.exitCode === 0 &&
        !isHelpProbeArgv(entry.attempt.argv)
    ) ?? null;

const selectEvidenceDirectExecutionDispatches = (
  dispatches: ExecutionContractDispatchResult[]
): ExecutionContractDispatchResult[] => {
  if (dispatches.length === 0) {
    return [];
  }
  const nonHelpAttempts = listDirectExecutionAttemptEnvelopes(dispatches).filter(
    (entry) => !isHelpProbeArgv(entry.attempt.argv)
  );
  const distinctTaskIds = new Set(nonHelpAttempts.map((entry) => entry.dispatch.taskId));
  if (distinctTaskIds.size > 1) {
    return nonHelpAttempts.map((entry) => entry.dispatch);
  }
  const latestSuccessfulDispatch = selectLatestSuccessfulNonHelpDirectExecutionAttempt(dispatches)?.dispatch;
  if (latestSuccessfulDispatch) {
    return [latestSuccessfulDispatch];
  }
  return nonHelpAttempts.length > 0 ? nonHelpAttempts.map((entry) => entry.dispatch) : dispatches;
};

const selectAuthoritativeDirectExecutionDispatches = (
  dispatches: ExecutionContractDispatchResult[]
): ExecutionContractDispatchResult[] => {
  if (dispatches.length === 0) {
    return [];
  }
  const latestSuccessfulDispatch = selectLatestSuccessfulNonHelpDirectExecutionAttempt(dispatches)?.dispatch;
  if (latestSuccessfulDispatch) {
    return [latestSuccessfulDispatch];
  }
  const latestNonHelpDispatch = selectLatestNonHelpDirectExecutionAttempt(dispatches)?.dispatch;
  if (latestNonHelpDispatch) {
    return [latestNonHelpDispatch];
  }
  return dispatches;
};

const summarizeExecutionContractDispatches = (
  dispatches: ExecutionContractDispatchResult[]
): {
  status: 'parsed' | 'invalid' | 'dispatched' | 'completed' | 'partial' | 'failed';
  summary: {
    queued: number;
    skipped: number;
    blocked: number;
    failed: number;
  };
} => {
  const summary = dispatches.reduce(
    (accumulator, dispatch) => {
      switch (dispatch.status) {
        case 'queued':
          accumulator.queued += 1;
          break;
        case 'skipped':
          accumulator.skipped += 1;
          break;
        case 'blocked':
          accumulator.blocked += 1;
          break;
        case 'failed':
          accumulator.failed += 1;
          break;
        default:
          break;
      }
      return accumulator;
    },
    {
      queued: 0,
      skipped: 0,
      blocked: 0,
      failed: 0
    }
  );
  const completedDirectExecutions = dispatches.filter(
    (dispatch) => dispatch.action === 'execute_command' && dispatch.status === 'completed'
  ).length;
  const handledDispatchCount = summary.queued + summary.skipped + completedDirectExecutions;
  const status: 'parsed' | 'invalid' | 'dispatched' | 'completed' | 'partial' | 'failed' =
    summary.queued > 0 && summary.blocked === 0 && summary.failed === 0
      ? 'dispatched'
      : handledDispatchCount > 0 && summary.blocked === 0 && summary.failed === 0
        ? 'completed'
        : handledDispatchCount > 0
          ? 'partial'
          : summary.blocked > 0 || summary.failed > 0
            ? 'failed'
            : 'parsed';
  return {
    status,
    summary
  };
};

const parseRecentVerifiedToolContext = (value: unknown): RecentVerifiedToolContext | null => {
  if (!isRecord(value) || value.schema !== 'ops.verified-tool-context.v1') {
    return null;
  }
  const sourceRunId = typeof value.sourceRunId === 'string' ? value.sourceRunId.trim() : '';
  const skillNames = Array.isArray(value.skillNames)
    ? value.skillNames.map((entry) => String(entry ?? '').trim().toLowerCase()).filter((entry) => entry.length > 0)
    : [];
  const executables = Array.isArray(value.executables)
    ? value.executables.map((entry) => normalizeToolName(String(entry ?? ''))).filter((entry) => entry.length > 0)
    : [];
  const latestSuccessfulArgv = Array.isArray(value.latestSuccessfulArgv)
    ? value.latestSuccessfulArgv.map((entry) => String(entry ?? '').trim()).filter((entry) => entry.length > 0)
    : null;
  const latestSuccessfulCommand =
    typeof value.latestSuccessfulCommand === 'string' && value.latestSuccessfulCommand.trim().length > 0
      ? value.latestSuccessfulCommand.trim()
      : null;
  const resultPreview =
    typeof value.resultPreview === 'string' && value.resultPreview.trim().length > 0
      ? value.resultPreview.trim()
      : null;
  if (!sourceRunId || (skillNames.length === 0 && executables.length === 0 && !latestSuccessfulCommand)) {
    return null;
  }
  return {
    schema: 'ops.verified-tool-context.v1',
    sourceRunId,
    skillNames: Array.from(new Set(skillNames)),
    executables: Array.from(new Set(executables)),
    latestSuccessfulArgv,
    latestSuccessfulCommand,
    resultPreview
  };
};

const extractSuccessfulSkillNamesFromToolEvents = (toolEvents: RuntimeToolSessionEvent[]): string[] =>
  Array.from(
    new Set(
      toolEvents
        .filter((event) => event.type === 'tool_result' && event.toolName === 'skill_call')
        .flatMap((event) => {
          const payload = isRecord(event.payload) ? event.payload : {};
          const skill = typeof payload.skill === 'string' ? payload.skill.trim().toLowerCase() : '';
          return skill ? [skill] : [];
        })
    )
  );

const extractSuccessfulSkillNamesFromTimelineEntries = (events: RunTimelineEntryShape[]): string[] =>
  Array.from(
    new Set(
      events.flatMap((event) => {
        const payload = parseJsonSafe<Record<string, unknown>>(event.payloadJson, {});
        const skillName =
          event.type === 'tool_result' &&
          typeof payload.toolName === 'string' &&
          payload.toolName === 'skill_call' &&
          isRecord(payload.payload) &&
          typeof payload.payload.skill === 'string'
            ? payload.payload.skill.trim().toLowerCase()
            : event.type === 'skill.called' && typeof payload.skillName === 'string'
              ? payload.skillName.trim().toLowerCase()
              : event.type === 'skill.called'
                ? /Autonomous skill invoked \((.+)\)/i.exec(event.details)?.[1]?.trim().toLowerCase() ?? ''
                : '';
        return skillName ? [skillName] : [];
      })
    )
  );

const buildRecentVerifiedToolContext = (input: {
  run: RunRecord;
  result: RuntimeExecutionResult;
  dispatches: ExecutionContractDispatchResult[];
  outboundContent: string;
  timeline: RunTimelineEntryShape[];
}): RecentVerifiedToolContext | null => {
  const latestSuccessfulAttempt = selectLatestSuccessfulNonHelpDirectExecutionAttempt(input.dispatches);
  const successfulSkillNames = Array.from(
    new Set([
      ...extractSuccessfulSkillNamesFromToolEvents(input.result.toolEvents ?? []),
      ...extractSuccessfulSkillNamesFromTimelineEntries(input.timeline)
    ])
  );
  const executables = Array.from(
    new Set(
      listDirectExecutionAttemptEnvelopes(input.dispatches)
        .filter((entry) => entry.dispatch.status === 'completed' && entry.attempt.exitCode === 0 && !isHelpProbeArgv(entry.attempt.argv))
        .map((entry) => normalizeToolName(entry.attempt.argv[0] ?? ''))
        .filter((entry) => entry.length > 0)
    )
  );
  if (!latestSuccessfulAttempt && successfulSkillNames.length === 0) {
    return null;
  }
  return {
    schema: 'ops.verified-tool-context.v1',
    sourceRunId: input.run.id,
    skillNames: successfulSkillNames,
    executables,
    latestSuccessfulArgv: latestSuccessfulAttempt?.attempt.argv ?? null,
    latestSuccessfulCommand: latestSuccessfulAttempt?.attempt.argv.join(' ') ?? null,
    resultPreview: summarizeCommandOutputSnippet(input.outboundContent, 320)
  };
};

const buildRecentVerifiedToolContextFromPersistedRun = (input: {
  run: RunRecord;
  dispatches: ExecutionContractDispatchResult[];
  timeline: RunTimelineEntryShape[];
  outboundContent: string;
}): RecentVerifiedToolContext | null => {
  const latestSuccessfulAttempt = selectLatestSuccessfulNonHelpDirectExecutionAttempt(input.dispatches);
  const successfulSkillNames = extractSuccessfulSkillNamesFromTimelineEntries(input.timeline);
  const executables = Array.from(
    new Set(
      listDirectExecutionAttemptEnvelopes(input.dispatches)
        .filter((entry) => entry.dispatch.status === 'completed' && entry.attempt.exitCode === 0 && !isHelpProbeArgv(entry.attempt.argv))
        .map((entry) => normalizeToolName(entry.attempt.argv[0] ?? ''))
        .filter((entry) => entry.length > 0)
    )
  );
  if (!latestSuccessfulAttempt && successfulSkillNames.length === 0) {
    return null;
  }
  const previewSource = input.outboundContent.trim().length > 0 ? input.outboundContent : input.run.resultSummary ?? '';
  return {
    schema: 'ops.verified-tool-context.v1',
    sourceRunId: input.run.id,
    skillNames: successfulSkillNames,
    executables,
    latestSuccessfulArgv: latestSuccessfulAttempt?.attempt.argv ?? null,
    latestSuccessfulCommand: latestSuccessfulAttempt?.attempt.argv.join(' ') ?? null,
    resultPreview: summarizeCommandOutputSnippet(previewSource, 320)
  };
};

const normalizePersistedExecutionContractDispatch = (
  dispatch: PersistedExecutionContractDispatch
): ExecutionContractDispatchResult => {
  const details = parseJsonSafe<Record<string, unknown>>(dispatch.detailsJson, {});
  return {
    taskId: dispatch.taskId,
    title: typeof details.title === 'string' && details.title.trim().length > 0 ? details.title.trim() : dispatch.action,
    action: dispatch.action === 'dispatch_subrun' ? 'dispatch_subrun' : 'execute_command',
    status: dispatch.status,
    reason: dispatch.reason,
    targetAgentId: dispatch.targetAgentId,
    targetSessionId: dispatch.targetSessionId,
    delegatedRunId: dispatch.delegatedRunId,
    dependsOnTaskIds: Array.isArray(details.dependsOnTaskIds)
      ? details.dependsOnTaskIds.filter((entry): entry is string => typeof entry === 'string' && entry.trim().length > 0)
      : [],
    details
  };
};

const isLikelyReferentialFollowupPrompt = (prompt: string): boolean => {
  const trimmed = prompt.trim();
  if (!trimmed || trimmed.startsWith('/')) {
    return false;
  }
  if (FRESH_TARGET_URL_PATTERN.test(trimmed)) {
    return false;
  }
  if (trimmed.length > 220 || LIGHTWEIGHT_COMMAND_PROMPT_PREFIX.test(trimmed)) {
    return false;
  }
  if (/[`]/.test(trimmed)) {
    return false;
  }
  return (
    FOLLOWUP_REFERENTIAL_PROMPT_PREFIX.test(trimmed) ||
    /\b(?:that|it|this|those|these|them)\b/i.test(trimmed) ||
    trimmed.endsWith('?')
  );
};

function splitReasoningText(text: string): { reasoning: string; answer: string } {
  if (!text) {
    return {
      reasoning: '',
      answer: ''
    };
  }

  let cursor = 0;
  let inCodeFence = false;
  let reasoning = '';
  let answer = '';

  while (cursor < text.length) {
    if (text.startsWith('```', cursor)) {
      inCodeFence = !inCodeFence;
      answer += '```';
      cursor += 3;
      continue;
    }

    if (!inCodeFence && text.startsWith('<think>', cursor)) {
      const closeIndex = text.indexOf('</think>', cursor + '<think>'.length);
      if (closeIndex < 0) {
        reasoning += text.slice(cursor + '<think>'.length);
        break;
      }
      reasoning += text.slice(cursor + '<think>'.length, closeIndex);
      cursor = closeIndex + '</think>'.length;
      continue;
    }

    const nextCodeFence = text.indexOf('```', cursor);
    const nextThink = inCodeFence ? -1 : text.indexOf('<think>', cursor);
    const nextBoundaryCandidates = [nextCodeFence, nextThink].filter((value) => value >= 0);
    const nextBoundary =
      nextBoundaryCandidates.length > 0 ? Math.min(...nextBoundaryCandidates) : text.length;
    answer += text.slice(cursor, nextBoundary);
    cursor = nextBoundary;
  }

  return {
    reasoning: reasoning.trim(),
    answer: answer.replace(/<\/?think>/gi, '').trim()
  };
}

function inferProvider(model: string | null): LlmProviderKey | null {
  const normalizedModel = normalizeModelInput(model);
  if (extractOpenRouterModelAlias(normalizedModel)) {
    return 'openrouter';
  }
  if (isGoogleProviderModel(normalizedModel)) {
    return 'google';
  }
  if (!normalizedModel) {
    return null;
  }
  // Any explicitly configured non-Gemini model is treated as OpenRouter-routed.
  return 'openrouter';
}

function buildRuntimeExecutionMetadata(input: {
  runtime: RuntimeKind;
  model: string | null;
  base?: Record<string, unknown>;
  provider?: LlmProviderKey | null;
  runtimeAdapterBaseDir?: string;
}): Record<string, unknown> {
  const provider = input.provider ?? inferProvider(input.model);
  const metadata: Record<string, unknown> = {
    ...(input.base ?? {}),
    ...(input.model ? { model: input.model } : {}),
    providerApiShortcut: provider !== null,
    runtimeAdapterBaseDir:
      typeof input.runtimeAdapterBaseDir === 'string' && input.runtimeAdapterBaseDir.trim().length > 0
        ? path.resolve(input.runtimeAdapterBaseDir)
        : process.cwd()
  };
  if (provider) {
    metadata.provider = provider;
  }
  if (input.runtime === 'process') {
    metadata.processCommandFallbackAllowed = provider === null;
  }
  return metadata;
}

type ExecutionPathMode = 'provider_api' | 'process_local_executor' | 'runtime_cli';
type ToolSessionMode = 'native_tool_session' | 'direct_runtime';
type ToolInvocationPath = 'tool_first_native' | 'local_executor_contract' | 'plain_provider_response';

interface RuntimeToolSessionHandle {
  schema: 'ops.native-tool-session-handle.v1';
  id: string;
  runtime: RuntimeKind;
  provider: LlmProviderKey | null;
  model: string | null;
  transport: 'provider_bridge' | 'none';
  resumable: boolean;
  version: number;
  createdAt: string;
  updatedAt: string;
  toolSessionMode: ToolSessionMode;
  lastToolName?: string | null;
  lastToolCallId?: string | null;
  eventCount: number;
}

interface PersistedNativeToolSessionState {
  schema: 'ops.native-tool-session-state.v1';
  handle: RuntimeToolSessionHandle;
  rootRunId: string;
  currentRunId: string;
  sessionId: string;
  executionPath: {
    mode: ExecutionPathMode;
    runtime: RuntimeKind;
    model: string | null;
    provider: LlmProviderKey | null;
    source: string;
    routeReason: string | null;
    toolSessionMode: ToolSessionMode | null;
    toolInvocationPath: ToolInvocationPath;
  };
  provenance: {
    updatedAt: string;
    lastToolEventAt: string | null;
    totalToolEvents: number;
    resumeSource: string | null;
    resumedFromRunId: string | null;
  };
}

function resolveDefaultToolInvocationPath(input: {
  runtime: RuntimeKind;
  provider: LlmProviderKey | null;
  toolInvocationPath?: ToolInvocationPath | null;
}): ToolInvocationPath {
  if (input.toolInvocationPath) {
    return input.toolInvocationPath;
  }
  if (input.runtime === 'process' && input.provider === null) {
    return 'local_executor_contract';
  }
  if (input.runtime === 'process' && input.provider !== null) {
    return 'tool_first_native';
  }
  return 'plain_provider_response';
}

function allowsRawExecutionContractCompatibility(
  snapshot:
    | {
        toolInvocationPath: ToolInvocationPath;
      }
    | null
): boolean {
  return snapshot?.toolInvocationPath === 'local_executor_contract';
}

function buildExecutionPathSnapshot(input: {
  runtime: RuntimeKind;
  model: string | null;
  provider?: LlmProviderKey | null;
  source: string;
  routeReason?: string | null;
  toolSessionMode?: ToolSessionMode | null;
  toolInvocationPath?: ToolInvocationPath | null;
}): {
  mode: ExecutionPathMode;
  runtime: RuntimeKind;
  model: string | null;
  provider: LlmProviderKey | null;
  source: string;
  routeReason: string | null;
  processCommandFallbackAllowed: boolean;
  toolSessionMode: ToolSessionMode | null;
  toolInvocationPath: ToolInvocationPath;
} {
  const provider = input.provider ?? inferProvider(input.model);
  const toolInvocationPath = resolveDefaultToolInvocationPath({
    runtime: input.runtime,
    provider,
    toolInvocationPath: input.toolInvocationPath ?? null
  });
  return {
    mode: provider ? 'provider_api' : input.runtime === 'process' ? 'process_local_executor' : 'runtime_cli',
    runtime: input.runtime,
    model: input.model ?? null,
    provider,
    source: input.source,
    routeReason: input.routeReason ?? null,
    processCommandFallbackAllowed: input.runtime === 'process' && provider === null,
    toolSessionMode: input.toolSessionMode ?? null,
    toolInvocationPath
  };
}

type ExecutionPathSnapshot = ReturnType<typeof buildExecutionPathSnapshot>;

  const parseExecutionPathSnapshot = (
  payloadJson: string
):
  | {
      mode: ExecutionPathMode;
      runtime: RuntimeKind;
      model: string | null;
      provider: LlmProviderKey | null;
      source: string;
      routeReason: string | null;
      processCommandFallbackAllowed: boolean;
      toolSessionMode: ToolSessionMode | null;
      toolInvocationPath: ToolInvocationPath;
    }
  | null => {
  const payload = parseJsonSafe<Record<string, unknown>>(payloadJson, {});
  const modeRaw = typeof payload.mode === 'string' ? payload.mode.trim() : '';
  if (modeRaw !== 'provider_api' && modeRaw !== 'process_local_executor' && modeRaw !== 'runtime_cli') {
    return null;
  }
  const runtimeRaw = typeof payload.runtime === 'string' ? payload.runtime.trim() : '';
  if (runtimeRaw !== 'codex' && runtimeRaw !== 'claude' && runtimeRaw !== 'gemini' && runtimeRaw !== 'process') {
    return null;
  }
  const providerRaw = typeof payload.provider === 'string' ? payload.provider.trim() : '';
  const provider =
    providerRaw === 'google' || providerRaw === 'openrouter' ? (providerRaw as LlmProviderKey) : null;
  const toolSessionModeRaw = typeof payload.toolSessionMode === 'string' ? payload.toolSessionMode.trim() : '';
  const toolSessionMode =
    toolSessionModeRaw === 'native_tool_session' || toolSessionModeRaw === 'direct_runtime'
      ? (toolSessionModeRaw as ToolSessionMode)
      : null;
  const toolInvocationPathRaw =
    typeof payload.toolInvocationPath === 'string' ? payload.toolInvocationPath.trim() : '';
  const toolInvocationPath =
    toolInvocationPathRaw === 'tool_first_native' ||
    toolInvocationPathRaw === 'local_executor_contract' ||
    toolInvocationPathRaw === 'plain_provider_response'
      ? (toolInvocationPathRaw as ToolInvocationPath)
      : null;
  if (!toolInvocationPath) {
    return null;
  }
  return {
    mode: modeRaw,
    runtime: runtimeRaw as RuntimeKind,
    model: normalizeModelInput(typeof payload.model === 'string' ? payload.model : null),
    provider,
    source: typeof payload.source === 'string' ? payload.source : 'unknown',
    routeReason: typeof payload.routeReason === 'string' ? payload.routeReason : null,
    processCommandFallbackAllowed: payload.processCommandFallbackAllowed === true,
    toolSessionMode,
    toolInvocationPath
  };
};

const selectLatestExecutionPathSnapshot = (
  timeline: Array<{ type: string; payloadJson: string }>
):
  | {
      mode: ExecutionPathMode;
      runtime: RuntimeKind;
      model: string | null;
      provider: LlmProviderKey | null;
      source: string;
      routeReason: string | null;
      processCommandFallbackAllowed: boolean;
      toolSessionMode: ToolSessionMode | null;
      toolInvocationPath: ToolInvocationPath;
    }
  | null => {
  let latestSnapshot: ReturnType<typeof parseExecutionPathSnapshot> = null;
  for (let index = timeline.length - 1; index >= 0; index -= 1) {
    const entry = timeline[index];
    if (entry?.type !== 'run.execution_path') {
      continue;
    }
    const parsed = parseExecutionPathSnapshot(entry.payloadJson);
    if (!parsed) {
      continue;
    }
    if (!latestSnapshot) {
      latestSnapshot = parsed;
    }
    if (parsed.toolSessionMode !== null) {
      return parsed;
    }
  }
  return latestSnapshot;
};

const buildNativeToolSessionRunSnapshotId = (runId: string): string => `native_tool_session.run.${runId}`;
const buildNativeToolSessionLineageSnapshotId = (rootRunId: string): string => `native_tool_session.lineage.${rootRunId}`;

const parseRuntimeToolSessionHandle = (value: unknown): RuntimeToolSessionHandle | null => {
  if (!isRecord(value) || value.schema !== 'ops.native-tool-session-handle.v1') {
    return null;
  }
  const id = typeof value.id === 'string' ? value.id.trim() : '';
  const runtime = typeof value.runtime === 'string' ? value.runtime.trim() : '';
  if (!id || (runtime !== 'codex' && runtime !== 'claude' && runtime !== 'gemini' && runtime !== 'process')) {
    return null;
  }
  const providerRaw = typeof value.provider === 'string' ? value.provider.trim() : '';
  const provider =
    providerRaw === 'openrouter' || providerRaw === 'google' ? (providerRaw as LlmProviderKey) : null;
  const transportRaw = typeof value.transport === 'string' ? value.transport.trim() : '';
  const transport = transportRaw === 'provider_bridge' || transportRaw === 'none' ? transportRaw : 'none';
  const toolSessionModeRaw = typeof value.toolSessionMode === 'string' ? value.toolSessionMode.trim() : '';
  const toolSessionMode =
    toolSessionModeRaw === 'native_tool_session' || toolSessionModeRaw === 'direct_runtime'
      ? (toolSessionModeRaw as ToolSessionMode)
      : 'direct_runtime';
  const version = Number(value.version);
  const eventCount = Number(value.eventCount);
  return {
    schema: 'ops.native-tool-session-handle.v1',
    id,
    runtime: runtime as RuntimeKind,
    provider,
    model: normalizeModelInput(typeof value.model === 'string' ? value.model : null),
    transport,
    resumable: value.resumable === true,
    version: Number.isFinite(version) && version > 0 ? Math.floor(version) : 1,
    createdAt: typeof value.createdAt === 'string' ? value.createdAt : utcNow(),
    updatedAt: typeof value.updatedAt === 'string' ? value.updatedAt : utcNow(),
    toolSessionMode,
    lastToolName: typeof value.lastToolName === 'string' ? value.lastToolName : null,
    lastToolCallId: typeof value.lastToolCallId === 'string' ? value.lastToolCallId : null,
    eventCount: Number.isFinite(eventCount) && eventCount >= 0 ? Math.floor(eventCount) : 0
  };
};

const runtimeResultToolSessionHandle = (result: RuntimeExecutionResult): RuntimeToolSessionHandle | null =>
  parseRuntimeToolSessionHandle((result as RuntimeExecutionResult & { toolSessionHandle?: unknown }).toolSessionHandle);

const parsePersistedNativeToolSessionState = (value: unknown): PersistedNativeToolSessionState | null => {
  if (!isRecord(value) || value.schema !== 'ops.native-tool-session-state.v1') {
    return null;
  }
  const handle = parseRuntimeToolSessionHandle(value.handle);
  if (!handle) {
    return null;
  }
  const executionPath = isRecord(value.executionPath) ? value.executionPath : null;
  const provenance = isRecord(value.provenance) ? value.provenance : null;
  const modeRaw = typeof executionPath?.mode === 'string' ? executionPath.mode.trim() : '';
  const mode =
    modeRaw === 'provider_api' || modeRaw === 'process_local_executor' || modeRaw === 'runtime_cli'
      ? (modeRaw as ExecutionPathMode)
      : null;
  if (!mode) {
    return null;
  }
  const runtimeRaw = typeof executionPath?.runtime === 'string' ? executionPath.runtime.trim() : '';
  if (runtimeRaw !== 'codex' && runtimeRaw !== 'claude' && runtimeRaw !== 'gemini' && runtimeRaw !== 'process') {
    return null;
  }
  const providerRaw = typeof executionPath?.provider === 'string' ? executionPath.provider.trim() : '';
  const provider =
    providerRaw === 'openrouter' || providerRaw === 'google' ? (providerRaw as LlmProviderKey) : null;
  const toolSessionModeRaw = typeof executionPath?.toolSessionMode === 'string' ? executionPath.toolSessionMode.trim() : '';
  const toolSessionMode =
    toolSessionModeRaw === 'native_tool_session' || toolSessionModeRaw === 'direct_runtime'
      ? (toolSessionModeRaw as ToolSessionMode)
      : null;
  const toolInvocationPathRaw =
    typeof executionPath?.toolInvocationPath === 'string' ? executionPath.toolInvocationPath.trim() : '';
  const toolInvocationPath =
    toolInvocationPathRaw === 'tool_first_native' ||
    toolInvocationPathRaw === 'local_executor_contract' ||
    toolInvocationPathRaw === 'plain_provider_response'
      ? (toolInvocationPathRaw as ToolInvocationPath)
      : null;
  if (!toolInvocationPath) {
    return null;
  }
  return {
    schema: 'ops.native-tool-session-state.v1',
    handle,
    rootRunId: typeof value.rootRunId === 'string' ? value.rootRunId : '',
    currentRunId: typeof value.currentRunId === 'string' ? value.currentRunId : '',
    sessionId: typeof value.sessionId === 'string' ? value.sessionId : '',
    executionPath: {
      mode,
      runtime: runtimeRaw as RuntimeKind,
      model: normalizeModelInput(typeof executionPath?.model === 'string' ? executionPath.model : null),
      provider,
      source: typeof executionPath?.source === 'string' ? executionPath.source : 'unknown',
      routeReason: typeof executionPath?.routeReason === 'string' ? executionPath.routeReason : null,
      toolSessionMode,
      toolInvocationPath
    },
    provenance: {
      updatedAt: typeof provenance?.updatedAt === 'string' ? provenance.updatedAt : utcNow(),
      lastToolEventAt: typeof provenance?.lastToolEventAt === 'string' ? provenance.lastToolEventAt : null,
      totalToolEvents: Number.isFinite(Number(provenance?.totalToolEvents)) ? Number(provenance?.totalToolEvents) : 0,
      resumeSource: typeof provenance?.resumeSource === 'string' ? provenance.resumeSource : null,
      resumedFromRunId: typeof provenance?.resumedFromRunId === 'string' ? provenance.resumedFromRunId : null
    }
  };
};

function estimateUsage(prompt: string, summary: string | null): {
  promptTokens: number;
  completionTokens: number;
  totalTokens: number;
} {
  const promptTokens = Math.max(1, Math.ceil(prompt.length / 4));
  const completionTokens = Math.max(1, Math.ceil((summary ?? '').length / 4));
  return {
    promptTokens,
    completionTokens,
    totalTokens: promptTokens + completionTokens
  };
}

