  app.patch('/api/housekeeping/retention', async (request, reply) => {
    if (!hasValidApiToken(request, config.server.apiToken)) {
      return jsonError(reply, 'Unauthorized', 401);
    }

    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const updatesRaw = isRecord(body.updates)
      ? body.updates
      : typeof body.path === 'string'
        ? { [body.path]: body.value }
        : null;
    if (!updatesRaw || Object.keys(updatesRaw).length === 0) {
      return jsonError(reply, 'Either updates object or path/value is required', 400);
    }

    const allowedNumericPaths = new Set([
      'sessionRetentionHours.delegate',
      'sessionRetentionHours.dashboard',
      'sessionRetentionHours.agent',
      'sessionRetentionHours.internal',
      'sessionRetentionHours.telegram',
      'sessionRetentionHours.office',
      'sessionRetentionHours.unknown',
      'runRetentionHours',
      'terminalRetentionHours',
      'waitingInputStaleMinutes',
      'messageRetentionHours',
      'realtimeRetentionHours',
      'officePresenceRetentionHours',
      'llmUsageRetentionDays',
      'memoryRetentionDays',
      'memoryMarkdownRetentionDays',
      'auditRetentionDays'
    ]);
    const allowlist = new Set([...allowedNumericPaths, 'protectedSessionKeys']);

    const nextConfigPayload = structuredClone(config) as unknown as Record<string, unknown>;
    const changed: Array<{ path: string; value: unknown }> = [];

    for (const [pathKeyRaw, incomingValue] of Object.entries(updatesRaw)) {
      const pathKey = pathKeyRaw.trim();
      if (!allowlist.has(pathKey)) {
        return jsonError(reply, `Unsupported retention field: ${pathKey}`, 400);
      }

      if (pathKey === 'protectedSessionKeys') {
        const normalized = Array.isArray(incomingValue)
          ? incomingValue.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0)
          : typeof incomingValue === 'string'
            ? incomingValue
                .split(',')
                .map((entry) => entry.trim())
                .filter((entry) => entry.length > 0)
            : [];
        setAtPath(nextConfigPayload, ['housekeeping', 'protectedSessionKeys'], normalized);
        changed.push({
          path: `housekeeping.${pathKey}`,
          value: normalized
        });
        continue;
      }

      const parsed = Number(incomingValue);
      if (!Number.isFinite(parsed) || parsed <= 0) {
        return jsonError(reply, `Invalid retention value for ${pathKey}. Expected positive number.`, 400);
      }
      setAtPath(nextConfigPayload, ['housekeeping', ...pathKey.split('.')], Math.floor(parsed));
      changed.push({
        path: `housekeeping.${pathKey}`,
        value: Math.floor(parsed)
      });
    }

    const parsedConfig = controlPlaneConfigSchema.safeParse(nextConfigPayload);
    if (!parsedConfig.success) {
      return jsonError(reply, 'Retention update failed validation', 400, {
        issues: parsedConfig.error.issues.map((issue) => ({
          path: issue.path.join('.'),
          message: issue.message
        }))
      });
    }

    database.upsertRuntimeConfigOverlay(parsedConfig.data as unknown as Record<string, unknown>);
    for (const [key, value] of Object.entries(parsedConfig.data)) {
      (config as Record<string, unknown>)[key] = value as unknown;
    }

    database.appendAudit({
      actor,
      action: 'housekeeping.retention.update',
      resource: RUNTIME_CONFIG_OVERLAY_RESOURCE,
      decision: 'allowed',
      reason: 'updated',
      details: {
        changed
      },
      correlationId: randomUUID()
    });

    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'info',
      message: 'Housekeeping retention updated',
      data: {
        actor,
        changed
      }
    });

    return jsonOk(reply, {
      housekeeping: {
        enabled: config.housekeeping.enabled,
        intervalSec: config.housekeeping.intervalSec,
        retention: {
          sessionsHours: config.housekeeping.sessionRetentionHours,
          runHours: config.housekeeping.runRetentionHours,
          terminalHours: config.housekeeping.terminalRetentionHours,
          waitingInputStaleMinutes: config.housekeeping.waitingInputStaleMinutes,
          messageHours: config.housekeeping.messageRetentionHours,
          realtimeHours: config.housekeeping.realtimeRetentionHours,
          officePresenceHours: config.housekeeping.officePresenceRetentionHours,
          llmUsageDays: config.housekeeping.llmUsageRetentionDays,
          memoryDays: config.housekeeping.memoryRetentionDays,
          memoryMarkdownDays: config.housekeeping.memoryMarkdownRetentionDays,
          auditDays: config.housekeeping.auditRetentionDays,
          protectedSessionKeys: config.housekeeping.protectedSessionKeys
        }
      },
      changed
    });
  });

