  if (process.env.NODE_ENV === 'test') {
    app.post('/api/watchdog/simulate', async (request, reply) => {
      const body = (request.body ?? {}) as Record<string, unknown>;
      const runId = typeof body.runId === 'string' && body.runId.trim().length > 0 ? body.runId.trim() : '';
      if (!runId) {
        return jsonError(reply, 'runId is required', 400);
      }
      const run = database.getRunById(runId);
      if (!run) {
        return jsonError(reply, 'Run not found', 404);
      }

      const runtimeRaw = typeof body.runtime === 'string' ? body.runtime.trim() : '';
      const runtime = isKnownRuntime(runtimeRaw) ? runtimeRaw : run.effectiveRuntime ?? run.runtime;
      const statusRaw = typeof body.status === 'string' ? body.status.trim() : '';
      const allowedStatuses = new Set(['healthy', 'stalled_no_output', 'error_detected', 'quota_exceeded', 'context_overflow', 'stuck_at_prompt']);
      if (!allowedStatuses.has(statusRaw)) {
        return jsonError(reply, 'status must be one of healthy|stalled_no_output|error_detected|quota_exceeded|context_overflow|stuck_at_prompt', 400);
      }
      const recommendationRaw = typeof body.recommendation === 'string' ? body.recommendation.trim() : '';
      const allowedRecommendations = new Set(['continue', 'abort_and_retry', 'abort_and_switch_provider', 'alert_human']);
      if (!allowedRecommendations.has(recommendationRaw)) {
        return jsonError(reply, 'recommendation must be one of continue|abort_and_retry|abort_and_switch_provider|alert_human', 400);
      }

      const event: WatchdogHealthEvent = {
        runId,
        runtime,
        status: statusRaw as WatchdogHealthEvent['status'],
        detectedPattern: typeof body.detectedPattern === 'string' ? body.detectedPattern : null,
        lastOutputAgeMs: Number.isFinite(Number(body.lastOutputAgeMs)) ? Math.max(0, Math.floor(Number(body.lastOutputAgeMs))) : 0,
        matchedSignature: typeof body.matchedSignature === 'string' ? body.matchedSignature : null,
        recommendation: recommendationRaw as WatchdogHealthEvent['recommendation'],
        ts: utcNow(),
        metadata: isRecord(body.metadata) ? body.metadata : undefined
      };

      await applyWatchdogHealthEvent(event);
      return jsonOk(reply, {
        event,
        run: database.getRunById(runId)
      });
    });
  }

  const parseScheduleSessionTargetInput = (value: unknown): ScheduleSessionTarget | null => {
    const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
    return normalized === 'origin_session' || normalized === 'dedicated_schedule_session' || normalized === 'explicit_session'
      ? (normalized as ScheduleSessionTarget)
      : null;
  };

  const parseScheduleDeliveryTargetInput = (value: unknown): ScheduleDeliveryTarget | null => {
    const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
    return normalized === 'origin_session' ||
      normalized === 'dedicated_schedule_session' ||
      normalized === 'artifact_only' ||
      normalized === 'silent_on_heartbeat'
      ? (normalized as ScheduleDeliveryTarget)
      : null;
  };

  const parseScheduleConcurrencyPolicyInput = (value: unknown): ScheduleRecord['concurrencyPolicy'] | null => {
    const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
    return normalized === 'skip' || normalized === 'queue' || normalized === 'replace'
      ? (normalized as ScheduleRecord['concurrencyPolicy'])
      : null;
  };

  const scheduleView = (schedule: ScheduleRecord) => {
    const nextRunAtMs = Date.parse(schedule.nextRunAt ?? '');
    const activeRun = resolveActiveScheduleRun(schedule.id);
    return {
      ...schedule,
      originRef: scheduleRecordJson(schedule.originRefJson),
      domainPolicy: scheduleRecordJson(schedule.domainPolicyJson),
      rateLimitPolicy: scheduleRecordJson(schedule.rateLimitPolicyJson),
      lastResult: scheduleRecordJson(schedule.lastResultJson),
      metadata: scheduleRecordJson(schedule.metadataJson),
      paused: Boolean(schedule.pausedAt) || !schedule.enabled,
      isDue: Number.isFinite(nextRunAtMs) && nextRunAtMs <= Date.now(),
      activeRun: activeRun
        ? {
            runId: activeRun.run.id,
            sessionId: activeRun.run.sessionId,
            status: activeRun.run.status
          }
        : null
    };
  };

  const scheduleHistoryView = (entry: ScheduleRunHistoryRecord) => ({
    ...entry,
    details: scheduleRecordJson(entry.detailsJson)
  });

  type ScheduleViewPayload = ReturnType<typeof scheduleView>;
  type ScheduleHistoryPayload = ReturnType<typeof scheduleHistoryView>;
  type ScheduleListCommandPayload = {
    error?: string;
    schedules?: ScheduleViewPayload[];
  };
  type ScheduleLookupCommandPayload = {
    error?: string;
    schedule?: ScheduleViewPayload | null;
    history?: ScheduleHistoryPayload[];
  };
  type ScheduleMutationCommandPayload = {
    error?: string;
    schedule?: ScheduleViewPayload | null;
    history?: ScheduleHistoryPayload | null;
    run?: RunRecord | null;
  };

  const validateScheduleInput = (
    body: Record<string, unknown>,
    mode: 'create' | 'update',
    existing?: ScheduleRecord | null
  ): {
    errors: Record<string, string>;
    value: {
      label?: string;
      category?: string;
      cadence?: string;
      cadenceKind?: ScheduleRecord['cadenceKind'];
      enabled?: boolean;
      targetAgentId?: string | null;
      requestingSessionId?: string | null;
      deliveryTargetSessionId?: string | null;
      sessionTarget?: ScheduleSessionTarget;
      deliveryTarget?: ScheduleDeliveryTarget;
      prompt?: string | null;
      runtime?: string | null;
      model?: string | null;
      jobMode?: string | null;
      approvalProfile?: string | null;
      concurrencyPolicy?: ScheduleRecord['concurrencyPolicy'];
      metadata?: Record<string, unknown>;
      requestedBy?: string | null;
      originRef?: Record<string, unknown>;
      domainPolicy?: Record<string, unknown>;
      rateLimitPolicy?: Record<string, unknown>;
    };
  } => {
    const errors: Record<string, string> = {};
    const value: ReturnType<typeof validateScheduleInput>['value'] = {};
    const existingMetadata = existing ? scheduleRecordJson(existing.metadataJson) : {};

    if (Object.prototype.hasOwnProperty.call(body, 'label') || mode === 'create') {
      const label = typeof body.label === 'string' ? body.label.trim() : '';
      if (!label) {
        errors.label = 'label is required';
      } else {
        value.label = label.slice(0, 160);
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'category') || mode === 'create') {
      const category = typeof body.category === 'string' ? body.category.trim().toLowerCase() : '';
      if (!category) {
        errors.category = 'category is required';
      } else {
        value.category = category.slice(0, 64);
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'cadence') || mode === 'create') {
      const cadence = typeof body.cadence === 'string' ? body.cadence.trim() : '';
      if (!cadence) {
        errors.cadence = 'cadence is required';
      } else {
        try {
          const parsed = parseScheduleCadence(cadence);
          value.cadence = parsed.expression;
          value.cadenceKind = parsed.kind;
        } catch (error) {
          errors.cadence = error instanceof Error ? error.message : 'schedule_expression_invalid';
        }
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'enabled')) {
      value.enabled = body.enabled !== false;
    }

    if (Object.prototype.hasOwnProperty.call(body, 'targetAgentId') || mode === 'create') {
      const targetAgentId = typeof body.targetAgentId === 'string' ? body.targetAgentId.trim() : '';
      if (!targetAgentId) {
        errors.targetAgentId = 'targetAgentId is required';
      } else if (!getAgentProfileById(targetAgentId)) {
        errors.targetAgentId = 'targetAgentId does not match a known agent profile';
      } else {
        value.targetAgentId = targetAgentId;
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'requestingSessionId')) {
      const requestingSessionId =
        typeof body.requestingSessionId === 'string' && body.requestingSessionId.trim().length > 0
          ? body.requestingSessionId.trim()
          : null;
      if (requestingSessionId && !database.getSessionById(requestingSessionId)) {
        errors.requestingSessionId = 'requestingSessionId was not found';
      } else {
        value.requestingSessionId = requestingSessionId;
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'deliveryTargetSessionId')) {
      const deliveryTargetSessionId =
        typeof body.deliveryTargetSessionId === 'string' && body.deliveryTargetSessionId.trim().length > 0
          ? body.deliveryTargetSessionId.trim()
          : null;
      if (deliveryTargetSessionId && !database.getSessionById(deliveryTargetSessionId)) {
        errors.deliveryTargetSessionId = 'deliveryTargetSessionId was not found';
      } else {
        value.deliveryTargetSessionId = deliveryTargetSessionId;
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'sessionTarget') || mode === 'create') {
      const sessionTarget = parseScheduleSessionTargetInput(body.sessionTarget ?? existing?.sessionTarget ?? 'dedicated_schedule_session');
      if (!sessionTarget) {
        errors.sessionTarget = 'sessionTarget must be origin_session|dedicated_schedule_session|explicit_session';
      } else {
        value.sessionTarget = sessionTarget;
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'deliveryTarget') || mode === 'create') {
      const deliveryTarget = parseScheduleDeliveryTargetInput(body.deliveryTarget ?? existing?.deliveryTarget ?? 'origin_session');
      if (!deliveryTarget) {
        errors.deliveryTarget = 'deliveryTarget must be origin_session|dedicated_schedule_session|artifact_only|silent_on_heartbeat';
      } else {
        value.deliveryTarget = deliveryTarget;
      }
    }

    const metadataCandidate = isRecord(body.metadata) ? body.metadata : existingMetadata;

    if (Object.prototype.hasOwnProperty.call(body, 'prompt') || mode === 'create') {
      const prompt = typeof body.prompt === 'string' ? body.prompt.trim() : '';
      const effectiveJobMode =
        typeof body.jobMode === 'string' && body.jobMode.trim().length > 0
          ? body.jobMode.trim()
          : existing?.jobMode ?? null;
      const metadataBrowserRequest = isRecord(metadataCandidate.browserRequest) ? metadataCandidate.browserRequest : null;
      const metadataWorkflow = isRecord(metadataCandidate.workflow) ? metadataCandidate.workflow : {};
      const workflowTemplateId = parseWorkflowTemplateId(metadataWorkflow.templateId);
      const browserCaptureUrl =
        metadataBrowserRequest && typeof metadataBrowserRequest.url === 'string' && metadataBrowserRequest.url.trim().length > 0
          ? metadataBrowserRequest.url.trim()
          : null;
      if (!prompt && effectiveJobMode === BROWSER_SCHEDULE_JOB_MODE && browserCaptureUrl) {
        value.prompt = buildBrowserSchedulePrompt({
          url: browserCaptureUrl,
          intent: 'monitor',
          extractionMode: 'markdown',
          dynamicLikely: true
        });
      } else if (!prompt && effectiveJobMode === WORKFLOW_SCHEDULE_JOB_MODE) {
        const workflowPrompt = buildWorkflowSchedulePrompt({
          templateId: workflowTemplateId,
          focus: typeof metadataWorkflow.focus === 'string' ? metadataWorkflow.focus : null,
          browserRequest: isRecord(metadataWorkflow.browserRequest) ? metadataWorkflow.browserRequest : null
        });
        if (workflowPrompt) {
          value.prompt = workflowPrompt;
        } else {
          errors.prompt = 'prompt is required';
        }
      } else if (!prompt) {
        errors.prompt = 'prompt is required';
      } else {
        value.prompt = prompt;
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'runtime')) {
      const runtime = typeof body.runtime === 'string' ? body.runtime.trim() : '';
      if (!runtime) {
        value.runtime = null;
      } else if (!isKnownRuntime(runtime)) {
        errors.runtime = 'runtime must be codex|claude|gemini|process';
      } else {
        value.runtime = runtime;
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'model')) {
      value.model = normalizeModelInput(typeof body.model === 'string' ? body.model : '') ?? null;
    }

    if (Object.prototype.hasOwnProperty.call(body, 'jobMode')) {
      value.jobMode = typeof body.jobMode === 'string' && body.jobMode.trim().length > 0 ? body.jobMode.trim() : null;
    }

    if (Object.prototype.hasOwnProperty.call(body, 'approvalProfile')) {
      value.approvalProfile =
        typeof body.approvalProfile === 'string' && body.approvalProfile.trim().length > 0 ? body.approvalProfile.trim() : null;
    }

    if (Object.prototype.hasOwnProperty.call(body, 'concurrencyPolicy') || mode === 'create') {
      const concurrencyPolicy = parseScheduleConcurrencyPolicyInput(body.concurrencyPolicy ?? existing?.concurrencyPolicy ?? 'skip');
      if (!concurrencyPolicy) {
        errors.concurrencyPolicy = 'concurrencyPolicy must be skip|queue|replace';
      } else {
        value.concurrencyPolicy = concurrencyPolicy;
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'metadata') && !isRecord(body.metadata)) {
      errors.metadata = 'metadata must be an object';
    } else if (isRecord(body.metadata)) {
      value.metadata = body.metadata;
    }

    const effectiveJobMode = value.jobMode ?? existing?.jobMode ?? null;
    if (effectiveJobMode === BROWSER_SCHEDULE_JOB_MODE) {
      const browserRequest = isRecord(metadataCandidate.browserRequest) ? metadataCandidate.browserRequest : null;
      const browserUrl =
        browserRequest && typeof browserRequest.url === 'string' && browserRequest.url.trim().length > 0
          ? browserRequest.url.trim()
          : null;
      if (!browserUrl) {
        errors.metadata = 'metadata.browserRequest.url is required when jobMode=browser_capture';
      } else {
        value.runtime = 'process';
        value.model = null;
      }
    } else if (effectiveJobMode === WORKFLOW_SCHEDULE_JOB_MODE) {
      const workflow = isRecord(metadataCandidate.workflow) ? metadataCandidate.workflow : null;
      const workflowTemplateId = parseWorkflowTemplateId(workflow?.templateId);
      if (!workflowTemplateId) {
        errors.metadata = 'metadata.workflow.templateId is required when jobMode=workflow';
      } else if (workflowTemplateUsesBrowser(workflowTemplateId)) {
        const browserRequest = workflow && isRecord(workflow.browserRequest) ? workflow.browserRequest : null;
        const browserUrl =
          browserRequest && typeof browserRequest.url === 'string' && browserRequest.url.trim().length > 0
            ? browserRequest.url.trim()
            : null;
        if (!browserUrl) {
          errors.metadata = 'metadata.workflow.browserRequest.url is required for browser-backed workflow schedules';
        } else {
          value.runtime = 'process';
          value.model = null;
        }
      }
    }

    if (Object.prototype.hasOwnProperty.call(body, 'domainPolicy') && !isRecord(body.domainPolicy)) {
      errors.domainPolicy = 'domainPolicy must be an object';
    } else if (isRecord(body.domainPolicy)) {
      value.domainPolicy = body.domainPolicy;
    }

    if (Object.prototype.hasOwnProperty.call(body, 'rateLimitPolicy') && !isRecord(body.rateLimitPolicy)) {
      errors.rateLimitPolicy = 'rateLimitPolicy must be an object';
    } else if (isRecord(body.rateLimitPolicy)) {
      value.rateLimitPolicy = body.rateLimitPolicy;
    }

    if (Object.prototype.hasOwnProperty.call(body, 'requestedBy')) {
      value.requestedBy = typeof body.requestedBy === 'string' && body.requestedBy.trim().length > 0 ? body.requestedBy.trim() : null;
    }

    if (Object.prototype.hasOwnProperty.call(body, 'originRef') && !isRecord(body.originRef)) {
      errors.originRef = 'originRef must be an object';
    } else if (isRecord(body.originRef)) {
      value.originRef = body.originRef;
    }

    if (
      value.sessionTarget === 'explicit_session' &&
      !(value.deliveryTargetSessionId ?? existing?.deliveryTargetSessionId ?? null)
    ) {
      errors.deliveryTargetSessionId = 'deliveryTargetSessionId is required when sessionTarget=explicit_session';
    }

    return {
      errors,
      value
    };
  };

  const createScheduleFromValidatedInput = (input: {
    actor: string;
    id?: string | null;
    value: ReturnType<typeof validateScheduleInput>['value'];
    metadata?: Record<string, unknown>;
  }): ScheduleRecord => {
    const nextRunAt = computeNextRunFromCadence(input.value.cadence!);
    return database.upsertScheduleJob({
      id:
        typeof input.id === 'string' && input.id.trim().length > 0
          ? input.id.trim()
          : `schedule:${input.value.category}:${Date.now().toString(36)}`,
      label: input.value.label!,
      category: input.value.category!,
      kind: 'targeted',
      cadenceKind: input.value.cadenceKind!,
      cadence: input.value.cadence!,
      enabled: input.value.enabled ?? true,
      pausedAt: null,
      pausedBy: null,
      requestedBy: input.value.requestedBy ?? input.actor,
      requestingSessionId: input.value.requestingSessionId ?? null,
      originRef: input.value.originRef ?? {},
      targetAgentId: input.value.targetAgentId!,
      sessionTarget: input.value.sessionTarget ?? 'dedicated_schedule_session',
      deliveryTarget: input.value.deliveryTarget ?? 'origin_session',
      deliveryTargetSessionId: input.value.deliveryTargetSessionId ?? null,
      prompt: input.value.prompt ?? null,
      runtime: input.value.runtime ?? null,
      model: input.value.model ?? null,
      jobMode: input.value.jobMode ?? null,
      approvalProfile: input.value.approvalProfile ?? null,
      concurrencyPolicy: input.value.concurrencyPolicy ?? 'skip',
      domainPolicy: input.value.domainPolicy ?? {},
      rateLimitPolicy: input.value.rateLimitPolicy ?? {},
      metadata: {
        ...(input.value.metadata ?? {}),
        ...(input.metadata ?? {}),
        createdBy: input.actor
      },
      nextRunAt
    });
  };

  const validateScheduleRequestContract = (
    body: Record<string, unknown>
  ):
    | {
        ok: true;
        actor: string;
        requesterAgentId: string;
        requesterSession: SessionRecord | null;
        payload: ReturnType<typeof validateScheduleInput>['value'];
        scheduleId: string | null;
      }
    | {
        ok: false;
        statusCode: number;
        error: string;
        details?: Record<string, unknown>;
      } => {
    const schema = typeof body.schema === 'string' ? body.schema.trim() : '';
    if (schema && schema !== 'ops.schedule-request.v1') {
      return {
        ok: false,
        statusCode: 400,
        error: 'Invalid schedule request schema',
        details: {
          schema
        }
      };
    }
    const requester = isRecord(body.requester) ? body.requester : {};
    const schedule = isRecord(body.schedule) ? body.schedule : {};
    const requesterAgentId =
      typeof requester.agentId === 'string' && requester.agentId.trim().length > 0 ? requester.agentId.trim() : '';
    if (!requesterAgentId) {
      return {
        ok: false,
        statusCode: 400,
        error: 'requester.agentId is required'
      };
    }
    const requesterProfile = getAgentProfileById(requesterAgentId);
    if (!requesterProfile) {
      return {
        ok: false,
        statusCode: 404,
        error: `Requester agent profile not found: ${requesterAgentId}`
      };
    }
    if (!requesterProfile.enabled) {
      return {
        ok: false,
        statusCode: 403,
        error: `Requester agent profile ${requesterProfile.name} is disabled`
      };
    }
    const requesterSessionId =
      typeof requester.sessionId === 'string' && requester.sessionId.trim().length > 0 ? requester.sessionId.trim() : '';
    const requesterSession = requesterSessionId ? database.getSessionById(requesterSessionId) ?? null : null;
    if (requesterSessionId && !requesterSession) {
      return {
        ok: false,
        statusCode: 404,
        error: `Requester session not found: ${requesterSessionId}`
      };
    }
    if (requesterSession && requesterSession.agentId !== requesterAgentId) {
      return {
        ok: false,
        statusCode: 409,
        error: 'Requester session does not belong to requester.agentId',
        details: {
          requesterAgentId,
          sessionAgentId: requesterSession.agentId
        }
      };
    }
    const requesterScheduleKey = `agent:${requesterAgentId}`;
    const activeSchedules = database.listScheduleJobs({
      kinds: ['targeted'],
      requestedBy: requesterScheduleKey,
      limit: 500
    });
    const nonPausedSchedules = activeSchedules.filter((entry) => entry.enabled && !entry.pausedAt);
    if (nonPausedSchedules.length >= 24) {
      return {
        ok: false,
        statusCode: 429,
        error: 'Requester schedule quota exceeded',
        details: {
          requesterAgentId,
          activeSchedules: nonPausedSchedules.length
        }
      };
    }
    const targetAgentId =
      typeof schedule.targetAgentId === 'string' && schedule.targetAgentId.trim().length > 0
        ? schedule.targetAgentId.trim()
        : requesterAgentId;
    const deliveryTargetSessionId =
      typeof schedule.deliveryTargetSessionId === 'string' && schedule.deliveryTargetSessionId.trim().length > 0
        ? schedule.deliveryTargetSessionId.trim()
        : requesterSession?.id ?? null;
    const normalizedScheduleBody: Record<string, unknown> = {
      ...schedule,
      targetAgentId,
      requestedBy: requesterScheduleKey,
      requestingSessionId: requesterSession?.id ?? null,
      deliveryTargetSessionId,
      sessionTarget: schedule.sessionTarget ?? (requesterSession ? 'origin_session' : 'dedicated_schedule_session'),
      deliveryTarget: schedule.deliveryTarget ?? (requesterSession ? 'origin_session' : 'dedicated_schedule_session'),
      originRef:
        isRecord(schedule.originRef)
          ? schedule.originRef
          : isRecord(requester.originRef)
            ? requester.originRef
            : {
                source: 'schedule_request',
                requesterAgentId,
                requestingSessionId: requesterSession?.id ?? null
              }
    };
    const validation = validateScheduleInput(normalizedScheduleBody, 'create');
    if (Object.keys(validation.errors).length > 0) {
      return {
        ok: false,
        statusCode: 400,
        error: 'Invalid schedule request payload',
        details: {
          fields: validation.errors
        }
      };
    }
    const duplicate = nonPausedSchedules.find((entry) => {
      const samePrompt = (entry.prompt ?? '').trim() === (validation.value.prompt ?? '').trim();
      return (
        entry.label.trim().toLowerCase() === (validation.value.label ?? '').trim().toLowerCase() &&
        entry.category.trim().toLowerCase() === (validation.value.category ?? '').trim().toLowerCase() &&
        entry.cadence.trim().toLowerCase() === (validation.value.cadence ?? '').trim().toLowerCase() &&
        entry.targetAgentId === validation.value.targetAgentId &&
        entry.requestingSessionId === (validation.value.requestingSessionId ?? null) &&
        samePrompt
      );
    });
    if (duplicate) {
      return {
        ok: false,
        statusCode: 409,
        error: 'An equivalent active schedule already exists for this requester',
        details: {
          schedule: scheduleView(duplicate)
        }
      };
    }
    return {
      ok: true,
      actor: String(body.actor ?? requesterScheduleKey).trim() || requesterScheduleKey,
      requesterAgentId,
      requesterSession,
      payload: validation.value,
      scheduleId: typeof schedule.id === 'string' && schedule.id.trim().length > 0 ? schedule.id.trim() : null
    };
  };

  app.get('/api/schedules', async (request, reply) => {
    syncBuiltinSchedules();
    const query = request.query as Record<string, unknown>;
    const kind: ScheduleRecord['kind'][] | undefined =
      typeof query.kind === 'string' && (query.kind === 'builtin' || query.kind === 'targeted')
        ? [query.kind]
        : undefined;
    const schedules = database.listScheduleJobs({
      kinds: kind,
      enabled: typeof query.enabled === 'string' ? query.enabled === 'true' : undefined,
      requestedBy: typeof query.requestedBy === 'string' ? query.requestedBy : undefined,
      targetAgentId: typeof query.targetAgentId === 'string' ? query.targetAgentId : undefined,
      limit: Number.isFinite(Number(query.limit)) ? Math.max(1, Math.min(1000, Number(query.limit))) : 500
    });
    return jsonOk(reply, {
      schedules: schedules.map((schedule) => scheduleView(schedule))
    });
  });

  app.get('/api/schedules/:scheduleId', async (request, reply) => {
    syncBuiltinSchedules();
    const params = request.params as { scheduleId: string };
    const schedule = database.getScheduleJobById(params.scheduleId);
    if (!schedule) {
      return jsonError(reply, 'Schedule not found', 404);
    }
    return jsonOk(reply, {
      schedule: scheduleView(schedule),
      history: database.listScheduleRunHistory({
        scheduleId: schedule.id,
        limit: 60
      }).map((entry) => scheduleHistoryView(entry))
    });
  });

  app.get('/api/schedules/:scheduleId/history', async (request, reply) => {
    const params = request.params as { scheduleId: string };
    const schedule = database.getScheduleJobById(params.scheduleId);
    if (!schedule) {
      return jsonError(reply, 'Schedule not found', 404);
    }
    return jsonOk(reply, {
      history: database.listScheduleRunHistory({
        scheduleId: schedule.id,
        limit: 200
      }).map((entry) => scheduleHistoryView(entry))
    });
  });

  app.post('/api/schedules', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const validation = validateScheduleInput(body, 'create');
    if (Object.keys(validation.errors).length > 0) {
      return jsonError(reply, 'Invalid schedule payload', 400, {
        fields: validation.errors
      });
    }
    const schedule = createScheduleFromValidatedInput({
      actor,
      id: typeof body.id === 'string' ? body.id : null,
      value: validation.value
    });
    database.appendAudit({
      actor,
      action: 'schedule.create',
      resource: schedule.id,
      decision: 'allowed',
      reason: 'operator_request',
      details: scheduleView(schedule),
      correlationId: randomUUID()
    });
    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: schedule.requestingSessionId,
      runId: null,
      level: 'info',
      message: 'Schedule created',
      data: {
        scheduleId: schedule.id,
        targetAgentId: schedule.targetAgentId
      }
    });
    return jsonOk(
      reply,
      {
        schedule: scheduleView(schedule)
      },
      201
    );
  });

  app.patch('/api/schedules/:scheduleId', async (request, reply) => {
    const params = request.params as { scheduleId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const schedule = database.getScheduleJobById(params.scheduleId);
    if (!schedule) {
      return jsonError(reply, 'Schedule not found', 404);
    }
    if (schedule.kind === 'builtin' && (Object.prototype.hasOwnProperty.call(body, 'cadence') || Object.prototype.hasOwnProperty.call(body, 'targetAgentId') || Object.prototype.hasOwnProperty.call(body, 'prompt'))) {
      return jsonError(reply, 'Built-in schedules only support enable/pause metadata edits.', 409, {
        reason: 'builtin_schedule_mutation_restricted'
      });
    }
    const validation = validateScheduleInput(body, 'update', schedule);
    if (Object.keys(validation.errors).length > 0) {
      return jsonError(reply, 'Invalid schedule payload', 400, {
        fields: validation.errors
      });
    }
    const updated = database.updateScheduleJob(schedule.id, {
      label: validation.value.label,
      category: validation.value.category,
      cadenceKind: validation.value.cadenceKind,
      cadence: validation.value.cadence,
      enabled: validation.value.enabled,
      requestedBy: validation.value.requestedBy,
      requestingSessionId: validation.value.requestingSessionId,
      originRef: validation.value.originRef,
      targetAgentId: validation.value.targetAgentId,
      sessionTarget: validation.value.sessionTarget,
      deliveryTarget: validation.value.deliveryTarget,
      deliveryTargetSessionId: validation.value.deliveryTargetSessionId,
      prompt: validation.value.prompt,
      runtime: validation.value.runtime,
      model: validation.value.model,
      jobMode: validation.value.jobMode,
      approvalProfile: validation.value.approvalProfile,
      concurrencyPolicy: validation.value.concurrencyPolicy,
      domainPolicy: validation.value.domainPolicy,
      rateLimitPolicy: validation.value.rateLimitPolicy,
      metadata:
        validation.value.metadata !== undefined
          ? {
              ...scheduleRecordJson(schedule.metadataJson),
              ...validation.value.metadata,
              updatedBy: actor
            }
          : undefined,
      nextRunAt:
        validation.value.cadence !== undefined ? computeNextRunFromCadence(validation.value.cadence, schedule.lastRunAt) : undefined
    });
    if (updated.kind === 'builtin') {
      syncBuiltinScheduleRecord(updated.id);
    }
    database.appendAudit({
      actor,
      action: 'schedule.update',
      resource: updated.id,
      decision: 'allowed',
      reason: 'operator_request',
      details: scheduleView(updated),
      correlationId: randomUUID()
    });
    return jsonOk(reply, {
      schedule: scheduleView(database.getScheduleJobById(updated.id) ?? updated)
    });
  });

  app.delete('/api/schedules/:scheduleId', async (request, reply) => {
    const params = request.params as { scheduleId: string };
    const query = (request.query ?? {}) as Record<string, unknown>;
    const actor = typeof query.actor === 'string' && query.actor.trim().length > 0 ? query.actor.trim() : 'operator';
    const schedule = database.getScheduleJobById(params.scheduleId);
    if (!schedule) {
      return jsonError(reply, 'Schedule not found', 404);
    }
    if (schedule.kind === 'builtin') {
      return jsonError(reply, 'Built-in schedules cannot be deleted.', 409, {
        reason: 'builtin_schedule_delete_restricted'
      });
    }
    const deleted = database.deleteScheduleJob(schedule.id);
    if (!deleted) {
      return jsonError(reply, 'Schedule not found', 404);
    }
    database.appendAudit({
      actor,
      action: 'schedule.delete',
      resource: schedule.id,
      decision: 'allowed',
      reason: 'operator_request',
      details: scheduleView(schedule),
      correlationId: randomUUID()
    });
    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: schedule.requestingSessionId,
      runId: null,
      level: 'info',
      message: 'Schedule deleted',
      data: {
        scheduleId: schedule.id,
        targetAgentId: schedule.targetAgentId
      }
    });
    return jsonOk(reply, {
      deleted: true
    });
  });

  app.post('/api/schedules/request', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const validation = validateScheduleRequestContract(body);
    if (!validation.ok) {
      return jsonError(reply, validation.error, validation.statusCode, validation.details);
    }
    const schedule = createScheduleFromValidatedInput({
      actor: validation.actor,
      id: validation.scheduleId,
      value: validation.payload,
      metadata: {
        createdVia: 'schedule_request',
        requesterAgentId: validation.requesterAgentId,
        requesterSessionId: validation.requesterSession?.id ?? null
      }
    });
    database.appendAudit({
      actor: validation.actor,
      action: 'schedule.request',
      resource: schedule.id,
      decision: 'allowed',
      reason: 'typed_schedule_request',
      details: {
        requesterAgentId: validation.requesterAgentId,
        requesterSessionId: validation.requesterSession?.id ?? null,
        schedule: scheduleView(schedule)
      },
      correlationId: randomUUID()
    });
    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: schedule.requestingSessionId,
      runId: null,
      level: 'info',
      message: 'Schedule created from typed request contract',
      data: {
        scheduleId: schedule.id,
        requesterAgentId: validation.requesterAgentId,
        targetAgentId: schedule.targetAgentId
      }
    });
    return jsonOk(
      reply,
      {
        request: {
          schema: 'ops.schedule-request.v1',
          version: 1,
          requester: {
            agentId: validation.requesterAgentId,
            sessionId: validation.requesterSession?.id ?? null
          },
          schedule: {
            id: schedule.id
          }
        },
        schedule: scheduleView(schedule)
      },
      201
    );
  });

  app.post('/api/schedules/:scheduleId/pause', async (request, reply) => {
    const params = request.params as { scheduleId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const schedule = database.getScheduleJobById(params.scheduleId);
    if (!schedule) {
      return jsonError(reply, 'Schedule not found', 404);
    }
    const updated = pauseScheduleRecord(schedule.id, actor);
    database.appendAudit({
      actor,
      action: 'schedule.pause',
      resource: updated.id,
      decision: 'allowed',
      reason: 'operator_request',
      details: scheduleView(updated),
      correlationId: randomUUID()
    });
    return jsonOk(reply, {
      schedule: scheduleView(updated)
    });
  });

  app.post('/api/schedules/:scheduleId/resume', async (request, reply) => {
    const params = request.params as { scheduleId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const schedule = database.getScheduleJobById(params.scheduleId);
    if (!schedule) {
      return jsonError(reply, 'Schedule not found', 404);
    }
    const updated = resumeScheduleRecord(schedule.id);
    if (updated.kind === 'builtin') {
      if (updated.id === 'housekeeping') {
        startHousekeeping();
      } else if (updated.id === 'cron_session_reaper') {
        startCronSessionReaper();
      } else if (updated.id === 'self_improvement_cycle') {
        startSelfImprovementScheduler();
      } else {
        startLocalRuntimeScanners();
      }
      syncBuiltinScheduleRecord(updated.id);
    }
    database.appendAudit({
      actor,
      action: 'schedule.resume',
      resource: updated.id,
      decision: 'allowed',
      reason: 'operator_request',
      details: scheduleView(database.getScheduleJobById(updated.id) ?? updated),
      correlationId: randomUUID()
    });
    return jsonOk(reply, {
      schedule: scheduleView(database.getScheduleJobById(updated.id) ?? updated)
    });
  });

  app.post('/api/schedules/:scheduleId/run', async (request, reply) => {
    const params = request.params as { scheduleId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const schedule = database.getScheduleJobById(params.scheduleId);
    if (!schedule) {
      return jsonError(reply, 'Schedule not found', 404);
    }

    if (schedule.kind === 'builtin') {
      const now = utcNow();
      const appendHistory = (status: ScheduleRunHistoryRecord['status'], summary: string, details?: Record<string, unknown>) =>
        database.appendScheduleRunHistory({
          scheduleId: schedule.id,
          trigger: 'manual',
          status,
          requestedBy: actor,
          deliveryTarget: schedule.deliveryTarget,
          summary,
          details
        });
      try {
        if (schedule.id === 'housekeeping') {
          const result = await runHousekeeping(actor, 'manual');
          const summary = isHousekeepingSkippedResult(result)
            ? `Housekeeping skipped (${result.reason}).`
            : `Housekeeping pruned ${result.deletedRecords} records.`;
          const history = appendHistory(
            isHousekeepingSkippedResult(result) ? 'skipped' : 'completed',
            summary,
            result as unknown as Record<string, unknown>
          );
          const updated = syncBuiltinScheduleRecord(schedule.id) ?? database.getScheduleJobById(schedule.id);
          return jsonOk(reply, {
            schedule: updated ? scheduleView(updated) : null,
            history: history ? scheduleHistoryView(history) : null
          });
        }
        if (schedule.id === 'cron_session_reaper') {
          const result = await runCronSessionReaper('manual');
          const history = appendHistory(
            'completed',
            `Cron reaper pruned ${result.totals.sessions} sessions.`,
            result as unknown as Record<string, unknown>
          );
          const updated = syncBuiltinScheduleRecord(schedule.id) ?? database.getScheduleJobById(schedule.id);
          return jsonOk(reply, {
            schedule: updated ? scheduleView(updated) : null,
            history: scheduleHistoryView(history)
          });
        }
        if (schedule.id === 'self_improvement_cycle') {
          const result = runSelfImprovementCycle('manual');
          const history = appendHistory(
            'completed',
            `Self-improvement reviewed ${result.reviewedAgents} agents and created ${result.created.length} proposals.`,
            result as unknown as Record<string, unknown>
          );
          const updated = syncBuiltinScheduleRecord(schedule.id) ?? database.getScheduleJobById(schedule.id);
          return jsonOk(reply, {
            schedule: updated ? scheduleView(updated) : null,
            history: scheduleHistoryView(history)
          });
        }
        const runtime = localRuntimeFromScheduleId(schedule.id);
        if (runtime) {
          const result = await runLocalRuntimeScan(runtime, 'manual');
          const history = appendHistory(
            'completed',
            `Local runtime scan (${runtime}) updated ${result.updatedSessions} sessions.`,
            result as unknown as Record<string, unknown>
          );
          const updated = syncBuiltinScheduleRecord(schedule.id) ?? database.getScheduleJobById(schedule.id);
          return jsonOk(reply, {
            schedule: updated ? scheduleView(updated) : null,
            history: scheduleHistoryView(history)
          });
        }
        return jsonError(reply, 'Built-in schedule runner is not implemented for this id', 501);
      } catch (error) {
        const history = appendHistory('failed', 'Built-in schedule execution failed.', {
          error: error instanceof Error ? error.message : String(error),
          at: now
        });
        syncBuiltinScheduleRecord(schedule.id);
        return jsonError(reply, error instanceof Error ? error.message : String(error), 500, {
          history: scheduleHistoryView(history)
        });
      }
    }

    const queued = await queueTargetedScheduleRun({
      schedule,
      trigger: 'manual',
      actor
    });
    if (!queued.queued) {
      return jsonError(reply, queued.error, 409, {
        schedule: scheduleView(queued.schedule),
        history: scheduleHistoryView(queued.history)
      });
    }
    return jsonOk(reply, {
      schedule: scheduleView(queued.schedule),
      history: scheduleHistoryView(queued.history),
      run: queued.run
    });
  });

