  app.get('/api/local/sessions', async (request, reply) => {
    const query = request.query as Record<string, unknown>;
    const runtime = parseLocalRuntimeFilter(query.runtime);
    if (!runtime) {
      return jsonError(reply, 'Invalid runtime filter. Expected codex|claude|gemini|all.', 400);
    }
    const limit = Math.max(1, Math.min(2000, Number(query.limit ?? 500)));
    const sessions = database.listLocalRuntimeSessions({
      limit,
      runtime
    });
    const gatewaySessions = database.listSessions({ limit: 2000, offset: 0 }).rows;
    const matchedGatewaySession = (localSession: LocalRuntimeSessionRecord): SessionRecord | null => {
      for (const session of gatewaySessions) {
        const metadata = parseJsonSafe<Record<string, unknown>>(session.metadataJson, {});
        const metadataRuntime = typeof metadata.localRuntime === 'string' ? metadata.localRuntime.trim().toLowerCase() : '';
        if (metadataRuntime.length > 0 && metadataRuntime !== localSession.runtime) {
          continue;
        }
        const metadataProjectSlug =
          typeof metadata.projectSlug === 'string' ? metadata.projectSlug.trim().toLowerCase() : '';
        const localSlug = localSession.projectSlug.trim().toLowerCase();
        if (metadataProjectSlug && metadataProjectSlug === localSlug) {
          return session;
        }
        const localIdFromMetadata =
          typeof metadata.localRuntimeSessionId === 'string'
            ? metadata.localRuntimeSessionId
            : typeof metadata.localSessionId === 'string'
              ? metadata.localSessionId
              : typeof metadata.localClaudeSessionId === 'string'
                ? metadata.localClaudeSessionId
                : '';
        if (localIdFromMetadata && localIdFromMetadata === localSession.id) {
          return session;
        }
        if (localSlug && session.sessionKey.toLowerCase().includes(localSlug)) {
          return session;
        }
      }
      return null;
    };
    return jsonOk(reply, {
      sessions: sessions.map((entry) => {
        const gatewaySession = matchedGatewaySession(entry);
        return {
          ...entry,
          details: parseJsonSafe<Record<string, unknown>>(entry.detailsJson, {}),
          gatewaySession: gatewaySession
            ? {
                id: gatewaySession.id,
                sessionKey: gatewaySession.sessionKey,
                channel: gatewaySession.channel,
                state: gatewaySession.state
              }
            : null
        };
      }),
      runtime,
      scanner: {
        runtimes: Object.fromEntries(
          LOCAL_RUNTIME_SCANNERS.map((item) => [
            item,
            {
              root: localRuntimeRoots[item],
              intervalMs: localRuntimeScanIntervalMs[item],
              activeThresholdMs: localRuntimeActiveThresholdMs[item],
              inFlight: localRuntimeScanInFlight[item],
              lastScanAt: localRuntimeLastScanAt[item],
              lastScanError: localRuntimeLastScanError[item],
              lastScanSummary: localRuntimeLastScanSummary[item]
            }
          ])
        )
      }
    });
  });

