  app.get('/api/local/stats', async (request, reply) => {
    const query = request.query as Record<string, unknown>;
    const runtime = parseLocalRuntimeFilter(query.runtime);
    if (!runtime) {
      return jsonError(reply, 'Invalid runtime filter. Expected codex|claude|gemini|all.', 400);
    }
    const sessions = database.listLocalRuntimeSessions({
      limit: 2000,
      runtime
    });
    const nowMs = Date.now();
    const dayCutoff = nowMs - 24 * 60 * 60 * 1000;
    const weekCutoff = nowMs - 7 * 24 * 60 * 60 * 1000;
    const monthCutoff = nowMs - 30 * 24 * 60 * 60 * 1000;

    let costToday = 0;
    let costThisWeek = 0;
    let costThisMonth = 0;
    const tokensByModel = new Map<string, number>();
    const byRuntimeAccumulator: Record<
      LocalRuntimeSessionKind,
      {
        costToday: number;
        costThisWeek: number;
        costThisMonth: number;
        activeSessions: number;
        totalSessions: number;
        totalTokens: number;
        tokensByModel: Map<string, number>;
      }
    > = {
      codex: {
        costToday: 0,
        costThisWeek: 0,
        costThisMonth: 0,
        activeSessions: 0,
        totalSessions: 0,
        totalTokens: 0,
        tokensByModel: new Map<string, number>()
      },
      claude: {
        costToday: 0,
        costThisWeek: 0,
        costThisMonth: 0,
        activeSessions: 0,
        totalSessions: 0,
        totalTokens: 0,
        tokensByModel: new Map<string, number>()
      },
      gemini: {
        costToday: 0,
        costThisWeek: 0,
        costThisMonth: 0,
        activeSessions: 0,
        totalSessions: 0,
        totalTokens: 0,
        tokensByModel: new Map<string, number>()
      }
    };
    const projectCounts = new Map<string, number>();
    for (const session of sessions) {
      const runtimeBucket = byRuntimeAccumulator[session.runtime];
      runtimeBucket.totalSessions += 1;
      if (session.active) {
        runtimeBucket.activeSessions += 1;
      }
      const ts = Date.parse(session.lastMessageAt);
      if (!Number.isFinite(ts)) {
        const tokenTotal =
          session.inputTokens + session.outputTokens + session.cacheReadInputTokens + session.cacheCreationInputTokens;
        runtimeBucket.totalTokens += tokenTotal;
        runtimeBucket.tokensByModel.set(session.model, (runtimeBucket.tokensByModel.get(session.model) ?? 0) + tokenTotal);
        tokensByModel.set(session.model, (tokensByModel.get(session.model) ?? 0) + tokenTotal);
        projectCounts.set(session.projectSlug, (projectCounts.get(session.projectSlug) ?? 0) + 1);
        continue;
      }
      if (ts >= monthCutoff) {
        costThisMonth += session.estimatedCostUsd;
        runtimeBucket.costThisMonth += session.estimatedCostUsd;
      }
      if (ts >= weekCutoff) {
        costThisWeek += session.estimatedCostUsd;
        runtimeBucket.costThisWeek += session.estimatedCostUsd;
      }
      if (ts >= dayCutoff) {
        costToday += session.estimatedCostUsd;
        runtimeBucket.costToday += session.estimatedCostUsd;
      }
      const tokenTotal =
        session.inputTokens + session.outputTokens + session.cacheReadInputTokens + session.cacheCreationInputTokens;
      runtimeBucket.totalTokens += tokenTotal;
      runtimeBucket.tokensByModel.set(session.model, (runtimeBucket.tokensByModel.get(session.model) ?? 0) + tokenTotal);
      tokensByModel.set(session.model, (tokensByModel.get(session.model) ?? 0) + tokenTotal);
      projectCounts.set(session.projectSlug, (projectCounts.get(session.projectSlug) ?? 0) + 1);
    }
    const topProjects = Array.from(projectCounts.entries())
      .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0]))
      .slice(0, 10)
      .map(([projectSlug, count]) => ({
        projectSlug,
        count
      }));
    const byRuntime = Object.fromEntries(
      LOCAL_RUNTIME_SCANNERS.map((item) => {
        const entry = byRuntimeAccumulator[item];
        return [
          item,
          {
            costToday: Number(entry.costToday.toFixed(6)),
            costThisWeek: Number(entry.costThisWeek.toFixed(6)),
            costThisMonth: Number(entry.costThisMonth.toFixed(6)),
            activeSessions: entry.activeSessions,
            totalSessions: entry.totalSessions,
            totalTokens: entry.totalTokens,
            tokensByModel: Object.fromEntries(entry.tokensByModel)
          }
        ];
      })
    ) as Record<
      LocalRuntimeSessionKind,
      {
        costToday: number;
        costThisWeek: number;
        costThisMonth: number;
        activeSessions: number;
        totalSessions: number;
        totalTokens: number;
        tokensByModel: Record<string, number>;
      }
    >;
    return jsonOk(reply, {
      stats: {
        runtime,
        costToday: Number(costToday.toFixed(6)),
        costThisWeek: Number(costThisWeek.toFixed(6)),
        costThisMonth: Number(costThisMonth.toFixed(6)),
        tokensByModel: Object.fromEntries(tokensByModel),
        topProjects,
        byRuntime,
        activeSessions: sessions.filter((entry) => entry.active).length,
        totalSessions: sessions.length
      }
    });
  });

