  app.post('/api/improvement/proposals/:proposalId/approve', async (request, reply) => {
    const params = request.params as { proposalId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const operatorNotes = typeof body.notes === 'string' ? body.notes : null;
    const proposal = database
      .listImprovementProposals({
        limit: 2000
      })
      .find((entry) => entry.id === params.proposalId);
    if (!proposal) {
      return jsonError(reply, 'Proposal not found', 404);
    }
    if (proposal.status !== 'pending') {
      return jsonError(reply, 'Proposal is not pending', 409, {
        status: proposal.status
      });
    }
    const profile = database.getAgentProfileById(proposal.agentId);
    if (!profile) {
      return jsonError(reply, 'Agent not found', 404);
    }
    const proposedChanges = parseJsonSafe<Array<Record<string, unknown>>>(proposal.proposedChangesJson, [])
      .map((change) => (typeof change.change === 'string' ? change.change.trim() : ''))
      .filter((change) => change.length > 0);
    const disallowedPattern =
      /\b(name|role|identity|sandbox|permission policy|security settings|api token|vault secret|filesystem policy)\b/i;
    const safeChanges = proposedChanges
      .map((entry) => String(entry).trim())
      .filter((entry) => entry.length > 0)
      .filter((entry) => !disallowedPattern.test(entry))
      .slice(0, 12);
    if (safeChanges.length > 0) {
      const marker = '## Approved Operational Improvements';
      const existingPrompt = profile.systemPrompt.trim();
      const section = `${marker}\nUpdated: ${utcNow()}\n${safeChanges.map((entry) => `- ${entry}`).join('\n')}`;
      const nextPrompt = existingPrompt.includes(marker)
        ? `${existingPrompt}\n\n${safeChanges.map((entry) => `- ${entry}`).join('\n')}`
        : `${existingPrompt}\n\n${section}`;
      const metadata = parseJsonSafe<Record<string, unknown>>(profile.metadataJson, {});
      metadata.selfImprovementLastAppliedAt = utcNow();
      metadata.selfImprovementLastProposalId = proposal.id;
      database.upsertAgentProfile({
        id: profile.id,
        name: profile.name,
        title: profile.title,
        parentAgentId: profile.parentAgentId,
        systemPrompt: nextPrompt,
        defaultRuntime: profile.defaultRuntime,
        defaultModel: profile.defaultModel,
        allowedRuntimes: normalizeRuntimeList(parseStringList(profile.allowedRuntimesJson)),
        skills: parseStringList(profile.skillsJson),
        tools: parseStringList(profile.toolsJson),
        metadata,
        enabled: profile.enabled
      });
    }
    const learningIds = parseJsonSafe<string[]>(proposal.learningIdsJson, []);
    database.markCompoundingLearningsApplied(learningIds);
    const updated = database.updateImprovementProposalStatus({
      id: proposal.id,
      status: 'approved',
      operatorNotes
    });
    database.appendAudit({
      actor,
      action: 'improvement.proposal.approve',
      resource: proposal.id,
      decision: 'allowed',
      reason: 'approved',
      details: {
        appliedChanges: safeChanges.length,
        learningIds
      },
      correlationId: randomUUID()
    });
    return jsonOk(reply, {
      proposal: updated
        ? {
            ...updated,
            proposedChanges: parseJsonSafe<Array<Record<string, unknown>>>(updated.proposedChangesJson, [])
              .map((change) => (typeof change.change === 'string' ? change.change.trim() : ''))
              .filter((change) => change.length > 0),
            learningIds: parseJsonSafe<string[]>(updated.learningIdsJson, [])
          }
        : null
    });
  });

