  app.post('/api/sessions/bulk-delete', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const requestedSessionIds = Array.isArray(body.sessionIds) ? body.sessionIds : [];
    const sessionIds = Array.from(
      new Set(
        requestedSessionIds
          .map((entry) => (typeof entry === 'string' ? entry.trim() : ''))
          .filter((entry) => entry.length > 0)
      )
    );

    if (sessionIds.length === 0) {
      return jsonError(reply, 'Provide at least one session id.', 400);
    }

    const sessions = sessionIds
      .map((sessionId) => database.getSessionById(sessionId))
      .filter((session): session is SessionRecord => session !== undefined);
    if (sessions.length === 0) {
      return jsonError(reply, 'No matching sessions found.', 404);
    }

    const activeRuns = sessions
      .map((session) => findLatestActiveRun(session.id))
      .filter((run): run is RunRecord => run !== undefined && ['queued', 'accepted', 'running', 'waiting_input'].includes(run.status));

    for (const run of activeRuns) {
      try {
        await runtimeManager.abort(run.id, run.runtime);
      } catch {
        // Keep cleanup resilient; the run rows are deleted with the session cascade right after.
      }
    }

    const deletedSessionIds = sessions.map((session) => session.id);
    const cleared = database.deleteSessionsByIds(deletedSessionIds);
    const deletedSet = new Set(deletedSessionIds);

    for (const [code, link] of pendingSessionLinks.entries()) {
      if (deletedSet.has(link.sessionId)) {
        pendingSessionLinks.delete(code);
      }
    }

    for (const [bindingKey, binding] of telegramSessionBindings.entries()) {
      if (deletedSet.has(binding.sessionId)) {
        telegramSessionBindings.delete(bindingKey);
      }
    }

    if (sessions.some((session) => session.agentId === resolvePrimaryCeoAgentId())) {
      ensureCeoOfficeAnchorSession();
    }

    database.appendAudit({
      actor,
      action: 'session.bulk_delete',
      resource: deletedSessionIds.join(','),
      decision: 'allowed',
      reason: 'operator_request',
      details: {
        deletedSessionIds,
        activeRunsAborted: activeRuns.map((run) => run.id),
        cleared
      },
      correlationId: randomUUID()
    });

    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'info',
      message: 'Sessions deleted from mission control',
      data: {
        deletedSessionIds,
        activeRunsAborted: activeRuns.map((run) => run.id)
      }
    });

    return jsonOk(reply, {
      sessionIds: deletedSessionIds,
      activeRunsAborted: activeRuns.map((run) => run.id),
      cleared
    });
  });

  app.post('/api/sessions', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const requestedSessionKey = typeof body.sessionKey === 'string' ? body.sessionKey.trim() : '';
    const label = typeof body.label === 'string' ? body.label.trim() : '';
    const explicitAgentId = typeof body.agentId === 'string' && body.agentId.trim().length > 0 ? body.agentId.trim() : null;
    const defaultAgentId = getDefaultIngressAgentId();
    const agentId = explicitAgentId ?? defaultAgentId;
    if (!agentId) {
      return jsonError(reply, 'Onboarding required: create a CEO baseline before creating default sessions.', 409, {
        reason: 'onboarding_required',
        guidance: 'POST /api/onboarding/ceo-baseline'
      });
    }
    const agentProfile = getAgentProfileById(agentId);
    if (!agentProfile) {
      return jsonError(reply, `Agent profile not found: ${agentId}`, 404);
    }
    if (!agentProfile.enabled) {
      return jsonError(reply, `Agent profile ${agentProfile.name} is disabled`, 403);
    }

    const runtimeInput = typeof body.runtime === 'string' ? body.runtime.trim() : '';
    if (runtimeInput && !isKnownRuntime(runtimeInput)) {
      return jsonError(reply, `Unsupported runtime: ${runtimeInput}`, 400);
    }

    const preferredRuntime = (runtimeInput ? (runtimeInput as RuntimeKind) : defaultRuntimeForProfile(agentProfile)) as
      | RuntimeKind
      | undefined;

    if (preferredRuntime && !isRuntimeAllowedForProfile(agentProfile, preferredRuntime)) {
      return jsonError(reply, `Runtime ${preferredRuntime} is not allowed for agent profile ${agentProfile.name}`, 403);
    }

    const modelInputRaw = typeof body.model === 'string' ? body.model.trim() : '';
    const parsedModelPreference = splitModelAndReasoning(modelInputRaw);
    const explicitReasoningEffort = normalizeReasoningInput(body.reasoningEffort);
    const normalizedLabel = label
      .toLowerCase()
      .replace(/[^a-z0-9_-]+/g, '-')
      .replace(/^-+|-+$/g, '')
      .slice(0, 40);
    const sessionKey =
      requestedSessionKey ||
      `dashboard:internal:${normalizedLabel || `session-${randomUUID().slice(0, 8)}`}:${Date.now().toString(36)}`;

    const session = database.upsertSessionByKey({
      sessionKey,
      channel: 'internal',
      chatType: 'internal',
      agentId,
      preferredRuntime,
      preferredModel: parsedModelPreference.model ?? agentProfile?.defaultModel ?? null,
      preferredReasoningEffort: explicitReasoningEffort ?? parsedModelPreference.reasoningEffort ?? null,
      metadata: {
        source: 'dashboard',
        label: label || null,
        agentProfileId: agentProfile?.id ?? null,
        agentTitle: agentProfile?.title ?? null
      }
    });
    ensureOfficePresenceForSession(session, {
      reason: 'Dashboard session presence synchronized',
      activityLabel: agentProfile?.title ?? 'Ready',
      onlyIfMissing: true
    });

    database.saveMessage({
      sessionId: session.id,
      channel: 'internal',
      direction: 'outbound',
      source: 'system',
      sender: 'system',
      content: `Dashboard session created${label ? `: ${label}` : ''}`,
      metadataJson: JSON.stringify({
        createdBy: 'dashboard'
      })
    });

    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: session.id,
      runId: null,
      level: 'info',
      message: 'Dashboard session created',
      data: {
        sessionId: session.id,
        sessionKey: session.sessionKey
      }
    });

    return jsonOk(
      reply,
      {
        session: {
          ...(() => {
            const metadata = parseJsonSafe<Record<string, unknown>>(session.metadataJson, {});
            return {
              metadata,
              runtimeOverrides: parseSessionRuntimeOverrides(metadata)
            };
          })(),
          ...session,
          agentProfile: getAgentProfileById(session.agentId),
          activeRunId: findLatestActiveRun(session.id)?.id ?? null
        }
      },
      201
    );
  });

  app.post('/api/sessions/:sessionId/link-code', async (request, reply) => {
    const params = request.params as { sessionId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const session = database.getSessionById(params.sessionId);
    if (!session) {
      return jsonError(reply, 'Session not found', 404);
    }

    const requestedTtlSec = Number(body.ttlSec ?? 600);
    const ttlSec = Number.isFinite(requestedTtlSec) ? Math.max(60, Math.min(3600, Math.floor(requestedTtlSec))) : 600;
    const actor = String(body.actor ?? 'dashboard');

    const link = issueSessionLinkCode(session.id, actor, ttlSec);
    database.appendAudit({
      actor,
      action: 'session.link.issue',
      resource: session.id,
      decision: 'allowed',
      reason: 'issued',
      details: {
        code: link.code,
        ttlSec,
        expiresAt: link.expiresAt
      },
      correlationId: randomUUID()
    });

    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: session.id,
      runId: null,
      level: 'info',
      message: 'Session link code issued',
      data: {
        code: link.code,
        ttlSec
      }
    });

    return jsonOk(
      reply,
      {
        link: {
          code: link.code,
          ttlSec,
          expiresAt: link.expiresAt,
          command: `/link ${link.code}`
        }
      },
      201
    );
  });

