  app.post('/api/sessions/:sessionId/browser-auth-profile', async (request, reply) => {
    const params = request.params as { sessionId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const session = database.getSessionById(params.sessionId);
    if (!session) {
      return jsonError(reply, 'Session not found', 404);
    }
    const requestedProfileId =
      typeof body.sessionProfileId === 'string' && body.sessionProfileId.trim().length > 0 ? body.sessionProfileId.trim() : null;
    if (!requestedProfileId) {
      const updated = updateSessionBrowserAuthProfile(session, null);
      return jsonOk(reply, {
        session: {
          ...updated,
          metadata: parseJsonSafe<Record<string, unknown>>(updated.metadataJson, {}),
          agentProfile: getAgentProfileById(updated.agentId),
          activeRunId: findLatestActiveRun(updated.id)?.id ?? null,
          browserSessionProfile: null
        }
      });
    }
    const profile = database.getBrowserSessionProfileById(requestedProfileId);
    if (!profile) {
      return jsonError(reply, 'Browser session profile not found', 404);
    }
    if (!canSessionUseBrowserSessionProfile(session, profile)) {
      return jsonError(reply, 'This browser session profile is not visible to the selected session.', 403);
    }
    const updated = updateSessionBrowserAuthProfile(session, profile.id);
    return jsonOk(reply, {
      session: {
        ...updated,
        metadata: parseJsonSafe<Record<string, unknown>>(updated.metadataJson, {}),
        agentProfile: getAgentProfileById(updated.agentId),
        activeRunId: findLatestActiveRun(updated.id)?.id ?? null,
        browserSessionProfile: serializeBrowserSessionProfile(profile)
      }
    });
  });

