  app.post('/api/backlog/orchestration/override', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const itemId = String(body.itemId ?? '').trim();
    const action = normalizeBacklogOverrideAction(body.action);
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const dryRun = body.dryRun === true || body.preview === true;
    const reason = String(body.reason ?? '').trim();
    if (!itemId || !action) {
      return jsonError(reply, 'itemId and action are required', 400);
    }
    if (!dryRun && !reason) {
      return jsonError(reply, 'reason is required for mutating override actions', 400, {
        reason: 'override_reason_required'
      });
    }

    const item = database.getBacklogItemById(itemId);
    if (!item) {
      return jsonError(reply, 'Backlog item not found', 404);
    }
    const normalizedReason = reason || `override:${action}`;
    const preview = buildBacklogOverridePreview({
      item,
      action,
      actor,
      reason: normalizedReason,
      targetAgentId: typeof body.targetAgentId === 'string' ? body.targetAgentId : null
    });
    if (dryRun) {
      return jsonOk(reply, {
        dryRun: true,
        preview,
        item: backlogItemView(item)
      });
    }
    if (!preview.allowed && action !== 'force_delegate') {
      return jsonError(reply, 'Override rejected by preview policy', 409, {
        reason: preview.reasonCode,
        preview
      });
    }

    try {
      if (action === 'block') {
        const updated = database.transitionBacklogItem({
          itemId,
          toState: 'blocked',
          actor,
          reason: normalizedReason
        });
        database.appendBacklogOrchestrationDecision({
          itemId,
          action,
          decision: 'applied',
          details: {
            actor,
            reason: normalizedReason,
            preview
          }
        });
        return jsonOk(reply, { item: backlogItemView(updated) });
      }

      if (action === 'requeue') {
        const updated = database.transitionBacklogItem({
          itemId,
          toState: 'planned',
          actor,
          reason: normalizedReason
        });
        database.appendBacklogOrchestrationDecision({
          itemId,
          action,
          decision: 'applied',
          details: {
            actor,
            reason: normalizedReason,
            preview
          }
        });
        return jsonOk(reply, { item: backlogItemView(updated) });
      }

      if (action === 'close') {
        const updated = database.transitionBacklogItem({
          itemId,
          toState: 'done',
          actor,
          reason: normalizedReason
        });
        database.appendBacklogOrchestrationDecision({
          itemId,
          action,
          decision: 'applied',
          details: {
            actor,
            reason: normalizedReason,
            preview
          }
        });
        return jsonOk(reply, { item: backlogItemView(updated) });
      }

      if (action === 'force_delegate' || action === 'force-delegate') {
        ensureCeoOfficeAnchorSession();
        const ceoSession = database.getSessionByKey(DEFAULT_CEO_OFFICE_SESSION_KEY);
        if (!ceoSession) {
          return jsonError(reply, 'CEO session unavailable', 409);
        }
        const explicitTarget = typeof body.targetAgentId === 'string' ? getAgentProfileById(body.targetAgentId) : null;
        const targetResolution =
          explicitTarget && explicitTarget.enabled
            ? {
                profile: explicitTarget,
                reason: 'override_explicit_target',
                rankedCandidates: [
                  {
                    agentId: explicitTarget.id,
                    score: 1_000,
                    reasons: ['explicit_override']
                  }
                ]
              }
            : await resolveBacklogDelegateTarget(ceoSession, item);
        const target = targetResolution.profile;
        if (!target) {
          return jsonError(reply, 'No eligible target agent for delegation', 409);
        }

        const activeDelegation = findActiveDelegatedRunForBacklogItem(item.id);
        if (activeDelegation) {
          const reconciled = reconcileBacklogItemToActiveDelegation(item, activeDelegation, actor, 'override_reconcile');
          database.appendBacklogOrchestrationDecision({
            itemId: item.id,
            action,
            decision: 'already_dispatched',
            details: {
              actor,
              runId: activeDelegation.run.id,
              targetAgentId: activeDelegation.session.agentId,
              targetSessionId: activeDelegation.session.id,
              source: activeDelegation.source,
              preview
            }
          });
          return jsonError(reply, 'Backlog item already has an active delegated run', 409, {
            reason: 'already_dispatched',
            item: backlogItemView(reconciled),
            delegation: {
              runId: activeDelegation.run.id,
              targetAgentId: activeDelegation.session.agentId,
              targetSessionId: activeDelegation.session.id
            }
          });
        }
        if (backlogDispatchLocks.has(item.id)) {
          return jsonError(reply, 'Backlog item dispatch is already in progress', 409, {
            reason: 'dispatch_locked'
          });
        }

        backlogDispatchLocks.add(item.id);
        try {
          const delegated = queueDelegatedRun({
            sourceSession: ceoSession,
            targetProfile: target,
            prompt: `${item.title}\n\n${item.description}`,
            runtimeCwd: item.repoRoot,
            mode: 'backlog_override_delegate',
            backlogItemId: item.id,
            deliveryTargetSessionId: resolveBacklogDeliveryTargetSessionId(item),
            lane: config.queue.defaultLane,
            priority: Math.max(1, 120 - item.priority),
            model: null
          });

          const existingMetadata = parseJsonSafe<Record<string, unknown>>(item.metadataJson, {});
          const withLinks = database.updateBacklogItem(item.id, {
            assignedAgentId: target.id,
            linkedSessionId: delegated.targetSession.id,
            linkedRunId: delegated.run.id,
            metadata: {
              ...existingMetadata,
              orchestration: {
                lastOverrideAt: utcNow(),
                overriddenBy: actor,
                targetAgentId: target.id,
                targetReason: targetResolution.reason,
                runtimeReason: `default_runtime:${defaultRuntimeForProfile(target)}`,
                parallelismSlot: 1
              }
            }
          });
          const transitioned = database.transitionBacklogItem({
            itemId: item.id,
            toState: 'in_progress',
            actor,
            reason: normalizedReason
          });

          database.appendBacklogOrchestrationDecision({
            itemId: item.id,
            action,
            decision: 'delegated',
            details: {
              actor,
              targetAgentId: target.id,
              runId: delegated.run.id,
              previousState: withLinks.state,
              targetReason: targetResolution.reason,
              runtimeReason: `default_runtime:${defaultRuntimeForProfile(target)}`,
              parallelismSlot: 1,
              rankedCandidates: targetResolution.rankedCandidates,
              preview
            }
          });
          await maybeSendDelegatedBacklogLifecycle({
            delegatedSession: delegated.targetSession,
            run: delegated.run,
            stage: 'queued'
          });

          return jsonOk(reply, {
            item: backlogItemView(transitioned),
            delegation: {
              runId: delegated.run.id,
              targetAgentId: target.id,
              targetSessionId: delegated.targetSession.id
            }
          });
        } finally {
          backlogDispatchLocks.delete(item.id);
        }
      }
    } catch (error) {
      if (error instanceof DelegationGuardError) {
        return jsonError(reply, error.message, 409, {
          reason: error.code,
          details: error.details
        });
      }
      return jsonError(reply, error instanceof Error ? error.message : 'Override failed', 409);
    }

    return jsonError(reply, 'Unsupported override action', 400);
  });

