  app.post('/api/agents/profiles/:agentId/sessions', async (request, reply) => {
    const params = request.params as { agentId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const profile = getAgentProfileById(params.agentId);
    if (!profile) {
      return jsonError(reply, 'Agent profile not found', 404);
    }
    if (!profile.enabled) {
      return jsonError(reply, `Agent profile ${profile.name} is disabled`, 403);
    }

    const runtimeInput = typeof body.runtime === 'string' ? body.runtime.trim() : defaultRuntimeForProfile(profile);
    if (!isKnownRuntime(runtimeInput)) {
      return jsonError(reply, `Unsupported runtime: ${runtimeInput}`, 400);
    }
    if (!isRuntimeAllowedForProfile(profile, runtimeInput)) {
      return jsonError(reply, `Runtime ${runtimeInput} is not allowed for agent profile ${profile.name}`, 403);
    }
    const toolPolicyError = assertRuntimeToolEnabled(runtimeInput);
    if (toolPolicyError) {
      return jsonError(reply, toolPolicyError, 403);
    }

    const label = typeof body.label === 'string' ? body.label.trim() : '';
    const modelInputRaw = typeof body.model === 'string' ? body.model.trim() : '';
    const parsedModelInput = splitModelAndReasoning(modelInputRaw);
    const reasoningEffortInput = normalizeReasoningInput(body.reasoningEffort) ?? parsedModelInput.reasoningEffort;
    const normalizedLabel = label
      .toLowerCase()
      .replace(/[^a-z0-9_-]+/g, '-')
      .replace(/^-+|-+$/g, '')
      .slice(0, 40);
    const requestedSessionKey = typeof body.sessionKey === 'string' ? body.sessionKey.trim() : '';
    const sessionKey =
      requestedSessionKey ||
      `agent:${profile.id}:${normalizedLabel || `session-${randomUUID().slice(0, 8)}`}:${Date.now().toString(36)}`;

    let session = database.upsertSessionByKey({
      sessionKey,
      channel: 'internal',
      chatType: 'internal',
      agentId: profile.id,
      preferredRuntime: runtimeInput,
      preferredModel: parsedModelInput.model ?? profile.defaultModel ?? null,
      preferredReasoningEffort: reasoningEffortInput ?? null,
      metadata: {
        source: 'dashboard',
        label: label || null,
        agentProfileId: profile.id,
        agentTitle: profile.title
      }
    });
    ensureOfficePresenceForSession(session, {
      reason: 'Agent profile session presence synchronized',
      activityLabel: profile.title,
      onlyIfMissing: true
    });

    let run: RunRecord | null = null;
    const firstPrompt = typeof body.firstPrompt === 'string' ? body.firstPrompt.trim() : '';
    if (firstPrompt) {
      session = maybePersistSessionLinkedRepoContext(session, firstPrompt);
      run = database.createRun({
        sessionId: session.id,
        runtime: runtimeInput,
        requestedRuntime: runtimeInput,
        requestedModel: parsedModelInput.model ?? profile.defaultModel ?? null,
        requestedReasoningEffort: reasoningEffortInput ?? null,
        effectiveRuntime: runtimeInput,
        effectiveModel: parsedModelInput.model ?? profile.defaultModel ?? null,
        effectiveReasoningEffort: reasoningEffortInput ?? null,
        triggerSource: 'dashboard',
        prompt: enrichPromptForSession(session, firstPrompt),
        status: 'queued'
      });

      database.enqueueQueueItem({
        lane: config.queue.defaultLane,
        sessionId: session.id,
        runId: run.id,
        payload: {
          source: 'dashboard',
          metadata: {
            agentProfileId: profile.id
          }
        },
        priority: 90,
        maxAttempts: config.queue.retry.maxAttempts
      });

      emitEvent({
        kind: 'run.queued',
        lane: config.queue.defaultLane,
        sessionId: session.id,
        runId: run.id,
        level: 'info',
        message: `Run queued for agent profile ${profile.name}`,
        data: {
          runtime: runtimeInput
        }
      });
    }

    return jsonOk(
      reply,
      {
        session: {
          ...session,
          metadata: parseJsonSafe<Record<string, unknown>>(session.metadataJson, {}),
          agentProfile: profile,
          activeRunId: run?.id ?? null
        },
        run: run ? serializeRunRecord(run) : null
      },
      201
    );
  });

  app.post('/api/sessions/:sessionId/delegate', async (request, reply) => {
    const params = request.params as { sessionId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const sourceSession = database.getSessionById(params.sessionId);
    if (!sourceSession) {
      return jsonError(reply, 'Source session not found', 404);
    }

    const targetAgentId = String(body.targetAgentId ?? '').trim();
    if (!targetAgentId) {
      return jsonError(reply, 'targetAgentId is required', 400);
    }
    const targetProfile = getAgentProfileById(targetAgentId);
    if (!targetProfile) {
      return jsonError(reply, 'Target agent profile not found', 404);
    }
    if (!targetProfile.enabled) {
      return jsonError(reply, `Agent profile ${targetProfile.name} is disabled`, 403);
    }

    const prompt = String(body.prompt ?? '').trim();
    if (!prompt) {
      return jsonError(reply, 'prompt is required', 400);
    }

    const runtimeInput = typeof body.runtime === 'string' ? body.runtime.trim() : defaultRuntimeForProfile(targetProfile);
    if (!isKnownRuntime(runtimeInput)) {
      return jsonError(reply, `Unsupported runtime: ${runtimeInput}`, 400);
    }
    if (!isRuntimeAllowedForProfile(targetProfile, runtimeInput)) {
      return jsonError(reply, `Runtime ${runtimeInput} is not allowed for agent profile ${targetProfile.name}`, 403);
    }
    const toolPolicyError = assertRuntimeToolEnabled(runtimeInput);
    if (toolPolicyError) {
      return jsonError(reply, toolPolicyError, 403);
    }

    const modelInput = typeof body.model === 'string' ? body.model.trim() : '';
    const mode = String(body.mode ?? 'handoff').trim() || 'handoff';
    let delegated;
    try {
      delegated = queueDelegatedRun({
        sourceSession,
        targetProfile,
        prompt,
        runtime: runtimeInput,
        model: modelInput || targetProfile.defaultModel || null,
        runtimeCwd: resolveSessionWorkspacePath(sourceSession),
        targetSessionKey: typeof body.targetSessionKey === 'string' ? body.targetSessionKey.trim() : null,
        mode,
        lane: config.queue.defaultLane,
        priority: 95
      });
    } catch (error) {
      if (error instanceof DelegationGuardError) {
        return jsonError(reply, error.message, 409, {
          reason: error.code,
          details: error.details
        });
      }
      throw error;
    }
    const targetSession = delegated.targetSession;
    const run = delegated.run;

    emitEvent({
      kind: 'run.queued',
      lane: config.queue.defaultLane,
      sessionId: targetSession.id,
      runId: run.id,
      level: 'info',
      message: 'Delegated run queued',
      data: {
        delegatedFromSessionId: sourceSession.id,
        targetAgentId: targetProfile.id,
        mode
      }
    });

    return jsonOk(reply, {
      delegation: {
        sourceSessionId: sourceSession.id,
        targetSessionId: targetSession.id,
        targetAgentId: targetProfile.id,
        runId: run.id,
        mode
      },
      targetSession: {
        ...targetSession,
        metadata: parseJsonSafe<Record<string, unknown>>(targetSession.metadataJson, {}),
        agentProfile: targetProfile,
        activeRunId: run.id
      },
      run: serializeRunRecord(run)
    }, 201);
  });

  app.get('/api/runs', async (request, reply) => {
    const query = request.query as Record<string, unknown>;
    const pagination = parsePagination(query);
    const status = query.status as RuntimeEvent['kind'] | undefined;

    const rows = database.listRuns({
      ...pagination,
      status: status && typeof status === 'string' ? (status as never) : undefined,
      sessionId: typeof query.sessionId === 'string' ? query.sessionId : undefined
    });

    return jsonOk(reply, {
      runs: rows.rows.map((row) => serializeRunRecord(row)),
      total: rows.total,
      ...pagination
    });
  });

  app.patch('/api/sessions/:sessionId/preferences', async (request, reply) => {
    const params = request.params as { sessionId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const session = database.getSessionById(params.sessionId);
    if (!session) {
      return jsonError(reply, 'Session not found', 404);
    }
    const sessionProfile = getSessionAgentProfile(session);
    if (sessionProfile && !sessionProfile.enabled) {
      return jsonError(reply, `Agent profile ${sessionProfile.name} is disabled`, 403);
    }

    const requestedRuntime = typeof body.runtime === 'string' ? body.runtime.trim() : undefined;
    if (requestedRuntime && !isKnownRuntime(requestedRuntime)) {
      return jsonError(reply, `Unsupported runtime: ${requestedRuntime}`, 400);
    }
    if (requestedRuntime) {
      const runtimeBlockReason = assertSessionRuntimeAllowed(session, requestedRuntime as RuntimeKind);
      if (runtimeBlockReason) {
        return jsonError(reply, runtimeBlockReason, 403);
      }
    }

    const modelPreferenceProvided = Object.prototype.hasOwnProperty.call(body, 'model');
    const parsedModelPreference = modelPreferenceProvided ? splitModelAndReasoning(body.model ?? null) : null;
    const nextModel = modelPreferenceProvided
      ? parsedModelPreference?.model ?? null
      : body.model === null
        ? null
        : undefined;
    const reasoningPreferenceProvided = Object.prototype.hasOwnProperty.call(body, 'reasoningEffort');
    const explicitReasoningPreference = normalizeReasoningInput(body.reasoningEffort);
    const nextReasoningEffort = reasoningPreferenceProvided
      ? body.reasoningEffort === null
        ? null
        : explicitReasoningPreference
      : modelPreferenceProvided
        ? parsedModelPreference?.reasoningEffort ?? null
        : undefined;

    let updated = database.updateSessionPreferences({
      sessionId: session.id,
      preferredRuntime: requestedRuntime as RuntimeKind | undefined,
      preferredModel: nextModel,
      preferredReasoningEffort: nextReasoningEffort
    });

    const metadataPatchSource: Record<string, unknown> = isRecord(body.runtimeOverrides)
      ? (body.runtimeOverrides)
      : body;
    const overrideKeys = ['timeoutMs', 'cwd', 'approvalProfile'] as const;
    const overridePatchRequested = overrideKeys.some((key) => Object.prototype.hasOwnProperty.call(metadataPatchSource, key));
    if (overridePatchRequested) {
      const metadata = parseJsonSafe<Record<string, unknown>>(updated.metadataJson, {});
      const currentOverrides = parseSessionRuntimeOverrides(metadata);
      const nextOverrides: SessionRuntimeOverrides = {
        ...currentOverrides
      };

      if (Object.prototype.hasOwnProperty.call(metadataPatchSource, 'timeoutMs')) {
        const rawTimeout = metadataPatchSource.timeoutMs;
        if (rawTimeout === null || rawTimeout === '') {
          nextOverrides.timeoutMs = null;
        } else {
          const timeout = Number(rawTimeout);
          if (!Number.isFinite(timeout) || timeout < 1_000 || timeout > 3_600_000) {
            return jsonError(reply, 'runtimeOverrides.timeoutMs must be between 1000 and 3600000 ms', 400);
          }
          nextOverrides.timeoutMs = Math.floor(timeout);
        }
      }

      if (Object.prototype.hasOwnProperty.call(metadataPatchSource, 'cwd')) {
        const rawCwd = metadataPatchSource.cwd;
        if (rawCwd === null || rawCwd === '') {
          nextOverrides.cwd = null;
        } else if (typeof rawCwd === 'string' && rawCwd.trim().length > 0) {
          const validatedCwd = validateSessionRuntimeOverrideCwd(updated, rawCwd.trim());
          if (!validatedCwd.ok) {
            return jsonError(reply, validatedCwd.error, 400);
          }
          nextOverrides.cwd = rawCwd.trim();
        } else {
          return jsonError(reply, 'runtimeOverrides.cwd must be a non-empty string or null', 400);
        }
      }

      if (Object.prototype.hasOwnProperty.call(metadataPatchSource, 'approvalProfile')) {
        const rawApprovalProfile = metadataPatchSource.approvalProfile;
        if (rawApprovalProfile === null || rawApprovalProfile === '') {
          nextOverrides.approvalProfile = null;
        } else if (typeof rawApprovalProfile === 'string' && rawApprovalProfile.trim().length > 0) {
          nextOverrides.approvalProfile = rawApprovalProfile.trim();
        } else {
          return jsonError(reply, 'runtimeOverrides.approvalProfile must be a non-empty string or null', 400);
        }
      }

      if (hasSessionRuntimeOverrides(nextOverrides)) {
        metadata.runtimeOverrides = {
          timeoutMs: nextOverrides.timeoutMs,
          cwd: nextOverrides.cwd,
          approvalProfile: nextOverrides.approvalProfile
        };
      } else {
        delete metadata.runtimeOverrides;
      }

      updated = database.updateSessionMetadata({
        sessionId: updated.id,
        metadata
      });
    }

    emitEvent({
      kind: 'session.preference.updated',
      lane: config.queue.defaultLane,
      sessionId: session.id,
      runId: null,
      level: 'info',
      message: 'Session runtime/model preferences updated',
      data: {
        runtime: updated.preferredRuntime,
        model: updated.preferredModel,
        reasoningEffort: updated.preferredReasoningEffort,
        runtimeOverrides: parseSessionRuntimeOverrides(parseJsonSafe<Record<string, unknown>>(updated.metadataJson, {}))
      }
    });

    const updatedMetadata = parseJsonSafe<Record<string, unknown>>(updated.metadataJson, {});
    return jsonOk(reply, {
      session: {
        ...updated,
        metadata: updatedMetadata,
        runtimeOverrides: parseSessionRuntimeOverrides(updatedMetadata),
        agentProfile: getAgentProfileById(updated.agentId),
        activeRunId: findLatestActiveRun(updated.id)?.id ?? null
      }
    });
  });

  app.post('/api/sessions/:sessionId/switch-runtime', async (request, reply) => {
    const params = request.params as { sessionId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;

    const session = database.getSessionById(params.sessionId);
    if (!session) {
      return jsonError(reply, 'Session not found', 404);
    }

    const runtimeInput = typeof body.runtime === 'string' ? body.runtime.trim() : '';
    if (runtimeInput && !isKnownRuntime(runtimeInput)) {
      return jsonError(reply, `Unsupported runtime: ${runtimeInput}`, 400);
    }

    const targetRuntime = resolveSessionRuntime(session, runtimeInput || undefined);
    const modelInputProvided = Object.prototype.hasOwnProperty.call(body, 'model');
    const parsedModelInput = modelInputProvided ? splitModelAndReasoning(body.model ?? null) : null;
    const targetModel = modelInputProvided ? parsedModelInput?.model ?? null : resolveSessionModel(session, body.model);
    const reasoningInputProvided = Object.prototype.hasOwnProperty.call(body, 'reasoningEffort');
    const explicitReasoningInput = normalizeReasoningInput(body.reasoningEffort);
    const targetReasoningEffort = reasoningInputProvided
      ? body.reasoningEffort === null
        ? null
        : explicitReasoningInput
      : modelInputProvided
        ? parsedModelInput?.reasoningEffort ?? null
        : resolveSessionReasoningEffort(session, body.model);
    const runtimeBlockReason = assertSessionRuntimeAllowed(session, targetRuntime);
    if (runtimeBlockReason) {
      return jsonError(reply, runtimeBlockReason, 403);
    }
    const toolBlockReason = assertRuntimeToolEnabled(targetRuntime);
    if (toolBlockReason) {
      return jsonError(reply, toolBlockReason, 403);
    }

    const updatedSession = database.updateSessionPreferences({
      sessionId: session.id,
      preferredRuntime: targetRuntime,
      preferredModel: targetModel,
      preferredReasoningEffort: targetReasoningEffort
    });

    emitEvent({
      kind: 'session.preference.updated',
      lane: config.queue.defaultLane,
      sessionId: session.id,
      runId: null,
      level: 'info',
      message: 'Session runtime/model preferences updated',
      data: {
        runtime: updatedSession.preferredRuntime,
        model: updatedSession.preferredModel,
        reasoningEffort: updatedSession.preferredReasoningEffort
      }
    });

    const activeRun = findLatestActiveRun(session.id);
    if (!activeRun) {
      const sessionMetadata = parseJsonSafe<Record<string, unknown>>(updatedSession.metadataJson, {});
      return jsonOk(reply, {
        switched: false,
        reason: 'no_active_run',
        session: {
          ...updatedSession,
          metadata: sessionMetadata,
          runtimeOverrides: parseSessionRuntimeOverrides(sessionMetadata),
          agentProfile: getAgentProfileById(updatedSession.agentId),
          activeRunId: null
        }
      });
    }

    await runtimeManager.abort(activeRun.id, activeRun.runtime);
    const abortedRun = database.updateRunStatus({
      runId: activeRun.id,
      status: 'aborted',
      error: 'runtime_switch'
    });

    emitEvent({
      kind: 'run.aborted',
      lane: config.queue.defaultLane,
      sessionId: abortedRun.sessionId,
      runId: abortedRun.id,
      level: 'warn',
      message: 'Run aborted for runtime/model switch',
      data: {
        previousRuntime: activeRun.runtime,
        nextRuntime: targetRuntime
      }
    });

    const overridePrompt = typeof body.prompt === 'string' ? body.prompt.trim() : '';
    const nextPrompt = overridePrompt.length > 0 ? enrichPromptForSession(session, overridePrompt) : activeRun.prompt;
    const nextRun = database.createRun({
      sessionId: session.id,
      runtime: targetRuntime,
      requestedRuntime: targetRuntime,
      requestedModel: targetModel,
      requestedReasoningEffort: targetReasoningEffort,
      effectiveRuntime: targetRuntime,
      effectiveModel: targetModel,
      effectiveReasoningEffort: targetReasoningEffort,
      triggerSource: 'runtime_switch',
      supersedesRunId: activeRun.id,
      prompt: nextPrompt,
      status: 'queued'
    });

    database.enqueueQueueItem({
      lane: config.queue.defaultLane,
      sessionId: session.id,
      runId: nextRun.id,
      payload: {
        metadata: {
          source: 'runtime_switch',
          model: targetModel,
          reasoningEffort: targetReasoningEffort,
          supersedesRunId: activeRun.id
        }
      },
      priority: 90,
      maxAttempts: config.queue.retry.maxAttempts
    });

    database.saveMessage({
      sessionId: session.id,
      channel: session.channel,
      direction: 'outbound',
      source: 'system',
      sender: 'system',
      content: `Runtime switched to ${targetRuntime}${targetModel ? ` (${targetModel})` : ''}. Previous run aborted and re-queued.`,
      metadataJson: JSON.stringify({
        previousRunId: activeRun.id,
        nextRunId: nextRun.id
      })
    });

    emitEvent({
      kind: 'run.queued',
      lane: config.queue.defaultLane,
      sessionId: session.id,
      runId: nextRun.id,
      level: 'info',
      message: 'Run re-queued after runtime/model switch',
      data: {
        previousRunId: activeRun.id,
        runtime: targetRuntime,
        model: targetModel,
        reasoningEffort: targetReasoningEffort
      }
    });

    return jsonOk(reply, {
      switched: true,
      session: {
        ...updatedSession,
        metadata: (() => {
          const metadata = parseJsonSafe<Record<string, unknown>>(updatedSession.metadataJson, {});
          return metadata;
        })(),
        runtimeOverrides: parseSessionRuntimeOverrides(
          parseJsonSafe<Record<string, unknown>>(updatedSession.metadataJson, {})
        ),
        agentProfile: getAgentProfileById(updatedSession.agentId),
        activeRunId: nextRun.id
      },
      previousRun: abortedRun,
      run: serializeRunRecord(nextRun)
    });
  });

  app.get('/api/runs/:runId', async (request, reply) => {
    const params = request.params as { runId: string };
    const run = database.getRunById(params.runId);
    if (!run) {
      return jsonError(reply, 'Run not found', 404);
    }
    const replacementRun = database.findLatestRunSuperseding(run.id) ?? null;
    const timeline = database.listRunTimeline(run.id);
    const executionPath = selectLatestExecutionPathSnapshot(timeline);
    const session = database.getSessionById(run.sessionId);
    const nativeToolSession = summarizeNativeToolSessionState(resolveNativeToolSessionStateForRun(run));

    const heartbeatStatus =
      run.status === 'completed'
        ? 'completed'
        : run.status === 'failed'
          ? 'failed'
          : ['queued', 'accepted', 'running', 'waiting_input'].includes(run.status)
            ? await runtimeManager.heartbeat(run.id, run.runtime)
            : 'unknown';

    return jsonOk(reply, {
      run: serializeRunRecord(run),
      executionPath,
      nativeToolSession,
      recovery: {
        replacementRunId: replacementRun?.id ?? null,
        replacementStatus: replacementRun?.status ?? null
      },
      liveness: {
        runStatus: run.status,
        heartbeat: heartbeatStatus,
        checkedAt: utcNow(),
        health:
          run.status === 'failed' || heartbeatStatus === 'failed'
            ? 'degraded'
          : heartbeatStatus === 'unknown' && ['running', 'accepted', 'waiting_input'].includes(run.status)
            ? 'degraded'
            : 'healthy'
      },
      lifecycle: session
        ? buildRunLifecycleState({
            run,
            session,
            executionPath,
            nativeToolSession: resolveNativeToolSessionStateForRun(run),
            heartbeat: heartbeatStatus
          })
        : null,
      timeline
    });
  });

