  app.post('/api/runs/:runId/control-actions', async (request, reply) => {
    const params = request.params as { runId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const action = typeof body.action === 'string' ? body.action.trim().toLowerCase() : '';
    const normalizedAction =
      action === 'dispatch_subrun' || action === 'dispatch-subrun'
        ? 'dispatch_subrun'
        : action === 'execute_command' || action === 'execute-command'
          ? 'execute_command'
          : null;
    if (!normalizedAction) {
      return jsonError(reply, 'Unsupported control action. Expected dispatch_subrun or execute_command.', 400);
    }

    const run = database.getRunById(params.runId);
    if (!run) {
      return jsonError(reply, 'Run not found', 404);
    }
    const session = database.getSessionById(run.sessionId);
    if (!session) {
      return jsonError(reply, 'Session not found for run', 404);
    }
    const contractRecord = database.getExecutionContractByRunId(run.id);
    if (!contractRecord) {
      return jsonError(reply, 'Execution contract not found for run', 409);
    }

    const parsed = extractExecutionContractFromOutput(contractRecord.contractJson);
    if (!parsed.contract) {
      return jsonError(reply, contractRecord.parseError ?? parsed.parseError ?? 'Execution contract payload is invalid', 409);
    }

    const selectedTaskIds =
      Array.isArray(body.taskIds)
        ? body.taskIds
            .map((taskId) => String(taskId ?? '').trim())
            .filter((taskId) => taskId.length > 0)
        : parsed.contract.tasks.filter((task) => task.action === normalizedAction).map((task) => task.taskId);
    const taskIds = new Set(selectedTaskIds);
    const actor = typeof body.actor === 'string' && body.actor.trim().length > 0 ? body.actor.trim() : 'operator';
    const dispatched = await dispatchExecutionContractSubruns({
      sourceSession: session,
      sourceRun: run,
      contract: parsed.contract,
      actor,
      source: 'manual',
      taskIds
    });
    return jsonOk(reply, {
      contract: {
        id: dispatched.contractRecord.id,
        runId: dispatched.contractRecord.runId,
        sessionId: dispatched.contractRecord.sessionId,
        source: dispatched.contractRecord.source,
        status: dispatched.contractRecord.status,
        parseError: dispatched.contractRecord.parseError,
        payload: parsed.contract.sourceJson,
        tasks: parsed.contract.tasks,
        backlog: parsed.contract.backlog,
        createdAt: dispatched.contractRecord.createdAt,
        updatedAt: dispatched.contractRecord.updatedAt
      },
      dispatches: dispatched.dispatches,
      summary: dispatched.summary
    });
  });

