  app.get('/api/runs/:runId/terminal/stream', async (request, reply) => {
    const params = request.params as { runId: string };
    const run = database.getRunById(params.runId);
    if (!run) {
      return jsonError(reply, 'Run not found', 404);
    }

    const query = request.query as Record<string, unknown>;
    const since = Math.max(0, Number(query.since ?? request.headers['last-event-id'] ?? 0));
    const limit = Math.max(1, Math.min(5000, Number(query.limit ?? 1200)));

    reply.raw.writeHead(200, {
      'Content-Type': 'text/event-stream',
      Connection: 'keep-alive',
      'Cache-Control': 'no-cache, no-transform'
    });

    let cursor = since;
    let active = true;

    const publishChunk = (chunk: {
      id: string;
      runId: string;
      sessionId: string;
      offset: number;
      chunk: string;
      source: string;
      createdAt: string;
    }): void => {
      if (!active || chunk.offset < cursor) {
        return;
      }
      if (reply.raw.writableLength > 1_000_000) {
        active = false;
        reply.raw.write(`event: backpressure\ndata: {"reason":"client_backpressure"}\n\n`);
        reply.raw.end();
        return;
      }

      reply.raw.write(`id: ${chunk.offset}\n`);
      reply.raw.write(`event: terminal.chunk\n`);
      reply.raw.write(`data: ${JSON.stringify(chunk)}\n\n`);
      cursor = chunk.offset + Buffer.byteLength(chunk.chunk, 'utf8');
    };

    const initial = database.listRunTerminalChunks(run.id, since, limit);
    for (const chunk of initial) {
      publishChunk(chunk);
    }

    const unsubscribe = observability.subscribe((event) => {
      if (!active || event.runId !== run.id) {
        return;
      }
      if (event.kind === 'terminal.chunk') {
        const data = event.data;
        publishChunk({
          id: String(data.id ?? event.id),
          runId: run.id,
          sessionId: run.sessionId,
          offset: Number(data.offset ?? 0),
          chunk: typeof data.chunk === 'string' ? data.chunk : '',
          source: typeof data.source === 'string' ? data.source : 'stdout',
          createdAt: event.ts
        });
      }
      if (event.kind === 'terminal.closed') {
        reply.raw.write(`event: terminal.closed\ndata: ${JSON.stringify(event.data)}\n\n`);
      }
    });

    const heartbeat = setInterval(() => {
      if (!active) {
        return;
      }
      reply.raw.write(`event: heartbeat\ndata: {"ts":"${utcNow()}","cursor":${cursor}}\n\n`);
    }, 10_000);

    request.raw.on('close', () => {
      active = false;
      clearInterval(heartbeat);
      unsubscribe();
    });

    return reply;
  });

  app.post('/api/sessions/:sessionId/runs', async (request, reply) => {
    const params = request.params as { sessionId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;

    let session = database.getSessionById(params.sessionId);
    if (!session) {
      return jsonError(reply, 'Session not found', 404);
    }

    const idempotencyKey = String(request.headers['idempotency-key'] ?? '').trim();
    if (!idempotencyKey) {
      return jsonError(reply, 'Missing Idempotency-Key header', 400);
    }

    const prompt = String(body.prompt ?? '').trim();
    if (!prompt) {
      return jsonError(reply, 'body.prompt is required', 400);
    }

    session = maybePersistSessionLinkedRepoContext(session, prompt);

    const runtimeInput = typeof body.runtime === 'string' ? body.runtime.trim() : '';
    if (runtimeInput && !isKnownRuntime(runtimeInput)) {
      return jsonError(reply, `Unsupported runtime: ${runtimeInput}`, 400);
    }

    const runtime = resolveSessionRuntime(session, runtimeInput || undefined);
    const modelInputProvided = Object.prototype.hasOwnProperty.call(body, 'model');
    const parsedModelInput = modelInputProvided ? splitModelAndReasoning(body.model ?? null) : null;
    const model = modelInputProvided ? parsedModelInput?.model ?? null : resolveSessionModel(session, body.model);
    const reasoningInputProvided = Object.prototype.hasOwnProperty.call(body, 'reasoningEffort');
    const explicitReasoningInput = normalizeReasoningInput(body.reasoningEffort);
    const reasoningEffort = reasoningInputProvided
      ? body.reasoningEffort === null
        ? null
        : explicitReasoningInput
      : modelInputProvided
        ? parsedModelInput?.reasoningEffort ?? null
        : resolveSessionReasoningEffort(session, body.model);
    const informationalPrompt = shouldTreatPromptAsInformationalConversation(prompt);
    const promptWithProfile = enrichPromptForSession(session, prompt);
    const lane = String(body.lane ?? config.queue.defaultLane);
    const priority = Number(body.priority ?? 100);
    const elevated = Boolean(body.elevated ?? false);
    const source = typeof body.source === 'string' && body.source.trim().length > 0 ? body.source.trim() : 'api';
    const autoDelegateEnabled = body.autoDelegate !== false;
    const dispatchOnly = isDispatchOnlySession(session);
    const hasDispatchCandidate = hasPotentialDispatchCandidate(session, autoDelegateEnabled);

    const runtimeProfileError = assertSessionRuntimeAllowed(session, runtime);
    if (runtimeProfileError && !hasDispatchCandidate) {
      return jsonError(reply, runtimeProfileError, 403);
    }

    const runtimeToolError = assertRuntimeToolEnabled(runtime);
    if (runtimeToolError && !hasDispatchCandidate) {
      return jsonError(reply, runtimeToolError, 403);
    }

    if (elevated && !config.policy.allowElevatedExecution) {
      database.appendAudit({
        actor: 'api',
        action: 'run.create',
        resource: session.id,
        decision: 'blocked',
        reason: 'elevated_execution_disabled',
        details: { prompt: prompt.slice(0, 120) },
        correlationId: randomUUID()
      });
      return jsonError(reply, 'Elevated execution disabled by policy', 403);
    }

    const idempotency = database.createOrReuseIdempotencyKey(idempotencyKey, () => randomUUID());
    let run = database.getRunById(idempotency.runId);
    let delegations: Array<{
      targetAgentId: string;
      targetSessionId: string;
      runId: string;
      mode: string;
    }> = [];
    let delegationDecision: AutoDelegationInference | null = null;
    let blockedDelegationTargets: string[] = [];

    if (!run) {
      run = database.createRun({
        id: idempotency.runId,
        sessionId: session.id,
        runtime,
        requestedRuntime: runtime,
        requestedModel: model,
        requestedReasoningEffort: reasoningEffort,
        effectiveRuntime: runtime,
        effectiveModel: model,
        effectiveReasoningEffort: reasoningEffort,
        triggerSource: source,
        prompt: promptWithProfile,
        status: 'queued'
      });

      database.saveMessage({
        sessionId: session.id,
        channel: session.channel,
        direction: 'inbound',
        source: source === 'dashboard' ? 'dashboard' : 'api',
        sender: 'operator',
        content: prompt,
        metadataJson: JSON.stringify({
          runId: run.id,
          source
        })
      });
      database.persistIdempotencyKey(idempotency.key, run.id);

      if (autoDelegateEnabled && informationalPrompt && !dispatchOnly) {
        delegationDecision = buildSyntheticIntakeInference('answer_direct', 'informational_prompt', 1);
      } else if (autoDelegateEnabled) {
        const delegationResult = await queueAutoDelegations({
          sourceSession: session,
          prompt,
          lane,
          priority,
          mode: 'auto_orchestrate'
        });
        delegations = delegationResult.delegations;
        delegationDecision = delegationResult.inference;
        blockedDelegationTargets = delegationResult.blockedTargetAgentIds;
      }

      const orchestration = summarizeOrchestratorDecision({
        dispatchOnly,
        delegations,
        inference: delegationDecision,
        blockedTargetAgentIds: blockedDelegationTargets
      });

      if (orchestration.status !== 'direct') {
        run = database.updateRunStatus({
          runId: run.id,
          status: 'completed',
          resultSummary: orchestration.message
        });

        const workspacePath = resolveRunWorkspacePath(config, session);
        const autoRemember = await memoryService.autoRememberRun({
          workspacePath,
          sessionId: session.id,
          agentId: session.agentId,
          channel: session.channel,
          runId: run.id,
          status: 'completed',
          runtime,
          model,
          summary: orchestration.message
        });

        emitEvent({
          kind: 'run.completed',
          lane,
          sessionId: session.id,
          runId: run.id,
          level: 'info',
          message: 'Orchestrator resolved request without direct CEO execution',
          data: {
            idempotencyKey,
            orchestration,
            delegations,
            autoRemember
          }
        });
      } else {
        database.enqueueQueueItem({
          lane,
          sessionId: session.id,
          runId: run.id,
          payload: {
            elevated,
            metadata: {
              source,
              idempotencyKey,
              model,
              reasoningEffort,
              intakeDecisionAction: delegationDecision?.action ?? null,
              intakeDecisionReason: delegationDecision?.reason ?? null
            }
          },
          priority,
          maxAttempts: config.queue.retry.maxAttempts
        });

        emitEvent({
          kind: 'run.queued',
          lane,
          sessionId: session.id,
          runId: run.id,
          level: 'info',
          message: 'Run queued via API',
          data: {
            idempotencyKey,
            created: true,
            delegationDecision: delegationDecision
              ? {
                  action: delegationDecision.action,
                  reason: delegationDecision.reason,
                  confidence: delegationDecision.confidence
                }
              : null
          }
        });
      }
    }

    return jsonOk(reply, {
      run: serializeRunRecord(run),
      delegations,
      delegationDecision: delegationDecision
        ? {
            action: delegationDecision.action,
            reason: delegationDecision.reason,
            confidence: delegationDecision.confidence,
            clarifyingQuestion: delegationDecision.clarifyingQuestion
          }
        : null,
      blockedDelegationTargets,
      idempotency: {
        key: idempotency.key,
        created: idempotency.created
      }
    }, idempotency.created ? 201 : 200);
  });

  const executeRunControlAction = async (input: {
    run: RunRecord;
    session: SessionRecord;
    action: 'steer' | 'resume';
    prompt: string;
    actor: string;
  }): Promise<{
    run: RunRecord;
    result: RuntimeExecutionResult;
    heartbeat: 'running' | 'waiting_input' | 'completed' | 'failed' | 'unknown';
  }> => {
    const { run, session, action, prompt, actor } = input;
    const workspacePath = resolveSessionWorkspacePath(session);
    await fs.mkdir(workspacePath, { recursive: true });

    const profile = getSessionAgentProfile(session);
    const overrides = sessionRuntimeOverrides(session);
    const executionTimeoutMs = resolveSessionTimeoutMs(session);
    const tmuxAvailable = commandExists('tmux');
    const persistentHarnessBound =
      profile !== null &&
      profile.executionMode === 'persistent_harness' &&
      profile.harnessRuntime === run.runtime &&
      profile.harnessSessionReady &&
      profile.harnessSessionName !== null &&
      tmuxAvailable;
    const shouldUseTmux = run.runtime !== 'process' && tmuxAvailable;
    const terminalMode: 'direct' | 'tmux' = shouldUseTmux ? 'tmux' : 'direct';
    const terminalSessionName = shouldUseTmux
      ? persistentHarnessBound
        ? profile.harnessSessionName
        : `ops-${run.runtime}-${run.id.slice(0, 10)}`
      : null;

    database.upsertRunTerminalSession({
      runId: run.id,
      sessionId: run.sessionId,
      runtime: run.runtime,
      mode: terminalMode,
      muxSessionId: terminalSessionName,
      workspacePath,
      status: 'active',
      metadata: {
        source: 'run_control',
        action,
        actor,
        timeoutMs: executionTimeoutMs,
        persistentHarness: persistentHarnessBound,
        approvalProfile: overrides.approvalProfile
      }
    });

    const appendTerminalChunk = (chunk: string, source: 'stdout' | 'stderr'): void => {
      if (!chunk) {
        return;
      }
      const record = database.appendRunTerminalChunk({
        runId: run.id,
        sessionId: run.sessionId,
        chunk,
        source
      });
      emitEvent({
        kind: 'terminal.chunk',
        lane: config.queue.defaultLane,
        sessionId: run.sessionId,
        runId: run.id,
        level: source === 'stderr' ? 'warn' : 'debug',
        message: `Terminal output chunk (${action})`,
        data: {
          id: record.id,
          offset: record.offset,
          bytes: Buffer.byteLength(record.chunk, 'utf8'),
          source: record.source,
          createdAt: record.createdAt,
          chunk: record.chunk.slice(0, 4000)
        }
      });
    };

    const appendRunControlToolSessionEvent = (event: RuntimeToolSessionEvent): void => {
      database.appendRunEvent({
        runId: run.id,
        sessionId: run.sessionId,
        type: event.type,
        details: `${event.type} (${event.toolName})`,
        payload: {
          toolName: event.toolName,
          callId: event.callId ?? null,
          payload: event.payload ?? null,
          summary: event.summary ?? null,
          error: event.error ?? null,
          native: event.native === true
        }
      });
      emitEvent({
        kind: 'system.info',
        lane: config.queue.defaultLane,
        sessionId: run.sessionId,
        runId: run.id,
        level: event.type === 'tool_error' || event.type === 'tool_policy_blocked' ? 'warn' : 'info',
        message: `Run-control native tool event: ${event.type} (${event.toolName})`,
        data: {
          callId: event.callId ?? null,
          payload: event.payload ?? null,
          summary: event.summary ?? null,
          error: event.error ?? null
        }
      });
    };

    database.updateRunStatus({
      runId: run.id,
      status: 'running',
      error: null
    });
    emitEvent({
      kind: 'run.running',
      lane: config.queue.defaultLane,
      sessionId: run.sessionId,
      runId: run.id,
      level: 'info',
      message: action === 'steer' ? 'Run steered by operator' : 'Run resumed by operator',
      data: {
        action,
        actor
      }
    });
    if (action === 'resume') {
      cancelScheduledWatchdogRecoveryJobs({
        rootRunId: resolveRootRunId(run),
        status: 'cancelled',
        reason: 'manual_resume',
        historyRunId: run.id
      });
    }

    const assembledPrompt = await assemblePromptForRun({
      run,
      session,
      basePrompt: prompt
    });
    const runControlPolicy = resolveContextAssemblyPolicy();
    persistPromptAssembly({
      run,
      session,
      assembly: assembledPrompt,
      overflowStrategy: runControlPolicy.overflowStrategy
    });
    let result: RuntimeExecutionResult;
    if (assembledPrompt.overflowed && runControlPolicy.overflowStrategy === 'fail_fast') {
      appendContinuitySignal({
        runId: run.id,
        sessionId: run.sessionId,
        severity: 'high',
        source: 'prompt_assembly',
        code: 'context_overflow_preflight',
        summary: `Run-control ${action} blocked by context budget preflight.`,
        details: {
          contextLimit: assembledPrompt.contextLimit,
          totalEstimatedTokens: assembledPrompt.totalEstimatedTokens
        }
      });
      result = {
        finalStatus: 'failed',
        error: `context_overflow_preflight: estimated_tokens=${assembledPrompt.totalEstimatedTokens} limit=${assembledPrompt.contextLimit}`
      };
    } else {
      const promptWithExecutionContext = withExecutionContext(
        assembledPrompt.prompt,
        buildExecutionContextPayload({
          session,
          run,
          profile,
          selectedRuntime: run.runtime,
          selectedModel: normalizeModelInput(run.effectiveModel ?? run.requestedModel ?? session.preferredModel ?? null),
          routeReason: `run_control_${action}`,
          workspacePath,
          terminalMode,
          terminalSessionName,
          executionTimeoutMs,
          attempt: 1,
          triggerSource: run.triggerSource
        })
      );

      const runControlModel = normalizeModelInput(
        run.effectiveModel ?? run.requestedModel ?? session.preferredModel ?? profile?.defaultModel ?? null
      );
      const reusableNativeToolSession =
        inferProvider(runControlModel) !== null
          ? selectReusableNativeToolSessionState({
              run,
              runtime: run.runtime,
              model: runControlModel,
              source: `run_control_${action}`
            })
          : null;
      const runControlExecutionPath = buildExecutionPathSnapshot({
        runtime: run.runtime,
        model: runControlModel,
        source: `run_control_${action}`,
        routeReason: `run_control_${action}`
      });
      database.appendRunEvent({
        runId: run.id,
        sessionId: run.sessionId,
        type: 'run.execution_path',
        details: `Execution path selected for run-control ${action}`,
        payload: runControlExecutionPath
      });
      result =
        action === 'steer'
          ? await runtimeManager.send({
              runtime: run.runtime,
              runId: run.id,
              sessionId: run.sessionId,
              prompt: promptWithExecutionContext,
              workspacePath,
              terminal: {
                mode: terminalMode,
                sessionName: terminalSessionName,
                maxDurationMs: executionTimeoutMs
              },
              onChunk: appendTerminalChunk,
              metadata: buildRuntimeExecutionMetadata({
                runtime: run.runtime,
                model: runControlModel,
                base: {
                  source: 'run_control',
                  action,
                  actor,
                  persistentHarness: persistentHarnessBound,
                  approvalProfile: overrides.approvalProfile,
                  executionContextSchema: 'ops.execution-context.v2',
                  routeReason: `run_control_${action}`,
                  nativeToolSessionHandle: reusableNativeToolSession?.handle,
                  nativeToolSessionResume: reusableNativeToolSession !== null
                }
              })
            })
          : await runtimeManager.resume({
              runtime: run.runtime,
              runId: run.id,
              sessionId: run.sessionId,
              prompt: promptWithExecutionContext,
              workspacePath,
              terminal: {
                mode: terminalMode,
                sessionName: terminalSessionName,
                maxDurationMs: executionTimeoutMs
              },
              onChunk: appendTerminalChunk,
              metadata: buildRuntimeExecutionMetadata({
                runtime: run.runtime,
                model: runControlModel,
                base: {
                  source: 'run_control',
                  action,
                  actor,
                  persistentHarness: persistentHarnessBound,
                  approvalProfile: overrides.approvalProfile,
                  executionContextSchema: 'ops.execution-context.v2',
                  routeReason: `run_control_${action}`,
                  nativeToolSessionHandle: reusableNativeToolSession?.handle,
                  nativeToolSessionResume: reusableNativeToolSession !== null
                }
              })
            });

      const normalizedToolSessionResult = normalizeReusableNativeToolSessionResult({
        result,
        reusableState: reusableNativeToolSession,
        resumeSource: reusableNativeToolSession ? `run_control_${action}` : null
      });
      if (
        normalizedToolSessionResult.handle !== runtimeResultToolSessionHandle(result) ||
        normalizedToolSessionResult.events !== (result.toolEvents ?? [])
      ) {
        result = {
          ...result,
          toolEvents: normalizedToolSessionResult.events,
          ...(normalizedToolSessionResult.handle ? { toolSessionHandle: normalizedToolSessionResult.handle } : {})
        } as RuntimeExecutionResult;
      }
      const resultToolSessionHandle = normalizedToolSessionResult.handle;
      if (resultToolSessionHandle) {
        for (const event of normalizedToolSessionResult.events) {
          appendRunControlToolSessionEvent(event);
        }
        persistNativeToolSessionState({
          run,
          sessionId: run.sessionId,
          executionPath: {
            ...runControlExecutionPath,
            toolSessionMode: result.toolSessionMode ?? runControlExecutionPath.toolSessionMode
          },
          handle: resultToolSessionHandle,
          toolEvents: normalizedToolSessionResult.events,
          resumeSource: reusableNativeToolSession ? `run_control_${action}` : null,
          resumedFromRunId: reusableNativeToolSession?.currentRunId ?? null
        });
      }
      if (result.toolSessionMode) {
        database.appendRunEvent({
          runId: run.id,
          sessionId: run.sessionId,
          type: 'run.execution_path',
          details: `Resolved run-control ${action} tool-session path`,
          payload: {
            ...runControlExecutionPath,
            toolSessionMode: result.toolSessionMode
          }
        });
      }
    }

    if (result.finalStatus === 'failed' && isProviderSaturationFailure(result, run.runtime, run.id)) {
      result = {
        ...result,
        finalStatus: 'waiting_input',
        error: 'runtime_quota_waiting',
        summary: buildQuotaRecoveryPauseMessage({
          runId: run.id,
          runtime: run.runtime,
          model: normalizeModelInput(run.effectiveModel ?? run.requestedModel ?? session.preferredModel ?? null),
          detectedSignal: result.error ?? result.summary ?? result.raw ?? null
        }),
        waitingPrompt: 'Wait for quota or rate-limit recovery, then resume the run.'
      };
    }

    const terminalFinalStatus =
      result.finalStatus === 'completed'
        ? 'completed'
        : result.finalStatus === 'aborted'
          ? 'aborted'
          : result.finalStatus === 'waiting_input'
            ? 'active'
            : 'failed';
    const terminalRetentionUntil =
      terminalFinalStatus === 'active'
        ? null
        : new Date(Date.now() + config.housekeeping.terminalRetentionHours * 60 * 60 * 1000).toISOString();
    database.closeRunTerminalSession(run.id, terminalFinalStatus, terminalRetentionUntil);

    const updated = database.updateRunStatus({
      runId: run.id,
      status: result.finalStatus,
      error: result.error ?? null,
      resultSummary: result.summary ?? null
    });
    if (TERMINAL_RUN_STATUSES.has(updated.status)) {
      cancelScheduledWatchdogRecoveryJobsIfLineageTerminal(updated);
    }
    if (updated.status !== 'waiting_input') {
      watchdogPauseNoticeByRunId.delete(run.id);
    }

    emitEvent({
      kind: `run.${updated.status}` as RuntimeEvent['kind'],
      lane: config.queue.defaultLane,
      sessionId: run.sessionId,
      runId: run.id,
      level: updated.status === 'failed' || updated.status === 'aborted' ? 'warn' : 'info',
      message: action === 'steer' ? 'Steer action completed' : 'Resume action completed',
      data: {
        action,
        actor,
        status: updated.status,
        error: updated.error
      }
    });

    const heartbeat = await runtimeManager.heartbeat(run.id, run.runtime);

    if ((updated.status === 'completed' || updated.status === 'failed' || updated.status === 'waiting_input') && (result.summary || result.error)) {
      const rawOutboundContent = result.summary ?? result.error ?? '';
      const shouldBypassSanitization = session.channel === 'telegram' && config.channel.telegram.debugRawOutput;
      const structuredFromRaw =
        !shouldBypassSanitization && typeof result.raw === 'string' && result.raw.length > 0
          ? extractStructuredAgentMessage(result.raw)
          : null;
      const rawDebugContent =
        shouldBypassSanitization && typeof result.raw === 'string' && result.raw.trim().length > 0
          ? result.raw
          : rawOutboundContent;
      const outboundContent = shouldBypassSanitization
        ? rawDebugContent
        : structuredFromRaw || sanitizeRuntimeSummary(rawOutboundContent) || rawOutboundContent;
      const outboundExecutionPath = selectLatestExecutionPathSnapshot(database.listRunTimeline(run.id));
      const outboundNativeToolSession = summarizeNativeToolSessionState(resolveNativeToolSessionStateForRun(run));
      await saveOutboundMessage(session, 'agent', session.agentId, outboundContent, {
        runId: run.id,
        source: 'run_control',
        action,
        interactionMode: 'direct_execute',
        interactionModeReason: 'run_control_followup',
        executionPath: outboundExecutionPath,
        nativeToolSession: outboundNativeToolSession,
        lifecycle: buildRunLifecycleState({
          run: updated,
          session,
          executionPath: outboundExecutionPath,
          nativeToolSession: resolveNativeToolSessionStateForRun(updated),
          heartbeat
        })
      });
      if (updated.status === 'completed' || updated.status === 'failed') {
        await maybeBridgeDelegatedBacklogReceipt({
          delegatedSession: session,
          run: updated,
          finalStatus: updated.status,
          outboundContent,
          workspacePath
        });
      }
    }
    return {
      run: updated,
      result,
      heartbeat
    };
  };

  app.post('/api/runs/:runId/steer', async (request, reply) => {
    const params = request.params as { runId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const run = database.getRunById(params.runId);
    if (!run) {
      return jsonError(reply, 'Run not found', 404);
    }
    if (run.status !== 'running' && run.status !== 'waiting_input') {
      return jsonError(reply, 'Run is not in a steerable state', 409, {
        runStatus: run.status
      });
    }
    const prompt = typeof body.prompt === 'string' ? body.prompt.trim() : '';
    if (!prompt) {
      return jsonError(reply, 'prompt is required', 400);
    }
    const session = database.getSessionById(run.sessionId);
    if (!session) {
      return jsonError(reply, 'Session not found for run', 404);
    }
    const actor = typeof body.actor === 'string' && body.actor.trim().length > 0 ? body.actor.trim() : 'operator';
    const response = await executeRunControlAction({
      run,
      session,
      action: 'steer',
      prompt,
      actor
    });
    return jsonOk(reply, {
      run: serializeRunRecord(response.run),
      result: response.result,
      liveness: {
        heartbeat: response.heartbeat,
        checkedAt: utcNow()
      }
    });
  });

  app.post('/api/runs/:runId/resume', async (request, reply) => {
    const params = request.params as { runId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const run = database.getRunById(params.runId);
    if (!run) {
      return jsonError(reply, 'Run not found', 404);
    }
    if (run.status !== 'waiting_input') {
      return jsonError(reply, 'Run is not resumable', 409, {
        runStatus: run.status
      });
    }
    const prompt = typeof body.prompt === 'string' ? body.prompt.trim() : '';
    const session = database.getSessionById(run.sessionId);
    if (!session) {
      return jsonError(reply, 'Session not found for run', 404);
    }
    const actor = typeof body.actor === 'string' && body.actor.trim().length > 0 ? body.actor.trim() : 'operator';
    const response = await executeRunControlAction({
      run,
      session,
      action: 'resume',
      prompt,
      actor
    });
    return jsonOk(reply, {
      run: serializeRunRecord(response.run),
      result: response.result,
      liveness: {
        heartbeat: response.heartbeat,
        checkedAt: utcNow()
      }
    });
  });

  app.post('/api/runs/:runId/abort', async (request, reply) => {
    const params = request.params as { runId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;

    const run = database.getRunById(params.runId);
    if (!run) {
      return jsonError(reply, 'Run not found', 404);
    }

    await runtimeManager.abort(run.id, run.runtime);
    const updated = database.updateRunStatus({
      runId: run.id,
      status: 'aborted',
      error: String(body.reason ?? 'operator_abort')
    });
    cancelScheduledWatchdogRecoveryJobsIfLineageTerminal(updated);

    emitEvent({
      kind: 'run.aborted',
      lane: config.queue.defaultLane,
      sessionId: run.sessionId,
      runId: run.id,
      level: 'warn',
      message: 'Run aborted by operator',
      data: {
        reason: body.reason ?? 'operator_abort'
      }
    });

    return jsonOk(reply, { run: serializeRunRecord(updated) });
  });

