  app.post('/api/onboarding/smoke-run', async (request, reply) => {
    if (!hasValidApiToken(request, config.server.apiToken)) {
      return jsonError(reply, 'Unauthorized', 401);
    }
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const snapshotBefore = computeOnboardingSnapshot();
    const blockedPrerequisites = snapshotBefore.steps.filter(
      (step) => step.id !== 'smoke_run' && step.status !== 'complete'
    );
    if (blockedPrerequisites.length > 0) {
      return jsonError(reply, 'Onboarding prerequisites are incomplete', 412, {
        blockers: blockedPrerequisites.map((step) => `${step.id}: ${step.detail}`),
        onboarding: {
          status: snapshotBefore.status,
          steps: snapshotBefore.steps,
          blockers: snapshotBefore.blockers,
          evidence: snapshotBefore.evidence,
          providerKeys: providerKeyDiagnostics(),
          companyName: resolveCompanyName(),
          ceoAgentId: resolvePrimaryCeoAgentId()
        }
      });
    }

    const ceo = getAgentProfileById(resolvePrimaryCeoAgentId());
    if (!ceo) {
      return jsonError(reply, 'Default CEO profile not found', 404);
    }

    const runtime = defaultRuntimeForProfile(ceo);
    const model = normalizeModelInput(body.model ?? ceo.defaultModel);
    const smokeSession: ExecutionPromptContextInput['session'] = {
      id: 'onboarding-smoke',
      sessionKey: 'onboarding-smoke',
      channel: 'internal',
      chatType: 'internal',
      agentId: ceo.id,
      preferredRuntime: runtime,
      preferredModel: model,
      preferredReasoningEffort: null,
      metadataJson: '{}'
    };
    const smokeSessionForRoute: SessionRecord = {
      ...smokeSession,
      state: 'active',
      lastActivityAt: utcNow()
    };
    const routeDecision = selectExecutableRouteForSession(smokeSessionForRoute, runtime, model, 'orchestrator');
    const policyReason = assertSessionRuntimeAllowed(smokeSessionForRoute, runtime) ?? assertRuntimeToolEnabled(runtime);
    const localRequestedRoute: LlmFallbackTarget | null =
      model === null && !policyReason
        ? {
            runtime,
            model: null
          }
        : null;
    const routeChecks = localRequestedRoute
      ? [
          {
            runtime: localRequestedRoute.runtime,
            model: localRequestedRoute.model,
            provider: inferProvider(localRequestedRoute.model),
            eligible: true,
            reason: 'explicit_local_requested',
            policyEligible: true,
            policyReason: undefined,
            snapshot: {
              dayCalls: 0,
              minuteCalls: 0,
              dayCostUsd: 0,
              monthCostUsd: 0,
              modelDayCalls: 0
            }
          },
          ...routeDecision.checks.filter(
            (check) => !sameRoute(check.runtime, check.model ?? null, localRequestedRoute.runtime, localRequestedRoute.model)
          )
        ]
      : routeDecision.checks;
    let activeRoute: LlmFallbackTarget | null =
      localRequestedRoute ??
      (routeDecision.selected
        ? {
            runtime: routeDecision.selected.runtime,
            model: normalizeModelInput(routeDecision.selected.model ?? model)
          }
        : null);
    let selectedRoute: LlmFallbackTarget = activeRoute ?? {
      runtime,
      model
    };
    const runId = `onboarding-smoke-${randomUUID()}`;
    let finalRunId = runId;
    const workspacePath = path.join(path.resolve(config.runtime.workspaceRoot), '.onboarding-smoke');
    await fs.mkdir(workspacePath, { recursive: true });
    const smokePrompt =
      typeof body.prompt === 'string' && body.prompt.trim().length > 0
        ? body.prompt.trim()
        : `Respond in one sentence confirming runtime readiness for ${resolveCompanyName()} onboarding.`;
    const prompt = [`ROLE: ${ceo.title} (${ceo.name})`, `SYSTEM: ${ceo.systemPrompt}`, '', `TASK: ${smokePrompt}`].join('\n');
    let attempt = 0;
    let result: RuntimeExecutionResult = {
      finalStatus: 'failed',
      error: `route_unavailable:${routeDecision.reason}`
    };
    while (activeRoute) {
      attempt += 1;
      const routeModel = normalizeModelInput(activeRoute.model ?? model);
      const promptWithExecutionContext = withExecutionContext(
        prompt,
        buildExecutionContextPayload({
          session: smokeSession,
          run: null,
          profile: ceo,
          selectedRuntime: activeRoute.runtime,
          selectedModel: routeModel,
          routeReason: 'onboarding_smoke_direct',
          routeChecks: routeChecks.map((check) => ({
            runtime: check.runtime,
            model: check.model ?? null,
            provider: check.provider ?? null,
            eligible: check.eligible,
            reason: check.reason,
            policyEligible: check.policyEligible,
            policyReason: check.policyReason
          })),
          workspacePath,
          terminalMode: 'none',
          attempt,
          triggerSource: 'onboarding_smoke'
        })
      );
      selectedRoute = {
        runtime: activeRoute.runtime,
        model: routeModel
      };
      finalRunId = `${runId}-attempt-${attempt}`;
      result = await runtimeManager.execute({
        runtime: activeRoute.runtime,
        runId: finalRunId,
        sessionId: 'onboarding-smoke',
        prompt: promptWithExecutionContext,
        workspacePath,
        metadata: buildRuntimeExecutionMetadata({
          runtime: activeRoute.runtime,
          model: routeModel,
          base: {
            source: 'onboarding_smoke',
            actor,
            executionContextSchema: 'ops.execution-context.v2'
          }
        })
      });
      if (result.finalStatus === 'completed') {
        break;
      }
      const activeProvider = inferProvider(selectedRoute.model);
      const saturationFailure = isProviderSaturationFailure(result, selectedRoute.runtime);
      if ((activeProvider !== 'openrouter' && activeProvider !== 'google') || !isRetryableRuntimeFailure(result)) {
        break;
      }
      const fallbackRoute = nextEligibleFallbackRoute({
        checks: routeChecks,
        selectedRuntime: activeRoute.runtime,
        selectedModel: routeModel,
        preferProviderSwitchFrom: saturationFailure ? activeProvider : null
      });
      if (!fallbackRoute) {
        break;
      }
      activeRoute = {
        runtime: fallbackRoute.runtime,
        model: normalizeModelInput(fallbackRoute.model)
      };
    }

    const now = utcNow();
    const persisted = writePersistedOnboardingState((current) => ({
      ...current,
      smokeRun: {
        runId: finalRunId,
        runtime: selectedRoute.runtime,
        model: selectedRoute.model,
        status: result.finalStatus,
        summary: result.summary ?? null,
        error: result.error ?? null,
        completedAt: now
      }
    }));
    const snapshotAfter = computeOnboardingSnapshot();

    database.appendAudit({
      actor,
      action: 'onboarding.smoke_run',
      resource: finalRunId,
      decision: result.finalStatus === 'completed' ? 'allowed' : 'blocked',
      reason: result.finalStatus,
      details: {
        runtime: selectedRoute.runtime,
        model: selectedRoute.model,
        error: result.error ?? null
      },
      correlationId: randomUUID()
    });

    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: result.finalStatus === 'completed' ? 'info' : 'warn',
      message: result.finalStatus === 'completed' ? 'Onboarding smoke run passed' : 'Onboarding smoke run failed',
      data: {
        runId: finalRunId,
        runtime: selectedRoute.runtime,
        model: selectedRoute.model,
        status: result.finalStatus,
        error: result.error ?? null
      }
    });

    return jsonOk(reply, {
      smokeRun: persisted.smokeRun,
      onboarding: {
        status: snapshotAfter.status,
        steps: snapshotAfter.steps,
        blockers: snapshotAfter.blockers,
        evidence: snapshotAfter.evidence,
        providerKeys: providerKeyDiagnostics(),
        companyName: resolveCompanyName(),
        ceoAgentId: resolvePrimaryCeoAgentId()
      }
    });
  });

