  const parseBrowserCookieSourceKind = (
    value: unknown
  ): 'raw_cookie_header' | 'netscape_cookies_txt' | 'manual' | 'json_cookie_export' | 'browser_profile_import' | null => {
    return value === 'raw_cookie_header' ||
      value === 'netscape_cookies_txt' ||
      value === 'manual' ||
      value === 'json_cookie_export' ||
      value === 'browser_profile_import'
      ? value
      : null;
  };
  const parseBrowserProfileVisibility = (value: unknown): 'shared' | 'session_only' =>
    value === 'session_only' ? 'session_only' : 'shared';
  const parseBrowserAllowedSessionIds = (value: unknown): string[] =>
    Array.isArray(value)
      ? Array.from(
          new Set(
            value
              .map((entry) => String(entry).trim())
              .filter((entry) => entry.length > 0)
          )
        )
      : [];
  const parseLocalBrowserKind = (value: unknown): 'chrome' | 'firefox' | null =>
    value === 'chrome' || value === 'firefox' ? value : null;

  app.put('/api/browser/config', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const candidate = { ...(isRecord(body.config) ? body.config : body) };
    delete candidate.actor;
    delete candidate.config;
    const currentBrowser = config.browser;
    const nextConfig = structuredClone(config);
    nextConfig.browser = {
      ...nextConfig.browser,
      ...currentBrowser,
      ...candidate,
      httpBaseUrl:
        typeof candidate.httpBaseUrl === 'string' && candidate.httpBaseUrl.trim().length > 0
          ? candidate.httpBaseUrl.trim()
          : candidate.httpBaseUrl === null
            ? undefined
            : nextConfig.browser.httpBaseUrl,
      allowedAgents: Array.isArray(candidate.allowedAgents)
        ? candidate.allowedAgents
            .map((entry) => String(entry).trim())
            .filter((entry) => entry.length > 0)
        : nextConfig.browser.allowedAgents,
      policy: {
        ...nextConfig.browser.policy,
        ...currentBrowser.policy,
        ...(isRecord(candidate.policy) ? candidate.policy : {})
      }
    };

    const parsed = controlPlaneConfigSchema.safeParse(nextConfig);
    if (!parsed.success) {
      return jsonError(reply, 'Invalid browser config payload', 400, {
        issues: parsed.error.issues.map((issue) => ({
          path: issue.path.join('.'),
          message: issue.message
        }))
      });
    }

    database.upsertRuntimeConfigOverlay(parsed.data as unknown as Record<string, unknown>);
    config.browser = parsed.data.browser;
    configValidationResult = null;
    database.appendAudit({
      actor,
      action: 'browser.config.update',
      resource: RUNTIME_CONFIG_OVERLAY_RESOURCE,
      decision: 'allowed',
      reason: 'saved',
      details: {
        enabled: config.browser.enabled,
        transport: config.browser.transport,
        allowStealth: config.browser.policy.allowStealth,
        requireApprovalForStealth: config.browser.policy.requireApprovalForStealth,
        allowedAgents: config.browser.allowedAgents
      },
      correlationId: randomUUID()
    });
    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'info',
      message: 'Browser capability policy updated',
      data: {
        actor,
        restartRequired: false,
        enabled: config.browser.enabled,
        transport: config.browser.transport
      }
    });
    return jsonOk(reply, {
      saved: true,
      restartRequired: false,
      status: browserCapabilityService.status(),
      config: browserConfigPayload()
    });
  });

