  app.post('/api/browser/test', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const url = typeof body.url === 'string' ? body.url.trim() : '';
    if (!url) {
      return jsonError(reply, 'url is required', 400);
    }

    const requestedAgentId = typeof body.agentId === 'string' && body.agentId.trim().length > 0 ? body.agentId.trim() : null;
    const profile = resolveBrowserTestProfile(requestedAgentId);
    if (!profile) {
      return jsonError(reply, requestedAgentId ? `Agent profile not found: ${requestedAgentId}` : 'No enabled browser-capable agent is available.', requestedAgentId ? 404 : 409, {
        guidance: requestedAgentId
          ? 'Choose an existing enabled agent profile or omit agentId to use the default browser-capable profile.'
          : 'Complete CEO onboarding or enable browser capability for at least one agent profile before running browser tests.'
      });
    }

    const session = database.upsertSessionByKey({
      sessionKey: `api:browser:test:${profile.id}:${randomUUID().slice(0, 8)}`,
      channel: 'internal',
      chatType: 'internal',
      agentId: profile.id,
      preferredRuntime: 'process',
      metadata: {
        source: 'browser_api',
        label: 'Browser API test',
        browserTest: true
      }
    });
    const run = database.createRun({
      sessionId: session.id,
      runtime: 'process',
      requestedRuntime: 'process',
      effectiveRuntime: 'process',
      triggerSource: 'api',
      prompt: `Browser API test for ${url}`,
      status: 'running'
    });

    try {
      const result = await browserCapabilityService.execute({
        runId: run.id,
        sessionId: session.id,
        agentId: profile.id,
        agentTools: profile.tools,
        workspacePath: resolveSessionWorkspacePath(session),
        request: {
          url,
          urls: Array.isArray(body.urls)
            ? body.urls.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0)
            : undefined,
          intent:
            typeof body.intent === 'string' && body.intent.trim().length > 0
              ? (body.intent.trim() as
                  | 'article_read'
                  | 'document_lookup'
                  | 'structured_extract'
                  | 'dynamic_app'
                  | 'monitor'
                  | 'download_probe')
              : 'document_lookup',
          extractionMode:
            typeof body.extractionMode === 'string' && body.extractionMode.trim().length > 0
              ? (body.extractionMode.trim() as 'markdown' | 'html' | 'text')
              : undefined,
          dynamicLikely: body.dynamicLikely === true,
          requiresStealth: body.requiresStealth === true,
          requiresProxy: body.requiresProxy === true,
          requiresVisibleBrowser: body.requiresVisibleBrowser === true,
          requiresDownload: body.requiresDownload === true,
          mainContentOnly: body.mainContentOnly === true,
          cacheTtlMs: Number.isFinite(Number(body.cacheTtlMs)) ? Number(body.cacheTtlMs) : undefined,
          extractorId: parseBrowserExtractorIdInput(body.extractorId) ?? undefined,
          selector: typeof body.selector === 'string' && body.selector.trim().length > 0 ? body.selector.trim() : undefined,
          waitSelector:
            typeof body.waitSelector === 'string' && body.waitSelector.trim().length > 0 ? body.waitSelector.trim() : undefined,
          locale: typeof body.locale === 'string' && body.locale.trim().length > 0 ? body.locale.trim() : undefined,
          countryCode:
            typeof body.countryCode === 'string' && body.countryCode.trim().length > 0
              ? body.countryCode.trim().toUpperCase()
              : undefined,
          timezoneId:
            typeof body.timezoneId === 'string' && body.timezoneId.trim().length > 0 ? body.timezoneId.trim() : undefined,
          verifyTls: body.verifyTls === false ? false : undefined,
          extraHeaders: parseOptionalStringMap(body.extraHeaders),
          extraCookies: parseOptionalStringMap(body.extraCookies),
          useRealChrome: body.useRealChrome === true,
          sessionProfileId:
            typeof body.sessionProfileId === 'string' && body.sessionProfileId.trim().length > 0
              ? body.sessionProfileId.trim()
              : undefined,
          cookieJarId:
            typeof body.cookieJarId === 'string' && body.cookieJarId.trim().length > 0 ? body.cookieJarId.trim() : undefined,
          headersProfileId:
            typeof body.headersProfileId === 'string' && body.headersProfileId.trim().length > 0
              ? body.headersProfileId.trim()
              : undefined,
          proxyProfileId:
            typeof body.proxyProfileId === 'string' && body.proxyProfileId.trim().length > 0 ? body.proxyProfileId.trim() : undefined,
          storageStateId:
            typeof body.storageStateId === 'string' && body.storageStateId.trim().length > 0
              ? body.storageStateId.trim()
              : undefined,
          suspiciousPromptInjection: body.suspiciousPromptInjection === true,
          previewChars: Number.isFinite(Number(body.previewChars)) ? Number(body.previewChars) : undefined
        }
      });
      database.updateRunStatus({
        runId: run.id,
        status: result.ok ? 'completed' : 'failed',
        error: result.ok ? null : result.error ?? result.blockedReason ?? 'browser_test_failed',
        resultSummary: result.ok
          ? `Browser test completed via ${result.selectedTool ?? 'browser'}`
          : `Browser test failed: ${result.error ?? result.blockedReason ?? 'browser_test_failed'}`
      });

      const trace = browserCapabilityService.describeRun(run.id);
      return jsonOk(reply, {
        run: database.getRunById(run.id),
        test: trace ? serializeBrowserTrace(trace) : result,
        status: browserCapabilityService.status()
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      database.updateRunStatus({
        runId: run.id,
        status: 'failed',
        error: message,
        resultSummary: `Browser test failed: ${message}`
      });
      return jsonError(reply, message, 500, {
        runId: run.id
      });
    }
  });

