  app.get('/api/browser/artifacts/:handle', async (request, reply) => {
    const params = request.params as { handle: string };
    const query = request.query as Record<string, unknown>;
    const artifact = await browserCapabilityService.inspectArtifact(params.handle);
    if (!artifact) {
      return jsonError(reply, 'Browser artifact not found', 404);
    }

    const download = String(query.download ?? '0').trim().toLowerCase();
    if (download === '1' || download === 'true') {
      reply.header('content-disposition', `attachment; filename="${artifact.fileName}"`);
      return reply.type(artifact.mimeType).send(artifact.content);
    }

    return jsonOk(reply, {
      artifact: serializeBrowserArtifactContent(artifact)
    });
  });

  app.post('/api/bootstrap/vendor', async (request, reply) => {
    if (!hasValidApiToken(request, config.server.apiToken)) {
      return jsonError(reply, 'Unauthorized', 401);
    }

    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = typeof body.actor === 'string' && body.actor.trim().length > 0 ? body.actor.trim() : 'dashboard';
    const targetRaw = typeof body.target === 'string' ? body.target.trim().toLowerCase() : 'all';
    const target: VendorBootstrapTarget | null =
      targetRaw === 'skills' || targetRaw === 'tools' || targetRaw === 'all' || targetRaw === 'baseline-skills'
        ? targetRaw
        : null;

    if (!target) {
      return jsonError(reply, 'target must be one of: tools, skills, all, baseline-skills', 400);
    }

    if (vendorBootstrapInFlight) {
      return jsonError(reply, 'Vendor bootstrap already in progress', 409, {
        inFlight: vendorBootstrapInFlight
      });
    }

    vendorBootstrapInFlight = {
      target,
      startedAt: utcNow()
    };

    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'info',
      message: `Vendor bootstrap started (${target})`,
      data: {
        actor,
        target
      }
    });

    try {
      const result = await runVendorBootstrap(target);
      emitEvent({
        kind: 'system.info',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: result.status === 'ok' ? 'info' : 'warn',
        message: `Vendor bootstrap ${result.status} (${target})`,
        data: {
          actor,
          target,
          stepCount: result.steps.length,
          warnings: result.warnings
        }
      });
      return jsonOk(reply, {
        result
      });
    } finally {
      vendorBootstrapInFlight = null;
    }
  });

  app.patch('/api/tools/:toolName', async (request, reply) => {
    const params = request.params as { toolName: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const enabled = Boolean(body.enabled);
    const existing = database.getTool(params.toolName);
    if (!existing) {
      return jsonError(reply, `Tool not found: ${params.toolName}`, 404);
    }

    const updated = database.setToolEnabled(params.toolName, enabled);
    if (!updated) {
      return jsonError(reply, `Tool not found: ${params.toolName}`, 404);
    }

    emitEvent({
      kind: 'tool.policy.updated',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'info',
      message: `Tool ${params.toolName} ${enabled ? 'enabled' : 'disabled'}`,
      data: {
        tool: params.toolName,
        enabled
      }
    });

    return jsonOk(reply, {
      tool: updated
    });
  });

  app.get('/api/llm/limits', async (_request, reply) => {
    try {
      const stored = database.getLlmLimits();
      if (stored) {
        llmLimits = mergeLlmLimits(structuredClone(DEFAULT_LLM_LIMITS), normalizeLlmLimits(parseJsonSafe(stored.limitsJson, {})));
        syncLlmValidationState();
      }
      const onboarding = llmOnboardingState();
      const requirements = llmCredentialRequirements(llmLimits);
      return jsonOk(reply, {
        limits: llmLimits,
        updatedAt: stored?.updatedAt ?? null,
        registry: buildLlmModelRegistry(),
        validation: llmValidationState,
        onboarding: {
          ...onboarding,
          requirements
        }
      });
    } catch (error) {
      const onboarding = llmOnboardingState();
      const requirements = llmCredentialRequirements(llmLimits);
      const message = error instanceof Error ? error.message : String(error);
      emitEvent({
        kind: 'system.info',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'warn',
        message: 'Failed to load persisted LLM limits; serving in-memory defaults.',
        data: { error: message }
      });
      return jsonOk(reply, {
        limits: llmLimits,
        updatedAt: null,
        registry: buildLlmModelRegistry(),
        validation: llmValidationState,
        onboarding: {
          ...onboarding,
          requirements
        },
        warning: 'Persisted limits unavailable; using in-memory defaults.'
      });
    }
  });

  app.put('/api/llm/limits', async (request, reply) => {
    if (!hasValidApiToken(request, config.server.apiToken)) {
      return jsonError(reply, 'Unauthorized', 401);
    }

    const body = (request.body ?? {}) as Record<string, unknown>;
    const candidate = body.limits ?? body;
    if (!isRecord(candidate)) {
      return jsonError(reply, 'Invalid llm limits payload', 400);
    }
    const validationError = validateLlmLimitsPayload(candidate);
    if (validationError) {
      return jsonError(reply, validationError, 400);
    }

    const nextLimits = mergeLlmLimits(structuredClone(DEFAULT_LLM_LIMITS), normalizeLlmLimits(candidate));
    const missingPrimary = missingPrimaryRuntimes(nextLimits);
    if (missingPrimary.worker.length > 0 || missingPrimary.orchestrator.length > 0) {
      return jsonError(reply, 'Primary model must be set for all runtimes', 400, {
        missingPrimaryByPolicy: missingPrimary
      });
    }
    const validation = validateLlmLimitsAgainstRegistry(nextLimits);
    if (!validation.valid) {
      return jsonError(reply, 'Invalid LLM model routing policy', 400, {
        validation,
        registry: buildLlmModelRegistry()
      });
    }
    const saved = writeLlmLimits(nextLimits);

    emitEvent({
      kind: 'system.info',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'info',
      message: 'LLM limits updated',
      data: {
        actor: String(body.actor ?? 'operator')
      }
    });

    return jsonOk(reply, {
      limits: saved,
      updatedAt: database.getLlmLimits()?.updatedAt ?? utcNow(),
      registry: buildLlmModelRegistry(),
      validation: llmValidationState
    });
  });

  app.get('/api/llm/costs', async (request, reply) => {
    try {
      const query = request.query as Record<string, unknown>;
      const now = utcNow();
      const fallbackDay = now.slice(0, 10);
      const fallbackMonth = now.slice(0, 7);
      const requestedOffsetRaw =
        typeof query.tzOffsetMinutes === 'string' || typeof query.tzOffsetMinutes === 'number'
          ? Number(query.tzOffsetMinutes)
          : Number.NaN;
      const hasOffset = Number.isFinite(requestedOffsetRaw) && requestedOffsetRaw >= -840 && requestedOffsetRaw <= 840;

      let dayKey = typeof query.day === 'string' && isIsoDay(query.day) ? query.day : fallbackDay;
      let monthKey = typeof query.month === 'string' && isIsoMonth(query.month) ? query.month : dayKey.slice(0, 7) || fallbackMonth;
      let windowMode: 'utc' | 'local' = 'utc';
      let offsetMinutes = 0;

      let snapshot;
      const snapshotByRange = (
        database as unknown as {
          getLlmCostsSnapshotByRange?: (input: {
            dayStartTs: string;
            dayEndTs: string;
            monthStartTs: string;
            monthEndTs: string;
            recentLimit?: number;
          }) => ReturnType<ControlPlaneDatabase['getLlmCostsSnapshot']>;
        }
      ).getLlmCostsSnapshotByRange;
      if (hasOffset && typeof snapshotByRange === 'function') {
        windowMode = 'local';
        offsetMinutes = Math.trunc(requestedOffsetRaw);
        const fallbackLocalDay = dayAtOffset(new Date(), offsetMinutes);
        dayKey = typeof query.day === 'string' && isIsoDay(query.day) ? query.day : fallbackLocalDay;
        monthKey = typeof query.month === 'string' && isIsoMonth(query.month) ? query.month : dayKey.slice(0, 7);

        const dayRange = localDayRangeToUtc(dayKey, offsetMinutes);
        const monthRange = localMonthRangeToUtc(monthKey, offsetMinutes);
        if (!dayRange || !monthRange) {
          return jsonError(reply, 'Invalid local day/month window', 400);
        }
        snapshot = snapshotByRange.call(database, {
          dayStartTs: dayRange.startTs,
          dayEndTs: dayRange.endTs,
          monthStartTs: monthRange.startTs,
          monthEndTs: monthRange.endTs,
          recentLimit: 200
        });
      } else {
        if (hasOffset && typeof snapshotByRange !== 'function') {
          emitEvent({
            kind: 'system.info',
            lane: config.queue.defaultLane,
            sessionId: null,
            runId: null,
            level: 'warn',
            message: 'Local-window LLM cost snapshot unavailable on this runtime; using UTC fallback.',
            data: { dayUtc: dayKey, monthUtc: monthKey }
          });
        }
        snapshot = database.getLlmCostsSnapshot({
          dayUtc: dayKey,
          monthUtc: monthKey
        });
      }

      const costs = {
        ...snapshot,
        providerDaily: snapshot.providerDaily.filter((row) => row.provider === 'openrouter' || row.provider === 'google'),
        providerMonthly: snapshot.providerMonthly.filter((row) => row.provider === 'openrouter' || row.provider === 'google'),
        modelDaily: snapshot.modelDaily.filter((row) => row.provider === 'openrouter' || row.provider === 'google'),
        recentEvents: snapshot.recentEvents.filter((row) => row.provider === 'openrouter' || row.provider === 'google')
      };

      const providerBudgetStatus = costs.providerDaily
        .map((row) => {
          const provider = row.provider as LlmProviderKey;
          const callBudget = llmLimits.providerCallBudgetDaily[provider];
          const costBudgetDay = llmLimits.providerCostBudgetUsdDaily[provider];
          const costBudgetMonth = llmLimits.providerCostBudgetUsdMonthly[provider];
          const monthlyRow = costs.providerMonthly.find((entry) => entry.provider === row.provider);

          return {
            provider: row.provider,
            dayCalls: row.calls,
            dayCostUsd: row.costUsd,
            monthCostUsd: monthlyRow?.costUsd ?? 0,
            budgets: {
              dailyCalls: callBudget ?? null,
              dailyCostUsd: costBudgetDay ?? null,
              monthlyCostUsd: costBudgetMonth ?? null
            },
            exhausted: {
              dailyCalls: typeof callBudget === 'number' ? row.calls >= callBudget : false,
              dailyCostUsd: typeof costBudgetDay === 'number' ? row.costUsd >= costBudgetDay : false,
              monthlyCostUsd:
                typeof costBudgetMonth === 'number' ? (monthlyRow?.costUsd ?? 0) >= costBudgetMonth : false
            }
          };
        });

      return jsonOk(reply, {
        window: {
          dayUtc: dayKey,
          monthUtc: monthKey,
          mode: windowMode,
          tzOffsetMinutes: offsetMinutes
        },
        costs,
        providerBudgetStatus
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      emitEvent({
        kind: 'system.info',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'warn',
        message: 'Failed to load LLM costs snapshot; serving empty fallback payload.',
        data: { error: message }
      });
      return jsonOk(reply, {
        window: {
          dayUtc: utcNow().slice(0, 10),
          monthUtc: utcNow().slice(0, 7),
          mode: 'utc',
          tzOffsetMinutes: 0
        },
        costs: {
          providerDaily: [],
          providerMonthly: [],
          modelDaily: [],
          recentEvents: []
        },
        providerBudgetStatus: [],
        warning: 'LLM costs temporarily unavailable; fallback payload served.'
      });
    }
  });

  app.get('/api/llm/routing/effective', async (request, reply) => {
    const query = request.query as Record<string, unknown>;
    const runtimeFilter = typeof query.runtime === 'string' ? query.runtime.trim() : '';
    if (runtimeFilter && !['codex', 'claude', 'gemini', 'process'].includes(runtimeFilter)) {
      return jsonError(reply, `Unsupported runtime: ${runtimeFilter}`, 400);
    }
    const policyRaw = typeof query.policy === 'string' ? query.policy.trim().toLowerCase() : '';
    const policy: LlmRoutePolicy = policyRaw === 'orchestrator' ? 'orchestrator' : 'worker';
    const modelFilter = normalizeModelInput(typeof query.model === 'string' ? query.model : null);
    const maps = llmPolicyMaps(llmLimits, policy);

    const runtimes = runtimeFilter
      ? ([runtimeFilter] as RuntimeKind[])
      : runtimeManager.availableRuntimes().map((item) => item.kind);

    const routes = runtimes.map((runtime) => {
      const decision = selectBudgetEligibleRoute(runtime, modelFilter, policy);
      return {
        runtime,
        policy,
        requestedModel: modelFilter,
        primaryModel: maps.primary[runtime] ?? null,
        strictPrimary: maps.strictPrimary[runtime] ?? false,
        localHarness: maps.localHarness[runtime] ?? false,
        selected: decision.selected,
        reason: decision.reason,
        validation: {
          valid: decision.configDiagnostics.length === 0,
          diagnostics: decision.configDiagnostics
        },
        checks: decision.checks
      };
    });

    return jsonOk(reply, {
      limits: llmLimits,
      registry: buildLlmModelRegistry(),
      validation: llmValidationState,
      routes
    });
  });

