  app.post('/api/skills/catalog/entries/upsert', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const approved = Boolean(body.approved ?? false);
    const pathInput = String(body.path ?? '').trim();
    if (!pathInput) {
      return jsonError(reply, 'path is required', 400);
    }

    const installerPolicy = skillRegistry.installerPolicy();
    if (installerPolicy.requireApproval && !approved) {
      const operation = database.appendSkillCatalogOperation({
        action: 'catalog_upsert',
        sourceRef: pathInput,
        actor,
        status: 'blocked',
        summary: 'Catalog update requires approval',
        details: {
          approved: false
        }
      });
      return jsonError(reply, 'Catalog update requires approval', 403, {
        operationId: operation.id
      });
    }

    const normalizedEntry: SkillCatalogEntry = {
      path: pathInput,
      ...(typeof body.name === 'string' && body.name.trim().length > 0 ? { name: body.name.trim() } : {}),
      ...(typeof body.enabled === 'boolean' ? { enabled: body.enabled } : {}),
      ...(typeof body.requiresApproval === 'boolean' ? { requiresApproval: body.requiresApproval } : {}),
      ...(typeof body.supportsDryRun === 'boolean' ? { supportsDryRun: body.supportsDryRun } : {}),
      ...(parseOptionalBodyStringArray(body.tags) ? { tags: parseOptionalBodyStringArray(body.tags) } : {}),
      ...(parseOptionalBodyStringArray(body.allowedCommands)
        ? { allowedCommands: parseOptionalBodyStringArray(body.allowedCommands) }
        : {}),
      ...(parseOptionalBodyStringArray(body.requiredTools) ? { requiredTools: parseOptionalBodyStringArray(body.requiredTools) } : {})
    };

    try {
      const entries = await skillRegistry.upsertCatalogEntry({
        entry: normalizedEntry
      });
      const loaded = await skillRegistry.load();
      syncToolRegistry();
      const operation = database.appendSkillCatalogOperation({
        action: 'catalog_upsert',
        sourceRef: pathInput,
        actor,
        status: 'ok',
        summary: `Catalog entry upserted (${pathInput})`,
        details: {
          entry: normalizedEntry
        }
      });
      return jsonOk(reply, {
        operation,
        entries,
        skills: loaded
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      const operation = database.appendSkillCatalogOperation({
        action: 'catalog_upsert',
        sourceRef: pathInput,
        actor,
        status: 'error',
        summary: 'Catalog entry upsert failed',
        details: {
          error: message
        }
      });
      return jsonError(reply, message, 500, {
        operationId: operation.id
      });
    }
  });

