  app.post('/api/skills/install', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const source = String(body.source ?? '').trim();
    const selectedSkills = parseOptionalBodyStringArray(body.selectedSkills);
    const approved = Boolean(body.approved ?? false);
    if (!source) {
      return jsonError(reply, 'source is required (skills.sh URL, owner/repo, github URL, or npx skills add command)', 400);
    }

    const installTarget = skillRegistry.resolveInstallTarget(source, selectedSkills);
    if (!installTarget) {
      database.appendSkillCatalogOperation({
        action: 'install',
        sourceRef: source,
        actor,
        status: 'blocked',
        summary: 'Invalid source reference',
        details: { source }
      });
      return jsonError(
        reply,
        'Invalid source reference. Expected a skills.sh URL, owner/repo, github URL, or npx skills add command.',
        400
      );
    }

    const sourcePolicy = skillRegistry.validateInstallerSource(installTarget.source);
    if (!sourcePolicy.allowed) {
      database.appendSkillCatalogOperation({
        action: 'install',
        sourceRef: installTarget.source.canonical,
        actor,
        status: 'blocked',
        summary: 'Installer source blocked by policy',
        details: { reason: sourcePolicy.reason }
      });
      return jsonError(reply, sourcePolicy.reason ?? 'Installer source blocked by policy', 403);
    }

    const installerPolicy = skillRegistry.installerPolicy();
    if (installerPolicy.requireApproval && !approved) {
      const operation = database.appendSkillCatalogOperation({
        action: 'install',
        sourceRef: installTarget.source.canonical,
        actor,
        status: 'blocked',
        summary: 'Install requires approval',
        details: {
          approved: false,
          selectedSkills: installTarget.selectedSkills
        }
      });
      return jsonError(reply, 'Install requires approval', 403, {
        operationId: operation.id
      });
    }

    const readiness = skillInstallerReadiness();
    if (!readiness.ready) {
      database.appendSkillCatalogOperation({
        action: 'install',
        sourceRef: installTarget.source.canonical,
        actor,
        status: 'blocked',
        summary: 'Installer prerequisites missing',
        details: { readiness }
      });
      return jsonError(reply, 'Installer prerequisites missing. See readiness details.', 409, { readiness });
    }

    try {
      const installation = await skillRegistry.installExternal({
        source,
        actor,
        approved,
        selectedSkills
      });
      const operation = database.appendSkillCatalogOperation({
        action: 'install',
        sourceRef: installTarget.source.canonical,
        actor,
        status: 'ok',
        summary:
          installation.selectedSkills.length > 0
            ? `Installed ${installTarget.source.canonical} (${installation.selectedSkills.length} selected skill${installation.selectedSkills.length === 1 ? '' : 's'})`
            : `Installed ${installTarget.source.canonical}`,
        details: {
          installRoot: installation.installRoot,
          installSource: installation.installSource,
          selectedSkills: installation.selectedSkills,
          installedSkillNames: installation.installedSkills.map((skill) => skill.name),
          stdout: installation.stdout.slice(0, 4000),
          stderr: installation.stderr.slice(0, 4000)
        }
      });
      syncToolRegistry();
      emitEvent({
        kind: 'system.info',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'info',
        message: `External skill install succeeded (${installTarget.source.canonical})`,
        data: {
          operationId: operation.id,
          installedSkills: installation.installedSkills.map((skill) => skill.name),
          selectedSkills: installation.selectedSkills
        }
      });
      return jsonOk(reply, {
        installation,
        operation,
        readiness: skillInstallerReadiness(),
        skills: skillRegistry.list()
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      const operation = database.appendSkillCatalogOperation({
        action: 'install',
        sourceRef: installTarget.source.canonical,
        actor,
        status: 'error',
        summary: 'External skill install failed',
        details: {
          error: message
        }
      });
      return jsonError(reply, message, 500, {
        operationId: operation.id
      });
    }
  });

