  app.post('/api/skills/autodiscover', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = String(body.actor ?? 'operator').trim() || 'operator';
    const approved = Boolean(body.approved ?? false);
    const installerPolicy = skillRegistry.installerPolicy();
    if (installerPolicy.requireApproval && !approved) {
      const operation = database.appendSkillCatalogOperation({
        action: 'resync',
        sourceRef: null,
        actor,
        status: 'blocked',
        summary: 'Autodiscover requires approval',
        details: {
          approved: false
        }
      });
      return jsonError(reply, 'Autodiscover requires approval', 403, {
        operationId: operation.id
      });
    }

    const roots =
      Array.isArray(body.roots) && body.roots.length > 0
        ? body.roots.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0)
        : [config.runtime.workspaceRoot];
    const depthRaw = Number(body.depth ?? 6);
    const depth = Number.isFinite(depthRaw) ? Math.max(1, Math.min(12, Math.floor(depthRaw))) : 6;

    try {
      const discovery = await skillRegistry.autodiscover({
        roots,
        depth
      });
      const loaded = await skillRegistry.load();
      syncToolRegistry();
      const operation = database.appendSkillCatalogOperation({
        action: 'resync',
        sourceRef: roots.join(','),
        actor,
        status: 'ok',
        summary: 'Skill catalog autodiscovered from roots',
        details: {
          roots: discovery.roots,
          depth,
          discoveredDirectories: discovery.discoveredDirectories.slice(0, 100),
          addedEntries: discovery.addedEntries,
          loadedCount: loaded.length
        }
      });
      return jsonOk(reply, {
        operation,
        discovery: {
          roots: discovery.roots,
          depth,
          discoveredDirectories: discovery.discoveredDirectories,
          addedEntries: discovery.addedEntries
        },
        skills: loaded,
        entries: discovery.entries
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      const operation = database.appendSkillCatalogOperation({
        action: 'resync',
        sourceRef: roots.join(','),
        actor,
        status: 'error',
        summary: 'Skill autodiscover failed',
        details: {
          error: message
        }
      });
      return jsonError(reply, message, 500, {
        operationId: operation.id
      });
    }
  });

  app.post('/api/skills/reload', async (_request, reply) => {
    try {
      await skillRegistry.autodiscover({
        roots: config.skills.directories,
        depth: 4
      });
    } catch {
      // Reload should still succeed even when some optional roots are absent.
    }
    const loaded = await skillRegistry.load();
    syncToolRegistry();
    return jsonOk(reply, {
      skills: loaded,
      count: loaded.length
    });
  });

  app.post('/api/skills/:skillName/invoke', async (request, reply) => {
    const params = request.params as { skillName: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const manifest = skillRegistry.get(params.skillName);
    if (!manifest) {
      return jsonError(reply, `Skill not found: ${params.skillName}`, 404);
    }

    for (const requiredTool of manifest.requiredTools ?? []) {
      const binary = normalizeToolName(requiredTool);
      if (!binary) {
        continue;
      }
      const policy = database.getTool(binary);
      if (policy && !policy.enabled) {
        return jsonError(reply, `Skill blocked: tool ${binary} is disabled by policy`, 403);
      }
      if (policy && !policy.installed) {
        return jsonError(reply, `Skill blocked: required tool ${binary} is not installed`, 403);
      }
    }

    try {
      const result = await skillRegistry.invoke({
        name: params.skillName,
        payload: (body.payload ?? {}) as Record<string, unknown>,
        dryRun: Boolean(body.dryRun ?? false),
        approved: Boolean(body.approved ?? false),
        actor: String(body.actor ?? 'operator'),
        correlationId: String(body.correlationId ?? randomUUID())
      });

      emitEvent({
        kind: 'skill.called',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'info',
        message: `Skill ${params.skillName} invoked`,
        data: {
          dryRun: Boolean(body.dryRun ?? false)
        }
      });

      return jsonOk(reply, {
        result
      });
    } catch (error) {
      emitEvent({
        kind: 'skill.denied',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'warn',
        message: `Skill ${params.skillName} blocked`,
        data: {
          error: error instanceof Error ? error.message : String(error)
        }
      });

      return jsonError(reply, error instanceof Error ? error.message : 'Skill invocation failed', 403);
    }
  });

  app.get('/api/pairings', async (request, reply) => {
    const query = request.query as Record<string, unknown>;
    const status = query.status as PairingRecord['status'] | undefined;
    return jsonOk(reply, {
      pairings: database.listPairings(status)
    });
  });

  app.post('/api/pairings/:channel/:senderId/approve', async (request, reply) => {
    const params = request.params as { channel: PairingRecord['channel']; senderId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const pair = database.decidePairing({
      channel: params.channel,
      senderId: params.senderId,
      status: 'approved',
      decidedBy: String(body.actor ?? 'operator')
    });

    return jsonOk(reply, { pairing: pair });
  });

  app.post('/api/pairings/:channel/:senderId/revoke', async (request, reply) => {
    const params = request.params as { channel: PairingRecord['channel']; senderId: string };
    const body = (request.body ?? {}) as Record<string, unknown>;
    const pair = database.decidePairing({
      channel: params.channel,
      senderId: params.senderId,
      status: 'revoked',
      decidedBy: String(body.actor ?? 'operator')
    });

    return jsonOk(reply, { pairing: pair });
  });

  app.post('/api/ingress/telegram', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const ingressMode = String(request.headers['x-ops-telegram-mode'] ?? 'ingress')
      .trim()
      .toLowerCase();

    if (!config.channel.telegram.enabled) {
      return jsonOk(reply, {
        status: 'ignored',
        reason: 'telegram_disabled'
      });
    }
    if (!hasTelegramBotTokenConfigured()) {
      return jsonOk(reply, {
        status: 'ignored',
        reason: 'telegram_token_unavailable'
      });
    }

    if (config.channel.telegram.useWebhook && ingressMode !== 'webhook') {
      return jsonOk(reply, {
        status: 'ignored',
        reason: 'webhook_mode_enabled_use_webhook_endpoint'
      });
    }

    if (!config.channel.telegram.useWebhook && ingressMode === 'webhook') {
      return jsonOk(reply, {
        status: 'ignored',
        reason: 'webhook_mode_disabled_use_ingress_endpoint'
      });
    }

    const message = parseTelegramMessage(body);

    if (message.chatType === 'direct') {
      void syncTelegramCommandMenus({
        reason: 'ingress',
        chatId: message.chatId,
        userId: message.senderId
      });
    }

    if (!message.text && message.attachments.length === 0) {
      return jsonOk(reply, {
        status: 'ignored',
        reason: 'empty_message'
      });
    }

    if (message.chatType !== 'direct' && config.channel.telegram.requireMentionInGroups && !message.mentionBot) {
      return jsonOk(reply, {
        status: 'ignored',
        reason: 'mention_required'
      });
    }

    if (config.channel.telegram.allowlist.length > 0 && !config.channel.telegram.allowlist.includes(message.senderId)) {
      database.createPairingRequest({
        channel: 'telegram',
        senderId: message.senderId,
        senderHandle: message.senderHandle
      });
      await sendTelegramDirectNotice({
        chatId: message.chatId,
        topicId: message.topicId ?? null,
        text:
          'I received your message, but this Telegram account is not approved for this workspace yet.\n\nAsk an operator to review Telegram access policy or approve your account, then try again.',
        throttleKey: `allowlist:${message.chatId}:${message.senderId}`,
        metadata: {
          reason: 'allowlist',
          senderId: message.senderId
        }
      });
      return jsonOk(reply, {
        status: 'blocked',
        reason: 'allowlist'
      });
    }

    if (config.policy.requirePairing && message.chatType === 'direct') {
      const pairing = database.getPairing('telegram', message.senderId);
      if (!pairing || pairing.status !== 'approved') {
        database.createPairingRequest({
          channel: 'telegram',
          senderId: message.senderId,
          senderHandle: message.senderHandle
        });
        await sendTelegramDirectNotice({
          chatId: message.chatId,
          topicId: message.topicId ?? null,
          text:
            'I received your message, but this workspace requires Telegram pairing before I can reply.\n\nAsk an operator to approve your Telegram pairing, then send your message again.',
          throttleKey: `pairing:${message.chatId}:${message.senderId}`,
          metadata: {
            reason: 'pairing_required',
            senderId: message.senderId
          }
        });
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'pairing_required'
        });
      }
    }

    const sessionKey = resolveSessionKey({
      channel: 'telegram',
      chatType: message.chatType,
      chatId: message.chatId,
      topicId: message.topicId,
      senderId: message.senderId,
      botId: 'telegram-bot',
      accountId: 'default',
      dmScope: config.channel.telegram.dmScope
    });

    const command = message.text.trim();
    if (command.toLowerCase().startsWith('/link')) {
      if (message.chatType !== 'direct') {
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'link_requires_direct_chat'
        });
      }

      const code = command.replace(/^\/link\b/i, '').trim();
      if (!code) {
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'missing_link_code'
        });
      }

      const pendingLink = consumeSessionLinkCode(code);
      if (!pendingLink) {
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'invalid_or_expired_link_code'
        });
      }

      const targetSession = database.getSessionById(pendingLink.sessionId);
      if (!targetSession) {
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'linked_session_not_found'
        });
      }

      telegramSessionBindings.set(sessionKey.key, {
        sessionId: targetSession.id,
        sessionKey: sessionKey.key,
        chatId: message.chatId,
        topicId: message.topicId ?? null,
        linkedAt: utcNow(),
        linkedBy: message.senderId
      });
      database.touchSession(targetSession.id);
      ensureOfficePresenceForSession(targetSession, {
        reason: 'Telegram link presence synchronized',
        onlyIfMissing: true
      });
      await saveOutboundMessage(
        targetSession,
        'system',
        'system',
        `Telegram chat linked to session via /link (${message.senderHandle}).`,
        {
          command: 'link',
          senderId: message.senderId,
          chatId: message.chatId,
          linkedAt: utcNow()
        }
      );

      emitEvent({
        kind: 'system.info',
        lane: config.queue.defaultLane,
        sessionId: targetSession.id,
        runId: null,
        level: 'info',
        message: 'Telegram linked to existing session',
        data: {
          sessionKey: targetSession.sessionKey,
          senderId: message.senderId
        }
      });

      return jsonOk(reply, {
        status: 'command_applied',
        command: 'link',
        linked: true,
        sessionId: targetSession.id,
        sessionKey: targetSession.sessionKey
      });
    }

    if (command.toLowerCase().startsWith('/unlink')) {
      const removed = telegramSessionBindings.delete(sessionKey.key);
      return jsonOk(reply, {
        status: removed ? 'command_applied' : 'ignored',
        command: 'unlink',
        unlinked: removed
      });
    }

    const bound = telegramSessionBindings.get(sessionKey.key);
    let session = bound ? database.getSessionById(bound.sessionId) : undefined;
    if (bound && !session) {
      telegramSessionBindings.delete(sessionKey.key);
    }
    const ingressProfile = getDefaultIngressAgentProfile();
    const ingressAgentId = getDefaultIngressAgentId();
    const ingressRuntime = getDefaultIngressRuntime();
    const ingressModel = getDefaultIngressModel();

    if (!session) {
      if (!ingressProfile || !ingressAgentId || !ingressRuntime) {
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'onboarding_required',
          detail: 'Create the CEO baseline from onboarding before Telegram ingress can open sessions.'
        });
      }
      session = database.upsertSessionByKey({
        sessionKey: sessionKey.key,
        channel: 'telegram',
        chatType: sessionChatType(message.chatType),
        agentId: ingressAgentId,
        preferredRuntime: ingressRuntime,
        preferredModel: ingressModel,
        metadata: {
          chatId: message.chatId,
          topicId: message.topicId,
          senderId: message.senderId,
          senderHandle: message.senderHandle,
          lastInboundAt: utcNow(),
          agentProfileId: ingressProfile?.id ?? null,
          agentTitle: ingressProfile?.title ?? null
        }
      });
      ensureOfficePresenceForSession(session, {
        reason: 'Telegram session presence synchronized',
        activityLabel: ingressProfile?.title ?? 'Ready',
        onlyIfMissing: true
      });
    } else {
      const sessionProfile = getAgentProfileById(session.agentId);
      const stalePrimaryCeoSession =
        Boolean(ingressAgentId) && session.agentId !== ingressAgentId && /^ceo-/i.test(session.agentId);
      const disabledProfileSession = Boolean(sessionProfile && !sessionProfile.enabled);
      const shouldRebindToDefaultIngress =
        Boolean(ingressProfile && ingressAgentId && ingressRuntime) && (stalePrimaryCeoSession || disabledProfileSession);
      if (shouldRebindToDefaultIngress && ingressAgentId && ingressRuntime) {
        const previousAgentId = session.agentId;
        const existingMetadata = parseJsonSafe<Record<string, unknown>>(session.metadataJson, {});
        session = database.upsertSessionByKey({
          sessionKey: session.sessionKey,
          channel: session.channel,
          chatType: session.chatType,
          agentId: ingressAgentId,
          preferredRuntime: ingressRuntime,
          preferredModel: ingressModel,
          metadata: {
            ...existingMetadata,
            chatId: message.chatId,
            topicId: message.topicId,
            senderId: message.senderId,
            senderHandle: message.senderHandle,
            lastInboundAt: utcNow(),
            agentProfileId: ingressProfile?.id ?? null,
            agentTitle: ingressProfile?.title ?? null,
            migratedFromAgentId: previousAgentId,
            migratedAt: utcNow(),
            migratedReason: stalePrimaryCeoSession ? 'stale_telegram_ceo_session' : 'disabled_agent_profile'
          }
        });
        emitEvent({
          kind: 'system.info',
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: null,
          level: 'info',
          message: 'Telegram session rebound to active default CEO profile',
          data: {
            previousAgentId,
            nextAgentId: ingressAgentId
          }
        });
      } else {
        const existingMetadata = parseJsonSafe<Record<string, unknown>>(session.metadataJson, {});
        session = database.updateSessionMetadata({
          sessionId: session.id,
          metadata: {
            ...existingMetadata,
            chatId: message.chatId,
            topicId: message.topicId,
            senderId: message.senderId,
            senderHandle: message.senderHandle,
            lastInboundAt: utcNow()
          }
        });
      }
      ensureOfficePresenceForSession(session, {
        reason: 'Telegram session presence synchronized',
        onlyIfMissing: true
      });
    }
    if (!session) {
      return jsonError(reply, 'Telegram session unavailable', 500);
    }

    telegramSessionBindings.set(sessionKey.key, {
      sessionId: session.id,
      sessionKey: sessionKey.key,
      chatId: message.chatId,
      topicId: message.topicId ?? null,
      linkedAt: utcNow(),
      linkedBy: message.senderId
    });

    const linkedBinding = telegramSessionBindings.get(sessionKey.key);
    const parseNaturalRememberContent = (input: string): string | null => {
      const trimmed = input.trim();
      if (!trimmed || trimmed.startsWith('/')) {
        return null;
      }
      const match = trimmed.match(/^remember(?:\s+(?:this|that))?\s*[:,-]?\s+(.+)$/i);
      if (!match) {
        return null;
      }
      const content = (match[1] ?? '').trim();
      return content.length > 0 ? content : null;
    };
    const parseNaturalMemoryQuery = (input: string): string | null => {
      const trimmed = input.trim();
      if (!trimmed || trimmed.startsWith('/')) {
        return null;
      }
      const checkMatch = trimmed.match(/^check\s+(?:your\s+)?memory(?:\s+(?:for|about))?\s+(.+)$/i);
      if (checkMatch) {
        const query = (checkMatch[1] ?? '').trim();
        return query.length > 0 ? query : null;
      }
      const rememberMatch = trimmed.match(/^what\s+do\s+you\s+remember(?:\s+about)?\s+(.+)$/i);
      if (!rememberMatch) {
        return null;
      }
      const query = (rememberMatch[1] ?? '').trim();
      return query.length > 0 ? query : null;
    };
    const storeExplicitMemoryEntry = async (
      content: string,
      source: 'command' | 'natural_language'
    ): Promise<{ memoryFilePath: string; dailyFilePath: string; rowId: string | null }> => {
      const workspacePath = resolveSessionWorkspacePath(session!);
      const remembered = await memoryService.remember({
        workspacePath,
        sessionId: session!.id,
        agentId: session!.agentId,
        content,
        tags: ['explicit-remember', 'telegram'],
        metadata: {
          source: 'telegram',
          requestMode: source,
          senderId: message.senderId,
          chatId: message.chatId,
          topicId: message.topicId ?? null
        }
      });
      return {
        memoryFilePath: remembered.memoryFilePath,
        dailyFilePath: remembered.dailyFilePath,
        rowId: remembered.row?.id ?? null
      };
    };
    const formatMemorySearchReply = (query: string, results: Awaited<ReturnType<typeof memoryService.search>>): string => {
      if (results.length === 0) {
        return `No memory results found for "${query}".`;
      }
      const lines = results.slice(0, 5).map((result, index) => {
        const compact = result.item.content.replace(/\s+/g, ' ').trim();
        const preview = compact.length > 180 ? `${compact.slice(0, 177)}...` : compact;
        return `${index + 1}. score=${result.combinedScore.toFixed(3)} date=${result.item.createdAt.slice(0, 10)} ${preview}`;
      });
      return [`Memory results for "${query}":`, ...lines].join('\n');
    };
    const persistTelegramInboundMessage = (
      targetSession: SessionRecord,
      content: string,
      metadata: Record<string, unknown> = {}
    ): void => {
      database.saveMessage({
        sessionId: targetSession.id,
        channel: 'telegram',
        direction: 'inbound',
        source: 'telegram',
        sender: message.senderHandle,
        content,
        metadataJson: JSON.stringify({
          chatId: message.chatId,
          topicId: message.topicId,
          attachments: message.attachments,
          updateId: message.updateId,
          ...metadata
        })
      });
    };

    const extractTelegramCollaborationMention = (
      input: string
    ): { selector: string | null; prompt: string; ambiguity: string[] } => {
      const matches = Array.from(input.matchAll(/(^|\s)@([a-z0-9_-]{2,64})\b/gi)).map((match) => String(match[2] ?? '').trim());
      const uniqueMatches = Array.from(new Set(matches.filter((entry) => entry.length > 0)));
      if (uniqueMatches.length === 0) {
        return {
          selector: null,
          prompt: input,
          ambiguity: []
        };
      }
      if (uniqueMatches.length > 1) {
        return {
          selector: null,
          prompt: input,
          ambiguity: uniqueMatches
        };
      }
      const selector = uniqueMatches[0]!;
      const stripped = input.replace(new RegExp(`(^|\\s)@${selector}\\b`, 'i'), ' ').replace(/\s+/g, ' ').trim();
      return {
        selector,
        prompt: stripped || input,
        ambiguity: []
      };
    };

    if (command.toLowerCase().startsWith('/agents')) {
      const route = collaborationRouteState(session);
      const summary = listCollaborationTargetsForOrigin(session)
        .slice(0, 12)
        .map((target) => {
          const routeMarker = route.targetAgentId === target.agentId ? ' [current route]' : '';
          const sessionMarker = target.activeSession ? ` session=${target.activeSession.sessionKey}` : '';
          const runMarker = target.activeRun ? ` run=${target.activeRun.status}` : '';
          return `- ${target.agentId} (${target.title})${routeMarker}${sessionMarker}${runMarker}`;
        })
        .join('\n');
      await saveOutboundMessage(
        session,
        'system',
        'system',
        summary.length > 0 ? `Specialists:\n${summary}` : 'No enabled specialists are available right now.',
        {
          command: 'agents',
          collaborationRoute: route
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'agents'
      });
    }

    if (command.toLowerCase().startsWith('/schedules')) {
      syncBuiltinSchedules();
      const schedules = database.listScheduleJobs({ limit: 16 });
      const summary = schedules
        .map((entry) => {
          const paused = entry.pausedAt ? ' paused' : '';
          const target = entry.targetAgentId ?? 'system';
          return `- ${entry.id} :: ${entry.label} [${entry.kind}/${entry.category}] ${entry.cadence} -> ${target}${paused} status=${entry.lastStatus ?? 'n/a'}`;
        })
        .join('\n');
      await saveOutboundMessage(
        session,
        'system',
        'system',
        summary.length > 0 ? `Schedules:\n${summary}` : 'No schedules are registered right now.',
        {
          command: 'schedules'
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'schedules'
      });
    }

    if (command.toLowerCase().startsWith('/schedule')) {
      const args = command
        .replace(/^\/schedule\b/i, '')
        .trim()
        .split(/\s+/)
        .filter((entry) => entry.length > 0);
      const subcommand = (args[0] ?? 'show').toLowerCase();
      const scheduleId = args[1] ?? '';
      const actor = `telegram:${message.senderId}`;

      if (subcommand === 'list') {
        const synthetic = await app.inject({
          method: 'GET',
          url: '/api/schedules?limit=16',
          headers: {
            Authorization: `Bearer ${config.server.apiToken}`,
            'x-ops-role': 'operator'
          }
        });
        const payload = parseJsonSafe<ScheduleListCommandPayload>(synthetic.body, {});
        if (synthetic.statusCode >= 400) {
          await saveOutboundMessage(session, 'system', 'system', `Schedule list failed: ${payload.error ?? `HTTP ${synthetic.statusCode}`}`, {
            command: 'schedule',
            subcommand: 'list'
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: payload.error ?? 'schedule_list_failed'
          });
        }
        const lines = (payload.schedules ?? []).map((entry) => {
          const id = String(entry.id ?? 'unknown');
          const label = String(entry.label ?? id);
          const cadence = String(entry.cadence ?? 'n/a');
          const target = String(entry.targetAgentId ?? 'system');
          const paused = entry.paused === true ? ' paused' : '';
          return `- ${id} :: ${label} :: ${cadence} -> ${target}${paused}`;
        });
        await saveOutboundMessage(
          session,
          'system',
          'system',
          lines.length > 0 ? `Schedules:\n${lines.join('\n')}` : 'No schedules are registered right now.',
          {
            command: 'schedule',
            subcommand: 'list'
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'schedule',
          subcommand: 'list'
        });
      }

      if (!scheduleId) {
        await saveOutboundMessage(
          session,
          'system',
          'system',
          'Usage: /schedule <show|pause|resume|run|route|history> <scheduleId> [args]',
          {
            command: 'schedule',
            reason: 'schedule_id_required'
          }
        );
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'schedule_id_required'
        });
      }

      if (subcommand === 'show' || subcommand === 'history') {
        const endpoint =
          subcommand === 'history'
            ? `/api/schedules/${encodeURIComponent(scheduleId)}/history`
            : `/api/schedules/${encodeURIComponent(scheduleId)}`;
        const synthetic = await app.inject({
          method: 'GET',
          url: endpoint,
          headers: {
            Authorization: `Bearer ${config.server.apiToken}`,
            'x-ops-role': 'operator'
          }
        });
        const payload = parseJsonSafe<ScheduleLookupCommandPayload>(synthetic.body, {});
        if (synthetic.statusCode >= 400) {
          await saveOutboundMessage(session, 'system', 'system', `Schedule lookup failed: ${payload.error ?? `HTTP ${synthetic.statusCode}`}`, {
            command: 'schedule',
            subcommand
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: payload.error ?? 'schedule_lookup_failed'
          });
        }
        const history = (payload.history ?? []).slice(0, 5);
        const schedule = payload.schedule ?? null;
        const scheduleSummary =
          schedule && subcommand === 'show'
            ? [
                `Schedule ${String(schedule.id ?? scheduleId)}`,
                `Label: ${String(schedule.label ?? 'n/a')}`,
                `Cadence: ${String(schedule.cadence ?? 'n/a')} (${String(schedule.kind ?? 'targeted')})`,
                `Target: ${String(schedule.targetAgentId ?? 'system')}`,
                `Requester: ${String(schedule.requestedBy ?? 'unknown')}`,
                `Delivery: ${String(schedule.deliveryTarget ?? 'origin_session')} -> ${String(schedule.deliveryTargetSessionId ?? 'auto')}`,
                `Next run: ${String(schedule.nextRunAt ?? 'n/a')}`,
                `Last status: ${String(schedule.lastStatus ?? 'n/a')}`,
                `Last error: ${String(schedule.lastError ?? 'none')}`
              ].join('\n')
            : '';
        const historySummary =
          history.length > 0
            ? history
                .map((entry) => `- ${String(entry.createdAt ?? 'n/a')} ${String(entry.status ?? 'n/a')} ${String(entry.summary ?? '')}`.trim())
                .join('\n')
            : 'No history yet.';
        await saveOutboundMessage(
          session,
          'system',
          'system',
          subcommand === 'history' ? `Schedule history for ${scheduleId}:\n${historySummary}` : `${scheduleSummary}\n\nRecent history:\n${historySummary}`,
          {
            command: 'schedule',
            subcommand,
            scheduleId
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'schedule',
          subcommand,
          scheduleId
        });
      }

      if (subcommand === 'route') {
        const deliveryTarget = args[2] ?? '';
        const deliveryTargetSessionId = args[3] ?? null;
        if (!deliveryTarget) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'schedule_delivery_target_required'
          });
        }
        const synthetic = await app.inject({
          method: 'PATCH',
          url: `/api/schedules/${encodeURIComponent(scheduleId)}`,
          headers: {
            Authorization: `Bearer ${config.server.apiToken}`,
            'x-ops-role': 'operator'
          },
          payload: {
            actor,
            deliveryTarget,
            deliveryTargetSessionId
          }
        });
        const payload = parseJsonSafe<ScheduleMutationCommandPayload>(synthetic.body, {});
        if (synthetic.statusCode >= 400) {
          await saveOutboundMessage(session, 'system', 'system', `Schedule route update failed: ${payload.error ?? `HTTP ${synthetic.statusCode}`}`, {
            command: 'schedule',
            subcommand: 'route',
            scheduleId
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: payload.error ?? 'schedule_route_failed'
          });
        }
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Schedule ${scheduleId} delivery updated to ${String(payload.schedule?.deliveryTarget ?? deliveryTarget)} -> ${String(payload.schedule?.deliveryTargetSessionId ?? deliveryTargetSessionId ?? 'auto')}.`,
          {
            command: 'schedule',
            subcommand: 'route',
            scheduleId
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'schedule',
          subcommand: 'route',
          scheduleId
        });
      }

      if (subcommand === 'pause' || subcommand === 'resume' || subcommand === 'run') {
        const synthetic = await app.inject({
          method: 'POST',
          url: `/api/schedules/${encodeURIComponent(scheduleId)}/${subcommand}`,
          headers: {
            Authorization: `Bearer ${config.server.apiToken}`,
            'x-ops-role': 'operator'
          },
          payload: {
            actor
          }
        });
        const payload = parseJsonSafe<ScheduleMutationCommandPayload>(synthetic.body, {});
        if (synthetic.statusCode >= 400) {
          await saveOutboundMessage(session, 'system', 'system', `Schedule ${subcommand} failed: ${payload.error ?? `HTTP ${synthetic.statusCode}`}`, {
            command: 'schedule',
            subcommand,
            scheduleId
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: payload.error ?? `schedule_${subcommand}_failed`
          });
        }
        const summary =
          subcommand === 'run'
            ? `Schedule ${scheduleId} queued run ${String(payload.run?.id ?? payload.history?.runId ?? 'n/a')}.`
            : `Schedule ${scheduleId} ${subcommand}d.`;
        await saveOutboundMessage(session, 'system', 'system', summary, {
          command: 'schedule',
          subcommand,
          scheduleId,
          runId: payload.run?.id ?? null
        });
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'schedule',
          subcommand,
          scheduleId,
          runId: payload.run?.id ?? null
        });
      }

      return jsonOk(reply, {
        status: 'ignored',
        reason: 'unknown_schedule_subcommand'
      });
    }

    if (command.toLowerCase().startsWith('/browser')) {
      const args = command
        .replace(/^\/browser\b/i, '')
        .trim()
        .split(/\s+/)
        .filter((entry) => entry.length > 0);
      const subcommand = (args[0] ?? 'show').toLowerCase();
      if (subcommand === 'list') {
        const profiles = listVisibleBrowserSessionProfiles(session).slice(0, 12);
        const summary = profiles
          .map((profile) => {
            const verification =
              profile.lastVerificationStatus === 'connected'
                ? 'connected'
                : profile.lastVerificationStatus === 'failed'
                  ? 'failed'
                  : 'unknown';
            const owner = profile.ownerLabel ? ` owner=${profile.ownerLabel}` : '';
            const site = profile.siteKey ? ` site=${profile.siteKey}` : '';
            const visibility = profile.visibility === 'session_only' ? ' session-only' : ' shared';
            return `- ${profile.id} :: ${profile.label}${owner}${site} :: ${verification}${visibility}`;
          })
          .join('\n');
        await saveOutboundMessage(
          session,
          'system',
          'system',
          summary.length > 0 ? `Browser session profiles:\n${summary}` : 'No browser session profiles are saved yet.',
          {
            command: 'browser',
            subcommand: 'list'
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'browser',
          subcommand: 'list'
          });
      }

      if (subcommand === 'connect') {
        const requestedSiteKey = (args[1] ?? '').trim().toLowerCase();
        const browserKind = parseLocalBrowserKind(args[2] ?? 'chrome') ?? 'chrome';
        const siteKey: BrowserConnectSiteKey =
          requestedSiteKey === 'tiktok' ||
          requestedSiteKey === 'instagram' ||
          requestedSiteKey === 'reddit' ||
          requestedSiteKey === 'x' ||
          requestedSiteKey === 'pinterest' ||
          requestedSiteKey === 'facebook' ||
          requestedSiteKey === 'generic'
            ? requestedSiteKey
            : 'generic';
        if (!requestedSiteKey) {
          await saveOutboundMessage(
            session,
            'system',
            'system',
            'Usage: /browser connect <tiktok|instagram|reddit|x|pinterest|facebook|generic> [chrome|firefox]',
            {
              command: 'browser',
              subcommand: 'connect'
            }
          );
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'browser_connect_site_required'
          });
        }
        const profile = resolveDefaultLocalBrowserProfile(browserKind);
        if (!profile) {
          await saveOutboundMessage(
            session,
            'system',
            'system',
            `No local ${browserKind} profile is available on the Elyze host. Open Browser Ops and import cookies manually instead.`,
            {
              command: 'browser',
              subcommand: 'connect'
            }
          );
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'browser_local_profile_missing'
          });
        }
        const preset = resolveBrowserConnectPreset(siteKey, null);
        try {
          startVisibleBrowserLogin({
            profile,
            url: preset.verifyUrl
          });
          const updatedSession = updatePendingBrowserConnect(session, {
            siteKey,
            browserKind,
            browserProfileId: profile.id,
            verifyUrl: preset.verifyUrl
          });
          await saveOutboundMessage(
            updatedSession,
            'system',
            'system',
            `Opened ${preset.label} in ${browserKind} on the Elyze host using profile ${profile.label}. Finish logging in, then run \`/browser save ${siteKey} ${browserKind}\`.`,
            {
              command: 'browser',
              subcommand: 'connect',
              siteKey,
              browserKind,
              browserProfileId: profile.id
            }
          );
          return jsonOk(reply, {
            status: 'command_applied',
            command: 'browser',
            subcommand: 'connect'
          });
        } catch (error) {
          const message = error instanceof Error ? error.message : String(error);
          await saveOutboundMessage(session, 'system', 'system', `Failed to open ${preset.label} in ${browserKind}: ${message}`, {
            command: 'browser',
            subcommand: 'connect',
            siteKey,
            browserKind
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'browser_connect_launch_failed'
          });
        }
      }

      if (subcommand === 'save') {
        const pending = parsePendingBrowserConnect(session);
        const requestedSiteKey = (args[1] ?? '').trim().toLowerCase();
        const siteKey = requestedSiteKey
          ? requestedSiteKey === 'tiktok' ||
            requestedSiteKey === 'instagram' ||
            requestedSiteKey === 'reddit' ||
            requestedSiteKey === 'x' ||
            requestedSiteKey === 'pinterest' ||
            requestedSiteKey === 'facebook' ||
            requestedSiteKey === 'generic'
              ? requestedSiteKey
              : null
          : pending?.siteKey ?? null;
        const browserKind = parseLocalBrowserKind(args[2] ?? '') ?? pending?.browserKind ?? null;
        if (!siteKey || !browserKind) {
          await saveOutboundMessage(
            session,
            'system',
            'system',
            'Usage: /browser save <site> [chrome|firefox]. Run /browser connect first to open the login window.',
            {
              command: 'browser',
              subcommand: 'save'
            }
          );
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'browser_save_site_required'
          });
        }
        const profile =
          (pending && pending.siteKey === siteKey && pending.browserKind === browserKind
            ? getLocalBrowserProfileById(pending.browserProfileId)
            : resolveDefaultLocalBrowserProfile(browserKind)) ?? null;
        if (!profile) {
          await saveOutboundMessage(session, 'system', 'system', `No local ${browserKind} profile is available on the Elyze host.`, {
            command: 'browser',
            subcommand: 'save'
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'browser_local_profile_missing'
          });
        }
        const preset = resolveBrowserConnectPreset(siteKey, pending?.verifyUrl ?? null);
        const ownerLabel = session.sessionKey;
        const label = `${preset.label} ${ownerLabel}`.slice(0, 80);
        try {
          const importedCookies = importCookiesFromLocalBrowserProfile({
            profile,
            domains: preset.domains
          });
          if (importedCookies.length === 0) {
            throw new Error('No matching cookies were found. Finish logging in first, then run the save command again.');
          }
          const importedCookieJar = browserSessionVault.saveCookieJar({
            id: `browser_cookie_jar:${Date.now().toString(36)}`,
            label: `${label} cookies`,
            domains: preset.domains,
            sourceKind: 'browser_profile_import',
            cookies: importedCookies,
            notes: `Imported from ${profile.browserKind} profile ${profile.label}`
          });
          const sessionProfile = browserSessionVault.upsertSessionProfile({
            id: `browser_session_profile:${Date.now().toString(36)}`,
            label,
            domains: preset.domains,
            cookieJarId: importedCookieJar.id,
            useRealChrome: profile.browserKind === 'chrome',
            ownerLabel,
            visibility: 'session_only',
            allowedSessionIds: [session.id],
            siteKey,
            browserKind: profile.browserKind,
            browserProfileName: profile.profileName,
            browserProfilePath: profile.profilePath,
            enabled: true
          });
          const verification = await verifyBrowserSessionProfile({
            profile: sessionProfile,
            verifyUrl: preset.verifyUrl
          });
          const updatedSession = updateSessionBrowserAuthProfile(
            updatePendingBrowserConnect(session, null),
            verification.profile.id
          );
          await saveOutboundMessage(
            updatedSession,
            'system',
            'system',
            `Saved ${verification.profile.label} for this chat only. ${verification.resultSummary ?? 'Verification completed.'}`,
            {
              command: 'browser',
              subcommand: 'save',
              sessionProfileId: verification.profile.id
            }
          );
          return jsonOk(reply, {
            status: 'command_applied',
            command: 'browser',
            subcommand: 'save',
            sessionProfileId: verification.profile.id
          });
        } catch (error) {
          const message = error instanceof Error ? error.message : String(error);
          await saveOutboundMessage(session, 'system', 'system', `Failed to save ${preset.label} login: ${message}`, {
            command: 'browser',
            subcommand: 'save'
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'browser_save_failed'
          });
        }
      }

      if (subcommand === 'clear') {
        const updatedSession = updateSessionBrowserAuthProfile(session, null);
        await saveOutboundMessage(updatedSession, 'system', 'system', 'Cleared the sticky browser auth profile for this chat.', {
          command: 'browser',
          subcommand: 'clear'
        });
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'browser',
          subcommand: 'clear'
        });
      }

      if (subcommand === 'use') {
        const selector = args.slice(1).join(' ').trim();
        if (!selector) {
          await saveOutboundMessage(
            session,
            'system',
            'system',
            'Usage: /browser use <profile id or label>',
            {
              command: 'browser',
              subcommand: 'use',
              reason: 'profile_selector_required'
            }
          );
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'profile_selector_required'
          });
        }
        const profile = resolveBrowserSessionProfileSelector(selector, { session });
        if (!profile) {
          await saveOutboundMessage(session, 'system', 'system', `Browser session profile not found: ${selector}`, {
            command: 'browser',
            subcommand: 'use'
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'browser_session_profile_not_found'
          });
        }
        const updatedSession = updateSessionBrowserAuthProfile(session, profile.id);
        const verificationSummary =
          profile.lastVerificationSummary && profile.lastVerificationSummary.trim().length > 0
            ? ` Last check: ${profile.lastVerificationSummary.trim()}`
            : '';
        await saveOutboundMessage(
          updatedSession,
          'system',
          'system',
          `Using browser auth profile ${profile.label} (${profile.id}) for future browser requests in this chat.${verificationSummary}`,
          {
            command: 'browser',
            subcommand: 'use',
            sessionProfileId: profile.id
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'browser',
          subcommand: 'use',
          sessionProfileId: profile.id
        });
      }

      const currentProfileId = parseSessionBrowserAuthProfileId(session);
      const currentProfile = currentProfileId ? database.getBrowserSessionProfileById(currentProfileId) : null;
      await saveOutboundMessage(
        session,
        'system',
        'system',
        currentProfile
          ? `Current browser auth profile: ${currentProfile.label} (${currentProfile.id}) [${currentProfile.lastVerificationStatus}]`
          : 'No sticky browser auth profile is selected for this chat. Use `/browser list` then `/browser use <profile>`.',
        {
          command: 'browser',
          subcommand: 'show',
          sessionProfileId: currentProfile?.id ?? null
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'browser',
        subcommand: 'show',
        sessionProfileId: currentProfile?.id ?? null
      });
    }

    if (command.toLowerCase().startsWith('/llm')) {
      const commandArgs = command
        .replace(/^\/llm\b/i, '')
        .trim()
        .split(/\s+/)
        .filter((entry) => entry.length > 0);
      const subcommand = (commandArgs[0] ?? 'show').toLowerCase();
      const parsePolicyRuntime = (
        args: string[],
        startIndex: number
      ): {
        policy: LlmRoutePolicy;
        runtime: RuntimeKind | null;
        nextIndex: number;
      } => {
        const hint = (args[startIndex] ?? '').trim().toLowerCase();
        if (hint === 'router' || hint === 'orchestrator') {
          return {
            policy: 'orchestrator',
            runtime: parseRoutingRuntime(args[startIndex + 1] ?? ''),
            nextIndex: startIndex + 2
          };
        }
        if (hint === 'worker') {
          return {
            policy: 'worker',
            runtime: parseRoutingRuntime(args[startIndex + 1] ?? ''),
            nextIndex: startIndex + 2
          };
        }
        return {
          policy: 'worker',
          runtime: parseRoutingRuntime(args[startIndex] ?? ''),
          nextIndex: startIndex + 1
        };
      };

      if (subcommand === 'show' || subcommand === 'status') {
        const workerMaps = llmPolicyMaps(llmLimits, 'worker');
        const routerMaps = llmPolicyMaps(llmLimits, 'orchestrator');
        const summary = [
          'LLM routing policy',
          '',
          'Worker routes (subagents / heavy execution):',
          ...(['codex', 'claude', 'gemini', 'process'] as RuntimeKind[]).map((runtime) => {
            const primary = workerMaps.primary[runtime] ?? 'default';
            const fallback = formatFallbackChain(workerMaps.fallback[runtime] ?? []);
            const strict = workerMaps.strictPrimary[runtime] ? 'on' : 'off';
            return `${runtime}: primary=${primary}; strict_primary=${strict}; fallback=${fallback}`;
          }),
          '',
          'Orchestrator routes (CEO conversation brain):',
          ...(['codex', 'claude', 'gemini', 'process'] as RuntimeKind[]).map((runtime) => {
            const primary = routerMaps.primary[runtime] ?? 'default';
            const fallback = formatFallbackChain(routerMaps.fallback[runtime] ?? []);
            const strict = routerMaps.strictPrimary[runtime] ? 'on' : 'off';
            return `${runtime}: primary=${primary}; strict_primary=${strict}; fallback=${fallback}`;
          }),
          '',
          'Model alias tips:',
          '- openrouter/openai/gpt-5-mini',
          '- openrouter:meta-llama/llama-3.1-8b-instruct:free',
          '- or:google/gemini-2.5-flash-lite',
          '',
          'Update examples:',
          '- /llm primary codex openrouter/openai/gpt-5-mini',
          '- /llm primary router process openrouter/openai/gpt-5-mini',
          '- /llm fallback router process codex:openrouter/openai/gpt-5-mini,process:openrouter/free'
        ].join('\n');

        await saveOutboundMessage(session, 'system', 'system', summary, {
          command: 'llm',
          subcommand: 'show'
        });
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'llm',
          subcommand: 'show'
        });
      }

      if (subcommand === 'primary') {
        const { policy, runtime, nextIndex } = parsePolicyRuntime(commandArgs, 1);
        if (!runtime) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'invalid_llm_primary_runtime'
          });
        }
        const nextModel = normalizeModelInput(commandArgs.slice(nextIndex).join(' '));
        if (nextModel === null) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'primary_model_required'
          });
        }
        const policyMaps = llmPolicyMaps(llmLimits, policy);
        const nextLimits =
          policy === 'orchestrator'
            ? mergeLlmLimits(structuredClone(DEFAULT_LLM_LIMITS), {
                ...llmLimits,
                orchestratorPrimaryModelByRuntime: {
                  ...policyMaps.primary,
                  [runtime]: nextModel
                }
              })
            : mergeLlmLimits(structuredClone(DEFAULT_LLM_LIMITS), {
                ...llmLimits,
                primaryModelByRuntime: {
                  ...policyMaps.primary,
                  [runtime]: nextModel
                }
              });
        const saved = writeLlmLimits(nextLimits);
        emitEvent({
          kind: 'system.info',
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: null,
          level: 'info',
          message: 'LLM primary model updated from Telegram',
          data: {
            runtime,
            model: nextModel ?? 'default',
            policy,
            actor: message.senderId
          }
        });
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Primary model for ${policy}:${runtime} set to ${nextModel ?? 'default'}.`,
          {
            command: 'llm',
            subcommand: 'primary'
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'llm',
          subcommand: 'primary',
          limits: saved
        });
      }

      if (subcommand === 'fallback') {
        const { policy, runtime, nextIndex } = parsePolicyRuntime(commandArgs, 1);
        if (!runtime) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'invalid_llm_fallback_runtime'
          });
        }
        const rawChain = commandArgs.slice(nextIndex).join(' ');
        const parsed = parseFallbackChainText(rawChain);
        if (!parsed) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'invalid_llm_fallback_chain'
          });
        }
        const policyMaps = llmPolicyMaps(llmLimits, policy);
        const nextLimits =
          policy === 'orchestrator'
            ? mergeLlmLimits(structuredClone(DEFAULT_LLM_LIMITS), {
                ...llmLimits,
                orchestratorFallbackByRuntime: {
                  ...policyMaps.fallback,
                  [runtime]: parsed
                }
              })
            : mergeLlmLimits(structuredClone(DEFAULT_LLM_LIMITS), {
                ...llmLimits,
                fallbackByRuntime: {
                  ...policyMaps.fallback,
                  [runtime]: parsed
                }
              });
        const saved = writeLlmLimits(nextLimits);
        emitEvent({
          kind: 'system.info',
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: null,
          level: 'info',
          message: 'LLM fallback routing updated from Telegram',
          data: {
            runtime,
            policy,
            fallback: parsed,
            actor: message.senderId
          }
        });
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Fallback chain for ${policy}:${runtime} updated: ${formatFallbackChain(parsed)}.`,
          {
            command: 'llm',
            subcommand: 'fallback'
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'llm',
          subcommand: 'fallback',
          limits: saved
        });
      }

      if (subcommand === 'strict') {
        const { policy, runtime, nextIndex } = parsePolicyRuntime(commandArgs, 1);
        if (!runtime) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'invalid_llm_strict_runtime'
          });
        }
        const rawToggle = String(commandArgs[nextIndex] ?? '').trim().toLowerCase();
        const enabled =
          rawToggle === 'on' || rawToggle === 'true' || rawToggle === '1' || rawToggle === 'enable' || rawToggle === 'enabled';
        const disabled =
          rawToggle === 'off' ||
          rawToggle === 'false' ||
          rawToggle === '0' ||
          rawToggle === 'disable' ||
          rawToggle === 'disabled';
        if (!enabled && !disabled) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'invalid_llm_strict_toggle'
          });
        }

        const policyMaps = llmPolicyMaps(llmLimits, policy);
        const nextLimits =
          policy === 'orchestrator'
            ? mergeLlmLimits(structuredClone(DEFAULT_LLM_LIMITS), {
                ...llmLimits,
                orchestratorStrictPrimaryByRuntime: {
                  ...policyMaps.strictPrimary,
                  [runtime]: enabled
                }
              })
            : mergeLlmLimits(structuredClone(DEFAULT_LLM_LIMITS), {
                ...llmLimits,
                strictPrimaryByRuntime: {
                  ...policyMaps.strictPrimary,
                  [runtime]: enabled
                }
              });
        const saved = writeLlmLimits(nextLimits);
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Strict-primary for ${policy}:${runtime} ${enabled ? 'enabled' : 'disabled'}.`,
          {
            command: 'llm',
            subcommand: 'strict'
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'llm',
          subcommand: 'strict',
          limits: saved
        });
      }

      return jsonOk(reply, {
        status: 'ignored',
        reason: 'unknown_llm_subcommand'
      });
    }

    if (command.toLowerCase().startsWith('/agent')) {
      const args = command
        .replace(/^\/agent\b/i, '')
        .trim()
        .split(/\s+/)
        .filter((entry) => entry.length > 0);
      const subcommand = (args[0] ?? 'show').toLowerCase();

      if (subcommand === 'use') {
        const selector = args.slice(1).join(' ').trim();
        if (!selector) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'missing_agent_target'
          });
        }
        const resolved = resolveCollaborationTarget(session, selector);
        if (!resolved.ok) {
          await saveOutboundMessage(session, 'system', 'system', resolved.message, {
            command: 'agent',
            subcommand: 'use',
            candidates: resolved.candidates ?? []
          });
          return jsonOk(reply, {
            status: 'blocked',
            reason: resolved.reason,
            candidates: resolved.candidates ?? []
          });
        }
        const updated = updateCollaborationRouteState(session, {
          targetAgentId: resolved.targetProfile.id,
          targetSessionId: resolved.targetSession?.id ?? null,
          setBy: message.senderId
        });
        session = updated;
        await saveOutboundMessage(
          updated,
          'system',
          'system',
          `Soft routing now targets ${resolved.targetProfile.title} (${resolved.targetProfile.name}). Use /agent back to return to the default route.`,
          {
            command: 'agent',
            subcommand: 'use',
            targetAgentId: resolved.targetProfile.id
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'agent',
          subcommand: 'use',
          route: collaborationRouteState(updated)
        });
      }

      if (subcommand === 'back') {
        const updated = updateCollaborationRouteState(session, null);
        session = updated;
        await saveOutboundMessage(updated, 'system', 'system', 'Soft routing cleared. This chat now targets the default agent again.', {
          command: 'agent',
          subcommand: 'back'
        });
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'agent',
          subcommand: 'back',
          route: collaborationRouteState(updated)
        });
      }

      const profile = getSessionAgentProfile(session);
      if (!profile) {
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'session_has_no_agent_profile'
        });
      }

      if (subcommand === 'show' || subcommand === 'status') {
        const harnessState = profile.harnessSessionReady ? 'ready' : profile.executionMode === 'persistent_harness' ? 'stopped' : 'n/a';
        const route = collaborationRouteState(session);
        const summary = [
          `Agent profile: ${profile.name} (${profile.title})`,
          `Mode: ${profile.executionMode}`,
          `Conversation model: ${profile.defaultModel ?? 'default'}`,
          `Default execution runtime: ${defaultRuntimeForProfile(profile)}`,
          `Harness runtime: ${profile.harnessRuntime ?? 'none'}`,
          `Harness tmux: ${harnessState}`,
          `Soft route: ${route.targetAgentId ?? 'default'}`
        ].join('\n');
        await saveOutboundMessage(session, 'system', 'system', summary, {
          command: 'agent',
          subcommand: 'show'
        });
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'agent',
          subcommand: 'show'
        });
      }

      if (subcommand === 'mode') {
        const rawMode = String(args[1] ?? '').trim().toLowerCase();
        if (!rawMode || (rawMode !== 'on_demand' && rawMode !== 'persistent_harness' && rawMode !== 'dispatch_only')) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'invalid_agent_mode'
          });
        }
        const requestedMode = rawMode as AgentExecutionMode;
        const existingRecord = database.getAgentProfileById(profile.id);
        if (!existingRecord) {
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'agent_profile_missing'
          });
        }
        const existingMetadata = parseJsonSafe<Record<string, unknown>>(existingRecord.metadataJson, {});
        const merged = mergeAgentMetadata(existingMetadata, { executionMode: requestedMode }, existingRecord.defaultRuntime);
        const nextRuntime =
          requestedMode === 'persistent_harness' ? merged.harnessRuntime : parseOptionalRuntime(String(existingRecord.defaultRuntime)) ?? 'process';
        const updated = database.upsertAgentProfile({
          id: existingRecord.id,
          name: existingRecord.name,
          title: existingRecord.title,
          parentAgentId: existingRecord.parentAgentId,
          systemPrompt: existingRecord.systemPrompt,
          defaultRuntime: nextRuntime,
          defaultModel: existingRecord.defaultModel,
          allowedRuntimes: normalizeRuntimeList(parseStringList(existingRecord.allowedRuntimesJson)),
          skills: parseStringList(existingRecord.skillsJson),
          tools: parseStringList(existingRecord.toolsJson),
          metadata: merged.metadata,
          enabled: existingRecord.enabled
        });
        const updatedProfile = toAgentProfileView(updated);
        ensurePersistentHarnessSession(updatedProfile);
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Agent mode updated to ${updatedProfile.executionMode}. Default execution runtime is now ${defaultRuntimeForProfile(updatedProfile)}.`,
          {
            command: 'agent',
            subcommand: 'mode'
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'agent',
          subcommand: 'mode',
          agentId: updatedProfile.id,
          executionMode: updatedProfile.executionMode
        });
      }

      if (subcommand === 'harness') {
        const requestedRuntime = parseOptionalRuntime(args[1] ?? '');
        if (!requestedRuntime) {
          return jsonOk(reply, {
            status: 'ignored',
            reason: 'invalid_harness_runtime'
          });
        }
        const existingRecord = database.getAgentProfileById(profile.id);
        if (!existingRecord) {
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'agent_profile_missing'
          });
        }
        const existingMetadata = parseJsonSafe<Record<string, unknown>>(existingRecord.metadataJson, {});
        const merged = mergeAgentMetadata(existingMetadata, { harnessRuntime: requestedRuntime }, existingRecord.defaultRuntime);
        const nextRuntime = merged.executionMode === 'persistent_harness' ? merged.harnessRuntime : existingRecord.defaultRuntime;
        const updated = database.upsertAgentProfile({
          id: existingRecord.id,
          name: existingRecord.name,
          title: existingRecord.title,
          parentAgentId: existingRecord.parentAgentId,
          systemPrompt: existingRecord.systemPrompt,
          defaultRuntime: nextRuntime,
          defaultModel: existingRecord.defaultModel,
          allowedRuntimes: normalizeRuntimeList(parseStringList(existingRecord.allowedRuntimesJson)),
          skills: parseStringList(existingRecord.skillsJson),
          tools: parseStringList(existingRecord.toolsJson),
          metadata: merged.metadata,
          enabled: existingRecord.enabled
        });
        const updatedProfile = toAgentProfileView(updated);
        ensurePersistentHarnessSession(updatedProfile);
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Harness runtime set to ${updatedProfile.harnessRuntime ?? 'none'} for ${updatedProfile.name}.`,
          {
            command: 'agent',
            subcommand: 'harness'
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'agent',
          subcommand: 'harness',
          agentId: updatedProfile.id,
          harnessRuntime: updatedProfile.harnessRuntime
        });
      }

      if (subcommand === 'start-harness') {
        const status = ensurePersistentHarnessSession(profile);
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Harness ${status.ready ? 'ready' : status.status} for ${profile.name}${status.sessionName ? ` (${status.sessionName})` : ''}.`,
          {
            command: 'agent',
            subcommand: 'start-harness'
          }
        );
        return jsonOk(reply, {
          status: status.ready ? 'command_applied' : 'blocked',
          command: 'agent',
          subcommand: 'start-harness',
          harness: status
        });
      }

      if (subcommand === 'stop-harness') {
        const stopped = stopPersistentHarnessSession(profile);
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Harness ${stopped.stopped ? 'stopped' : 'not running'} for ${profile.name}${stopped.sessionName ? ` (${stopped.sessionName})` : ''}.`,
          {
            command: 'agent',
            subcommand: 'stop-harness'
          }
        );
        return jsonOk(reply, {
          status: stopped.stopped ? 'command_applied' : 'ignored',
          command: 'agent',
          subcommand: 'stop-harness'
        });
      }

      return jsonOk(reply, {
        status: 'ignored',
        reason: 'unknown_agent_subcommand'
      });
    }

    if (command.startsWith('/session')) {
      const activeRun = findLatestActiveRun(session.id);
      const sessionProfile = getSessionAgentProfile(session);
      const collaborationRoute = collaborationRouteState(session);
      const summary = `Session ${session.sessionKey}
Agent: ${session.agentId}${sessionProfile ? ` (${sessionProfile.title})` : ''}
Execution runtime: ${session.preferredRuntime ?? (sessionProfile ? defaultRuntimeForProfile(sessionProfile) : config.runtime.defaultRuntime)}
Conversation model: ${session.preferredModel ?? sessionProfile?.defaultModel ?? 'default'}
Mode: ${sessionProfile?.executionMode ?? 'n/a'}
Harness runtime: ${sessionProfile?.harnessRuntime ?? 'n/a'}${sessionProfile?.executionMode === 'persistent_harness' ? ` (${sessionProfile.harnessSessionReady ? 'ready' : 'stopped'})` : ''}
Soft route: ${collaborationRoute.targetAgentId ?? 'default'}${collaborationRoute.setAt ? ` (set ${collaborationRoute.setAt}${collaborationRoute.setBy ? ` by ${collaborationRoute.setBy}` : ''})` : ''}
Active run: ${activeRun ? `${activeRun.id} (${activeRun.status})` : 'none'}
Linked via /link: ${linkedBinding ? 'yes' : 'no'}`;

      await saveOutboundMessage(session, 'system', 'system', summary, {
        command: 'session'
      });

      return jsonOk(reply, {
        status: 'command_applied',
        command: 'session',
        sessionId: session.id,
        sessionKey: session.sessionKey
      });
    }

    if (command.toLowerCase().startsWith('/clear')) {
      const now = utcNow();
      const existingMetadata = parseJsonSafe<Record<string, unknown>>(session.metadataJson, {});
      const updated = database.updateSessionMetadata({
        sessionId: session.id,
        metadata: {
          ...existingMetadata,
          transcriptResetAt: now,
          transcriptResetBy: message.senderId,
          transcriptResetMode: 'soft_clear'
        }
      });
      await saveOutboundMessage(
        updated,
        'system',
        'system',
        'Conversation context cleared for this chat. Long-term memory remains intact.',
        {
          command: 'clear',
          transcriptResetAt: now
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'clear',
        sessionId: updated.id,
        transcriptResetAt: now
      });
    }

    if (command.toLowerCase().startsWith('/compact')) {
      const compaction = applyContinuityCompaction({
        session,
        mode: 'manual_compact',
        reason: 'telegram_manual_compact',
        actor: `telegram:${message.senderId}`,
        preserveMessages: 6
      });
      session = compaction.session;
      await saveOutboundMessage(
        session,
        'system',
        'system',
        compaction.summary
          ? `Conversation compacted. Carry-forward summary preserved.\n\n${compaction.summary}`
          : 'Conversation compacted. Carry-forward summary preserved for future turns.',
        {
          command: 'compact',
          continuitySummary: compaction.summary
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'compact',
        sessionId: session.id
      });
    }

    if (command.toLowerCase().startsWith('/new')) {
      const now = utcNow();
      const newSessionKey = `${session.sessionKey}::new:${Date.now().toString(36)}`;
      const existingMetadata = parseJsonSafe<Record<string, unknown>>(session.metadataJson, {});
      const currentTranscriptResetAt =
        typeof existingMetadata.transcriptResetAt === 'string' ? Date.parse(existingMetadata.transcriptResetAt) : Number.NaN;
      const rolloverTranscript = filterTranscriptMessagesAfterReset(
        database.listMessages(session.id, 120),
        currentTranscriptResetAt
      );
      const rolloverSummary = buildContinuityCompactionPayload(rolloverTranscript, 6);
      const ensuredRolloverSummary =
        rolloverSummary.summary ??
        (rolloverSummary.unresolvedConstraint ? `Carry forward: ${rolloverSummary.unresolvedConstraint}` : null);
      const created = database.upsertSessionByKey({
        sessionKey: newSessionKey,
        channel: session.channel,
        chatType: session.chatType,
        agentId: session.agentId,
        preferredRuntime: session.preferredRuntime,
        preferredModel: session.preferredModel,
        preferredReasoningEffort: session.preferredReasoningEffort,
        metadata: {
          ...existingMetadata,
          parentSessionId: session.id,
          transcriptResetAt: now,
          transcriptResetBy: message.senderId,
          transcriptResetMode: 'new_session',
          continuitySummary: ensuredRolloverSummary,
          continuitySummaryMode: 'rollover_summary',
          continuitySummaryAt: now,
          continuityUnresolvedConstraint: rolloverSummary.unresolvedConstraint,
          continuityOriginSessionId: session.id
        }
      });
      const createdWithContinuity = database.updateSessionMetadata({
        sessionId: created.id,
        metadata: {
          ...parseJsonSafe<Record<string, unknown>>(created.metadataJson, {}),
          continuitySummary: ensuredRolloverSummary,
          continuitySummaryMode: 'rollover_summary',
          continuitySummaryAt: now,
          continuityUnresolvedConstraint: rolloverSummary.unresolvedConstraint,
          continuityOriginSessionId: session.id
        }
      });
      recordContinuityLedger({
        sessionId: createdWithContinuity.id,
        mode: 'rollover_summary',
        reason: 'telegram_new_session',
        summary: ensuredRolloverSummary,
        details: {
          previousSessionId: session.id,
          transcriptResetAt: now,
          compactedMessages: rolloverSummary.compactedMessages,
          retainedMessages: rolloverSummary.retainedMessages,
          unresolvedConstraint: rolloverSummary.unresolvedConstraint
        }
      });
      ensureOfficePresenceForSession(createdWithContinuity, {
        reason: 'Telegram /new session created',
        onlyIfMissing: true
      });
      telegramSessionBindings.set(sessionKey.key, {
        sessionId: createdWithContinuity.id,
        sessionKey: sessionKey.key,
        chatId: message.chatId,
        topicId: message.topicId ?? null,
        linkedAt: utcNow(),
        linkedBy: message.senderId
      });

      await saveOutboundMessage(
        createdWithContinuity,
        'system',
        'system',
        'Started a fresh session for this chat. You are now in a new thread with retained long-term memory.',
        {
          command: 'new',
          previousSessionId: session.id,
          transcriptResetAt: now
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'new',
        previousSessionId: session.id,
        sessionId: createdWithContinuity.id,
        sessionKey: createdWithContinuity.sessionKey
      });
    }

    if (command.toLowerCase().startsWith('/idea') || command.toLowerCase().startsWith('/task')) {
      const isTask = command.toLowerCase().startsWith('/task');
      const text = command.replace(/^\/(idea|task)\b/i, '').trim();
      if (!text) {
        await saveOutboundMessage(
          session,
          'system',
          'system',
          isTask ? 'Usage: /task <title>' : 'Usage: /idea <title>',
          {
            command: isTask ? 'task' : 'idea'
          }
        );
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'missing_backlog_text'
        });
      }

      const autoDetectedRepoMatch = resolveGithubRepoHintMatch(text);
      const autoDetectedRepo = autoDetectedRepoMatch.repoHint;
      const item = database.createBacklogItem({
        title: text.slice(0, 180),
        description: text,
        state: isTask ? 'planned' : 'idea',
        priority: isTask ? 70 : 45,
        projectId: deriveProjectIdFromRepoName(autoDetectedRepo?.repo ?? null) ?? deriveProjectIdFromText(text),
        source: 'telegram',
        sourceRef: message.chatId,
        createdBy: message.senderId,
        linkedSessionId: session.id,
        originSessionId: session.id,
        originMessageId: message.updateId,
        originChannel: 'telegram',
        originChatId: message.chatId,
        originTopicId: message.topicId ?? null,
        metadata: {
          updateId: message.updateId,
          senderHandle: message.senderHandle,
          ingress: 'telegram',
          ...(autoDetectedRepo
            ? {
                githubRepoHint: {
                  owner: autoDetectedRepo.owner,
                  repo: autoDetectedRepo.repo,
                  matchedConnectionId: autoDetectedRepoMatch.connection?.id ?? null
                }
              }
            : {}),
          originRef: buildOriginRef({
            channel: 'telegram',
            sessionId: session.id,
            messageId: message.updateId,
            chatId: message.chatId,
            topicId: message.topicId ?? null,
            sourceRef: message.chatId
          })
        }
      });

      if (autoDetectedRepoMatch.connection) {
        database.upsertBacklogDeliveryLink({
          itemId: item.id,
          repoConnectionId: autoDetectedRepoMatch.connection.id,
          status: 'planned',
          metadata: {
            source: 'telegram_auto_detect',
            owner: autoDetectedRepo?.owner ?? null,
            repo: autoDetectedRepo?.repo ?? null
          }
        });
      }

      emitEvent({
        kind: 'system.info',
        lane: config.queue.defaultLane,
        sessionId: session.id,
        runId: null,
        level: 'info',
        message: 'Backlog item captured from Telegram',
        data: {
          itemId: item.id,
          state: item.state,
          source: 'telegram'
        }
      });

      await saveOutboundMessage(
        session,
        'system',
        'system',
        `${isTask ? 'Task' : 'Idea'} captured: ${item.id} (${item.state})`,
        {
          command: isTask ? 'task' : 'idea',
          itemId: item.id
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: isTask ? 'task' : 'idea',
        itemId: item.id
      });
    }

    if (command.toLowerCase().startsWith('/backlog')) {
      const items = database.listBacklogItems({
        states: ['in_progress', 'review', 'planned', 'blocked', 'idea', 'triage'],
        limit: 8,
        offset: 0
      }).rows;
      if (items.length === 0) {
        await saveOutboundMessage(session, 'system', 'system', 'Backlog is empty.', {
          command: 'backlog'
        });
      } else {
        const summary = items
          .map((item) => `- ${item.id.slice(0, 8)} ${item.state.padEnd(11)} p${item.priority}: ${item.title}`)
          .join('\n');
        await saveOutboundMessage(session, 'system', 'system', `Backlog snapshot:\n${summary}`, {
          command: 'backlog'
        });
      }
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'backlog'
      });
    }

    if (command.toLowerCase().startsWith('/turbo')) {
      const arg = command
        .replace(/^\/turbo\b/i, '')
        .trim()
        .toLowerCase();
      const engineer = resolveSoftwareEngineerProfile();
      if (!engineer) {
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'software_engineer_profile_missing'
        });
      }
      const enabled = arg === 'on' || arg === 'enable' || arg === '1' || arg === 'true';
      const disabled = arg === 'off' || arg === 'disable' || arg === '0' || arg === 'false';
      if (!enabled && !disabled) {
        await saveOutboundMessage(
          session,
          'system',
          'system',
          'Usage: /turbo on|off',
          {
            command: 'turbo'
          }
        );
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'invalid_turbo_argument'
        });
      }

      const next = setTurboCodingMode(engineer.id, enabled, message.senderId);
      await saveOutboundMessage(
        session,
        'system',
        'system',
        `Turbo coding mode ${enabled ? 'enabled' : 'disabled'} for ${next.title}. Runtime=${defaultRuntimeForProfile(next)} Mode=${next.executionMode}.`,
        {
          command: 'turbo',
          enabled
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'turbo',
        enabled,
        agentId: next.id
      });
    }

    if (command.startsWith('/runtime')) {
      const nextRuntime = command.replace('/runtime', '').trim();
      if (!nextRuntime || !isKnownRuntime(nextRuntime)) {
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'invalid_runtime_command'
        });
      }

      const runtimeProfileBlock = assertSessionRuntimeAllowed(session, nextRuntime);
      if (runtimeProfileBlock) {
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'agent_profile_policy',
          details: runtimeProfileBlock
        });
      }

      const toolBlockReason = assertRuntimeToolEnabled(nextRuntime);
      if (toolBlockReason) {
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'tool_policy',
          details: toolBlockReason
        });
      }

      const updatedSession = database.updateSessionPreferences({
        sessionId: session.id,
        preferredRuntime: nextRuntime
      });

      emitEvent({
        kind: 'session.preference.updated',
        lane: config.queue.defaultLane,
        sessionId: session.id,
        runId: null,
        level: 'info',
        message: 'Session runtime preference updated from Telegram',
        data: {
          runtime: updatedSession.preferredRuntime,
          actor: message.senderId
        }
      });

      const activeRun = findLatestActiveRun(session.id);
      if (activeRun) {
        await runtimeManager.abort(activeRun.id, activeRun.runtime);
        database.updateRunStatus({
          runId: activeRun.id,
          status: 'aborted',
          error: 'runtime_switch_telegram'
        });

        emitEvent({
          kind: 'run.aborted',
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: activeRun.id,
          level: 'warn',
          message: 'Run aborted after Telegram runtime switch',
          data: {
            previousRuntime: activeRun.runtime,
            nextRuntime
          }
        });

        const replacementRun = database.createRun({
          sessionId: session.id,
          runtime: nextRuntime,
          requestedRuntime: nextRuntime,
          requestedModel: updatedSession.preferredModel,
          requestedReasoningEffort: updatedSession.preferredReasoningEffort,
          effectiveRuntime: nextRuntime,
          effectiveModel: updatedSession.preferredModel,
          effectiveReasoningEffort: updatedSession.preferredReasoningEffort,
          triggerSource: 'telegram',
          supersedesRunId: activeRun.id,
          prompt: activeRun.prompt,
          status: 'queued'
        });

        database.enqueueQueueItem({
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: replacementRun.id,
          payload: {
            source: 'telegram',
            updateId: message.updateId,
            metadata: {
              model: updatedSession.preferredModel,
              reasoningEffort: updatedSession.preferredReasoningEffort,
              supersedesRunId: activeRun.id
            }
          },
          priority: 90,
          maxAttempts: config.queue.retry.maxAttempts
        });

        emitEvent({
          kind: 'run.queued',
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: replacementRun.id,
          level: 'info',
          message: 'Run re-queued after Telegram runtime switch',
          data: {
            previousRunId: activeRun.id,
            runtime: nextRuntime
          }
        });
      }

      await saveOutboundMessage(session, 'system', 'system', `Runtime set to ${nextRuntime}${activeRun ? ' (active run restarted)' : ''}.`, {
        command: 'runtime'
      });

      return jsonOk(reply, {
        status: 'command_applied',
        command: 'runtime',
        switched: Boolean(activeRun),
        sessionId: session.id,
        sessionKey: session.sessionKey
      });
    }

    if (command.startsWith('/model')) {
      const rawModel = command.replace('/model', '').trim();
      const parsedModelInput = splitModelAndReasoning(rawModel);
      const nextModel = parsedModelInput.model;
      const nextReasoningEffort = parsedModelInput.reasoningEffort;

      const updatedSession = database.updateSessionPreferences({
        sessionId: session.id,
        preferredModel: nextModel,
        preferredReasoningEffort: nextReasoningEffort
      });

      emitEvent({
        kind: 'session.preference.updated',
        lane: config.queue.defaultLane,
        sessionId: session.id,
        runId: null,
        level: 'info',
        message: 'Session model preference updated from Telegram',
        data: {
          model: updatedSession.preferredModel,
          reasoningEffort: updatedSession.preferredReasoningEffort,
          actor: message.senderId
        }
      });

      const activeRun = findLatestActiveRun(session.id);
      if (activeRun) {
        const targetRuntime = resolveSessionRuntime(updatedSession);
        const runtimeProfileBlock = assertSessionRuntimeAllowed(updatedSession, targetRuntime);
        if (runtimeProfileBlock) {
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'agent_profile_policy',
            details: runtimeProfileBlock
          });
        }
        const toolBlockReason = assertRuntimeToolEnabled(targetRuntime);
        if (toolBlockReason) {
          return jsonOk(reply, {
            status: 'blocked',
            reason: 'tool_policy',
            details: toolBlockReason
          });
        }

        await runtimeManager.abort(activeRun.id, activeRun.runtime);
        database.updateRunStatus({
          runId: activeRun.id,
          status: 'aborted',
          error: 'model_switch_telegram'
        });

        emitEvent({
          kind: 'run.aborted',
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: activeRun.id,
          level: 'warn',
          message: 'Run aborted after Telegram model switch',
          data: {
            runtime: targetRuntime,
            model: nextModel,
            reasoningEffort: updatedSession.preferredReasoningEffort
          }
        });

        const replacementRun = database.createRun({
          sessionId: session.id,
          runtime: targetRuntime,
          requestedRuntime: targetRuntime,
          requestedModel: nextModel,
          requestedReasoningEffort: updatedSession.preferredReasoningEffort,
          effectiveRuntime: targetRuntime,
          effectiveModel: nextModel,
          effectiveReasoningEffort: updatedSession.preferredReasoningEffort,
          triggerSource: 'telegram',
          supersedesRunId: activeRun.id,
          prompt: activeRun.prompt,
          status: 'queued'
        });

        database.enqueueQueueItem({
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: replacementRun.id,
          payload: {
            source: 'telegram',
            updateId: message.updateId,
            metadata: {
              model: nextModel,
              reasoningEffort: updatedSession.preferredReasoningEffort,
              supersedesRunId: activeRun.id
            }
          },
          priority: 90,
          maxAttempts: config.queue.retry.maxAttempts
        });

        emitEvent({
          kind: 'run.queued',
          lane: config.queue.defaultLane,
          sessionId: session.id,
          runId: replacementRun.id,
          level: 'info',
          message: 'Run re-queued after Telegram model switch',
          data: {
            previousRunId: activeRun.id,
            runtime: targetRuntime,
            model: nextModel,
            reasoningEffort: updatedSession.preferredReasoningEffort
          }
        });
      }

      await saveOutboundMessage(
        session,
        'system',
        'system',
        `Model set to ${nextModel ?? 'default'}${nextReasoningEffort ? ` (${nextReasoningEffort})` : ''}${activeRun ? ' (active run restarted)' : ''}.`,
        {
          command: 'model'
        }
      );

      return jsonOk(reply, {
        status: 'command_applied',
        command: 'model',
        switched: Boolean(activeRun),
        sessionId: session.id,
        sessionKey: session.sessionKey
      });
    }

    if (command.toLowerCase().startsWith('/remember')) {
      const content = command.replace(/^\/remember\b/i, '').trim();
      if (!content) {
        await saveOutboundMessage(
          session,
          'system',
          'system',
          'Usage: /remember <fact to store>',
          {
            command: 'remember'
          }
        );
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'remember_content_required'
        });
      }

      const stored = await storeExplicitMemoryEntry(content, 'command');
      await saveOutboundMessage(session, 'system', 'system', 'Noted. I saved this to memory.', {
        command: 'remember',
        memoryRowId: stored.rowId,
        memoryFilePath: stored.memoryFilePath,
        dailyFilePath: stored.dailyFilePath
      });
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'remember',
        memoryRowId: stored.rowId
      });
    }

    if (/^\/skill(?:\s|$)/i.test(command)) {
      const skillInvocation = resolveTelegramSkillCommandInvocation(command);
      if (!skillInvocation?.skillName) {
        const availableSkills = buildTelegramSkillCommandEntries()
          .slice(0, 12)
          .map((entry) => `/${entry.command}`)
          .join(', ');
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Usage: /skill <name> [task]\nAvailable skills: ${availableSkills || '(none)'}`,
          {
            command: 'skill',
            reason: 'skill_name_required'
          }
        );
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'skill_name_required'
        });
      }
    }

    if (command.toLowerCase().startsWith('/memory')) {
      const query = command.replace(/^\/memory\b/i, '').trim();
      if (!query) {
        await saveOutboundMessage(
          session,
          'system',
          'system',
          'Usage: /memory <query>\nExample: /memory deployment checklist',
          {
            command: 'memory'
          }
        );
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'memory_query_required'
        });
      }

      const results = await memoryService.search({
        agentId: session.agentId,
        query,
        limit: 5
      });
      await saveOutboundMessage(session, 'system', 'system', formatMemorySearchReply(query, results), {
        command: 'memory',
        query,
        resultCount: results.length
      });
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'memory',
        resultCount: results.length
      });
    }

    if (command.toLowerCase().startsWith('/retention')) {
      const authorized =
        config.channel.telegram.allowlist.length === 0 || config.channel.telegram.allowlist.includes(message.senderId);
      const normalized = command.trim();
      const setMatch = normalized.match(/^\/retention\s+set\s+([a-zA-Z0-9_.]+)\s+(.+)$/i);

      if (!setMatch) {
        const retentionSummary = [
          'Housekeeping retention policy:',
          `sessions(delegate/dashboard/agent/internal/telegram/office/unknown): ${config.housekeeping.sessionRetentionHours.delegate}/${config.housekeeping.sessionRetentionHours.dashboard}/${config.housekeeping.sessionRetentionHours.agent}/${config.housekeeping.sessionRetentionHours.internal}/${config.housekeeping.sessionRetentionHours.telegram}/${config.housekeeping.sessionRetentionHours.office}/${config.housekeeping.sessionRetentionHours.unknown} hours`,
          `run=${config.housekeeping.runRetentionHours}h terminal=${config.housekeeping.terminalRetentionHours}h waitingInputStale=${config.housekeeping.waitingInputStaleMinutes}m`,
          `message=${config.housekeeping.messageRetentionHours}h realtime=${config.housekeeping.realtimeRetentionHours}h officePresence=${config.housekeeping.officePresenceRetentionHours}h`,
          `llmUsage=${config.housekeeping.llmUsageRetentionDays}d memory=${config.housekeeping.memoryRetentionDays}d memoryMarkdown=${config.housekeeping.memoryMarkdownRetentionDays}d audit=${config.housekeeping.auditRetentionDays}d`,
          `protectedSessionKeys=${config.housekeeping.protectedSessionKeys.join(', ') || '(none)'}`,
          authorized ? 'Use /retention set <path> <value> to update.' : 'You are not authorized to update retention.'
        ].join('\n');
        await saveOutboundMessage(session, 'system', 'system', retentionSummary, {
          command: 'retention',
          authorized
        });
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'retention',
          authorized
        });
      }

      if (!authorized) {
        await saveOutboundMessage(session, 'system', 'system', 'Retention update blocked: unauthorized sender.', {
          command: 'retention',
          reason: 'unauthorized'
        });
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'unauthorized'
        });
      }

      const pathKey = setMatch[1]!;
      const rawValue = setMatch[2]!.trim();
      const updates: Record<string, unknown> = { [pathKey]: rawValue };
      const requestShape: Record<string, unknown> = {
        updates
      };
      const synthetic = await app.inject({
        method: 'PATCH',
        url: '/api/housekeeping/retention',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`,
          'x-ops-role': 'operator'
        },
        payload: {
          ...requestShape,
          actor: `telegram:${message.senderId}`
        }
      });
      if (synthetic.statusCode >= 400) {
        // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
        const payload = synthetic.json();
        await saveOutboundMessage(
          session,
          'system',
          'system',
          // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
          `Retention update failed: ${payload.error ?? `HTTP ${synthetic.statusCode}`}`,
          {
            command: 'retention',
            path: pathKey
          }
        );
        return jsonOk(reply, {
          status: 'blocked',
          // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
          reason: payload.error ?? 'retention_update_failed'
        });
      }

      // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
      const payload = synthetic.json();
      await saveOutboundMessage(
        session,
        'system',
        'system',
        // eslint-disable-next-line @typescript-eslint/no-unsafe-call, @typescript-eslint/no-unsafe-member-access
        `Retention updated: ${(payload.changed ?? []).map((entry: any) => `${entry.path}=${String(entry.value)}`).join(', ') || pathKey}`,
        {
          command: 'retention',
          // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
          changed: payload.changed ?? []
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'retention',
        // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
        changed: payload.changed ?? []
      });
    }

    if (/^\/purge(?:\s+sessions)?\b/i.test(command)) {
      const currentSession = session;
      if (!currentSession) {
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'session_not_found'
        });
      }
      const authorized =
        config.channel.telegram.allowlist.length === 0 || config.channel.telegram.allowlist.includes(message.senderId);
      if (!authorized) {
        await saveOutboundMessage(currentSession, 'system', 'system', 'Session purge blocked: unauthorized sender.', {
          command: 'purge_sessions',
          reason: 'unauthorized'
        });
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'unauthorized'
        });
      }

      const purgeTargets = listAllSessions().filter((candidate) => candidate.id !== currentSession.id);
      const sessionIds = purgeTargets.map((candidate) => candidate.id);
      const activeRuns = purgeTargets
        .map((candidate) => findLatestActiveRun(candidate.id))
        .filter(
          (run): run is RunRecord => run !== undefined && ['queued', 'accepted', 'running', 'waiting_input'].includes(run.status)
        );

      for (const run of activeRuns) {
        try {
          await runtimeManager.abort(run.id, run.runtime);
        } catch {
          // Keep purge resilient; deleted sessions cascade run cleanup right after.
        }
      }

      const cleared =
        sessionIds.length > 0
          ? database.deleteSessionsByIds(sessionIds)
          : {
              sessions: 0,
              runs: 0,
              messages: 0,
              officePresence: 0,
              realtimeEvents: 0,
              llmUsageEvents: 0
            };
      const deletedSet = new Set(sessionIds);
      for (const [code, link] of pendingSessionLinks.entries()) {
        if (deletedSet.has(link.sessionId)) {
          pendingSessionLinks.delete(code);
        }
      }
      for (const [bindingKey, binding] of telegramSessionBindings.entries()) {
        if (deletedSet.has(binding.sessionId)) {
          telegramSessionBindings.delete(bindingKey);
        }
      }

      if (purgeTargets.some((candidate) => candidate.agentId === resolvePrimaryCeoAgentId())) {
        ensureCeoOfficeAnchorSession();
      }

      database.appendAudit({
        actor: `telegram:${message.senderId}`,
        action: 'session.telegram_purge',
        resource: 'sessions',
        decision: 'allowed',
        reason: 'operator_cleanup',
        details: {
          preservedSessionId: currentSession.id,
          deletedSessionIds: sessionIds,
          activeRunsAborted: activeRuns.map((run) => run.id),
          cleared
        },
        correlationId: randomUUID()
      });

      await saveOutboundMessage(
        currentSession,
        'system',
        'system',
        `Session purge completed.\nDeleted sessions: ${cleared.sessions}\nRuns deleted: ${cleared.runs}\nMessages deleted: ${cleared.messages}\nRealtime events deleted: ${cleared.realtimeEvents}\nLLM usage events deleted: ${cleared.llmUsageEvents}\nCurrent session preserved: ${currentSession.sessionKey}`,
        {
          command: 'purge_sessions',
          cleared,
          preservedSessionId: currentSession.id
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'purge_sessions',
        cleared,
        preservedSessionId: currentSession.id
      });
    }

    if (/^\/reset(?:\s+memory)?\b/i.test(command)) {
      const authorized =
        config.channel.telegram.allowlist.length === 0 || config.channel.telegram.allowlist.includes(message.senderId);
      if (!authorized) {
        await saveOutboundMessage(session, 'system', 'system', 'Memory reset blocked: unauthorized sender.', {
          command: 'reset_memory',
          reason: 'unauthorized'
        });
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'unauthorized'
        });
      }

      try {
        const result = await executeMemoryReset({
          actor: `telegram:${message.senderId}`,
          scopeRoot: config.runtime.workspaceRoot
        });
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Memory reset completed.\nStructured memory rows deleted: ${result.db.items}\nEmbedding rows deleted: ${result.db.embeddings}\nMarkdown artifacts removed: ${result.filesRemoved}`,
          {
            command: 'reset_memory',
            result
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'reset_memory',
          result
        });
      } catch (error) {
        const messageText = error instanceof Error ? error.message : String(error);
        await saveOutboundMessage(session, 'system', 'system', `Memory reset failed: ${messageText}`, {
          command: 'reset_memory',
          error: messageText
        });
        return jsonOk(reply, {
          status: 'blocked',
          reason: messageText
        });
      }
    }

    if (/^\/cleanup(?:\s+now)?\b/i.test(command)) {
      const authorized =
        config.channel.telegram.allowlist.length === 0 || config.channel.telegram.allowlist.includes(message.senderId);
      if (!authorized) {
        await saveOutboundMessage(session, 'system', 'system', 'Cleanup command blocked: unauthorized sender.', {
          command: 'cleanup',
          reason: 'unauthorized'
        });
        return jsonOk(reply, {
          status: 'blocked',
          reason: 'unauthorized'
        });
      }

      try {
        const result = await runHousekeeping(`telegram:${message.senderId}`, 'manual');
        if (isHousekeepingSkippedResult(result)) {
          await saveOutboundMessage(
            session,
            'system',
            'system',
            `Cleanup skipped (${result.reason}).`,
            {
              command: 'cleanup',
              result
            }
          );
          return jsonOk(reply, {
            status: 'command_applied',
            command: 'cleanup',
            result
          });
        }

        const runsPruned = result.prune.runsPrunedFromSessionPrune + result.prune.runsPrunedByAge;
        const messagesPruned = result.prune.messagesPrunedFromSessionPrune + result.prune.messagesPrunedByAge;
        const terminalsPruned =
          result.prune.terminalSessionsPrunedBySessionPrune + result.prune.terminalSessionsPrunedByAge;
        const terminalChunksPruned =
          result.prune.terminalChunksPrunedBySessionPrune + result.prune.terminalChunksPrunedByAge;
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `Cleanup completed.\nSessions pruned: ${result.prune.sessionsPruned}\nRuns pruned: ${runsPruned}\nMessages pruned: ${messagesPruned}\nTerminal sessions pruned: ${terminalsPruned}\nTerminal chunks pruned: ${terminalChunksPruned}\nStale waiting demoted: ${result.prune.staleWaitingRunsDemoted}\nStale live demoted: ${result.prune.staleLiveRunsDemoted}`,
          {
            command: 'cleanup',
            result
          }
        );
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'cleanup',
          result
        });
      } catch (error) {
        const messageText = error instanceof Error ? error.message : String(error);
        await saveOutboundMessage(session, 'system', 'system', `Cleanup failed: ${messageText}`, {
          command: 'cleanup',
          error: messageText
        });
        return jsonOk(reply, {
          status: 'blocked',
          reason: messageText
        });
      }
    }

    if (command.startsWith('/tail')) {
      const activeRun = findLatestActiveRun(session.id);
      if (!activeRun) {
        await saveOutboundMessage(session, 'system', 'system', 'No active run to tail right now.', {
          command: 'tail'
        });
        return jsonOk(reply, {
          status: 'command_applied',
          command: 'tail',
          activeRun: null
        });
      }

      const terminal = database.getRunTerminalSession(activeRun.id);

      const rawTailArg = command.replace('/tail', '').trim();
      const maxChars = (() => {
        const parsed = Number(rawTailArg);
        if (!Number.isFinite(parsed)) {
          return 1800;
        }
        return Math.max(200, Math.min(3200, Math.floor(parsed)));
      })();
      const chunks = database.listRunTerminalChunks(activeRun.id, 0, 5000);
      const merged = chunks.map((chunk) => chunk.chunk).join('');
      const tail = merged.length > maxChars ? merged.slice(-maxChars) : merged;
      const content = tail.trim().length > 0 ? tail.trim() : '(no output yet)';

      await saveOutboundMessage(
        session,
        'system',
        'system',
        `Run ${activeRun.id} (${activeRun.status}) terminal tail:\n\n${content}`,
        {
          command: 'tail',
          runId: activeRun.id,
          chars: content.length,
          mode: terminal?.mode ?? 'unknown'
        }
      );

      return jsonOk(reply, {
        status: 'command_applied',
        command: 'tail',
        activeRun: activeRun.id,
        terminal: Boolean(terminal)
      });
    }

    if (command.toLowerCase().startsWith('/resume')) {
      const activeRun = findLatestActiveRun(session.id);
      if (!activeRun || activeRun.status !== 'waiting_input') {
        await saveOutboundMessage(
          session,
          'system',
          'system',
          'No paused run is waiting for input right now.',
          {
            command: 'resume'
          }
        );
        return jsonOk(reply, {
          status: 'ignored',
          reason: 'no_waiting_run'
        });
      }

      const rawPrompt = command.replace(/^\/resume\b/i, '').trim();
      const resumePrompt =
        rawPrompt.length > 0
          ? rawPrompt
          : 'Continue the task after operator remediation and provide the final result.';
      const resumed = await executeRunControlAction({
        run: activeRun,
        session,
        action: 'resume',
        prompt: resumePrompt,
        actor: message.senderId
      });

      const responseLine =
        resumed.run.status === 'waiting_input'
          ? 'Run resumed, but it is still waiting for additional input.'
          : `Run resumed and is now ${resumed.run.status}.`;
      const waitingPromptLine =
        typeof resumed.result.waitingPrompt === 'string' && resumed.result.waitingPrompt.trim().length > 0
          ? `\nNext prompt: ${resumed.result.waitingPrompt.trim()}`
          : '';

      await saveOutboundMessage(
        session,
        'system',
        'system',
        `${responseLine}${waitingPromptLine}`,
        {
          command: 'resume',
          runId: activeRun.id,
          actor: message.senderId
        }
      );
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'resume',
        runId: resumed.run.id,
        runStatus: resumed.run.status,
        heartbeat: resumed.heartbeat
      });
    }

    const naturalRememberContent = parseNaturalRememberContent(command);
    if (naturalRememberContent) {
      const stored = await storeExplicitMemoryEntry(naturalRememberContent, 'natural_language');
      await saveOutboundMessage(session, 'system', 'system', 'Noted. I saved this to memory.', {
        command: 'remember',
        mode: 'natural_language',
        memoryRowId: stored.rowId,
        memoryFilePath: stored.memoryFilePath,
        dailyFilePath: stored.dailyFilePath
      });
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'remember',
        mode: 'natural_language',
        memoryRowId: stored.rowId
      });
    }

    const naturalMemoryQuery = parseNaturalMemoryQuery(command);
    if (naturalMemoryQuery) {
      const results = await memoryService.search({
        agentId: session.agentId,
        query: naturalMemoryQuery,
        limit: 5
      });
      await saveOutboundMessage(session, 'system', 'system', formatMemorySearchReply(naturalMemoryQuery, results), {
        command: 'memory',
        mode: 'natural_language',
        query: naturalMemoryQuery,
        resultCount: results.length
      });
      return jsonOk(reply, {
        status: 'command_applied',
        command: 'memory',
        mode: 'natural_language',
        resultCount: results.length
      });
    }

    const skillInvocation = resolveTelegramSkillCommandInvocation(command);
    const skillCommandEntries = buildTelegramSkillCommandEntries();
    const resolvedSkillMenuEntry = skillInvocation
      ? skillCommandEntries.find((entry) => entry.skillName === skillInvocation.skillName) ?? null
      : null;
    const telegramSkillInvocationMetadata = skillInvocation
      ? {
          skillName: skillInvocation.skillName,
          source: skillInvocation.mode,
          args: skillInvocation.args,
          alias: resolvedSkillMenuEntry?.command ?? null,
          visibleInMenu: resolvedSkillMenuEntry?.visibleInMenu ?? false,
          hiddenReason: resolvedSkillMenuEntry?.hiddenReason ?? null
        }
      : null;
    const effectivePrompt = skillInvocation ? buildTelegramSkillCommandPrompt(skillInvocation) : message.text;
    session = maybePersistSessionLinkedRepoContext(session, effectivePrompt);
    const collaborationMention = extractTelegramCollaborationMention(message.text);
    const collaborationRoute = collaborationRouteState(session);
    const resolveStickyCollaborationTarget = () => {
      if (!collaborationRoute.targetAgentId && !collaborationRoute.targetSessionId) {
        return null;
      }
      return resolveCollaborationTarget(session!, collaborationRoute.targetSessionId ?? collaborationRoute.targetAgentId ?? '');
    };
    if (collaborationMention.ambiguity.length > 1) {
      persistTelegramInboundMessage(session, message.text, {
        telegramSkillInvocation: telegramSkillInvocationMetadata,
        collaboration: {
          mode: 'telegram_mention',
          ambiguity: collaborationMention.ambiguity
        }
      });
      await saveOutboundMessage(
        session,
        'system',
        'system',
        `Mention routing blocked. Use a single specialist mention only: ${collaborationMention.ambiguity.map((entry) => `@${entry}`).join(', ')}`,
        {
          command: 'agent',
          subcommand: 'mention',
          ambiguity: collaborationMention.ambiguity
        }
      );
      return jsonOk(reply, {
        status: 'blocked',
        reason: 'collaboration_mention_ambiguous',
        candidates: collaborationMention.ambiguity
      });
    }
    if (collaborationMention.selector) {
      const resolvedMention = resolveCollaborationTarget(session, collaborationMention.selector);
      if (!resolvedMention.ok) {
        persistTelegramInboundMessage(session, message.text, {
          telegramSkillInvocation: telegramSkillInvocationMetadata,
          collaboration: {
            mode: 'telegram_mention',
            selector: collaborationMention.selector,
            reason: resolvedMention.reason,
            candidates: resolvedMention.candidates ?? []
          }
        });
        await saveOutboundMessage(session, 'system', 'system', resolvedMention.message, {
          command: 'agent',
          subcommand: 'mention',
          selector: collaborationMention.selector,
          candidates: resolvedMention.candidates ?? []
        });
        return jsonOk(reply, {
          status: 'blocked',
          reason: resolvedMention.reason,
          candidates: resolvedMention.candidates ?? []
        });
      }
      if (!(resolvedMention.targetSession?.id === session.id && resolvedMention.targetProfile.id === session.agentId)) {
        persistTelegramInboundMessage(session, message.text, {
          telegramSkillInvocation: telegramSkillInvocationMetadata,
          collaboration: {
            mode: 'telegram_mention',
            selector: collaborationMention.selector,
            targetAgentId: resolvedMention.targetProfile.id,
            prompt: collaborationMention.prompt
          }
        });
        const collaboration = queueCollaborativeRun({
          originSession: session,
          targetProfile: resolvedMention.targetProfile,
          prompt: collaborationMention.prompt,
          actor: message.senderId,
          resolvedBy: resolvedMention.resolvedBy,
          announce: true,
          routeMode: 'telegram_mention'
        });
        return jsonOk(reply, {
          status: 'queued',
          sessionId: session.id,
          sessionKey: session.sessionKey,
          targetSessionId: collaboration.targetSession.id,
          targetAgentId: resolvedMention.targetProfile.id,
          routeMode: 'telegram_mention',
          skillInvocation: telegramSkillInvocationMetadata,
          runId: collaboration.run.id
        });
      }
    } else if (collaborationRoute.targetAgentId || collaborationRoute.targetSessionId) {
      const resolvedStickyTarget = resolveStickyCollaborationTarget();
      if (!resolvedStickyTarget || !resolvedStickyTarget.ok) {
        session = updateCollaborationRouteState(session, null);
        persistTelegramInboundMessage(session, message.text, {
          telegramSkillInvocation: telegramSkillInvocationMetadata,
          collaboration: {
            mode: 'telegram_switch',
            routeInvalidated: true,
            targetAgentId: collaborationRoute.targetAgentId,
            targetSessionId: collaborationRoute.targetSessionId,
            reason: resolvedStickyTarget?.reason ?? 'missing'
          }
        });
        await saveOutboundMessage(
          session,
          'system',
          'system',
          `${resolvedStickyTarget?.message ?? 'Soft route is no longer valid.'} Soft routing was cleared; your message stayed in the current chat.`,
          {
            command: 'agent',
            subcommand: 'back',
            clearedBecause: resolvedStickyTarget?.reason ?? 'missing'
          }
        );
      } else if (!(resolvedStickyTarget.targetSession?.id === session.id && resolvedStickyTarget.targetProfile.id === session.agentId)) {
        persistTelegramInboundMessage(session, message.text, {
          telegramSkillInvocation: telegramSkillInvocationMetadata,
          collaboration: {
            mode: 'telegram_switch',
            targetAgentId: resolvedStickyTarget.targetProfile.id
          }
        });
        const collaboration = queueCollaborativeRun({
          originSession: session,
          targetProfile: resolvedStickyTarget.targetProfile,
          prompt: effectivePrompt,
          actor: message.senderId,
          resolvedBy: resolvedStickyTarget.resolvedBy,
          announce: true,
          routeMode: 'telegram_switch'
        });
        return jsonOk(reply, {
          status: 'queued',
          sessionId: session.id,
          sessionKey: session.sessionKey,
          targetSessionId: collaboration.targetSession.id,
          targetAgentId: resolvedStickyTarget.targetProfile.id,
          routeMode: 'telegram_switch',
          skillInvocation: telegramSkillInvocationMetadata,
          runId: collaboration.run.id
        });
      }
    }
    const runtime = resolveSessionRuntime(session);
    const model = resolveSessionModel(session);
    const reasoningEffort = resolveSessionReasoningEffort(session);
    const hasDispatchCandidate = hasPotentialDispatchCandidate(session, true);
    const runtimeProfileError = assertSessionRuntimeAllowed(session, runtime);
    if (runtimeProfileError && !hasDispatchCandidate) {
      await saveOutboundMessage(session, 'system', 'system', `Run blocked: ${runtimeProfileError}`, {
        command: 'run',
        reason: 'agent_profile_policy'
      });
      return jsonOk(reply, {
        status: 'blocked',
        reason: 'agent_profile_policy',
        details: runtimeProfileError
      });
    }
    const runtimeToolError = assertRuntimeToolEnabled(runtime);
    if (runtimeToolError && !hasDispatchCandidate) {
      await saveOutboundMessage(session, 'system', 'system', `Run blocked: ${runtimeToolError}`, {
        command: 'run',
        reason: 'tool_policy'
      });
      return jsonOk(reply, {
        status: 'blocked',
        reason: 'tool_policy',
        details: runtimeToolError
      });
    }

    const backlogItemIdFromIngress: string | null = null;
    const informationalPrompt = shouldTreatPromptAsInformationalConversation(effectivePrompt);

    const promptWithProfile = enrichPromptForSession(session, effectivePrompt);
    let run = database.createRun({
      sessionId: session.id,
      runtime,
      requestedRuntime: runtime,
      requestedModel: model,
      requestedReasoningEffort: reasoningEffort,
      effectiveRuntime: runtime,
      effectiveModel: model,
      effectiveReasoningEffort: reasoningEffort,
      triggerSource: 'telegram',
      prompt: promptWithProfile,
      status: 'queued'
    });

    persistTelegramInboundMessage(session, message.text, {
      telegramSkillInvocation: telegramSkillInvocationMetadata
    });
    if (telegramSkillInvocationMetadata) {
      database.appendRunEvent({
        runId: run.id,
        sessionId: session.id,
        type: 'run.telegram_skill_invocation',
        details: 'Telegram skill command resolved before queueing the run.',
        payload: telegramSkillInvocationMetadata
      });
    }

    const dispatchOnly = isDispatchOnlySession(session);
    const delegationResult =
      informationalPrompt && !dispatchOnly
        ? {
            delegations: [],
            blockedTargetAgentIds: [],
            inference: buildSyntheticIntakeInference('answer_direct', 'informational_prompt', 1)
          }
        : await queueAutoDelegations({
            sourceSession: session,
            prompt: effectivePrompt,
            lane: config.queue.defaultLane,
            priority: 90,
            mode: 'auto_orchestrate'
          });
    const delegations = delegationResult.delegations;
    const delegationDecisionSummary = delegationResult.inference
      ? {
          action: delegationResult.inference.action,
          reason: delegationResult.inference.reason,
          confidence: delegationResult.inference.confidence,
          clarifyingQuestion: delegationResult.inference.clarifyingQuestion
        }
      : null;
    const orchestration = summarizeOrchestratorDecision({
      dispatchOnly,
      delegations,
      inference: delegationResult.inference,
      blockedTargetAgentIds: delegationResult.blockedTargetAgentIds
    });

    if (orchestration.status !== 'direct') {
      run = database.updateRunStatus({
        runId: run.id,
        status: 'completed',
        resultSummary: orchestration.message
      });

      const workspacePath = resolveRunWorkspacePath(config, session);
      const autoRemember = await memoryService.autoRememberRun({
        workspacePath,
        sessionId: session.id,
        agentId: session.agentId,
        channel: session.channel,
        runId: run.id,
        status: 'completed',
        runtime,
        model,
        summary: orchestration.message
      });

      if (delegations.length === 0) {
        await saveOutboundMessage(session, 'system', 'system', orchestration.message, {
          runId: run.id,
          interactionMode: delegationResult.inference?.action ?? null,
          interactionModeReason: delegationResult.inference?.reason ?? null,
          mode: 'orchestrator',
          orchestration,
          delegations,
          blockedTargetAgentIds: delegationResult.blockedTargetAgentIds,
          backlogItemId: backlogItemIdFromIngress
        });
      }

      emitEvent({
        kind: 'run.completed',
        lane: config.queue.defaultLane,
        sessionId: session.id,
        runId: run.id,
        level: 'info',
        message: 'Telegram orchestrator resolved request without direct CEO execution',
        data: {
          senderId: message.senderId,
          delegations,
          orchestration,
          autoRemember,
          backlogItemId: backlogItemIdFromIngress
        }
      });

      return jsonOk(reply, {
        status: orchestration.status,
        sessionId: session.id,
        runId: run.id,
        sessionKey: session.sessionKey,
        skillInvocation: telegramSkillInvocationMetadata,
        delegations,
        delegationDecision: delegationDecisionSummary,
        blockedDelegationTargets: delegationResult.blockedTargetAgentIds,
        backlogItemId: backlogItemIdFromIngress
      });
    }

    database.enqueueQueueItem({
      lane: config.queue.defaultLane,
      sessionId: session.id,
      runId: run.id,
      payload: {
        updateId: message.updateId,
        attachments: message.attachments,
        source: 'telegram',
        metadata: {
          model,
          reasoningEffort,
          intakeDecisionAction: delegationResult.inference?.action ?? null,
          intakeDecisionReason: delegationResult.inference?.reason ?? null
        }
      },
      priority: 90,
      maxAttempts: config.queue.retry.maxAttempts
    });

    emitEvent({
      kind: 'run.queued',
      lane: config.queue.defaultLane,
      sessionId: session.id,
      runId: run.id,
      level: 'info',
      message: 'Telegram ingress queued run',
      data: {
        senderId: message.senderId,
        chatType: message.chatType,
        attachments: message.attachments.length,
        runtime,
        model,
        reasoningEffort,
        delegations,
        delegationDecision: delegationDecisionSummary,
        backlogItemId: backlogItemIdFromIngress
      }
    });

    return jsonOk(reply, {
      status: 'queued',
      sessionId: session.id,
      runId: run.id,
      sessionKey: session.sessionKey,
      skillInvocation: telegramSkillInvocationMetadata,
      delegations,
      delegationDecision: delegationDecisionSummary,
      blockedDelegationTargets: delegationResult.blockedTargetAgentIds,
      backlogItemId: backlogItemIdFromIngress
    });
  });

