  app.get('/api/events/stream', async (request, reply) => {
    const query = request.query as Record<string, unknown>;
    const since = Math.max(0, Number(query.since ?? request.headers['last-event-id'] ?? 0));

    reply.raw.writeHead(200, {
      'Content-Type': 'text/event-stream',
      Connection: 'keep-alive',
      'Cache-Control': 'no-cache, no-transform'
    });

    let cursor = since;
    let active = true;

    const sendEvent = (event: RuntimeEvent): void => {
      if (!active || event.sequence <= cursor) {
        return;
      }

      const payload = JSON.stringify(event);
      if (reply.raw.writableLength > 1_000_000) {
        active = false;
        reply.raw.write(`event: backpressure\ndata: {"reason":"client_backpressure"}\n\n`);
        reply.raw.end();
        return;
      }

      reply.raw.write(`id: ${event.sequence}\n`);
      reply.raw.write(`event: ${event.kind}\n`);
      reply.raw.write(`data: ${payload}\n\n`);
      cursor = event.sequence;
    };

    for (const event of database.listRealtimeEvents(since, 500)) {
      sendEvent(event);
    }

    const unsubscribe = observability.subscribe(sendEvent);

    const heartbeat = setInterval(() => {
      if (!active) {
        return;
      }
      reply.raw.write(`event: heartbeat\ndata: {"ts":"${utcNow()}","cursor":${cursor}}\n\n`);
    }, 10_000);

    request.raw.on('close', () => {
      active = false;
      clearInterval(heartbeat);
      unsubscribe();
    });

    return reply;
  });

