  app.get('/api/office/stream', async (request, reply) => {
    const query = request.query as Record<string, unknown>;
    const since = Math.max(0, Number(query.since ?? 0));

    reply.raw.writeHead(200, {
      'Content-Type': 'text/event-stream',
      Connection: 'keep-alive',
      'Cache-Control': 'no-cache, no-transform'
    });

    let cursor = since;

    const publishPresence = (event: RuntimeEvent): void => {
      if (event.sequence <= cursor) {
        return;
      }

      if (event.kind !== 'presence.updated' && !event.kind.startsWith('run.')) {
        return;
      }

      const payload = {
        event,
        presence: latestPresenceByAgent(database.listOfficePresence())
      };

      reply.raw.write(`id: ${event.sequence}\n`);
      reply.raw.write(`event: office\n`);
      reply.raw.write(`data: ${JSON.stringify(payload)}\n\n`);
      cursor = event.sequence;
    };

    for (const event of database.listRealtimeEvents(since, 500)) {
      publishPresence(event);
    }

    const unsubscribe = observability.subscribe(publishPresence);
    const heartbeat = setInterval(() => {
      reply.raw.write(`event: heartbeat\ndata: {"ts":"${utcNow()}","cursor":${cursor}}\n\n`);
    }, 10_000);

    request.raw.on('close', () => {
      clearInterval(heartbeat);
      unsubscribe();
    });

    return reply;
  });

  app.get('/api/bff/cards', async (_request, reply) => {
    const queueMetrics = database.queueMetrics();
    const sessions = database.listSessions({ limit: 500, offset: 0 }).rows;
    const runs = database.listRuns({ limit: 2000, offset: 0 }).rows;
    const localRuntimeSessions = database.listLocalRuntimeSessions({ limit: 2000, runtime: 'all' });
    const compactNumberFormatter = new Intl.NumberFormat('en-US', {
      notation: 'compact',
      maximumFractionDigits: 1
    });
    const formatPercent = (value: number): string => `${Number.isInteger(value) ? value.toFixed(0) : value.toFixed(1)}%`;
    const latestRunBySession = new Map<string, RunRecord>();
    for (const run of runs) {
      if (!latestRunBySession.has(run.sessionId)) {
        latestRunBySession.set(run.sessionId, run);
      }
    }

    const activeFleet = sessions.reduce((count, session) => {
      const latestRun = latestRunBySession.get(session.id);
      if (!latestRun) {
        return count;
      }
      if (latestRun.status === 'accepted' || latestRun.status === 'running' || latestRun.status === 'waiting_input') {
        return count + 1;
      }
      return count;
    }, 0);

    const nowMs = Date.now();
    const failedRunWindowCutoffMs = nowMs - 24 * 60 * 60 * 1000;
    const failedRuns = runs.filter((run) => {
      if (run.status !== 'failed') {
        return false;
      }
      const ts = run.endedAt ?? run.updatedAt ?? run.createdAt;
      if (!ts) {
        return false;
      }
      const parsed = Date.parse(ts);
      return Number.isFinite(parsed) && parsed >= failedRunWindowCutoffMs;
    }).length;
    const waitingRuns = runs.filter((run) => run.status === 'waiting_input').length;
    const successfulTerminalRuns = runs.filter((run) => {
      if (run.status !== 'completed' && run.status !== 'failed') {
        return false;
      }
      const ts = run.endedAt ?? run.updatedAt ?? run.createdAt;
      if (!ts) {
        return false;
      }
      const parsed = Date.parse(ts);
      return Number.isFinite(parsed) && parsed >= failedRunWindowCutoffMs;
    });
    const completedRuns = successfulTerminalRuns.filter((run) => run.status === 'completed').length;
    const successRate =
      successfulTerminalRuns.length > 0 ? Number(((completedRuns / successfulTerminalRuns.length) * 100).toFixed(1)) : 0;

    const [oneMinuteLoad = 0] = os.loadavg();
    const hostLoadPct = Number(
      Math.max(0, Math.min(100, (oneMinuteLoad / Math.max(1, os.cpus().length)) * 100)).toFixed(1)
    );

    let tokensToday = 0;
    for (const session of localRuntimeSessions) {
      const ts = Date.parse(session.lastMessageAt);
      if (!Number.isFinite(ts) || ts < failedRunWindowCutoffMs) {
        continue;
      }
      tokensToday +=
        session.inputTokens + session.outputTokens + session.cacheReadInputTokens + session.cacheCreationInputTokens;
    }
    const hasLocalTokenTelemetry = localRuntimeSessions.length > 0;

    return jsonOk(reply, {
      cards: [
        {
          id: 'active_fleet',
          label: 'Active Fleet',
          value: activeFleet,
          displayValue: String(activeFleet),
          tone: activeFleet > 0 ? 'positive' : 'neutral'
        },
        {
          id: 'success_rate',
          label: 'Run Success (24h)',
          value: successRate,
          displayValue: successfulTerminalRuns.length > 0 ? formatPercent(successRate) : '--',
          tone:
            successfulTerminalRuns.length === 0 ? 'neutral' : successRate >= 95 ? 'positive' : successRate >= 80 ? 'warn' : 'critical'
        },
        {
          id: 'host_load',
          label: 'Host Load',
          value: hostLoadPct,
          displayValue: formatPercent(hostLoadPct),
          tone: hostLoadPct >= 85 ? 'critical' : hostLoadPct >= 65 ? 'warn' : 'positive'
        },
        {
          id: 'tokens_today',
          label: 'Tokens Today',
          value: tokensToday,
          displayValue: hasLocalTokenTelemetry ? compactNumberFormatter.format(tokensToday) : '--',
          tone: !hasLocalTokenTelemetry ? 'neutral' : tokensToday >= 1_000_000 ? 'warn' : 'neutral'
        },
        {
          id: 'sessions',
          label: 'Active Sessions',
          value: sessions.filter((session) => session.state === 'active').length,
          tone: 'neutral'
        },
        {
          id: 'queue',
          label: 'Queued Items',
          value: queueMetrics.queued,
          tone: queueMetrics.queued > 15 ? 'warn' : 'neutral'
        },
        {
          id: 'failed_runs',
          label: 'Failed Runs (24h)',
          value: failedRuns,
          tone: failedRuns > 0 ? 'critical' : 'positive'
        },
        {
          id: 'waiting_input',
          label: 'Waiting Input',
          value: waitingRuns,
          tone: waitingRuns > 0 ? 'warn' : 'neutral'
        }
      ]
    });
  });

  app.get('/api/bff/board', async (request, reply) => {
    const query = request.query as Record<string, unknown>;
    const search = typeof query.search === 'string' ? query.search : undefined;

    const sessions = database.listSessions({ limit: 500, offset: 0, search }).rows;

    const lanes = {
      queued: [] as Array<Record<string, unknown>>,
      running: [] as Array<Record<string, unknown>>,
      waiting_input: [] as Array<Record<string, unknown>>,
      failed: [] as Array<Record<string, unknown>>,
      completed: [] as Array<Record<string, unknown>>
    };

    for (const session of sessions) {
      const run = database.listRuns({ limit: 1, offset: 0, sessionId: session.id }).rows[0];
      const payload = {
        session,
        run,
        queue: database.listQueueItems('queued', 1000).filter((item) => item.sessionId === session.id).length
      };

      if (!run) {
        lanes.queued.push(payload);
        continue;
      }

      switch (run.status) {
        case 'queued':
          lanes.queued.push(payload);
          break;
        case 'running':
        case 'accepted':
          lanes.running.push(payload);
          break;
        case 'waiting_input':
          lanes.waiting_input.push(payload);
          break;
        case 'failed':
          lanes.failed.push(payload);
          break;
        case 'completed':
        case 'aborted':
          lanes.completed.push(payload);
          break;
        default:
          lanes.running.push(payload);
      }
    }

    return jsonOk(reply, {
      lanes
    });
  });

