  app.post('/api/security/elevated-check', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const requested = Boolean(body.requested ?? false);
    const approved = Boolean(body.approved ?? false);
    const actor = resolveRequestAuditActor(request, config.server.apiToken);
    const action = String(body.action ?? 'unknown_action');
    const correlationId = String(body.correlationId ?? randomUUID());

    if (requested && !config.policy.allowElevatedExecution) {
      const audit = database.appendAudit({
        actor,
        action,
        resource: 'elevated_execution',
        decision: 'blocked',
        reason: 'disabled_by_policy',
        correlationId,
        details: {}
      });

      emitEvent({
        kind: 'security.decision',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'warn',
        message: 'Elevated execution blocked by policy',
        data: {
          auditId: audit.id,
          action
        }
      });

      return jsonError(reply, 'Elevated execution is disabled in policy', 403);
    }

    if (requested && !approved) {
      const audit = database.appendAudit({
        actor,
        action,
        resource: 'elevated_execution',
        decision: 'blocked',
        reason: 'approval_required',
        correlationId,
        details: {}
      });

      emitEvent({
        kind: 'security.decision',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'warn',
        message: 'Elevated execution requires explicit approval',
        data: {
          auditId: audit.id,
          action
        }
      });

      return jsonError(reply, 'Approval required for elevated execution', 412);
    }

    const audit = database.appendAudit({
      actor,
      action,
      resource: 'elevated_execution',
      decision: 'allowed',
      reason: 'approved',
      correlationId,
      details: {
        approver: config.policy.elevatedApprover
      }
    });

    emitEvent({
      kind: 'security.decision',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'info',
      message: 'Elevated execution approved',
      data: {
        auditId: audit.id,
        action
      }
    });

    return jsonOk(reply, {
      allowed: true,
      approver: config.policy.elevatedApprover,
      audit
    });
  });

