  app.post('/api/remediation/signals', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const source = (body.source as 'quality_gate' | 'incident' | 'feedback') ?? 'feedback';
    const severity = (body.severity as 'low' | 'medium' | 'high' | 'critical') ?? 'medium';
    const blastRadius = (body.blastRadius as 'single' | 'lane' | 'multi_lane' | 'global') ?? 'single';
    const summary = String(body.summary ?? body.title ?? 'Untitled signal');
    const details = String(body.details ?? '');
    const evidence = (body.evidence ?? {}) as Record<string, unknown>;
    const signalKey = stableSignalKey([
      source,
      severity,
      blastRadius,
      typeof evidence.lane === 'string' ? evidence.lane : '',
      summary.toLowerCase().slice(0, 120)
    ]);

    const signal = database.createRemediationSignal({
      source,
      signalKey,
      severity,
      blastRadius,
      summary,
      details,
      evidence
    });

    const plan = database.createRemediationPlan({
      signalId: signal.id,
      priority: remediationPriority(severity, blastRadius),
      requiresApproval: remediationNeedsApproval(severity, blastRadius),
      status: 'planned',
      title: `Remediate: ${summary}`,
      actions: remediationPlanActions(summary),
      policy: {
        severity,
        blastRadius,
        source,
        requiresApproval: remediationNeedsApproval(severity, blastRadius)
      }
    });

    emitEvent({
      kind: 'remediation.signal.ingested',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: severity === 'critical' ? 'error' : severity === 'high' ? 'warn' : 'info',
      message: `Remediation signal ingested (${severity})`,
      data: {
        signalId: signal.id,
        signalKey: signal.signalKey,
        planId: plan.id
      }
    });

    emitEvent({
      kind: 'remediation.plan.created',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'info',
      message: 'Remediation plan created',
      data: {
        signalId: signal.id,
        planId: plan.id,
        priority: plan.priority,
        requiresApproval: plan.requiresApproval
      }
    });

    return jsonOk(reply, { signal, plan }, 201);
  });

