  const readManifestFromSource = async (source: Record<string, unknown>): Promise<Record<string, unknown>> => {
    const mode = typeof source.mode === 'string' ? source.mode.trim().toLowerCase() : 'local';
    if (mode === 'local') {
      const ref = String(source.reference ?? source.path ?? '').trim();
      if (!ref) {
        throw new Error('local source requires reference/path');
      }
      const resolved = path.isAbsolute(ref) ? ref : path.resolve(ref);
      const raw = await fs.readFile(resolved, 'utf8');
      return parseJsonSafe<Record<string, unknown>>(raw, {});
    }
    if (mode === 'url') {
      const ref = String(source.reference ?? source.url ?? '').trim();
      if (!ref) {
        throw new Error('url source requires reference/url');
      }
      const response = await fetch(ref);
      if (!response.ok) {
        throw new Error(`failed to fetch manifest: ${response.status}`);
      }
      const text = await response.text();
      return parseJsonSafe<Record<string, unknown>>(text, {});
    }
    if (mode === 'git') {
      const repo = String(source.repository ?? process.cwd()).trim() || process.cwd();
      const tree = String(source.reference ?? '').trim();
      if (!tree || !tree.includes(':')) {
        throw new Error('git source requires reference like "<ref>:<path>"');
      }
      const show = spawnSync('git', ['-C', repo, 'show', tree], {
        encoding: 'utf8'
      });
      if (show.status !== 0) {
        throw new Error(show.stderr || show.stdout || 'git show failed');
      }
      return parseJsonSafe<Record<string, unknown>>(String(show.stdout ?? ''), {});
    }
    throw new Error(`unsupported source mode: ${mode}`);
  };

