  app.get('/api/frontier/governance', async (request, reply) => {
    const actor = resolveFrontierActor(request);
    const principal = frontierGovernanceState.principals.find((entry) => entry.id === actor.principalId);
    if (principal?.instanceAdmin) {
      return jsonOk(reply, {
        governance: frontierGovernanceState
      });
    }
    const memberships = frontierGovernanceState.memberships.filter(
      (entry) => entry.principalId === actor.principalId && entry.status === 'active'
    );
    const companyIds = new Set(memberships.map((entry) => entry.companyId));
    const companies = frontierGovernanceState.companies.filter((entry) => companyIds.has(entry.id));
    const principalIds = new Set([actor.principalId, ...companies.map((entry) => entry.ownerPrincipalId)]);
    for (const membership of memberships) {
      principalIds.add(membership.principalId);
    }
    return jsonOk(reply, {
      governance: {
        ...frontierGovernanceState,
        principals: frontierGovernanceState.principals.filter((entry) => principalIds.has(entry.id)),
        companies,
        memberships,
        grants: frontierGovernanceState.grants.filter(
          (entry) => companyIds.has(entry.companyId) && entry.principalId === actor.principalId
        )
      }
    });
  });

