  app.post('/api/frontier/deployment/doctor', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const runRepair = body.repair === true;
    const checks: Array<{
      id: string;
      status: 'pass' | 'warn' | 'fail';
      detail: string;
      repairable: boolean;
      repaired: boolean;
    }> = [];
    const hostAllowlistMissing = frontierDeploymentState.allowedHostnames.length === 0;
    checks.push({
      id: 'hostname_allowlist',
      status: hostAllowlistMissing ? 'fail' : 'pass',
      detail: hostAllowlistMissing ? 'No allowed hostnames configured.' : 'Allowed hostnames configured.',
      repairable: true,
      repaired: false
    });
    if (hostAllowlistMissing && runRepair) {
      frontierDeploymentState.allowedHostnames = [config.server.host, '127.0.0.1', 'localhost']
        .map((entry) => entry.trim())
        .filter((entry, index, all) => entry.length > 0 && all.indexOf(entry) === index);
      checks[checks.length - 1] = {
        ...checks[checks.length - 1]!,
        status: 'pass',
        repaired: true,
        detail: 'Allowed hostnames repaired from runtime config defaults.'
      };
    }

    const trustedOriginsMissing = frontierDeploymentState.mode !== 'local_trusted' && frontierDeploymentState.trustedOrigins.length === 0;
    checks.push({
      id: 'trusted_origins',
      status: trustedOriginsMissing ? 'fail' : 'pass',
      detail: trustedOriginsMissing ? 'No trusted origins configured for authenticated mode.' : 'Trusted origins configured.',
      repairable: true,
      repaired: false
    });
    if (trustedOriginsMissing && runRepair) {
      frontierDeploymentState.trustedOrigins = localTrustedOrigins(config.server.port);
      checks[checks.length - 1] = {
        ...checks[checks.length - 1]!,
        status: 'pass',
        repaired: true,
        detail: 'Trusted origins repaired with local ElyzeLabs defaults.'
      };
    }

    const authReady = config.server.apiToken.trim().length >= 8 && !config.server.apiToken.includes('change-me');
    checks.push({
      id: 'auth_readiness',
      status: frontierDeploymentState.mode === 'local_trusted' || authReady ? 'pass' : 'fail',
      detail:
        frontierDeploymentState.mode === 'local_trusted' || authReady
          ? 'Auth readiness check passed.'
          : 'Authenticated mode requires a non-placeholder API token.',
      repairable: false,
      repaired: false
    });

    const runtimeChecks = adapterDiagnostics(config);
    const runtimeFails = runtimeChecks.filter((entry) => entry.status === 'fail').length;
    checks.push({
      id: 'runtime_diagnostics',
      status: runtimeFails > 0 ? 'warn' : 'pass',
      detail: runtimeFails > 0 ? `${runtimeFails} runtime adapter probes failed.` : 'Runtime adapter probes passed.',
      repairable: false,
      repaired: false
    });

    if (runRepair) {
      persistFrontierDeployment(frontierDeploymentState);
    }

    const overall = checks.some((entry) => entry.status === 'fail') ? 'fail' : checks.some((entry) => entry.status === 'warn') ? 'warn' : 'pass';
    const report = {
      schema: 'ops.frontier-doctor.v1',
      version: 1,
      overall,
      checks,
      deployment: frontierDeploymentState,
      runtimeDiagnostics: runtimeChecks,
      generatedAt: utcNow()
    };
    database.upsertRuntimeStateSnapshot('frontier.deployment.doctor-report.v1', report as unknown as Record<string, unknown>);
    return jsonOk(reply, {
      doctor: report
    });
  });

