  app.put('/api/frontier/scorecard', async (request, reply) => {
    const permission = requireFrontierPermission(
      request,
      reply,
      'frontier.scorecard.update',
      'deployment.configure',
      resolveFrontierPrimaryCompanyId()
    );
    if (!permission) {
      return reply;
    }
    const body = (request.body ?? {}) as Record<string, unknown>;
    const current = loadFrontierScorecard();
    const incoming = isRecord(body.scorecard) ? body.scorecard : body;
    const dimensionsRaw = isRecord(incoming.dimensions) ? incoming.dimensions : current.dimensions;
    const dimensions: FrontierScorecard['dimensions'] = {};
    for (const [dimension, value] of Object.entries(dimensionsRaw)) {
      if (!isRecord(value)) {
        continue;
      }
      const threshold = Number(value.threshold);
      const weight = Number(value.weight);
      dimensions[dimension] = {
        threshold: Number.isFinite(threshold) ? Math.max(0, Math.min(1, threshold)) : 0.8,
        weight: Number.isFinite(weight) ? Math.max(0, Math.min(1, weight)) : 0.2,
        label:
          typeof value.label === 'string' && value.label.trim().length > 0
            ? value.label.trim()
            : current.dimensions[dimension]?.label ?? dimension,
        comparatorFocus: Array.isArray(value.comparatorFocus)
          ? value.comparatorFocus.map((entry) => String(entry).trim()).filter((entry) => entry.length > 0)
          : current.dimensions[dimension]?.comparatorFocus ?? [],
        rubric:
          typeof value.rubric === 'string' && value.rubric.trim().length > 0
            ? value.rubric.trim()
            : current.dimensions[dimension]?.rubric ?? ''
      };
    }
    const next = mergeFrontierScorecardSnapshot(
      {
        ...current,
        ...incoming,
        dimensions: Object.keys(dimensions).length > 0 ? dimensions : current.dimensions,
        updatedAt: utcNow()
      },
      process.cwd()
    );
    database.upsertRuntimeStateSnapshot(FRONTIER_SCORECARD_SNAPSHOT_ID, next as unknown as Record<string, unknown>);
    return jsonOk(reply, {
      scorecard: next
    });
  });

