  const requireVaultSensitiveApproval = (category: string, approved: boolean): string | null => {
    const sensitiveCategories = new Set(['telegram', 'llm', 'runtime', 'provider']);
    if (sensitiveCategories.has(category) && !approved) {
      return `Category "${category}" requires approved=true`;
    }
    return null;
  };

  app.get('/api/vault/status', async (_request, reply) => {
    return jsonOk(reply, {
      vault: vault.status()
    });
  });

  app.post('/api/vault/reset-empty', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = resolveRequestAuditActor(request, config.server.apiToken);
    const approved = Boolean(body.approved ?? false);
    if (!approved) {
      return jsonError(reply, 'approved=true is required to reset vault keys', 412);
    }

    const secrets = vault.listSecretMetadata(true);
    if (secrets.length > 0) {
      return jsonError(reply, 'Vault reset is only allowed when no secrets are stored', 409);
    }

    database.db.prepare('DELETE FROM vault_secrets').run();
    database.db.prepare('DELETE FROM vault_key_versions').run();
    vault.lock();

    database.appendAudit({
      actor,
      action: 'vault.reset_empty',
      resource: 'vault',
      decision: 'allowed',
      reason: 'keys_cleared',
      details: {
        secretCount: secrets.length
      },
      correlationId: randomUUID()
    });

    emitEvent({
      kind: 'vault.status',
      lane: config.queue.defaultLane,
      sessionId: null,
      runId: null,
      level: 'warn',
      message: 'Vault keys reset because vault had no stored secrets',
      data: {
        resetEmpty: true
      }
    });

    return jsonOk(reply, { vault: vault.status() });
  });

  app.post('/api/vault/bootstrap', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = resolveRequestAuditActor(request, config.server.apiToken);
    const material = String(body.material ?? config.vault.envKey ?? '').trim();
    if (!material) {
      return jsonError(reply, 'material is required to bootstrap vault', 400);
    }

    try {
      const bootstrap = vault.bootstrap(material);
      database.appendAudit({
        actor,
        action: 'vault.bootstrap',
        resource: 'vault',
        decision: 'allowed',
        reason: 'initialized',
        details: bootstrap,
        correlationId: randomUUID()
      });
      emitEvent({
        kind: 'vault.status',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'info',
        message: 'Vault initialized',
        data: bootstrap
      });
      return jsonOk(reply, { vault: vault.status(), bootstrap }, 201);
    } catch (error) {
      return jsonError(reply, error instanceof Error ? error.message : 'Vault bootstrap failed', 400);
    }
  });

  app.post('/api/vault/unlock', async (request, reply) => {
    const body = (request.body ?? {}) as Record<string, unknown>;
    const actor = resolveRequestAuditActor(request, config.server.apiToken);
    const suppliedMaterial = String(body.material ?? body.passphrase ?? '').trim();
    const configuredEnvMaterial = String(config.vault.envKey ?? '').trim();
    const usingManualMaterial = suppliedMaterial.length > 0;

    if (
      usingManualMaterial &&
      !config.vault.allowPassphraseUnlock &&
      (!configuredEnvMaterial || suppliedMaterial !== configuredEnvMaterial)
    ) {
      return jsonError(reply, 'Vault passphrase unlock is disabled by config (vault.allowPassphraseUnlock=false).', 403);
    }

    const material = suppliedMaterial || configuredEnvMaterial;
    if (!material) {
      return jsonError(reply, 'material or passphrase is required', 400);
    }

    try {
      const status = vault.unlock(material);
      hydrateSecretBindingsToEnv();
      database.appendAudit({
        actor,
        action: 'vault.unlock',
        resource: 'vault',
        decision: 'allowed',
        reason: 'unlocked',
        details: {
          activeKeyVersion: status.activeKeyVersion
        },
        correlationId: randomUUID()
      });
      emitEvent({
        kind: 'vault.status',
        lane: config.queue.defaultLane,
        sessionId: null,
        runId: null,
        level: 'info',
        message: 'Vault unlocked',
        data: { ...status }
      });
      return jsonOk(reply, { vault: status });
    } catch (error) {
      database.appendAudit({
        actor,
        action: 'vault.unlock',
        resource: 'vault',
        decision: 'blocked',
        reason: 'unlock_failed',
        details: {
          error: error instanceof Error ? error.message : String(error)
        },
        correlationId: randomUUID()
      });
      return jsonError(reply, error instanceof Error ? error.message : 'Vault unlock failed', 403);
    }
  });

